INSERT INTO public.artist (spotify_id, name, image_url, created_at, updated_at, bio) VALUES ('2uFlruav0o4m1tVv05Bvuc', 'Tim Goldsworthy', 'https://i.scdn.co/image/ab67616d0000b273da09326143c7f88778d9aee4', '2026-04-29 14:48:56.154698+00', '2026-04-29 14:48:56.154698+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.artist (spotify_id, name, image_url, created_at, updated_at, bio) VALUES ('2FXC3k01G6Gw61bmprjgqS', 'Hozier', 'https://i.scdn.co/image/ab6761610000e5ebad85a585103dfc2f3439119a', '2026-04-29 06:27:38.951117+00', '2026-04-29 06:27:38.951117+00', 'In September 2013, when Irish solo artist Andrew Hozier-Byrne released his debut single - a song called ‘Take Me To Church’ - which he had mostly recorded in the attic of his parent’s house in Wicklow (his father a blues musician, his mother an artist), little did he know about the hurricane-strength surge in public interest that the song would spark, carrying him to international stardom.
INSERT INTO public.artist (spotify_id, name, image_url, created_at, updated_at, bio) VALUES ('1r1uxoy19fzMxunt3ONAkG', 'Phoebe Bridgers', 'https://i.scdn.co/image/ab6761610000e5eb626686e362d30246e816cc5b', '2026-04-29 06:26:31.916652+00', '2026-04-29 06:26:31.916652+00', 'A Los Angeles-based singer/songwriter with a dreamy and hook-filled indie pop heart, Phoebe Bridgers'' witty lyrical perspectives, sadly beautiful songs, and commanding melodies have connected with millions of fans worldwide. Bridgers emerged out of nowhere in 2015, and in the space of just a few years her songs drew significant praise and attention, with a solid debut giving way to darker tones on 2020''s Grammy-nominated Punisher. In addition to her solo work, Bridgers has collaborated with other artists to equal and sometimes greater acclaim. In addition to work with Taylor Swift, SZA, Muna, and others, she teamed with Bright Eyes'' Conor Oberst under the name Better Oblivion Community Center, and famously joined forces with likeminded songwriters Lucy Dacus and Julien Baker to form Boygenius, a supergroup who enjoyed chart success and across-the-board critical praise for their Grammy-winning 2023 full-length debut The Record.
INSERT INTO public.artist (spotify_id, name, image_url, created_at, updated_at, bio) VALUES ('2h93pZq0e7k5yf4dywlkpM', 'Frank Ocean', 'https://i.scdn.co/image/ab6761610000e5ebee3123e593174208f9754fab', '2026-04-29 06:13:45.298947+00', '2026-04-29 06:13:45.298947+00', 'Visionary American recording artist Frank Ocean is one of the most celebrated and critically acclaimed artists of this era.
