INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('b36ac547-2033-4c89-883f-6b724dd1e025', 'd23c619e-e097-419d-89b5-263800ce70fa', '{"headline": "A quiet understanding of moments passed, holding onto the bittersweet ache of memory.", "compound_mood": "Echoing Melancholy", "sonic_texture": "Warm, shimmering synth pads swell and recede, painting vast, open spaces. Underneath, a deep, resonant bass provides a quiet anchor, as delicate electronic arpeggios twinkle like distant stars. A gentle, insistent beat pulses, giving everything a soft forward momentum.", "audio_features": {"tempo": 127.945, "energy": 0.472, "valence": 0.0424, "liveness": 0.11, "loudness": -9.277, "speechiness": 0.0739, "acousticness": 0.534, "danceability": 0.525, "instrumentalness": 0.614}, "mood_description": "A gentle pulse moves through you, a quiet hum that pulls at something deep inside. You feel a familiar ache, like a moment caught between wistful remembering and the quiet acceptance of time passing."}', 'google:gemini-2.5-flash', '2', 2484, NULL, '2026-04-08 05:26:25.784521+00', '2026-04-08 05:26:25.784521+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('904579b2-6463-4694-b69d-0aa65ccc3063', '2e151589-3139-4afd-8d08-2d91e94fb857', '{"themes": [{"name": "testing commitment", "description": "Challenging a potential partner to prove their sincerity and effort before a connection deepens."}, {"name": "playful elusiveness", "description": "The enjoyment and power found in being hard to catch, keeping someone intrigued and on their toes."}, {"name": "self-preservation in dating", "description": "Protecting oneself from superficial connections by maintaining a readiness to leave if expectations aren''t met."}, {"name": "the desire for permanence", "description": "Despite the game of chase, a quiet wish for someone to be truly exceptional and make the act of disappearing unnecessary."}], "journey": [{"mood": "Bold, evasive", "section": "Opening Challenge", "description": "A confident declaration sets the tone, announcing an inclination to leave as quickly as arriving, daring someone to keep up."}, {"mood": "Inviting, fleeting", "section": "Observational Flirtation", "description": "Watching and inviting closeness, but underscoring the precious, limited nature of the moment, a silent challenge to act."}, {"mood": "Hopeful, conditional", "section": "Vulnerable Opening", "description": "A surprising shift reveals a crack in the playful facade, admitting a deep desire for someone to be significant enough to make staying an option."}, {"mood": "Skeptical, direct", "section": "Demanding Verification", "description": "Sweet words aren''t enough; a demand for genuine action and belief-inspiring effort, needing more than just talk."}, {"mood": "Insistent, playful", "section": "Echoing Promise", "description": "The core challenge echoes one last time, a final reminder of the escape artist''s nature, leaving the ball in the other''s court."}], "headline": "A thrilling game of chase, daring a lover to prove their worth before disappearing into the night.", "key_lines": [{"line": "I''m not here for long", "insight": "The scarcity creates value, making every moment a test of genuine interest."}, {"line": "Catch me or I go Houdini", "insight": "A clear warning: engage fully or face the consequences of inaction and a swift departure."}, {"line": "It''s your moment, baby, don''t let it slip", "insight": "Seizing the opportunity before it vanishes is the ultimate proof of their dedication."}, {"line": "Maybe you could be the one to make me stay", "insight": "Beneath the detachment, a surprising vulnerability and a wish for a truly lasting connection."}, {"line": "But do you practise everything that you preach?", "insight": "Skepticism of words alone, demanding actions to match promises and build trust."}], "compound_mood": "Elusive Challenge", "sonic_texture": "Pulsing basslines and shimmering synths create a vibrant, propulsive dance groove. The rhythm feels both effortless and insistent, like a playful chase unfolding on a crowded dancefloor, topped with clear, confident vocals.", "interpretation": "Setting a clear ultimatum in a potential romance, a confident declaration that one must earn commitment or face swift departure. There''s a self-protective stance, but also a hidden hope that someone might be ''good enough'' to make them change their fleeting ways.", "mood_description": "A flirtatious energy pulses, a confident dare wrapped in a vibrant, almost insistent rhythm. It feels like setting the terms for a high-stakes romance, a game only one person can win."}', 'google:gemini-2.5-flash', '2', 6240, NULL, '2026-04-08 05:26:43.582518+00', '2026-04-08 05:26:43.582518+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('b035839c-96e3-468e-801a-778d8fb43e6b', '08864488-ec58-4791-a31e-1bf3db5bda5a', '{"themes": [{"name": "unrequited futures", "description": "One person dreams of ''forever'' while the other seems to live in the moment, creating an emotional rift."}, {"name": "defensive vulnerability", "description": "Masking deep feelings with dismissive lines, attempting to protect a wounded heart."}, {"name": "enduring first love", "description": "The indelible mark of a transformative first experience, kept alive in spirit even after the relationship ends."}, {"name": "emotional imbalance", "description": "The stark contrast between one person''s overwhelming feelings and the other''s perceived apathy."}], "journey": [{"mood": "Quiet admission", "section": "Verse 1", "description": "Life was a mess before, and now the calm brought by another is gone, leaving a heavy rainfall of tears."}, {"mood": "Desperate uncertainty", "section": "Pre-Chorus", "description": "The realization hits, bringing a desperate uncertainty while wondering if they feel anything close to the same."}, {"mood": "Aching question", "section": "Chorus", "description": "A future is imagined, full of ''forever,'' but there''s a painful doubt if the other person even considers such a thing."}, {"mood": "Feigned indifference", "section": "Verse 2", "description": "A flash of anger and defensiveness emerges, dismissing the connection, even as the longing pushes through."}, {"mood": "Profound confession", "section": "Bridge", "description": "The memory of a first, transformative love comes flooding back, something so fundamental it could never truly fade."}, {"mood": "Solitary yearning", "section": "Outro", "description": "The aching question returns, as the ''forever'' that was once a shared dream now feels like a solitary, unanswered plea."}], "headline": "A tender, obsessive plea for a love that might only exist in memory.", "key_lines": [{"line": "My eyes don''t shed tears, but boy, they pour", "insight": "The outward expression of sadness is muted, but internally, the grief is overwhelming."}, {"line": "Or do you not think so far ahead?", "insight": "A quiet, devastating fear that love is not equally felt or considered."}, {"line": "No, I don''t like you, I just thought you were cool enough to kick it", "insight": "A self-protective lie, trying to diminish a profound connection to avoid further hurt."}, {"line": "You know you were my first time", "insight": "The indelible, foundational nature of this past relationship, forever etched into memory."}, {"line": "We''ll go down this road ''til it turns from color to black and white", "insight": "A commitment to carrying the memory, even as time fades its vividness."}], "compound_mood": "Tender Desperation", "sonic_texture": "Smooth, echoing synths drift over a relaxed, yet subtly propulsive beat. Frank''s layered vocals float with an ethereal, almost mournful quality, creating a warm, hazy soundscape that belies the emotional weight of the words. The bassline is soft but ever-present, guiding the sad, danceable rhythm.", "audio_features": {"tempo": 129.83, "energy": 0.339, "valence": 0.2, "liveness": 0.0973, "loudness": -11.195, "speechiness": 0.0532, "acousticness": 0.409, "danceability": 0.721, "instrumentalness": 0.00153}, "interpretation": "The raw, often contradictory feelings of a broken first love emerge here. It’s a battle between feigned indifference and profound yearning, where one person imagines a shared future while the other remains a mystery. The smooth, almost laid-back production creates a stark contrast to the emotional turmoil in the words, highlighting the internal struggle to maintain composure even as a deep wound is exposed. It’s the agony of knowing you felt everything, and wondering if they felt anything at all.", "mood_description": "A yearning confession floats over a deceptively smooth and danceable groove. It''s a sad sway, caught between reliving a first love and the ache of its fading."}', 'google:gemini-2.5-flash', '2', 6314, NULL, '2026-04-08 05:27:05.219535+00', '2026-04-08 05:27:05.219535+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('001abd79-85c7-4d6b-851f-928d1a9eb11d', '8dc3d88e-cf16-494e-8471-40cdd2df561c', '{"themes": [{"name": "post-breakup turmoil", "description": "The confusing, contradictory feelings that remain long after a relationship ends, blending anger, longing, and a strange sense of relief."}, {"name": "imbalanced power dynamics", "description": "Unpacking a relationship where one person held significant control, using manipulation and age difference to their advantage."}, {"name": "reclaiming self", "description": "The difficult, ongoing process of finding your own voice and strength after being silenced or diminished by a partner."}, {"name": "the ghost of abuse", "description": "The haunting presence of a former abuser''s behavior, making it hard to find peace or move on completely."}], "journey": [{"mood": "Raw contradiction", "section": "Verse 1", "description": "A confession of conflicting feelings, both sharp and childlike, immediately followed by the sting of manipulation and faked connection."}, {"mood": "Overwhelming nausea", "section": "Chorus", "description": "The sudden jolt of emotional motion sickness, a desperate plea to escape an inescapable presence that follows everywhere."}, {"mood": "Cold clarity", "section": "Verse 2", "description": "Stepping back to see the wreckage, finding a quiet, conflicted relief in having escaped the chaos, even while acknowledging the pain it caused."}, {"mood": "Flickers of defiance", "section": "Chorus (extended)", "description": "Direct confrontation with the past, attempting to claw back agency with subtle jabs, trying to drown out the lingering echoes even if the fight feels impossible."}, {"mood": "Stark imbalance", "section": "Bridge", "description": "The unsettling revelation of a predatory age gap, laying bare the unsettling power dynamic and the ex''s jaded motivation."}, {"mood": "Worn resignation", "section": "Final Chorus", "description": "A final, weary attempt to break free, invoking the language of addiction as it contemplates surrendering to the overwhelming pull of the past."}], "headline": "The dizzying aftermath of a toxic love, where hate and longing spin in an endless loop.", "key_lines": [{"line": "I hate you for what you did And I miss you like a little kid", "insight": "The bewildering internal tug-of-war between fury and childlike yearning after a breakup, a messy, human contradiction."}, {"line": "I have emotional motion sickness", "insight": "The physical manifestation of a chaotic internal state, a dizzying inability to find stillness or peace."}, {"line": "You were in a band when I was born", "insight": "The chilling revelation of a predatory age gap, laying bare the unsettling power dynamic at the heart of the relationship."}, {"line": "But I will try to drown you out", "insight": "A shift from passive overwhelm to active, though still desperate, resistance against the lingering influence of a past love."}, {"line": "If I surrender to the sound", "insight": "The agonizing consideration of letting go and giving in, even if it means succumbing to the very chaos fought against."}], "compound_mood": "Wounded Disorientation", "sonic_texture": "Warm, strumming acoustic guitars with a steady, propulsive rhythm section. Vocals are clear and direct, cutting through a slightly melancholic, yet engaging, indie-folk soundscape.", "audio_features": {"tempo": 107.021, "energy": 0.546, "valence": 0.623, "liveness": 0.0842, "loudness": -9.021, "speechiness": 0.0357, "acousticness": 0.774, "danceability": 0.651, "instrumentalness": 0.0437}, "interpretation": "Escaping a toxic relationship doesn''t always mean escaping its emotional residue. It''s a messy, contradictory fight to reconcile lingering attachment with sharp resentment, constantly replaying the past while trying desperately to move forward.", "mood_description": "A feeling of being perpetually off-kilter, wrestling with conflicting emotions that refuse to settle. It''s catchy and moving, like dancing through a heavy fog."}', 'google:gemini-2.5-flash', '2', 5367, NULL, '2026-04-08 05:27:21.900426+00', '2026-04-08 05:27:21.900426+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('f7ad4a1d-071d-4d33-91fc-0c407dd6753c', '6714100d-0719-4372-ba4d-0ab5d654386b', '{"themes": [{"name": "irreconcilable differences", "description": "Two individuals, deeply fond of each other, find their fundamental ways of life are simply too far apart."}, {"name": "hedonism vs. discipline", "description": "The clash between a free-spirited, late-night existence and a meticulous, early-morning routine."}, {"name": "playful rejection", "description": "A kindhearted, almost teasing acknowledgment that someone''s ''sweetness'' is lovely, but ultimately not a fit."}, {"name": "self-acceptance", "description": "Embracing one''s own habits and preferences, even when they diverge from a partner''s expectations or desires."}], "journey": [{"mood": "Playful Observation", "section": "Verse 1", "description": "Waking late, grumpy, and observing a partner''s perfect, disciplined life with a mix of awe and mild disbelief."}, {"mood": "Cheeky Challenge", "section": "Pre-Chorus", "description": "A direct, teasing question inviting a partner to shed their inhibitions and embrace a wilder, more carefree moment."}, {"mood": "Confident Declaration", "section": "Chorus", "description": "The ultimate statement: a firm commitment to one''s own ''neat'' preferences, recognizing the stark, but not bitter, incompatibility."}, {"mood": "Assertive Explanation", "section": "Verse 2", "description": "A deeper dive into one''s own work-late, aim-low philosophy, contrasting it with a partner''s meticulous self-care, acknowledging the beauty but also the distance."}, {"mood": "Wry Longing", "section": "Pre-Chorus (Reprise)", "description": "Admiring the partner''s inherent sweetness while playfully suggesting a desire for them to become ''aged'' and ''bitter'' like a fine whiskey, knowing it''s a pipe dream."}, {"mood": "Firm Acceptance", "section": "Outro", "description": "The final, unyielding embrace of one''s chosen path, reiterating the core truth that some differences are simply too sweet to overcome."}], "headline": "A playful rejection, acknowledging that some loves simply can''t bridge fundamental differences in how life is lived.", "key_lines": [{"line": "Don''t you just wanna wake up, dark as a lake / Smellin'' like a bonfire, lost in a haze?", "insight": "A yearning for shared wildness, inviting another to shed their inhibitions and experience life less strictly."}, {"line": "I think I''ll take my whiskey neat / My coffee black and my bed at 3", "insight": "Embracing a life lived on one''s own terms, unbound by conventional timelines or tastes."}, {"line": "You treat your mouth as if it''s Heaven''s gate / The rest of you like you''re the TSA", "insight": "A pointed, vivid image of rigid self-regulation and strictness, bordering on comedic."}, {"line": "If you can sit in a barrel, maybe I''ll wait", "insight": "A witty, slightly teasing hope for a partner to become more seasoned and complex, like aged alcohol."}, {"line": "You''re too sweet for me", "insight": "A lighthearted declaration of incompatibility, rooted in fundamental differences rather than a lack of affection."}], "compound_mood": "Sardonic Affection", "sonic_texture": "A vibrant, blues-infused rock groove driven by a punchy bassline and crisp drums, topped with Hozier''s signature soulful, soaring vocals and hints of gospel-tinged harmonies. It''s danceable and energetic, with a classic, full-bodied feel that makes you want to move.", "audio_features": {"tempo": 117.038, "energy": 0.62, "valence": 0.934, "liveness": 0.0398, "loudness": -5.505, "speechiness": 0.0412, "acousticness": 0.0295, "danceability": 0.741, "instrumentalness": 0.000809}, "interpretation": "Recognizing that even deep affection can''t overcome two vastly different approaches to life. It''s a declaration of self-acceptance, choosing to stay true to one''s own nature rather than conform, even if it means letting go of someone adored. The story here isn''t one of heartbreak, but of a cheerful, self-aware parting of ways.", "mood_description": "A confident, funky groove carries a cheeky observation about incompatible lifestyles. It''s a knowing smile at a love that''s just too pure to last."}', 'google:gemini-2.5-flash', '2', 5731, NULL, '2026-04-08 05:27:36.340166+00', '2026-04-08 05:27:36.340166+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('ac459b30-cea5-4bce-8aea-cce5c04e5ff7', '429d8a32-b808-47be-b3cb-7ada5081f334', '{"themes": [{"name": "obsessive longing", "description": "An inescapable mental loop, replaying interactions and questioning every subtle, unspoken signal."}, {"name": "desperate pursuit", "description": "A relentless, almost undignified effort to re-establish a connection, regardless of the emotional cost."}, {"name": "emotional uncertainty", "description": "Navigating the agonizing space between hoping for mutual feelings and fearing rejection."}], "journey": [{"mood": "Anxious Probing", "section": "Verse 1", "description": "A string of intimate, uneasy questions, dissecting every subtle signal and wondering if there''s a hidden truth. The feeling of someone entirely consumed by another''s presence, even in dreams."}, {"mood": "Hesitant Inquiry", "section": "Pre-Chorus", "description": "The crucial question finally surfaces, a hesitant whisper of whether these intense feelings are returned. There''s a bittersweet acknowledgment of how alcohol loosens tongues, revealing unspoken truths."}, {"mood": "Magnetic Helplessness", "section": "Chorus", "description": "An admission of total surrender to an undeniable pull, confessing to repeatedly returning to the same person, unable to move on. It’s a desperate confession of being utterly consumed and bound."}, {"mood": "Bold Uncertainty", "section": "Verse 2", "description": "A shift to more direct, almost daring questions, pushing for an answer about the other person''s heart. Yet, the deep insecurity remains, unsure if the desire for a kiss is shared."}, {"mood": "Lingering Doubt", "section": "Outro", "description": "The core questions echo and repeat, fading out unresolved, a testament to the persistent, nagging uncertainty that refuses to disappear. The feeling of being stuck in an endless loop of wanting."}], "headline": "A low hum of obsession, driven by endless questions and a desperate magnetic pull to someone you can''t shake.", "key_lines": [{"line": "How many secrets can you keep?", "insight": "The emotional distance felt from someone holding back."}, {"line": "(Do I wanna know) If this feelin'' flows both ways?", "insight": "The terrifying vulnerability of hoping for mutuality."}, {"line": "Maybe I''m too busy bein'' yours to fall for somebody new", "insight": "The complete devotion that makes moving on impossible."}, {"line": "Do you want me crawlin'' back to you?", "insight": "The ultimate fear that one''s desperate return isn''t actually desired."}], "compound_mood": "Magnetic Desperation", "sonic_texture": "A dark, slinky guitar riff leads the way, accompanied by a heavy, steady drum beat and a deep, pulsing bassline. The vocals are a cool, almost detached murmur, carrying a potent undercurrent of longing, all wrapped in a smooth, studio-polished haze.", "audio_features": {"tempo": 85.03, "energy": 0.532, "valence": 0.405, "liveness": 0.217, "loudness": -7.596, "speechiness": 0.0323, "acousticness": 0.186, "danceability": 0.548, "instrumentalness": 0.000263}, "interpretation": "Consumed by uncertainty and an inescapable pull, desperately searching for any sign of mutual feeling from someone who seems distant or indifferent. The internal monologue is a restless loop of ''do I wanna know?'' as an unshakeable connection binds, even if it''s painful and one-sided.", "mood_description": "A hazy, slow-burning groove pulls you into a swirl of unanswered questions. Every beat feels like a persistent echo of someone you can''t get out of your head."}', 'google:gemini-2.5-flash', '2', 6513, NULL, '2026-04-08 05:27:54.873983+00', '2026-04-08 05:27:54.873983+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('652ad697-c959-4d2a-9b82-1cf599a95246', '1a28ed64-772b-4e69-8ad8-719c898c6019', '{"themes": [{"name": "possessive obsession", "description": "The consuming desire to control a past lover, even when it leads to destructive thoughts and actions."}, {"name": "fear of abandonment", "description": "A deep-seated dread of being left alone, making drastic, even violent, alternatives seem preferable to solitude."}, {"name": "performative maturity", "description": "The ironic claim of personal growth and therapy, immediately undercut by the inability to move past a singular, unhealthy desire."}], "journey": [{"mood": "Bitter reflection", "section": "Verse 1", "description": "Watching from a distance, the hurt turns into a simmering resentment at someone else''s happiness, a quiet admission of lingering attachment."}, {"mood": "Ironic self-talk", "section": "Pre-Chorus", "description": "Professing maturity and therapy-driven growth, but immediately backtracking to a singular, all-consuming desire that refuses to be reasoned with."}, {"mood": "Unsettling fantasy", "section": "Chorus", "description": "The idea of extreme action floats to the surface, a chilling thought wrapped in a confession of enduring love and the unbearable weight of solitude."}, {"mood": "Escalating fixation", "section": "Verse 2", "description": "The realization of true loss hardens into concrete plans, the mundane turning sinister as dark fantasies are meticulously detailed."}, {"mood": "Dark justification", "section": "Bridge", "description": "Rationalizing intense, premeditated actions as being ''all for love,'' a sober decision made out of deep, unwavering devotion."}, {"mood": "Fantasy realized", "section": "Chorus (Outro)", "description": "A chilling, almost casual admission of crossing a line, still anchored by the unbearable thought of solitude, as the story closes on a dangerous note."}], "headline": "A smooth, irresistible groove that cradles a dangerous fantasy of love pushed to its breaking point.", "key_lines": [{"line": "Hate to see you happy if I''m not the one drivin''", "insight": "Not just jealousy, but a need for control over the other person''s joy and destiny, a deeply possessive viewpoint."}, {"line": "If I can''t have you, no one should", "insight": "The ultimate declaration of possessive love, transforming desire into a zero-sum game where self-interest dictates the rules."}, {"line": "Rather be in jail than alone", "insight": "The unbearable weight of solitude, making any consequence, even incarceration, preferable to the emptiness of isolation."}, {"line": "Now I''m in the basement plannin'' home invasion", "insight": "The mundane setting for escalating dark thoughts, making the fantasy feel disturbingly real and close to home."}, {"line": "I did it all for love", "insight": "A twisted rationalization, presenting extreme and violent actions as the logical, selfless outcome of deep affection."}], "compound_mood": "Obsessive Yearning", "sonic_texture": "A smooth, undulating R&B beat lays down a seductive groove, with SZA''s cool vocals drifting over a low-key trap pulse. There''s a persistent, slightly melancholic warmth in the production, masking the lyrical tension with an effortless, danceable sway.", "audio_features": {"tempo": 88.98, "energy": 0.735, "valence": 0.418, "liveness": 0.161, "loudness": -5.747, "speechiness": 0.0391, "acousticness": 0.0521, "danceability": 0.644, "instrumentalness": 0.144}, "interpretation": "It''s not just about a murderous fantasy; it''s a raw confession of the terrifying depths of possessive love and the desperate fear of being utterly alone. The violent imagery becomes a desperate expression of a love that can''t let go, even when it knows it should, revealing the dangerous logic of a heart pushed to extremes.", "mood_description": "A cool, laid-back beat draws you in, but underneath the effortless flow, a simmering frustration starts to boil. It feels like dancing slowly while the darkest thoughts flicker at the edges of your mind."}', 'google:gemini-2.5-flash', '2', 5115, NULL, '2026-04-08 05:28:09.742937+00', '2026-04-08 05:28:09.742937+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('3a47c640-721f-4909-b9be-781b2b308113', 'd91b3121-99a3-49de-abea-befefc5ad42c', '{"themes": [{"name": "territorial dominance", "description": "Claiming undisputed authority and legacy within a specific cultural space, dismissing any challengers as illegitimate."}, {"name": "predatory accusations", "description": "Directly and repeatedly leveling severe allegations of sexual misconduct against a rival, weaponizing deeply unsettling claims."}, {"name": "cultural appropriation", "description": "Criticizing the adoption of Black culture and community connections as a means to gain commercial success or street credibility."}, {"name": "collective rejection", "description": "Framing a personal feud as a broader community''s unified dismissal and ostracization of an unwelcome presence."}], "journey": [{"mood": "Eerie confidence", "section": "Opening Salvo", "description": "A chilling whisper sets a dark tone, then a confident beat immediately drops, launching into a relentless barrage of personal attacks and accusations that establish dominance."}, {"mood": "Unrelenting indictment", "section": "Scathing Exposé", "description": "The rhythmic momentum carries forward, but the words sharpen into deeply uncomfortable allegations, creating a public spectacle of moral condemnation while maintaining an undeniable swagger."}, {"mood": "Unifying dismissal", "section": "Collective Proclamation", "description": "The song explodes into a hypnotic, undeniable chant, transforming the personal beef into a communal rallying cry, a public declaration of who belongs and who doesn''t."}, {"mood": "Authoritative exposé", "section": "Cultural Reckoning", "description": "More layers of betrayal and inauthenticity are peeled back, extending the attack to cultural heritage and industry practices, delivered with unflinching authority over the persistent beat."}, {"mood": "Exultant mockery", "section": "Celebratory Dismissal", "description": "The insults become a catchy, communal taunt, turning the rival''s downfall into a dance-along event, with instructions to move as the final, triumphant dismissal echoes."}], "headline": "The absolute confidence of an undisputed champion, turning a personal feud into a communal declaration of victory.", "key_lines": [{"line": "Say, Drake, I hear you like ''em youngYou better not ever go to cell block one", "insight": "The blunt, public accusation that shifts from rumor to a direct warning of legal consequences."}, {"line": "Certified Lover Boy? Certified pedophiles", "insight": "Transforming a brand identity into a damning indictment, crystallizing the central, darkest accusation."}, {"line": "They not like us, they not like us, they not like us", "insight": "A potent, unifying chant that draws a clear line of demarcation, solidifying community against an outsider."}, {"line": "No, you not a colleague, you a fuckin'' colonizer", "insight": "Rejecting any pretense of equality or mutual respect, instead labeling the rival as an exploiter of culture."}, {"line": "Then step this way, step that way", "insight": "Turning a personal attack into a dance instruction, transforming humiliation into a collective, physical celebration."}], "compound_mood": "Triumphant Condemnation", "sonic_texture": "A pulsating G-funk bassline drives a propulsive, almost hypnotic rhythm, layered with sharp, declarative vocal delivery and occasional eerie synth accents, all designed for maximum dancefloor impact.", "audio_features": {"tempo": 101.061, "energy": 0.472, "valence": 0.214, "liveness": 0.141, "loudness": -7.001, "speechiness": 0.0776, "acousticness": 0.0107, "danceability": 0.898, "instrumentalness": 0}, "interpretation": "This isn''t just a diss track; it''s a statement of cultural ownership and a community''s rejection of an outsider. Leveraging serious allegations, it solidifies a narrative of moral and artistic superiority, turning a personal beef into a collective indictment. The danceable beat paradoxically amplifies the harshness, making the condemnation feel inescapable, a public execution on the dancefloor.", "mood_description": "A swaggering beat propels accusations forward, forcing movement even as the words cut deep. It''s a party anthem for an enemy''s downfall."}', 'google:gemini-2.5-flash', '2', 9934, NULL, '2026-04-08 05:28:32.539264+00', '2026-04-08 05:28:32.539264+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('64380742-0796-46f8-80c8-1875e797cc49', '462d171c-27ff-4bec-a2d0-303c2b97f739', '{"themes": [{"name": "rebellious refusal", "description": "Rejecting external demands, even to a destructive degree, choosing to stand firm against perceived injustices."}, {"name": "self-punishment", "description": "A belief in deserving pain, actively inflicting it as a form of reclaiming agency or atonement."}, {"name": "societal burden", "description": "The overwhelming feeling of being crushed by compulsory obligations and the hypocrisy of those who impose them."}, {"name": "martyrdom", "description": "A willingness to suffer greatly rather than submit, drawing on imagery of ultimate sacrifice."}], "journey": [{"mood": "self-condemning plea", "section": "Verse 1", "description": "A raw confession of unworthiness, followed by a sudden widening of perspective to universal suffering, hinting at shared burdens."}, {"mood": "fierce confrontation", "section": "Verse 2", "description": "A direct challenge to authority, drawing a line in the sand with images of ultimate sacrifice, daring others to enforce their will."}, {"mood": "internalized struggle", "section": "Verse 3", "description": "The focus shifts inward, redirecting the defiance into a choice of self-inflicted pain, reclaiming agency over one''s own suffering."}, {"mood": "lingering anguish", "section": "Outro", "description": "Wordless vocalizations echo the weight of the previous declarations, a mournful, drawn-out consequence of the struggle that hangs in the air."}], "headline": "A desperate refusal to submit, choosing self-punishment and defiance over compromise with external demands.", "key_lines": [{"line": "I should burn in hell", "insight": "The profound weight of past wrongs, a self-imposed sentence echoing deep-seated guilt."}, {"line": "Nobody deserves this", "insight": "A sudden moment of empathy amidst self-loathing, extending suffering beyond oneself to all."}, {"line": "You''re gonna have to nail me down", "insight": "An unyielding refusal to yield, choosing ultimate sacrifice over submission to an unwanted demand."}, {"line": "Doctor, doctor, heal yourself", "insight": "A biting challenge to hypocrisy, demanding accountability from those in positions of power or judgment."}, {"line": "I will break my own heart", "insight": "Reclaiming agency over pain, choosing self-destruction rather than having it forced or inflicted by others."}], "compound_mood": "Resentful Defiance", "sonic_texture": "A raw, unvarnished energy pervades, with a stark and direct feel that mirrors the defiant, confrontational lyrics.", "interpretation": "A refusal to conform, even if it means self-destruction, driven by a deep sense of injustice and perhaps unworthiness. The narrative links societal obligations with a personal martyrdom, suggesting that some principles are worth sacrificing everything for, even one''s own well-being.", "mood_description": "A raw, guttural cry against forced compliance, where anger and self-loathing collide in a desperate stand."}', 'google:gemini-2.5-flash', '2', 4155, NULL, '2026-04-08 05:28:46.699098+00', '2026-04-08 05:28:46.699098+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('71964440-1e91-45a0-a811-dca40ad4d5a1', '23089639-7c1d-4fad-9ebc-d102d2cee38a', '{"themes": [{"name": "fragile happiness", "description": "The realization that even the best moments are temporary and can be taken away."}, {"name": "fear of loss", "description": "The overwhelming anxiety that comes with finding something precious, making its potential absence unbearable."}, {"name": "spiritual bargaining", "description": "Pleading with a higher power to preserve the good things given, acknowledging divine control over one''s fortune."}, {"name": "post-struggle peace", "description": "Experiencing a calm and stable period after enduring significant personal hardship and chaos."}], "journey": [{"mood": "Reflective peace", "section": "Verse 1", "description": "Finding unexpected calm after a long struggle, everything finally clicking into place with family, love, and a sense of belonging."}, {"mood": "Sudden dread", "section": "Verse 1 (transition)", "description": "A quiet, unsettling awareness that this perfect moment is fragile, a gift that could just as easily be reclaimed."}, {"mood": "Desperate plea", "section": "Pre-Chorus / Chorus", "description": "The quiet fear erupts into a raw, urgent cry, begging for these precious things to remain, a heartfelt prayer against inevitable change."}, {"mood": "Inner turmoil", "section": "Verse 2", "description": "Despite outward peace, an internal battle rages, haunted by the question of why good things always seem to disappear, fueling the fear of impending loss."}, {"mood": "Lingering anxiety", "section": "Outro", "description": "The pleas persist, echoing with a deep-seated need, the voice fading but the desperate longing for security remaining unresolved."}], "headline": "A tender, overwhelming joy, shadowed by the deep terror that every beautiful thing could vanish in an instant.", "key_lines": [{"line": "But I know the things He gives me, He can take away", "insight": "The divine blessing is also a source of terrifying vulnerability."}, {"line": "But there''s no man as terrified as the man who stands to lose you", "insight": "The depth of love creates an equally profound capacity for fear."}, {"line": "If everything''s good and it''s great, why do I sit and wait ''til it''s gone?", "insight": "The mind sabotages peace by anticipating its end, even when things are perfect."}, {"line": "Don''t take These beautiful things that I''ve got", "insight": "A primal, simple prayer to keep what brings joy, uttered from a place of deep need."}], "compound_mood": "Anxious Contentment", "sonic_texture": "Earnest, powerful vocals rise over a dynamic pop-rock arrangement of driving drums and layered guitars. It builds with a raw, anthemic feel, carrying a weight of emotion that feels more pleading than purely energetic.", "audio_features": {"tempo": 105.029, "energy": 0.471, "valence": 0.219, "liveness": 0.14, "loudness": -5.692, "speechiness": 0.0603, "acousticness": 0.151, "danceability": 0.472, "instrumentalness": 0}, "interpretation": "The agonizing fear that accompanies true happiness, especially after a period of struggle. When life finally feels good, the vulnerability to lose it becomes overwhelming, leading to a desperate, almost spiritual, plea to hold onto the \"beautiful things\" found.", "mood_description": "A rising swell of heartfelt emotion, caught between the warmth of newfound happiness and the chilling dread of it all slipping away."}', 'google:gemini-2.5-flash', '2', 4898, NULL, '2026-04-08 05:29:02.129842+00', '2026-04-08 05:29:02.129842+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('d0a85ceb-b82c-4600-8f65-019183227722', 'acb2449c-e1eb-49da-8fc3-e62b01657013', '{"themes": [{"name": "eternal commitment", "description": "An unwavering promise of love that extends beyond life itself, a desire for a bond that death cannot sever."}, {"name": "self-sabotage", "description": "A loved one''s internal battle with self-worth, pushing away affection and questioning the validity of being loved."}, {"name": "fated connection", "description": "The feeling of having known someone across lifetimes, suggesting a spiritual or destined bond."}, {"name": "unconditional love", "description": "Loving someone completely, even when they struggle to accept that love or recognize their own value."}], "journey": [{"mood": "immediate longing", "section": "Intro / Verse 1", "description": "A raw, unyielding declaration of a love that promises to last beyond life itself, bordering on an almost possessive devotion."}, {"mood": "expansive pledge", "section": "Refrain / Pre-Chorus / Chorus", "description": "An undeniable bond takes hold, moving past the idea of being better off alone. There''s an underlying tremble of emotion, almost overwhelmed by the depth of feeling that commits to forever."}, {"mood": "gentle frustration", "section": "Verse 2", "description": "A pivot to trying to make a loved one see their own beauty and worth, encountering their deep-seated self-doubt and resistance with a mix of understanding and exasperation."}, {"mood": "reassuring embrace", "section": "Pre-Chorus / Chorus (Reprise)", "description": "The unwavering promise returns, now laced with the ache of wanting to reassure and prevent a goodbye, despite the partner''s internal struggles that threaten the connection."}, {"mood": "destined affirmation", "section": "Post-Chorus", "description": "A comforting whisper of destiny, affirming a love that feels ancient and undeniable, ending with a soft, knowing certainty that brushes away any surprise or doubt."}], "headline": "A profound, fated love that demands permanence, even as it battles the partner''s own shadows and self-doubt.", "key_lines": [{"line": "''Til I''m in the grave ''Til I rot away, dead and buried", "insight": "A commitment that transcends life, a literal intertwining with fate itself."}, {"line": "Nothin'' left to lose without my baby", "insight": "Utter vulnerability, where identity and purpose hinge entirely on the presence of another."}, {"line": "Birds of a feather, we should stick together, I know", "insight": "The profound recognition that a solitary path is no longer desirable, a deep sense of belonging found in connection."}, {"line": "Say you wanna quit, don''t be stupid", "insight": "A blunt, almost exasperated plea for a partner to stop undermining their own happiness and the love they share."}, {"line": "I love you, don''t act so surprised", "insight": "A definitive, almost final statement of affection, dismissing any lingering disbelief with a knowing confidence."}], "compound_mood": "Fervent Devotion", "sonic_texture": "A smooth, mid-tempo pop groove with a relaxed, almost swaying rhythm. The vocals are clear and intimate, floating over warm, layered synths and a gentle, persistent bassline that grounds the emotional intensity without overpowering it.", "audio_features": {"tempo": 104.978, "energy": 0.507, "valence": 0.438, "liveness": 0.117, "loudness": -10.171, "speechiness": 0.0358, "acousticness": 0.2, "danceability": 0.747, "instrumentalness": 0.0608}, "interpretation": "It''s about a love so powerful it defies logic and self-preservation, characterized by one person''s unshakeable belief in a connection. This intense bond is tested by the partner''s struggle to accept that love or see their own worth, hinting at a dynamic where one person is giving everything while the other is withdrawing or pushing away due to deep-seated insecurity.", "mood_description": "A warm, pulsing groove carries an intense, almost desperate plea for a love that lasts forever. The air feels thick with devotion, yet a quiet urgency hums underneath."}', 'google:gemini-2.5-flash', '2', 5473, NULL, '2026-04-08 05:29:19.093293+00', '2026-04-08 05:29:19.093293+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('a5ccb638-bdfc-4068-b888-9aaee4d92907', '93d580b3-10ae-4123-871c-b3f2508256b6', '{"themes": [{"name": "shattered expectations", "description": "The painful realization that promises of forever can break, leaving behind a profound sense of disbelief."}, {"name": "ghosts in familiar places", "description": "Everywhere feels haunted by memories of a past relationship, making it impossible to escape the reminders."}, {"name": "the other woman", "description": "The specific sting of an ex moving on to someone who embodies all your insecurities."}, {"name": "lonely independence", "description": "A newly acquired freedom that feels hollow and isolating without the person it was meant to be shared with."}], "journey": [{"mood": "grieving independence", "section": "Verse 1", "description": "The symbol of newfound freedom, a driver''s license, becomes a vehicle for tears and a stark reminder of an absent love."}, {"mood": "crushing comparison", "section": "Verse 2", "description": "A rumored new partner ignites deep insecurities, questioning worth and the possibility of ever loving again."}, {"mood": "disbelieving pain", "section": "Chorus", "description": "An anguished cry of confusion and hurt, wondering how someone could be so effortlessly okay after everything."}, {"mood": "lingering obsession", "section": "Verse 3", "description": "Friends are tired of the sorrow, but the memories are too real, driving through old streets imagining a shared past."}, {"mood": "overwhelming presence", "section": "Bridge", "description": "Every corner, every sound, every familiar spot brings a fresh wave of memories, culminating in a raw, undeniable admission of enduring love."}, {"mood": "echoing emptiness", "section": "Outro", "description": "The repeated promise of forever now rings hollow, as the drive continues alone, past a street that used to mean home."}], "headline": "A crushing first heartbreak, every familiar road a cruel mirror reflecting a lost future.", "key_lines": [{"line": "But today, I drove through the suburbsCrying ''cause you weren''t around", "insight": "The independence once eagerly anticipated now serves only to magnify the emptiness."}, {"line": "She''s everything I''m insecure about", "insight": "The sudden, devastating clarity of how easily you can be replaced by your deepest fears."}, {"line": "And I just can''t imagine how you could be so okay now that I''m gone", "insight": "The baffling, infuriating calm of someone who appears untouched by the wreckage of a shared past."}, {"line": "Guess you didn''t mean what you wrote in that song about me", "insight": "The gut punch of realizing past declarations of love were a performance, not a promise."}, {"line": "Can''t drive past the places we used to go to ''Cause I still fuckin'' love you, babe", "insight": "An unfiltered scream of enduring affection that refuses to let go, despite everything."}], "compound_mood": "Anguished Longing", "sonic_texture": "A somber piano opening gives way to building orchestral swells and a driving drum beat, layering raw, emotional vocals with subtle atmospheric backing. The sound feels like a night drive through heavy rain, emotionally turbulent yet deeply intimate.", "interpretation": "The bitter irony of achieving a long-anticipated milestone of freedom, only for it to expose the gaping hole left by a lost love. Every familiar route becomes a painful replay of shared dreams, while the casual ease with which an ex moves on shatters any illusion of their past sincerity. It''s the bewildering pain of watching someone become a stranger, taking all the shared history with them.", "mood_description": "Driving through familiar streets, each turn a fresh pang of loss, where new freedom is just a heavy reminder of what''s missing. The world moves on, but the ache remains, raw and exposed."}', 'google:gemini-2.5-flash', '2', 6130, NULL, '2026-04-08 05:29:38.711449+00', '2026-04-08 05:29:38.711449+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('efbb9f33-fcf7-4d26-8220-7ab0b2c9aa7e', '4b92eb17-60f6-41ce-849a-a9bd905a9282', '{"themes": [{"name": "finding queer community", "description": "Discovering a sense of home and acceptance in queer spaces, particularly West Hollywood, after feeling out of place elsewhere."}, {"name": "parental disappointment", "description": "The painful reality of knowing personal happiness and authenticity will clash with a parent''s hopes and values, causing distress."}, {"name": "midwest escape", "description": "The urgent need to leave a small, conservative hometown to pursue a life that aligns with one''s true self."}, {"name": "defiant self-acceptance", "description": "Boldly embracing an identity and lifestyle despite anticipated judgment and pushback from those who wish you''d stayed the same."}], "journey": [{"mood": "yearning freedom", "section": "Verse 1 / Refrain", "description": "The pull of a life elsewhere begins, a vision of L.A. and a place where everyone can be their true self, despite the unspoken wishes of home."}, {"mood": "exultant defiance", "section": "Pre-Chorus / Chorus", "description": "The fantasy takes hold, embracing the ''pink pony girl'' identity on stage, knowing it will shock and disappoint, but feeling truly at home in the moment."}, {"mood": "realized joy", "section": "Verse 2 / Refrain", "description": "The dream is now reality, a vibrant club scene affirming the decision to leave, every wild night a confirmation of freedom and no regrets."}, {"mood": "lingering connection", "section": "Bridge", "description": "A brief, tender pause acknowledging that home and family aren''t forgotten, a soft echo of a mother''s voice still heard across the miles, a reminder of what was left behind."}, {"mood": "unwavering commitment", "section": "Chorus / Outro", "description": "The commitment to this new life solidifies, the dancing continues, a persistent, joyous declaration of resilience and a refusal to turn back, fading out on a note of pure, ongoing liberation."}], "headline": "A vibrant escape from expectation, celebrating a new identity with defiant joy, even as echoes of home still sting.", "key_lines": [{"line": "Won''t make my mama proud, it''s gonna cause a scene", "insight": "The painful awareness that authenticity comes with a cost, predicting the emotional clash with parental expectations."}, {"line": "On the stage in my heels, it''s where I belong", "insight": "Finding a deep, affirming sense of home and purpose in unexpected, vibrant spaces."}, {"line": "Every night''s another reason why I left it all", "insight": "The constant validation of a life-altering decision, affirming that the leap was worth every sacrifice."}, {"line": "I can hear your Southern drawl a thousand miles away, saying", "insight": "The persistent, internal echo of a parent''s voice and values, even after physically leaving them behind."}], "compound_mood": "Joyful Rebellion", "sonic_texture": "Pulsing synth bass and glittery, layered synthesizers create a driving, danceable beat. Clean, bright vocals float above a rich electronic soundscape, feeling both expansive and intimately personal.", "audio_features": {"tempo": 106.719, "energy": 0.65, "valence": 0.507, "liveness": 0.11, "loudness": -6.199, "speechiness": 0.0474, "acousticness": 0.399, "danceability": 0.61, "instrumentalness": 0}, "interpretation": "This is about the exhilarating, yet often painful, journey of self-discovery and embracing a queer identity, particularly when it means breaking from conservative family expectations and a restrictive upbringing. It''s a vivid depiction of finding belonging and joy in new spaces, even as the emotional ties to the past persist, creating a bittersweet tension between newfound freedom and familial disapproval. The music amplifies this feeling, providing an almost celebratory soundtrack to a deeply personal and defiant act.", "mood_description": "A rush of shimmering synth-pop energy sweeps you onto the dance floor. It feels like pure liberation, but there''s an undercurrent of knowing this freedom comes at a cost."}', 'google:gemini-2.5-flash', '2', 5451, NULL, '2026-04-08 05:29:51.318433+00', '2026-04-08 05:29:51.318433+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('9a63a928-2563-445d-b2df-515244bb6e4c', 'a0a8200e-97bf-4e2e-abc0-ed3074c66137', '{"themes": [{"name": "self-blame", "description": "Taking responsibility for the breakdown of a relationship, even when pain is mutual."}, {"name": "destructive love", "description": "A love so intense it feels like a natural disaster, shaking the foundation of everything."}, {"name": "desperate pleading", "description": "An urgent, almost frantic begging for a partner to stay, despite the clear signs of trouble."}, {"name": "emotional dependency", "description": "The feeling of needing someone so intensely that their departure feels like the world ending."}], "journey": [{"mood": "urgent anticipation", "section": "Intro", "description": "A repetitive, almost hypnotic chant sets a tone of earnest conviction, hinting at a crucial confession about to unfold."}, {"mood": "shaken heartbreak", "section": "Chorus", "description": "The confession bursts out: a love so powerful it’s a seismic event, joyfully unsettling but also breaking hearts, a dizzying blend of ecstasy and pain."}, {"mood": "vulnerable plea", "section": "Refrain", "description": "A desperate, repeated cry of ''Don''t leave, it''s my fault'' emerges, revealing a deep sense of responsibility and a fear of total collapse, a double meaning of physical and emotional fault lines."}, {"mood": "street-level anxiety", "section": "Verse", "description": "A different voice enters, recounting anxieties of betrayal and street life, a brief diversion from the emotional core, yet concluding with a surprising, quiet declaration of being ''so in love.''"}, {"mood": "desperate negotiation", "section": "Bridge", "description": "The emotional core returns, directly confronting the lack of communication, pleading for clarity and confirmation, wanting honesty over conflict or secondhand rumors."}, {"mood": "fading desperation", "section": "Outro", "description": "The pleas become an echo, repeating ''Don''t leave, it''s my fault'' as the sound gently recedes, leaving a lingering sense of unfulfilled longing."}], "headline": "A frantic, almost pleading negotiation with a love that''s violently shaking everything apart, desperately trying to avert the inevitable collapse.", "key_lines": [{"line": "Bitch, I cannot fall short", "insight": "The fierce determination to succeed or measure up, even in the face of emotional collapse."}, {"line": "''Cause you make my earth quake", "insight": "A love so intense it''s both thrilling and terrifyingly destructive, shaking the very ground beneath you."}, {"line": "Don''t leave, it''s my fault", "insight": "The crushing weight of self-blame, taking ownership for a relationship''s breakdown while begging for its survival."}, {"line": "I just need some confirmation on how you feel, for real", "insight": "The desperate need for clarity and honesty when lost in emotional uncertainty, tired of guessing games."}, {"line": "So in love", "insight": "A simple, stark admission that cuts through the chaos, revealing the raw, unwavering core of affection despite everything."}], "compound_mood": "Turbulent Longing", "sonic_texture": "Warm, slightly melancholic synths drift over a driving, almost shuffling beat. There''s a raw, live energy to the vocals, layered with smooth backing harmonies that give it a soulful, pleading quality. The bass is prominent, giving it a solid, grounding feel despite the emotional turbulence.", "audio_features": {"tempo": 79.635, "energy": 0.498, "valence": 0.413, "liveness": 0.795, "loudness": -8.866, "speechiness": 0.0685, "acousticness": 0.23, "danceability": 0.554, "instrumentalness": 0.00000598}, "interpretation": "The agonizing truth that love, even when it feels like an existential tremor, makes you cling harder, desperately negotiating for a future with someone who''s already tearing you apart. It''s a raw confession of fault and dependency, where the emotional chaos of heartbreak is felt as a physical, destabilizing force, even as the groove keeps a steady, almost hypnotic pull.", "mood_description": "An anxious urgency pulses beneath a heartfelt plea. It feels like the ground is shifting, but there''s a desperate need to keep things from falling apart."}', 'google:gemini-2.5-flash', '2', 6027, NULL, '2026-04-08 05:30:09.371974+00', '2026-04-08 05:30:09.371974+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('62373b1b-c19d-47d2-afff-8f324b84acb2', '140ebf68-f075-45f4-83c1-893170346487', '{"themes": [{"name": "desperate yearning", "description": "A profound emotional need for another person''s presence to find clarity and stability amidst personal turmoil."}, {"name": "urban isolation", "description": "Experiencing deep loneliness and a sense of being lost within the stimulating but ultimately empty backdrop of a \"Sin City\" environment."}, {"name": "self-medication", "description": "Using external means, whether substances or reckless pursuits, to cope with internal pain and vulnerability."}, {"name": "blurred reality", "description": "A state where one''s perception is clouded by overwhelming experiences, making it hard to see clearly without a grounding connection."}], "journey": [{"mood": "raw vulnerability", "section": "Opening Confession", "description": "A quiet, almost hesitant opening reveals a deep-seated loneliness and a plea for connection, hinting at withdrawals and a desperate sensitivity to touch."}, {"mood": "uneasy isolation", "section": "Sin City''s Emptiness", "description": "The energy swells as the cold, empty city is revealed, a place where judgment is absent but clarity is impossible without the other person."}, {"mood": "frantic yearning", "section": "Blinding Desperation", "description": "An explosive surge of energy as the realization hits: blinded and drowning, only one person can be trusted, making the need urgent and overwhelming."}, {"mood": "urgent haste", "section": "Reckless Pursuit", "description": "Time is running out, and the drive becomes more frantic, hitting the road \"in overdrive\" in a desperate attempt to find that crucial connection before dawn."}, {"mood": "steadfast declaration", "section": "Unwavering Resolve", "description": "A brief pause in the urgency to declare a firm commitment, a promise never to let go this time, too important for a phone call."}, {"mood": "persistent longing", "section": "Lingering Plea", "description": "The initial plea echoes, repeating the desperate state of being blinded and unable to rest until that vital touch is felt, fading out with the unresolved yearning."}], "headline": "A desperate chase through neon nights, seeking a singular touch to cut through the haze of a life spinning out of control.", "key_lines": [{"line": "I''m goin'' through withdrawals", "insight": "The physical and emotional cost of a life lived on the edge, longing for relief."}, {"line": "I can''t see clearly when you''re gone", "insight": "Complete dependence on another person to make sense of a chaotic, blurry world."}, {"line": "ooh, I''m blinded by the lights", "insight": "The overwhelming sensory input and dangerous lifestyle have obscured reality, leading to a state of desperate disorientation."}, {"line": "Oh, when I''m like this, you''re the one I trust", "insight": "Amidst chaos and self-inflicted wounds, a singular person becomes the last bastion of safety and faith."}, {"line": "Will never let you go this time", "insight": "A promise born from past mistakes and the fear of losing the one stabilizing force."}], "compound_mood": "Desperate Urgency", "sonic_texture": "A propulsive 80s synthwave throb, with glittering, layered synthesizers driving a relentless beat. The sound is sleek and electronic, creating a vibrant, almost dizzying backdrop for the desperate vocals.", "audio_features": {"tempo": 171.001, "energy": 0.73, "valence": 0.334, "liveness": 0.0897, "loudness": -5.94, "speechiness": 0.0598, "acousticness": 0.00143, "danceability": 0.513, "instrumentalness": 0.0000954}, "interpretation": "A life of destructive hedonism collides with a desperate need for genuine human connection. The \"blinding lights\" represent the overwhelming chaos and blurred reality of a life lived on the edge, where substances and fleeting encounters leave one vulnerable and aching for a singular, anchoring touch. It''s a stark portrayal of seeking salvation in another person when everything else is falling apart, even as the pursuit itself feels reckless and out of control.", "mood_description": "A relentless synth-pop drive pushes you forward, but a profound loneliness tugs at the edges, making every flash of light a reminder of what''s missing. It feels like chasing something vital, just out of reach."}', 'google:gemini-2.5-flash', '2', 6189, NULL, '2026-04-08 05:30:31.495453+00', '2026-04-08 05:30:31.495453+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('0d60a2df-db45-4f33-8a0b-53dc25c6c8d1', 'df14a8d9-303c-4fe9-a862-b31dfcc0b510', '{"themes": [{"name": "irreplaceable past", "description": "A constant pull backward to a time or person that cannot be brought back."}, {"name": "lonely independence", "description": "Finding yourself alone and having to navigate new realities without old support systems."}, {"name": "pervasive change", "description": "The inescapable feeling that nothing is truly the same as it once was, especially after a collective upheaval."}, {"name": "emotional masking", "description": "Projecting an upbeat facade while internally grappling with heavy feelings of loss and solitude."}], "journey": [{"mood": "Playful connection", "section": "Intro", "description": "A warm, intimate voice cuts through, a playful reminder of connection before plunging into the heart of things."}, {"mood": "Stuck longing", "section": "Verse 1", "description": "A sudden weight. You''re held back, stuck in a loop of past conversations, searching for a familiar hand to hold."}, {"mood": "Frantic acceptance", "section": "Chorus", "description": "The world shrinks to just you and a memory. The beat quickens, almost frantic, trying to outrun the undeniable truth that things are irrevocably altered."}, {"mood": "Vulnerable isolation", "section": "Verse 2", "description": "A phone rings, a voice from the outside checking in, revealing a deeper loneliness, a quiet desperation for help that isn''t coming."}, {"mood": "Desperate distraction", "section": "Bridge", "description": "A brief, sharp break. Thoughts scatter about escaping and not wanting to revisit painful topics, a desperate rush for distraction."}, {"mood": "Resigned echo", "section": "Outro", "description": "The frantic energy slowly gives way to a resigned acceptance, the echo of what was fading into the distance but never fully disappearing."}], "headline": "A frantic attempt to dance away the past, even as its ghosts whisper in your ear.", "key_lines": [{"line": "Gravity''s holdin'' me back", "insight": "An invisible force keeps you tethered to a previous life, unable to fully step into the new."}, {"line": "You know it''s not the same as it was", "insight": "The stark, repeated acknowledgment that a fundamental shift has occurred, leaving a permanent mark."}, {"line": "Harry, you''re no good alone", "insight": "The painful truth from an outside perspective, highlighting a vulnerable reliance on others for well-being."}, {"line": "Nobody''s coming to help", "insight": "The gut-wrenching realization that you''re truly on your own, facing challenges without a safety net."}, {"line": "I don''t wanna talk about the way that it was", "insight": "A desperate attempt to shut down introspection and avoid reliving a past that still hurts."}], "compound_mood": "Frenetic Longing", "sonic_texture": "A relentlessly pulsing synth bass underpins bright, shimmering keyboard melodies and a tight, driving drum machine beat. Vocals are upfront and clean, carrying a wistful ache despite the electrifying, dance-oriented production.", "audio_features": {"tempo": 173.93, "energy": 0.731, "valence": 0.662, "liveness": 0.311, "loudness": -5.338, "speechiness": 0.0557, "acousticness": 0.342, "danceability": 0.52, "instrumentalness": 0.00101}, "interpretation": "The dizzying realization that life has fundamentally shifted, leaving a profound sense of isolation and an unshakeable longing for what once was. Even with a vibrant, pulsating beat pushing forward, the lyrics confess a deep struggle to accept this new reality, portraying a person trapped between the need to move on and the pull of irreplaceable memories and connections.", "mood_description": "An electric current of synth-pop energy courses through you, making your body move, but your mind stays fixed on a past that feels miles away."}', 'google:gemini-2.5-flash', '2', 5195, NULL, '2026-04-08 05:30:48.200793+00', '2026-04-08 05:30:48.200793+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('6b01c0da-840d-4877-88bc-99f60696c11d', 'b194ad65-b64e-425a-8a67-6da6549b7044', '{"themes": [{"name": "perpetual immaturity", "description": "The endless cycle of childish behavior and irresponsibility in a romantic connection."}, {"name": "emotional burden", "description": "The heavy weight of being consistently responsible for another''s basic functions and emotional needs."}, {"name": "ironic self-awareness", "description": "Finding humor and perspective in a frustrating situation, even when it means acknowledging your own role in choosing it."}, {"name": "blaming the roots", "description": "Tracing current failings back to early influences, specifically a mother''s perceived over-coddling."}], "journey": [{"mood": "Annoyed observation", "section": "Intro/Verse 1", "description": "A sharp, observant start. Little details of incompetence pile up, leading to a quizzical, sarcastic question about the state of things."}, {"mood": "Biting accusation", "section": "Pre-Chorus/Chorus", "description": "The mood shifts to direct confrontation. A playful but firm takedown, naming the core problem with a catchy, undeniable hook."}, {"mood": "Exasperated insight", "section": "Verse 2", "description": "Deepening the frustration. Blame gets redirected, questioning fundamental survival skills with a knowing, almost comical exasperation."}, {"mood": "Ironic resignation", "section": "Bridge", "description": "A moment of self-reflection, tinged with dark humor. A sarcastic admission of a pattern, almost a prayer, acknowledging the absurdity of it all."}, {"mood": "Worn-out defiance", "section": "Chorus/Outro", "description": "The initial observations loop back, ending with a final, ironic acceptance of the situation, still wrapped in that danceable energy."}], "headline": "The exasperated eye-roll at a partner who refuses to grow up, set to a deceptively bright beat.", "key_lines": [{"line": "Did you just say you''re finished? Didn''t know we started", "insight": "The stark realization that you''re investing in something that was never truly reciprocal."}, {"line": "Man-child", "insight": "A perfectly distilled label for the frustratingly common archetype of an immature adult."}, {"line": "Never heard of self-care", "insight": "Pointing out a fundamental lack of personal responsibility in a cutting, almost childlike observation."}, {"line": "I choose to blame your mom", "insight": "A humorous yet pointed deflection of accountability, highlighting the absurdity of the situation."}, {"line": "And I swear they choose me, I''m not choosing them", "insight": "The wry, self-aware admission of an unfortunate, repeating dating pattern."}], "compound_mood": "Sarcastic Groove", "sonic_texture": "Bright, driving synths and a buoyant bassline underpin a clean, pop-forward vocal. It’s a danceable, high-energy track that feels effortlessly cool, with just a hint of sparkling sonic detail.", "audio_features": {"tempo": 123.01, "energy": 0.685, "valence": 0.811, "liveness": 0.317, "loudness": -5.087, "speechiness": 0.0572, "acousticness": 0.122, "danceability": 0.731, "instrumentalness": 0}, "interpretation": "The relentless emotional labor of parenting a grown man who should be a partner. It’s a weary recognition of repeated patterns, wrapped in a defiant, sarcastic shrug.", "mood_description": "An upbeat pop rhythm masks a sharp, witty frustration. It''s dancing through annoyance, a smile stretched thin as you deal with yet another childish mess."}', 'google:gemini-2.5-flash', '2', 5474, NULL, '2026-04-08 05:31:04.364851+00', '2026-04-08 05:31:04.364851+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('013b0550-ba4f-4e1c-ac62-f7a4d9121da6', '9a35420c-309b-4df1-aa9f-a394ff5fadda', '{"themes": [{"name": "divine protection", "description": "Believing in a higher power or fate to shield from negativity and guide choices."}, {"name": "loyalty''s embrace", "description": "The profound importance of a small, trusted circle against a world of adversaries."}, {"name": "the cost of fame", "description": "The constant vigilance required against those who wish ill, and the emotional distance it creates."}, {"name": "hometown pride", "description": "A deep connection to roots and a commitment to uplifting the people and places that shaped one''s identity."}], "journey": [{"mood": "Anticipatory unease", "section": "Intro", "description": "A subtle hum of warning, hinting at unseen conflicts just beneath the surface."}, {"mood": "Defiant assertion", "section": "Verse 1", "description": "Laying down boundaries with a quiet resolve, aware of the envy and wishes of others, but choosing peace as a struggle."}, {"mood": "Fated resolve", "section": "Pre-Chorus", "description": "A sudden declaration of purpose, acknowledging internal struggles while committing to a path believed to be guided by destiny."}, {"mood": "Echoing threats", "section": "Chorus", "description": "The quiet warnings turn into a resounding chant, a reminder of the relentless negativity constantly aimed at success."}, {"mood": "Inner circle''s strength", "section": "Verse 2", "description": "Pulling back the curtain on the chosen few, revealing the unbreakable bonds that truly sustain, a stark contrast to external drama."}, {"mood": "Lingering affirmation", "section": "Outro", "description": "The chant slowly fades, leaving a final impression of resilience and the persistent belief in a predetermined path."}], "headline": "Navigating the perilous path of success, shielded by a divine belief even as shadows loom.", "key_lines": [{"line": "I only love my bed and my mama, I''m sorry", "insight": "A stark confession of where true affection lies, revealing the emotional walls built around success."}, {"line": "Don''t pull up at 6 a.m. to cuddle with me", "insight": "Setting clear boundaries on casual intimacy, asserting self-worth beyond fleeting desires."}, {"line": "Hope I got some brothers that outlive me", "insight": "A sobering reflection on mortality and the enduring legacy desired through loyal friendships."}, {"line": "I make sure that north-side eat", "insight": "A powerful declaration of commitment to hometown and community, ensuring their prosperity alongside personal success."}, {"line": "I can''t do this on my own, ayy", "insight": "Acknowledging the reliance on something greater than oneself, whether fate or a divine power, for guidance and strength."}], "compound_mood": "Guarded Confidence", "sonic_texture": "A heavy, thumping bassline anchors a sparse, confident beat. Whispering synth pads create a subtle atmospheric tension, while Drake''s laid-back yet assertive flow cuts through the deep, rhythmic groove.", "audio_features": {"tempo": 77.169, "energy": 0.449, "valence": 0.357, "liveness": 0.552, "loudness": -9.211, "speechiness": 0.109, "acousticness": 0.0332, "danceability": 0.754, "instrumentalness": 0.0000829}, "interpretation": "A testament to loyalty and self-preservation in the face of widespread animosity. It''s about holding onto a personal code and trusting in an almost fated path, even as external pressures threaten to crumble connections and peace. The cold pragmatism of fame requires a tight inner circle and a strong belief in an overarching plan.", "mood_description": "A steady, low-slung beat that carries a weight of expectation. There''s a quiet determination moving through the rhythm, constantly aware of unseen eyes."}', 'google:gemini-2.5-flash', '2', 6232, NULL, '2026-04-08 05:31:56.890598+00', '2026-04-08 05:31:56.890598+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('a5490b39-de96-4476-96fd-77c6429f856b', 'c1d0a2e9-1758-478b-9f59-5f23502be75f', '{"themes": [{"name": "lost chances", "description": "Regretting not fully appreciating or capturing moments with someone important."}, {"name": "rooted belonging", "description": "Finding comfort and identity in local culture, friends, and family, particularly in Puerto Rico."}, {"name": "escapist revelry", "description": "Using partying and alcohol as a way to cope with underlying sadness or unaddressed feelings."}, {"name": "fading memory", "description": "The struggle to hold onto precious memories that are slowly becoming less clear."}], "journey": [{"mood": "distant hum", "section": "Intro", "description": "A quiet, almost observational hum, setting a scene of introspection before the story truly begins."}, {"mood": "bittersweet reflection", "section": "Verso 1", "description": "Sunsets in San Juan clash with a heavy heart, recalling missed moments and longing for a lost connection, even as friends and local life buzz around."}, {"mood": "aching regret", "section": "Estribillo", "description": "The deep, aching core of the regret surfaces, a quiet lament for forgotten embraces and unseen pictures, clinging to the familiar faces that remain."}, {"mood": "blurred denial", "section": "Verso 2", "description": "A fragile denial takes hold, pretending not to care while diving deeper into hazy celebration, seeking temporary oblivion from the lingering pain."}, {"mood": "raw connection", "section": "Interludio", "description": "A sudden, tender break in the haze, speaking directly to the crowd, pulling everyone in for a shared moment of gratitude and belonging before the party resumes."}, {"mood": "fading resignation", "section": "Outro", "description": "The regrets echo, mixed with a final, almost desperate plea for help and a slightly crass longing, as the night slowly fades into a blurry memory."}], "headline": "A hazy dance through past regrets, trying to find joy in the blur of present-day Puerto Rico.", "key_lines": [{"line": "Pero queriendo volver a la última vezQue a los ojos te miré", "insight": "The exact point where present enjoyment shatters against a specific, painful memory."}, {"line": "Debí tirar más fotos de cuando te tuve", "insight": "The quiet, crushing realization that not enough was done to preserve a cherished past."}, {"line": "Si me pregunta si aún pienso en ti, yo le digo que no", "insight": "The internal lie told to oneself and others, a protective shield against genuine feeling."}, {"line": "Vamo'' a disfrutar, que nunca se sabe si nos queda poco", "insight": "A frantic embrace of the present, driven by the fear of future loss and the passage of time."}, {"line": "Ojalá que los mío'' nunca se muden", "insight": "The desperate hope that some constants will remain, even as other connections dissolve."}], "compound_mood": "Wistful Daze", "sonic_texture": "A subdued reggaeton rhythm underpins a hazy soundscape of muted percussive elements and distant, longing melodies. It feels like a late-night, low-volume mix, with a gentle, persistent sway that hints at movement more than full-blown dance, occasionally punctuated by spoken word asides.", "audio_features": {"tempo": 136.02, "energy": 0.131, "valence": 0.032, "liveness": 0.0807, "loudness": -27.405, "speechiness": 0.0717, "acousticness": 0.177, "danceability": 0.625, "instrumentalness": 0.218}, "interpretation": "A danceable current of regret carries you through a night of distraction. Even surrounded by friends and the vibrant energy of San Juan, there''s a deep ache for past connections, a silent wish to relive moments that slipped away without enough photos or goodbyes.", "mood_description": "A slow, heavy sway of regret and longing, trying to find release in a hazy night out."}', 'google:gemini-2.5-flash', '2', 5503, NULL, '2026-04-08 05:32:12.908304+00', '2026-04-08 05:32:12.908304+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('143e9296-5f71-42aa-b8d2-66cdf4826ca5', '03b0c165-6c9b-47d9-8e1e-131bddcaf106', '{"themes": [{"name": "voyeuristic jealousy", "description": "Watching an ex move on from a distance, feeling the sting of their new happiness and dissecting the new person."}, {"name": "bitter defense mechanisms", "description": "Using sarcasm and self-deprecating humor as a shield against the pain of seeing a former partner with someone new."}, {"name": "emotional ghosting", "description": "The feeling of emotional death after a breakup, even when trying to appear fine on the surface."}, {"name": "complicated empathy", "description": "A surprising flicker of understanding or even liking for the ''other'' person, adding a layer of confusion to the bitterness."}], "journey": [{"mood": "Peering in", "section": "Verse 1", "description": "Standing just outside, watching a former lover''s new life unfold, dissecting every detail with a mix of lingering hurt and cutting judgment."}, {"mood": "Pointed warning", "section": "Pre-Chorus", "description": "The internal monologue sharpens into a definitive judgment, a protective instinct stirring to caution the new person about past mistakes."}, {"mood": "Familiar sting", "section": "Chorus", "description": "A vivid, almost cinematic replay of a scene from the past, recognizing the comfortable intimacy with a fresh sting of what''s been lost."}, {"mood": "Conflicted chaos", "section": "Verse 2", "description": "A descent into petty jealousy and vivid memories, bouncing wildly between a surprising soft spot for the new person and a quick retraction back to bitter hatred."}, {"mood": "Ghostly defiance", "section": "Bridge", "description": "The facade crumbles, revealing the deep wounds and the feeling of having died when the other person walked away, leading to a defiant, almost haunting presence."}, {"mood": "Resigned clarity", "section": "Outro", "description": "The bitter truth settles in: the cycle of attraction and disappointment repeats, leaving a cynical acceptance of the game being played."}], "headline": "The relentless loop of post-breakup obsession, caught between cutting remarks and a surprising, almost reluctant, curiosity.", "key_lines": [{"line": "Living in your glass house, I''m outside, uh", "insight": "The vulnerable exposure of a new relationship, visible and judged from the periphery of a past connection."}, {"line": "Smiling through it all, yeah, that''s my life", "insight": "A sardonic self-awareness, acknowledging the performative facade maintained while privately reeling from pain."}, {"line": "Wait, I think I hate her, I''m not that evolved, I''m sorry", "insight": "The honest, immediate confession of falling short of an ideal self, succumbing to base, human emotion."}, {"line": "Said that I was fine, said it from my coffin", "insight": "The stark contrast between outward composure and the internal devastation felt after a significant loss."}, {"line": "And she''ll spend the night, catch me on your ceiling", "insight": "A lingering, almost spectral presence haunting the new relationship, a constant reminder of what came before."}], "compound_mood": "Frenetic Jealousy", "sonic_texture": "Driving indie pop with bright, propulsive drums and a clear, forward vocal delivery, balanced by a subtle undercurrent of acoustic warmth that keeps it grounded, even as the energy surges.", "audio_features": {"tempo": 108.548, "energy": 0.808, "valence": 0.372, "liveness": 0.159, "loudness": -4.169, "speechiness": 0.0368, "acousticness": 0.214, "danceability": 0.554, "instrumentalness": 0}, "interpretation": "The tangled mess of post-breakup emotions, where sharp wit and self-aware sarcasm barely hide the raw sting of jealousy and lingering attachment. It’s the internal battle between wishing an ex well and secretly wanting them to fail, all while observing their new life with a mix of judgment and morbid fascination.", "mood_description": "A rush of sharp-edged observations carried by a bright, urgent beat. It feels like dancing through a complicated, self-aware moment of intense, conflicted feelings."}', 'google:gemini-2.5-flash', '2', 5894, NULL, '2026-04-08 05:32:30.214914+00', '2026-04-08 05:32:30.214914+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('19e10f09-9eaf-4fe2-aee4-fa22eeb6be70', '7e066add-1267-4ae6-a1f7-7e5dc2c0f87d', '{"themes": [{"name": "cultural authenticity", "description": "Claiming ownership of a community and heritage, while accusing another of appropriation and being an outsider."}, {"name": "unmasking hypocrisy", "description": "Directly calling out alleged moral failings and perceived inauthenticity, aiming to dismantle a public persona."}, {"name": "community allegiance", "description": "A strong rallying cry that unites a specific community in shared opposition against a common foe."}, {"name": "relentless attack", "description": "The sustained, direct, and aggressive nature of the lyrical content, leaving no room for rebuttal."}], "journey": [{"mood": "Ominous whisper", "section": "Intro", "description": "A dark, unsettling voice sets a menacing tone, hinting at hidden truths about to be revealed."}, {"mood": "Sudden onslaught", "section": "Verse 1", "description": "The beat drops, and the words come like rapid-fire punches, direct accusations building immediate, fierce momentum."}, {"mood": "Unifying defiance", "section": "Chorus", "description": "A powerful, chant-like assertion solidifies an ''us'' against ''them,'' creating an infectious, rallying cry."}, {"mood": "Deepening scrutiny", "section": "Verse 2", "description": "More damning claims pile on, questioning identity and motive, keeping the pressure intense and unwavering."}, {"mood": "Historical context", "section": "Verse 3", "description": "The scope widens, connecting current events to a larger pattern of cultural exploitation and adding heavy weight to every accusation."}, {"mood": "Hypnotic dismissal", "section": "Bridge/Outro", "description": "The accusations morph into a rhythmic, almost celebratory dance, a collective and undeniable act of rejection that fades into an echo."}], "headline": "A relentless assault, exposing perceived deceit and asserting an unyielding claim to authenticity.", "key_lines": [{"line": "Say, Drake, I hear you like ''em youngYou better not ever go to cell block one", "insight": "Directly dropping heavy, disturbing allegations, making them central to the entire narrative being crafted."}, {"line": "Certified Lover Boy? Certified pedophiles", "insight": "A devastating twist on a known title, reducing the opponent''s carefully constructed persona to a singular, damning accusation."}, {"line": "No, you not a colleague, you a fuckin'' colonizer", "insight": "Drawing a clear, unbridgeable line of cultural ownership and exploitation, completely severing any perceived professional or social ties."}, {"line": "They not like us, they not like us, they not like us", "insight": "The ultimate statement of exclusion, defining the rigid boundaries of a community and who truly belongs within it."}], "compound_mood": "Aggressive Celebration", "sonic_texture": "A bouncy, driving West Coast G-funk inspired beat with a thick bassline and sharp, insistent drum programming. Bright, slightly menacing synth stabs punctuate the relentless, confident vocal delivery, creating an aggressive swagger built for movement.", "audio_features": {"tempo": 101.06, "energy": 0.448, "valence": 0.206, "liveness": 0.146, "loudness": -7.186, "speechiness": 0.0753, "acousticness": 0.00943, "danceability": 0.899, "instrumentalness": 0}, "interpretation": "A definitive line is drawn, asserting an unshakeable identity and community against an outsider perceived as morally bankrupt and culturally exploitative. The highly danceable production belies the gravity of the accusations, transforming a direct attack into a unifying anthem of rejection and scorn.", "mood_description": "The infectious beat demands movement, yet the lyrical barbs are sharp and cutting. It feels like a charged confrontation, ready to ignite a communal defiance."}', 'google:gemini-2.5-flash', '2', 8836, NULL, '2026-04-29 14:50:46.25006+00', '2026-04-29 14:50:46.25006+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('617dd7a5-2a41-4a02-9c86-0ecdf791a1b0', '21b8e7a6-a1d4-481f-b1ff-827a2d70de90', '{"themes": [{"name": "fragile masculinity", "description": "Men who are physically grown but emotionally stunted, relying on others for basic functionality and refusing to take responsibility."}, {"name": "emotional labor", "description": "The invisible burden placed on women to constantly nurture, guide, and ''mother'' their adult male partners, often without recognition."}, {"name": "sarcastic resignation", "description": "Using humor and biting wit as a coping mechanism for the repetitive and frustrating cycle of dealing with immature romantic partners."}, {"name": "self-awareness of dating patterns", "description": "Acknowledging a tendency to pick partners who require constant care, even while criticizing the immaturity itself."}], "journey": [{"mood": "Weary preamble", "section": "Intro", "description": "A deep, exasperated sigh sets the stage for a story that''s all too familiar and incredibly tiresome, a prelude to the coming frustration."}, {"mood": "Mounting annoyance", "section": "Verse 1", "description": "The trivial excuses and ridiculous antics pile up, painting a picture of someone clearly not living in reality, sparking a dry, sarcastic wit that barely conceals irritation."}, {"mood": "Sharp realization", "section": "Chorus buildup", "description": "The annoyance boils over into direct questions, escalating to the cutting diagnosis of ''man-child,'' a pointed label for the emotional immaturity on painful display."}, {"mood": "Cynical inquiry", "section": "Verse 2", "description": "A mix of attraction and utter bewilderment, questioning how such an incompetent person functions and even going so far as to sarcastically blame their upbringing."}, {"mood": "Ironic acceptance", "section": "Bridge", "description": "A moment of self-deprecating humor and insight, realizing a pattern in one''s own choices, almost sarcastically accepting this recurring romantic fate."}, {"mood": "Defiant dismissal", "section": "Outro", "description": "The final words are a collective, sarcastic benediction and a playful call-out to men in general, a last laugh before walking away from the constant emotional drain."}], "headline": "A sharp, witty battle cry from a woman who''s completely over the emotional burden of dealing with an immature partner.", "key_lines": [{"line": "Did you just say you''re finished? Didn''t know we started", "insight": "The casual dismissal of emotional connection, where one person is already checked out before the other even realizes things began."}, {"line": "Half your brain just ain''t there", "insight": "The blunt assessment of a profound lack of emotional maturity and basic competence, delivered with comedic exasperation."}, {"line": "I choose to blame your mom", "insight": "The desperate search for an external cause for inherent immaturity, shifting responsibility with a touch of dark, sarcastic humor."}, {"line": "And I swear they choose me, I''m not choosing them", "insight": "The ironic recognition of a recurring pattern, a reluctant admission of her own attraction to the very dynamic she criticizes, wrapped in a playful denial."}], "compound_mood": "Sardonic Exasperation", "sonic_texture": "Clean, punchy pop rhythms with a confident, almost conversational vocal delivery, underpinned by modern R&B inflections and a bright, polished production that gives a sharp edge to the witty lyrics.", "interpretation": "It''s the exasperating reality of constantly finding yourself in relationships where you''re expected to be the adult, the emotional support system, and the primary problem-solver. It captures the fatigue of pouring energy into someone who refuses to grow up, coupled with a sarcastic resignation about one''s own unwitting role in perpetuating the pattern.", "mood_description": "A sharp eye-roll set to a pop beat. The feeling of being completely over it, yet still having to deal with the ridiculousness of it all, with a dry, knowing smirk."}', 'google:gemini-2.5-flash', '2', 5729, NULL, '2026-04-29 14:50:48.353474+00', '2026-04-29 14:50:48.353474+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('d17643f0-cf9a-4b7a-84ea-2ef9e8709387', '8bc81d75-d38c-4dc0-a3c9-bf62df393e12', '{"themes": [{"name": "obsessive love", "description": "A love so profound it turns possessive, unable to tolerate the happiness of another if not the one providing it."}, {"name": "fear of loneliness", "description": "The dread of being by oneself, feeling that any form of companionship, even prison, is preferable to isolation."}, {"name": "performative maturity", "description": "Outwardly claiming growth and self-awareness while inwardly battling intense, unresolved emotions."}, {"name": "destructive fantasy", "description": "Imagining extreme, violent acts as a way to cope with overwhelming hurt and jealousy."}], "journey": [{"mood": "Lingering bitterness", "section": "Verse 1", "description": "A smooth rhythm settles in, softly revealing the sting of a former lover''s happiness with someone new."}, {"mood": "Mature facade", "section": "Pre-Chorus", "description": "A confident declaration of maturity and self-work is quickly undercut by a singular, persistent longing for what''s lost."}, {"mood": "Dangerous fantasy", "section": "Chorus", "description": "The raw, shocking thought of ultimate revenge is casually laid bare, revealing a terrifying preference for any fate over being alone."}, {"mood": "Obsessive plotting", "section": "Verse 2", "description": "The dark fantasy intensifies, shifting from a hypothetical threat to vivid, almost playful images of premeditated acts."}, {"mood": "Sober devotion", "section": "Bridge", "description": "A calm, almost rational justification emerges, declaring extreme actions were a clear-eyed act of love, for \"us.\""}, {"mood": "Imagined consequence", "section": "Final Chorus", "description": "The fantasy culminates in a chilling, detached recounting of the deed, still rooted in the desperate avoidance of loneliness."}], "headline": "A dark fantasy of revenge fueled by desperate love, wrapped in a deceptively sweet melody.", "key_lines": [{"line": "Hate to see you happy if I''m not the one drivin''", "insight": "Wishing for a former partner''s unhappiness unless you are still the center of their world."}, {"line": "If I can''t have you, no one should", "insight": "A possessive desire to destroy what cannot be owned, born from a desperate attachment."}, {"line": "Rather be in jail than alone", "insight": "The deep, unsettling dread of solitude, where even incarceration feels like a better option."}, {"line": "Now I''m in the basement plannin'' home invasion", "insight": "The chilling shift from abstract thought to detailed, disturbing scenarios."}, {"line": "I did it all for love", "insight": "Rationalizing extreme and violent actions as the ultimate expression of devotion."}], "compound_mood": "Sardonic Desperation", "sonic_texture": "A smooth, low-key R&B groove built on a pulsing bassline and subtle, hazy synths. Vocals float above the rhythm, conversational and deceptively calm, creating a mellow yet unsettling atmosphere.", "audio_features": {"tempo": 88.993, "energy": 0.728, "valence": 0.43, "liveness": 0.161, "loudness": -5.75, "speechiness": 0.0351, "acousticness": 0.0543, "danceability": 0.644, "instrumentalness": 0.169}, "interpretation": "The agonizing realization that being alone feels worse than any crime, pushing desperate thoughts to the surface. It''s about grappling with overwhelming jealousy and the inability to cope with a lost love, even when trying to appear mature and rational. The slick, understated production creates a chilling contrast, making the extreme fantasies feel oddly calm.", "mood_description": "A smooth, low-key groove pulls you into a dangerous fantasy. It feels like casually contemplating extreme measures while everything else is chill."}', 'google:gemini-2.5-flash', '2', 6197, NULL, '2026-04-29 14:50:50.515836+00', '2026-04-29 14:50:50.515836+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('e1b0887a-2f4e-4ec1-98aa-f72ccabd59a6', '8ad8c789-d7aa-4ff8-976a-94c7849eeb33', '{"themes": [{"name": "self-condemnation", "description": "Grappling with a deep sense of guilt and believing one deserves severe punishment for past actions."}, {"name": "defiant resistance", "description": "A stubborn refusal to comply with demands from authority, even if it means facing extreme consequences."}, {"name": "self-inflicted pain", "description": "Choosing to harm oneself as an act of autonomy, rejecting external judgment or intervention."}, {"name": "moral hypocrisy", "description": "Questioning the legitimacy of those in power who preach morality but are themselves flawed."}], "journey": [{"mood": "Guilty Resignation", "section": "Verse 1", "description": "A stark confession of unworthiness and a deep, self-imposed judgment. There''s a feeling of deserving the worst, but also a quiet plea for universal mercy."}, {"mood": "Fierce Defiance", "section": "Verse 2", "description": "A direct challenge to authority emerges, demanding an ultimate sacrifice if compliance is expected. The mood shifts to a fierce, almost sacred refusal."}, {"mood": "Sharp Accusation", "section": "Verse 3", "description": "A cutting accusation thrown at those who claim to heal but cannot mend themselves. The mood is critical and confrontational, revealing a core hypocrisy."}, {"mood": "Somber Autonomy", "section": "Outro", "description": "A personal, heartbreaking decision to internalize the pain and break one''s own spirit. It ends with a self-determined acceptance of suffering, on one''s own terms."}], "headline": "A defiant spirit facing down judgment, choosing self-inflicted pain over bending to a world it sees as corrupt.", "key_lines": [{"line": "I should burn in hell", "insight": "A self-assessment of profound wrongdoing, where past actions leave a permanent stain."}, {"line": "You''d better come over with a crucifixYou''re gonna have to nail me down", "insight": "An absolute refusal to yield, equating compliance with a death sentence rather than submission."}, {"line": "Doctor, doctor, heal yourself", "insight": "Calling out the hypocrisy of those who offer solutions while being unable to fix their own flaws."}, {"line": "I will break my own heart from now on", "insight": "An ultimate act of self-sovereignty, choosing to inflict personal pain as a last stand against external control."}], "compound_mood": "Resigned Defiance", "sonic_texture": "Raw, urgent guitars with a driving, unpolished rhythm section, providing a direct, unvarnished backdrop for a defiant vocal performance. The \"Ooh-ooh\" sections likely add a haunting, atmospheric layer, pushing the sound towards a psychedelic edge.", "interpretation": "The burden of personal failings intertwines with a deep distrust of societal structures. It''s about acknowledging past misdeeds and feeling worthy of damnation, but refusing to be coerced by a hypocritical authority. The ultimate choice is to inflict self-punishment as an act of perverse autonomy, rejecting external judgment or intervention, even if it means breaking one''s own spirit.", "mood_description": "A heavy weight of past mistakes presses down, yet there''s a stubborn refusal to be broken by external forces. It feels like a grim resolve, accepting a painful future on one''s own terms."}', 'google:gemini-2.5-flash', '2', 5053, NULL, '2026-04-29 14:51:01.784576+00', '2026-04-29 14:51:01.784576+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('b92df8a7-a8fe-4fae-9f56-5227728dea17', 'a803252e-b76d-4839-8332-a47c83b63ed2', '{"themes": [{"name": "first heartbreak", "description": "The intense, all-consuming pain of a first major breakup."}, {"name": "ghosts of the past", "description": "How places and shared experiences become painful reminders of what''s lost."}, {"name": "unkept promises", "description": "The bitter feeling when someone''s ''forever'' turns out to be temporary."}, {"name": "lonely freedom", "description": "The ironic pain of achieving personal independence that now feels meaningless without a specific person."}], "journey": [{"mood": "quiet ache", "section": "Verse 1", "description": "A quiet ache settles in, driving through familiar streets with a newfound freedom that only emphasizes the absence."}, {"mood": "bitter envy", "section": "Verse 2", "description": "The ache sharpens into bitter envy, picturing a rival and questioning self-worth, wondering how love could disappear so completely."}, {"mood": "raw heartbreak", "section": "Chorus", "description": "A tidal wave of raw heartbreak crashes, disbelief at how easily a shared ''forever'' was dismissed, leaving behind a solitary journey."}, {"mood": "stubborn attachment", "section": "Verse 3", "description": "Even when friends grow weary, a stubborn attachment remains, convinced no one else could understand the depth of that lost connection."}, {"mood": "haunted memory", "section": "Bridge", "description": "Every red light, every street, every sound becomes a haunted memory, leading to an undeniable, aching declaration of love that refuses to let go."}, {"mood": "resigned sorrow", "section": "Outro", "description": "The journey ends with a resigned sorrow, driving alone past a street that once promised everything, now just a painful landmark."}], "headline": "A bittersweet freedom ride, haunted by shattered promises and the ghost of a love that just won''t fade.", "key_lines": [{"line": "Just like we always talked about", "insight": "The crushing weight of future plans becoming painful reminders of what will never be."}, {"line": "She''s so much older than meShe''s everything I''m insecure about", "insight": "The raw, unfiltered self-doubt that surfaces when comparing oneself to a perceived replacement."}, {"line": "Guess you didn''t mean what you wrote in that song about me", "insight": "The specific sting of a public declaration of love being proven false, adding insult to injury."}, {"line": "Red lights, stop signsI still see your face in the white cars, front yards", "insight": "How the everyday world transforms into a constant, inescapable reminder of a lost connection."}, {"line": "But I still fuckin'' love you, babe", "insight": "The visceral, untamed cry of a heart that refuses to accept the end, despite all the pain."}], "compound_mood": "Shattered Nostalgia", "sonic_texture": "A tender piano melody opens, layered with a gently strummed acoustic guitar, setting an intimate, almost fragile scene. The vocals rise from a vulnerable whisper to a powerful, soaring cry, supported by a gradual build of steady drums and sweeping string arrangements that create a wide, emotional sweep, yet always keeping the raw, unadorned voice at the forefront.", "audio_features": {"tempo": 143.994, "energy": 0.433, "valence": 0.14, "liveness": 0.106, "loudness": -8.822, "speechiness": 0.0533, "acousticness": 0.743, "danceability": 0.584, "instrumentalness": 0.0000135}, "interpretation": "The devastating sting of reaching a long-anticipated milestone only to find it''s empty without the person who was supposed to share it. It''s a cruel twist, turning a symbol of independence into a vehicle for heartbreak, driving endlessly through memories of a love that was promised forever but suddenly vanished, leaving behind the bitter taste of betrayal and lingering doubt.", "mood_description": "A raw, whispered confession that swells into a powerful, heartbroken wail. You''re driving alone, reliving every painful memory, the world blurring past."}', 'google:gemini-2.5-flash', '2', 6670, NULL, '2026-04-29 14:51:08.519074+00', '2026-04-29 14:51:08.519074+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('66feb699-c143-4075-aa40-0221e0563b41', '7c3cba29-b42c-4a5c-975f-80b9673caae8', '{"themes": [{"name": "elusive attraction", "description": "The thrill of the chase, where the desired person is always just out of reach, demanding more from their suitor."}, {"name": "proving worth", "description": "A direct challenge to a potential partner to demonstrate genuine effort and commitment, rather than mere words."}, {"name": "fleeting moments", "description": "The understanding that opportunities for connection are brief, emphasizing the urgency to act before time runs out."}, {"name": "self-preservation in dating", "description": "Protecting oneself from half-hearted attempts at romance by maintaining an independent, ready-to-disappear stance."}], "journey": [{"mood": "Confident pulse", "section": "Intro", "description": "A confident pulse emerges, setting a rhythmic stage for what’s to come, a subtle invitation to the game."}, {"mood": "Playful challenge", "section": "Chorus", "description": "The game begins with a clear warning: interest is fleeting, and genuine connection needs to be earned, or a quick exit is assured."}, {"mood": "Flirtatious observation", "section": "Verse 1", "description": "Watching a suitor with detached interest, a flirtatious exchange unfolds, but a silent challenge hangs in the air."}, {"mood": "Vulnerable possibility", "section": "Post-Chorus", "description": "A moment of openness, hinting that genuine effort might just break through the facade and make her consider staying."}, {"mood": "Testing sincerity", "section": "Verse 2", "description": "Questioning sincerity and demanding substance beyond sweet words, pushing for true conviction."}, {"mood": "Lingering invitation", "section": "Outro", "description": "The challenge echoes, fading into the night but leaving the invitation open for anyone bold enough to try and keep her."}], "headline": "A dancefloor dare, inviting someone to truly earn a moment before it slips away.", "key_lines": [{"line": "Catch me or I go Houdini", "insight": "The explicit declaration of being hard to hold onto, a test of real desire and effort."}, {"line": "Time is passin'' like a solar eclipse", "insight": "The fleeting nature of opportunity, demanding immediate action before the moment vanishes."}, {"line": "Maybe you could be the one to make me stay", "insight": "A rare moment of openness, revealing the possibility of commitment hidden behind the guarded exterior."}, {"line": "But do you practise everything that you preach?", "insight": "Directly calling out potential insincerity, seeking depth and action over empty promises."}], "compound_mood": "Slippery Seduction", "sonic_texture": "A sleek, pulsing dance-pop groove with an infectious disco heartbeat. Synthesizers shimmer and bass lines throb, creating a vibrant, club-ready energy under confident, airy vocals that glide effortlessly above the beat.", "audio_features": {"tempo": 116.985, "energy": 0.789, "valence": 0.866, "liveness": 0.0947, "loudness": -4.876, "speechiness": 0.059, "acousticness": 0.0036, "danceability": 0.744, "instrumentalness": 0.00144}, "interpretation": "It''s about setting a high bar for romantic pursuit, challenging a potential lover to prove their sincerity and effort. There''s a playful yet firm warning: if you can''t keep up or aren''t genuinely invested, she''s gone without a trace. It’s not just about ghosting; it''s about reclaiming agency in dating by making the other person work to truly connect.", "mood_description": "A shimmering invitation to the dancefloor, holding a promise that might vanish at any moment. It''s exhilarating and just a little bit dangerous, a confident stride into the night."}', 'google:gemini-2.5-flash', '2', 5103, NULL, '2026-04-29 14:52:01.27574+00', '2026-04-29 14:52:01.27574+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('58457cbd-f2f7-41aa-8fd4-9661e18ea698', '722817f8-3dc2-4f2b-abcc-4ea5ff884ed2', '{"themes": [{"name": "self-preservation", "description": "Protecting oneself from repeating painful patterns by enforcing strict personal rules."}, {"name": "boundary setting", "description": "Establishing firm limits with an ex to prevent further emotional entanglement and maintain mental health."}, {"name": "addictive patterns", "description": "The constant struggle to resist the temptation of falling back into a familiar, yet toxic, relationship cycle."}, {"name": "internal monologue", "description": "The necessary, repetitive self-talk and affirmations used to reinforce new behaviors and build resolve."}], "journey": [{"mood": "Hesitant resolve", "section": "Intro", "description": "A single, emphatic word rings out, a determined mantra against picking up the phone, already highlighting the core temptation."}, {"mood": "Conflicted longing", "section": "First Struggle", "description": "Sleepless nights and desperate attempts to write down salvation reveal the deep pull of a love that hurts, a cycle of hope and heartbreak playing on repeat."}, {"mood": "Fierce affirmation", "section": "The Proclamation", "description": "A clear, numbered list of non-negotiable rules bursts forth, a defiant declaration against manipulation, transforming internal struggle into an empowering anthem for self-control."}, {"mood": "Steadfast determination", "section": "Relentless Practice", "description": "Despite being pulled backward, the commitment to moving forward intensifies, acknowledging the ongoing effort required to internalize these rules and perform the act of getting over someone."}, {"mood": "Lasting resolve", "section": "Final Command", "description": "The rules echo one last time, a powerful, fading reminder to stay strong, ending not with a question, but with the firm assertion that the healing process is underway."}], "headline": "An unwavering vow to sever ties, a desperate yet determined battle against old habits and manipulative allure.", "key_lines": [{"line": "One, don''t pick up the phone", "insight": "The first and hardest boundary, a direct confrontation with the habit of falling back into old patterns."}, {"line": "And if you''re under him, you ain''t gettin'' over him", "insight": "A raw, physical metaphor for the impossible task of truly moving on while still entangled in intimacy."}, {"line": "I gotta tell them to myself", "insight": "The lonely act of self-parenting, a constant reinforcement against personal weakness and temptation."}, {"line": "Practice makes perfect I''m still tryna learn it by heart", "insight": "The honest admission that breaking habits isn''t instantaneous, it''s a learned, practiced performance that takes time."}], "compound_mood": "Resilient Resolution", "sonic_texture": "A crisp, relentless beat pulses beneath layered synth textures, creating an undeniable, high-energy dancefloor momentum. Clean, sharp vocals cut through the bright production, giving a feeling of confident command even as the bassline propels everything forward.", "audio_features": {"tempo": 116.073, "energy": 0.7, "valence": 0.608, "liveness": 0.153, "loudness": -6.021, "speechiness": 0.0694, "acousticness": 0.00261, "danceability": 0.762, "instrumentalness": 0.0000156}, "interpretation": "Breaking free from a magnetic, yet detrimental past relationship requires an ironclad set of personal boundaries. It''s an act of radical self-affirmation, where the pain of letting go is constantly weighed against the self-respect gained by refusing to fall back into old patterns. The upbeat, driving sound acts as a defiant shield, powering through the emotional labor of building a new identity apart from the ex.", "mood_description": "The beat drives forward with an irresistible push, masking the internal argument playing out in every line. It''s a fight for self-preservation on a neon-lit dance floor."}', 'google:gemini-2.5-flash', '2', 6254, NULL, '2026-04-29 14:52:02.271609+00', '2026-04-29 14:52:02.271609+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('5684d635-9200-4e0b-b44e-ed3600aed116', '171027a5-d544-4657-ad4c-165849f20106', '{"themes": [{"name": "clashing lifestyles", "description": "The friction between a disciplined, early-rising existence and a free-spirited, late-night way of life."}, {"name": "stubborn self-truth", "description": "The unwavering commitment to one''s own authentic nature, even when it creates incompatibility."}, {"name": "uncompromising love", "description": "An affection that acknowledges deep differences rather than trying to erase them, leading to a bittersweet acceptance."}, {"name": "bitter preference", "description": "A leaning towards raw, unadulterated experiences over those that are softened or idealized."}], "journey": [{"mood": "sleepy observation", "section": "Verse 1", "description": "A bleary-eyed morning reveals the stark contrast between a night-owl''s routine and a partner''s vibrant, early start, hinting at attempts to align lifestyles."}, {"mood": "playful temptation", "section": "Pre-Chorus", "description": "A mischievous invitation to step away from rigid discipline and embrace the wild, unkempt beauty of a bonfire night and a hazy morning."}, {"mood": "firm declaration", "section": "Chorus", "description": "An unwavering commitment to a raw, unsweetened existence, choosing black coffee, neat whiskey, and late nights, acknowledging the partner''s sweetness is simply incompatible."}, {"mood": "cynical defense", "section": "Verse 2", "description": "A deeper dive into a chosen path of working late and aiming low, dismissing the partner''s strict self-regulation as an overly strict gatekeeper for the body."}, {"mood": "aging analogy", "section": "Pre-Chorus", "description": "An appreciation for the partner''s fresh, unaged beauty, yet a wistful suggestion that acquiring complexity and bitterness, like wine in a barrel, would make them a better match."}, {"mood": "resigned reiteration", "section": "Outro", "description": "A final, lingering affirmation of an unchangeable nature, repeating the core truth that some tastes, and some people, are just \"too sweet.\""}], "headline": "The sweet allure of a pristine life meets the bitter truth of a wild heart, recognizing an unbridgeable divide.", "key_lines": [{"line": "Don''t you just wanna wake up, dark as a lake Smellin'' like a bonfire, lost in a haze?", "insight": "The yearning for a shared, uninhibited wildness, away from pristine perfection."}, {"line": "I think I''ll take my whiskey neat My coffee black and my bed at 3", "insight": "An unyielding commitment to a raw, unsweetened existence, a personal creed."}, {"line": "You treat your mouth as if it''s Heaven''s gate The rest of you like you''re the TSA", "insight": "The meticulous, almost regulatory approach to life that feels suffocatingly pure."}, {"line": "If you can sit in a barrel, maybe I''ll wait Until that day", "insight": "A cynical hope for the partner to acquire complexity and bitterness, recognizing the futility of such a transformation."}], "compound_mood": "Defiant Admiration", "sonic_texture": "A deep, resonant vocal layered over a soulful, almost gospel-tinged groove. The sound feels warm and lived-in, like a comfortable, slightly smoky room, with a rhythm that sways between laid-back and subtly driving.", "interpretation": "The quiet acknowledgment that some fundamental differences in lifestyle and temperament are too vast to bridge, even within affection. There''s an admiration for a partner''s radiant purity and disciplined living, but an honest, almost resigned admission that a wilder, less refined path is simply a part of who you are, making true integration feel ''too sweet'' to stomach.", "mood_description": "A smooth, late-night confession, cool and collected but laced with a hint of longing. There''s a magnetic pull towards a brighter life, yet an unwavering commitment to a darker comfort."}', 'google:gemini-2.5-flash', '2', 6561, NULL, '2026-04-29 14:52:06.661185+00', '2026-04-29 14:52:06.661185+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('ab55c5bf-8d4c-4117-8f70-3fa35bd9fad3', '4c803f80-1dd3-45f0-922b-e67997165cd0', '{"themes": [{"name": "reckless abandon", "description": "A willingness to ignore caution and dive into intense feelings, despite past hurts."}, {"name": "addictive cycles", "description": "Repeating patterns of falling hard and getting hurt, unable to break free from the thrill."}, {"name": "intoxicating love", "description": "The dizzying, almost drunken feeling of new romance that overrides logic and self-preservation."}, {"name": "self-sabotage", "description": "Choosing a path known to lead to pain, driven by an uncontrollable urge."}], "journey": [{"mood": "Giddy Plunge", "section": "Chorus: JENNIE", "description": "A swift, energetic dive into a feeling, acknowledging the head-over-heels chaos and the inevitable hard landing."}, {"mood": "Wry Resignation", "section": "Verse 1: JENNIE, Dua Lipa", "description": "A moment of questioning why love is so unkind, admitting to being a ''fool'' who rushes in, yet still drawn to the burn."}, {"mood": "Sudden Yearning", "section": "Pre-Chorus: Dua Lipa, JENNIE & Both", "description": "The spark ignites, a swift shift to contemplating forever, a moment of impulsive desire taking over any lingering caution."}, {"mood": "Drunk Devotion", "section": "Verse 2: Dua Lipa", "description": "A deeper immersion into the intoxicating effect, losing all sense of self-control and clarity, blurring the lines between love and a dizzying buzz."}, {"mood": "Shared Recklessness", "section": "Chorus: JENNIE & Dua Lipa", "description": "The feeling intensifies, a unified voice affirming the impulsive, all-in nature of this fall, embracing the chaotic journey together."}, {"mood": "Lingering Afterglow", "section": "Outro: Dua Lipa & JENNIE", "description": "The energy slowly dissipates, a final, almost dismissive wave, suggesting the wild ride is over but its memory, and the readiness for the next fall, remains."}], "headline": "A thrilling, reckless dive into love, knowing the crash is likely, but going all in anyway.", "key_lines": [{"line": "I trip and fall in love Just like a Tuesday drunk", "insight": "The casual, almost accidental way intense feelings can ambush you, even on an ordinary day."}, {"line": "Over the handlebars Hitting the ground so hard", "insight": "The vivid image of crashing spectacularly, a familiar consequence accepted with a shrug."}, {"line": "Why am I still fixing for this frying pan", "insight": "A self-aware lament, knowing the pain is coming but still drawn to the heat."}, {"line": "I don''t ever think twice, and, baby, that''s why", "insight": "The core of the impulsivity, the surrender to instinct over logic, despite the cost."}, {"line": "And I''m a little too buzzed on your love to play it cute", "insight": "The honesty of being completely overwhelmed by affection, losing all pretense."}], "compound_mood": "Dizzying Recklessness", "sonic_texture": "A propulsive, synth-driven beat anchors a high-energy pop sound, bright and polished. Shimmering electronic textures create an almost intoxicating buzz, while clear, confident vocals ride effortlessly over the dynamic, R&B-infused rhythm.", "audio_features": {"tempo": 152.018, "energy": 0.855, "valence": 0.669, "liveness": 0.0524, "loudness": -4.208, "speechiness": 0.0426, "acousticness": 0.00377, "danceability": 0.51, "instrumentalness": 0}, "interpretation": "The exhilarating, yet self-aware, surrender to an all-consuming love. It''s an intoxicating cycle of diving in headfirst, knowing the potential for hurt is high, but the thrill of the moment is too powerful to resist. The energetic production makes this reckless abandon feel like a vibrant, irresistible dance.", "mood_description": "Feel the pulse of an addictive beat, a whirlwind of emotion where falling hard feels both exhilarating and a little dangerous."}', 'google:gemini-2.5-flash', '2', 4847, NULL, '2026-04-29 14:52:14.798529+00', '2026-04-29 14:52:14.798529+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('2606a659-fb0b-4e88-b2cf-2cad5839b29f', '817243d6-7f10-436c-a020-ca948f5d55f5', '{"themes": [{"name": "toxic legacy", "description": "The lasting emotional scars and behavioral patterns left by a damaging relationship."}, {"name": "performative detachment", "description": "The act of pretending indifference or faking feelings to cope or survive a difficult emotional situation."}, {"name": "unequal power", "description": "The inherent imbalance in relationships with significant age gaps or manipulative partners."}, {"name": "haunted escape", "description": "Finding freedom from a bad situation, but still being pursued by its ghost and lingering effects."}], "journey": [{"mood": "Conflicted regret", "section": "Verse 1", "description": "A raw confession of hate and longing opens the story, revealing a history of faking feelings and the ex''s bizarre attempts at control."}, {"mood": "Overwhelmed dizziness", "section": "Chorus", "description": "The core feeling of being emotionally sick takes hold, an urgent plea to escape the suffocating presence of the past."}, {"mood": "Clear-eyed relief", "section": "Verse 2", "description": "A shift in perspective allows for seeing the ex''s self-destruction from a distance, feeling both glad to be out and sorry for the mess."}, {"mood": "Frustrated confrontation", "section": "Chorus 2", "description": "The emotional sickness returns, but now with direct challenges to the ex''s affected behaviors and a stronger resolve to actively fight back against the memories."}, {"mood": "Stark realization", "section": "Bridge", "description": "Unpacking the relationship''s unsettling origin, a powerful reminder of the age and power disparity present from the very start."}, {"mood": "Weary struggle", "section": "Final Chorus/Outro", "description": "A final, desperate attempt to break free, viewing the past relationship as an addiction and contemplating a surrender to the overwhelming feelings, or perhaps the healing process itself."}], "headline": "Navigating the dizzying aftermath of a toxic love, grasping for solid ground in the emotional wreckage.", "key_lines": [{"line": "I hate you for what you did And I miss you like a little kid", "insight": "The painful paradox of love and hate intertwined, a confused longing for a connection that caused so much damage."}, {"line": "I faked it every time, but that''s alright I can hardly feel anything", "insight": "The numbness that comes from emotional self-preservation, or perhaps the hollowness of the relationship itself."}, {"line": "I have emotional motion sickness", "insight": "The perfect metaphor for the internal turmoil and inability to find balance in the wake of a toxic connection."}, {"line": "You were in a band when I was born", "insight": "The unsettling power dynamic laid bare, highlighting a manipulative age gap that defined the relationship."}, {"line": "I try to stay clean and live without If I surrender to the sound", "insight": "Viewing the relationship as an addiction, and the tempting, frightening thought of giving in to the lingering emotions or finding solace in the music itself."}], "compound_mood": "Disoriented Reckoning", "sonic_texture": "A deceptively bright indie folk arrangement with raw, intimate vocals. Acoustic guitars drive a steady, mid-tempo rhythm, creating a sound that feels both grounded and gently propulsive, contrasting with the swirling emotional chaos in the lyrics.", "audio_features": {"tempo": 107.021, "energy": 0.546, "valence": 0.623, "liveness": 0.0842, "loudness": -9.021, "speechiness": 0.0357, "acousticness": 0.774, "danceability": 0.651, "instrumentalness": 0.0437}, "interpretation": "The song unpacks the complex, often contradictory emotions that linger after escaping a manipulative relationship. It''s about the struggle to reconcile genuine grief for a lost connection with the deep-seated anger and relief of survival, constantly battling the memory and influence of the abuser while striving for emotional freedom.", "mood_description": "The gentle strumming belies a turbulent heart, caught between missing what''s gone and raging at what was. It feels like trying to steady yourself on a rocking boat."}', 'google:gemini-2.5-flash', '2', 5563, NULL, '2026-04-29 14:52:15.592682+00', '2026-04-29 14:52:15.592682+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('f925f1f8-549b-4c0d-aa35-9b8502edea10', 'a742071c-3a6e-4c39-a050-0277228bdb0d', '{"themes": [{"name": "irresistible attraction", "description": "The overwhelming, instant pull of infatuation takes over, leaving no room for doubt or hesitation."}, {"name": "confident seduction", "description": "An unshakeable belief in one''s own charm and the power to effortlessly captivate."}, {"name": "fleeting intimacy", "description": "The promise of deep connection and love, intensely felt in the present, even if its duration is uncertain."}, {"name": "dancefloor magic", "description": "The transformative power of music and movement to create a space for immediate, exhilarating romance."}], "journey": [{"mood": "Confident Invitation", "section": "Intro/Verse 1", "description": "A magnetic pull starts immediately, an open invitation to a night of effortless connection, bold and knowing."}, {"mood": "Rising Ecstasy", "section": "Pre-Chorus", "description": "A feeling ignites, a spark turning into a brilliant light that keeps you awake, completely absorbed in movement and touch."}, {"mood": "Hypnotic Affirmation", "section": "Chorus", "description": "The core promise repeats, a mantra of undeniable attraction where a single moment holds endless potential."}, {"mood": "Singular Focus", "section": "Post-Chorus/Bridge", "description": "Everything narrows to that one, essential connection, a brief glimpse of deeper need within the intoxicating loop."}, {"mood": "Endless Groove", "section": "Outro", "description": "The irresistible feeling fades into the dancefloor haze, a lingering echo of that singular, potent kiss, forever looping."}], "headline": "An undeniable pull, promising everything in a single, electrifying moment.", "key_lines": [{"line": "One kiss is all it takesFallin'' in love with me", "insight": "The audacious confidence of an immediate, unshakeable connection taking hold."}, {"line": "Let me love you while the moon is still out", "insight": "Embracing the fleeting magic of a night, before the harsh light of day brings an end to the spell."}, {"line": "Something in you-ou-ouLit up heaven in me-e-e", "insight": "The sudden, overwhelming rush of finding something divine and profoundly uplifting in another person."}, {"line": "I look like all you need", "insight": "The playful, self-assured certainty that you are the perfect, indispensable fit."}], "compound_mood": "Confident Rapture", "sonic_texture": "Pulsing house beats drive an infectious rhythm, layered with vibrant synth chords and a powerful, clear vocal delivery that feels both immediate and effortlessly cool. The whole sound is bright, clean, and designed for uninhibited movement, like a summer night on the dancefloor.", "audio_features": {"tempo": 123.992, "energy": 0.862, "valence": 0.593, "liveness": 0.0814, "loudness": -3.24, "speechiness": 0.11, "acousticness": 0.037, "danceability": 0.79, "instrumentalness": 0.0000225}, "interpretation": "The thrilling, almost audacious confidence of knowing you''re exactly what someone needs, and the intoxicating rush of an attraction so potent it feels like destiny in a single glance. It''s about the joyous surrender to immediate chemistry, embracing a connection that might be fleeting but feels utterly complete in its present moment.", "mood_description": "The air crackles with an electric current, pulling you onto the dancefloor and into a dizzying spell of instant connection."}', 'google:gemini-2.5-flash', '2', 4736, NULL, '2026-04-29 14:52:47.041336+00', '2026-04-29 14:52:47.041336+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('6875b760-5cfd-4f5c-82ee-f8647563b960', '9bc50a13-265c-49f1-86aa-848d03d21e10', '{"themes": [{"name": "relationship fatigue", "description": "The weariness that comes from repeatedly investing in relationships that require constant guidance and explanation."}, {"name": "asserting boundaries", "description": "Drawing a firm line in the sand, refusing to continue patterns of unequal emotional effort."}, {"name": "desire for equal partnership", "description": "A deep yearning for a lover who is not only capable but willing to take initiative and connect on a profound level."}], "journey": [{"mood": "Cautious Inquiry", "section": "Verse 1", "description": "A direct question to a potential partner: are you a true connection or just another mistake? The skepticism is palpable, built on past lessons learned the hard way."}, {"mood": "Passionate Demand", "section": "Chorus", "description": "The beat swells, and the longing bursts out. It''s a vivid picture of the ideal partner — someone who can handle vulnerability, provide deep connection, and even a bit of thrilling chaos, causing a delicious ''vertigo''."}, {"mood": "Final Ultimatum", "section": "Post-Chorus", "description": "The declaration rings out: ''training season''s over.'' There''s no more time for teaching or showing; either you''re ready, or you''re not. This is a moment of clear-eyed self-respect."}, {"mood": "Weary Optimism", "section": "Verse 2", "description": "Reflecting on the effort put into past relationships, and the hope for a love that strikes true, like an arrow. The desire for ''potential'' feels both hopeful and slightly exasperated."}, {"mood": "Challenging Call", "section": "Bridge", "description": "The intensity builds, framing love as a competition where commitment is key. Are you in the game, or waiting on the sidelines? The stakes are clear, and the whistle has blown."}, {"mood": "Unwavering Finality", "section": "Outro", "description": "The repeated phrase hammers home the message: the era of patience and instruction is done. It''s a definitive, liberating close, pulsing with the energy of a new beginning."}], "headline": "The exhausting cycle of dating, finally broken by a clear demand for true partnership.", "key_lines": [{"line": "Or just the poison that I''m drawn to?", "insight": "The painful awareness of repeatedly falling for what isn''t good, knowing the pattern is hard to break."}, {"line": "And, baby, I don''t need to learn my lesson twice", "insight": "A firm line drawn against repeating past heartbreaks, rooted in hard-won wisdom."}, {"line": "Whose love feels like a rodeo", "insight": "Craving a relationship with wild, thrilling excitement, but also a partner who knows how to master it."}, {"line": "''Cause training season''s over", "insight": "The final, unequivocal declaration of self-worth and a refusal to settle for less than a fully formed partnership."}, {"line": "Are you on my team or stuck on the sidelines", "insight": "A direct challenge for commitment, asking for an active, engaged partner rather than a passive observer."}], "compound_mood": "Assertive Liberation", "sonic_texture": "A vibrant blend of disco-infused basslines and shimmering synths, topped with crisp, confident vocals. The driving, infectious groove feels both expansive and intimately direct, making you want to move while processing a profound personal declaration.", "audio_features": {"tempo": 123.041, "energy": 0.587, "valence": 0.664, "liveness": 0.123, "loudness": -4.483, "speechiness": 0.0477, "acousticness": 0.0349, "danceability": 0.812, "instrumentalness": 0.00000264}, "interpretation": "It''s about the emotional labor of constantly having to educate partners on how to love right, and the breaking point where that labor becomes intolerable. There''s a deep longing for a connection that simply ''gets it,'' a partner who can meet her emotional intelligence and desire for control without needing a syllabus. The dancefloor energy doesn''t mask the frustration; it amplifies the resolve to move past the ''training season'' for good.", "mood_description": "An irresistible, pulsing beat drives a deep sense of self-assuredness. It feels like dancing off the weight of past disappointments, stepping into a new era with confident stride."}', 'google:gemini-2.5-flash', '2', 4000, NULL, '2026-04-29 14:52:49.891717+00', '2026-04-29 14:52:49.891717+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('9eaa3dbe-259a-450f-ae99-a9cd06205bdd', '7dfe0dce-e229-48e5-bef8-024cff55be56', '{"themes": [{"name": "post-breakup glow", "description": "The radiant transformation that follows the end of a relationship."}, {"name": "unwanted return", "description": "An ex trying to re-engage after the hard work of moving on is done."}, {"name": "fierce independence", "description": "Asserting a boundary and celebrating newfound freedom."}, {"name": "joyful defiance", "description": "Finding pleasure and strength in refusing to look back."}], "journey": [{"mood": "Quiet determination", "section": "Intro", "description": "A quiet but firm declaration. Setting a boundary before the story even begins, a hint of something decisive."}, {"mood": "Reflective transformation", "section": "Verse 1", "description": "A look back at the difficult path. Acknowledging the past hurt and the transformation it sparked, leading to a new, unexpected place."}, {"mood": "Unshakeable confidence", "section": "Refrain", "description": "A moment of self-affirmation, proclaiming full recovery and a complete detachment from the past."}, {"mood": "Building warning", "section": "Pre-Chorus", "description": "The warning intensifies. A direct challenge to any lingering doubts or attempts to undermine the newfound freedom, building tension."}, {"mood": "Liberated command", "section": "Chorus", "description": "The ultimate rejection. A forceful, liberating command to stay away, delivered with an undeniable groove that makes the refusal feel like a celebration."}, {"mood": "Empowered recall", "section": "Verse 2", "description": "Recalling the sting of goodbye. Reinforcing why the boundary is necessary, contrasting the past pain with the vibrant present."}, {"mood": "Unwavering stance", "section": "Bridge", "description": "Doubling down on the pre-chorus''s defiance, leaving no room for misinterpretation, fueled by a driving rhythm."}, {"mood": "Echoing finality", "section": "Outro", "description": "The final, echoing message. Fading out with the core command, solidifying the victory of moving on completely."}], "headline": "A dazzling declaration of independence, leaving past heartbreak in the rearview mirror.", "key_lines": [{"line": "Did a full one-eighty, crazy Thinking ''bout the way I was", "insight": "The dizzying sensation of looking back at a past self and barely recognizing them after profound change."}, {"line": "I''m all good already So moved on, it''s scary", "insight": "The surprising, almost unnerving realization of just how completely you''ve healed and progressed beyond a past hurt."}, {"line": "If you don''t wanna see me dancing with somebody If you wanna believe that anything could stop me", "insight": "The open challenge to a former partner, daring them to think they still have any hold or influence."}, {"line": "Don''t show up, don''t come out Don''t start caring about me now", "insight": "The firm, non-negotiable boundary drawn against an ex trying to re-enter a life they previously left."}, {"line": "Though it took some time to survive you I''m better on the other side", "insight": "The hard-won triumph over past pain, acknowledging the struggle but celebrating the superior outcome."}], "compound_mood": "Defiant Exuberance", "sonic_texture": "A vibrant, pulsating disco-pop groove driven by a funky bassline and shimmering synth layers. The bright, confident vocals glide effortlessly over a tight, energetic beat, creating an irresistible urge to dance.", "audio_features": {"tempo": 123.95, "energy": 0.793, "valence": 0.679, "liveness": 0.0951, "loudness": -4.521, "speechiness": 0.083, "acousticness": 0.0123, "danceability": 0.793, "instrumentalness": 0}, "interpretation": "It''s a powerful reclaiming of self after a painful breakup, a moment where the past trying to creep back in only strengthens the resolve to move forward. The initial hurt has transformed into an undeniable joy and autonomy, leaving no room for a former partner to re-enter a life they once abandoned.", "mood_description": "Pure, unadulterated confidence set to a pulsating disco beat. Every synth shimmer and bassline throb feels like a victory lap after heartbreak."}', 'google:gemini-2.5-flash', '2', 5467, NULL, '2026-04-29 14:52:54.816179+00', '2026-04-29 14:52:54.816179+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('63093af9-f34e-4964-88d0-5287c68c5eaf', 'a6bcfb20-a41f-49ad-b223-9eabce5a8a05', '{"themes": [{"name": "emotional disconnect", "description": "The inability for people, especially romantic partners, to truly hear and understand each other''s feelings."}, {"name": "performative indifference", "description": "Acting like nothing matters as a defense mechanism against personal sadness or relational effort."}, {"name": "lonely resignation", "description": "A quiet acceptance that profound understanding is out of reach, for oneself and from others."}, {"name": "unspoken sadness", "description": "A persistent feeling of being \"down\" without a clear reason or outlet, leading to internal isolation."}], "journey": [{"mood": "Hesitant, resigned", "section": "Opening exchange", "description": "A direct, yet emotionally distant, recount of a partner''s distress met with a dismissive shrug."}, {"mood": "Lost, wandering", "section": "Personal unraveling", "description": "A sudden shift inward, revealing a personal struggle with unexplained sadness and a sense of being lost."}, {"mood": "Crushing, lonely", "section": "Universal isolation", "description": "The feeling that no one, not even those closest, can truly grasp the internal state, solidifying a lonely perspective."}, {"mood": "Revealing, detached", "section": "Fading pretense", "description": "A repeat of the earlier exchange, but with a stark admission of a lie, cementing the breakdown and the ultimate departure."}, {"mood": "Cold, definitive", "section": "Final dismissal", "description": "The conversation cycles back again, ending with the same resolute, cold detachment and a definitive closing of the door."}], "headline": "A messy breakup caught in a spiral of indifference and unspoken sadness. Walking away when all anyone needs is a moment of real connection.", "key_lines": [{"line": "\"Oh, baby, I feel so down Oh, it turn'' me off When I feel left out\"", "insight": "The quiet desperation of wanting to be seen and heard, only to be met with emotional distance."}, {"line": "\"Oh, babe, I don''t care no more I know this for sure I''m walkin'' out that door\"", "insight": "The jarring swiftness of emotional shutdown, a decision made out of self-preservation or apathy."}, {"line": "\"Oh, people, they don''t understand No, girlfriends, they don''t understand\"", "insight": "The crushing weight of isolation, realizing that a unique internal struggle feels incomprehensible to others."}, {"line": "\"Oh, baby, gonna be alright It was a great big lie ''Cause I left that night, yeah\"", "insight": "The stark admission of a broken promise, exposing the fragile nature of attempts at comfort when true connection is absent."}], "compound_mood": "Detached Melancholy", "sonic_texture": "A raw, stripped-back indie rock feel. Distorted, jangling guitars and a driving, unfussy drum beat carry a casual, almost mumbled vocal delivery, adding to the feeling of detachment with an underlying nervous energy.", "interpretation": "Navigating the frustrating landscape of emotional unavailability, both personal and in a relationship. It''s about how easier it is to walk away than to confront genuine feelings or try to understand another''s pain. The male character''s own internal struggle with feeling \"down\" becomes a barrier, preventing him from offering comfort or even acknowledging the distress of the woman, leading to a breakdown in communication and an ultimate departure. The core issue is a deep-seated inability, or refusal, to truly connect and empathize, leaving everyone isolated in their own feelings.", "mood_description": "A cool, almost nonchalant sadness hangs in the air. Feeling disconnected even when trying to express something, like watching a slow-motion car crash of a relationship from a distance."}', 'google:gemini-2.5-flash', '2', 5310, NULL, '2026-04-29 14:53:02.390929+00', '2026-04-29 14:53:02.390929+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('df70e6d8-9e26-4a1f-bd2d-eead2685de70', 'e2ff9c6d-b39d-4cae-8b4b-5e934eaf132e', '{"themes": [{"name": "revisiting the past", "description": "Old feelings and iconic lines from a lifetime are brought forward, transformed by new energy."}, {"name": "unexpressed emotion", "description": "The quiet tragedy of words left unsaid, shaping who one becomes."}, {"name": "authentic identity", "description": "The struggle to reconcile an inner truth with the expectations and perceptions of others."}, {"name": "emotional resilience", "description": "Finding new ways to process old wounds, allowing them to fuel a forward momentum."}], "journey": [{"mood": "Ethereal opening", "section": "Intro", "description": "A gentle beckoning, a soft hum drawing you into a space where time feels suspended, preparing for what''s to come."}, {"mood": "Lingering regret", "section": "Verse", "description": "A recognition of deep-seated human weakness and the lasting imprint of past desires, carried on a steady beat that hints at deeper currents."}, {"mood": "Hardened truth", "section": "Pre-Chorus", "description": "A stark confession of emotional defense, the feeling of a heart protected by walls built from past experiences, yet still vulnerable."}, {"mood": "Propulsive introspection", "section": "Chorus", "description": "Old feelings rush forward with an undeniable urgency, as iconic lines about longing and unsaid words blend into a soaring, irresistible plea for self-discovery."}, {"mood": "Echoing surrender", "section": "Outro", "description": "A playful, almost resigned chant, dissolving into the pulsing rhythm as the journey through memories fades back into the vibrant present, leaving a lingering sweetness."}], "headline": "Longing for a forgotten sense of self, caught in a whirlwind of past echoes and new energy.", "key_lines": [{"line": "Cold, cold heart", "insight": "The lasting impact of past hurts, shaping how one approaches future connection and keeping parts of the self guarded."}, {"line": "And I think it''s gonna be a long, long time", "insight": "The endless wait for true understanding, both from others and from within, stretching out like an open road."}, {"line": "I''m not the man they think I am at home", "insight": "The weight of an assumed identity, yearning to break free and be seen authentically, beyond the facade."}, {"line": "Well, I thought it, but I kept it hid", "insight": "The quiet tragedy of unexpressed truths, creating a chasm between inner self and outward presentation, leading to regret."}], "compound_mood": "Melancholy Groove", "sonic_texture": "A vibrant tapestry of pulsing synth bass and a driving house beat, adorned with shimmering electronic melodies. Layered vocals intertwine, creating a sound that feels both classic and utterly fresh, designed for movement and introspection.", "interpretation": "Revisiting old regrets and unexpressed truths, the song pulls fragments of a past life into a dazzling, present-day reckoning. It''s a confession of a ''cold heart'' and a yearning for an authentic self, all while the world keeps spinning with a new, urgent rhythm. This isn''t just a remix; it''s a re-contextualization, allowing old pain to find new expression on the dancefloor, making the heartache feel both distant and intensely immediate.", "mood_description": "A swirling rush of nostalgia that makes you want to dance and cry at the same time. The past echoes through a vibrant, pulsating present, making you feel everything all at once."}', 'google:gemini-2.5-flash', '2', 4785, NULL, '2026-05-02 10:53:31.351977+00', '2026-05-02 10:53:31.351977+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('fab581eb-fa99-4bbc-89ac-8612caa23e05', 'ec77e61a-d43f-47d5-b52c-97e3b259ad36', '{"themes": [{"name": "societal critique", "description": "Calling out the hypocrisy and flaws of the established order and those in power."}, {"name": "generational conflict", "description": "The tension between those who embody traditional structures and a younger perspective trying to find its way."}, {"name": "moral compromise", "description": "The difficulty of doing what''s right when the world demands you play by its often corrupt rules."}, {"name": "communication breakdown", "description": "The struggle to speak truth or be understood when language itself is twisted and ambiguous."}], "journey": [{"mood": "Sharply observant", "section": "Opening observations", "description": "Pointing out the critics and the perceived sophistication, a shared understanding forms, a mirror reflecting back words felt but unspoken."}, {"mood": "Cynical warning", "section": "Rising tension", "description": "The world threatens to blame and shame, pushing back against those who stand out, leading to a stark warning about the path of corruption and the confusion of trying to stay true."}, {"mood": "Disillusioned echo", "section": "Overwhelmed repetition", "description": "A flood of information makes questioning seem obsolete, yet the same pitfalls and confused attempts to navigate morality resurface, stuck in a loop of trying to do right but failing."}, {"mood": "Resigned detachment", "section": "Moment of retreat", "description": "A quiet withdrawal, a declaration of not wanting anything from this tangled mess, acknowledging a lack of blame but still seeking distance."}, {"mood": "Weary acceptance", "section": "Stark resignation", "description": "The blunt call-out of \"stockholders\" and the repetitive, defeated \"maybe not tonight\" settles in, a tired acceptance that change is hard, perhaps impossible, and the cycle continues."}], "headline": "Navigating a world that demands conformity, even when you know better, all while trying to stay true.", "key_lines": [{"line": "Don''t go there ''cause you''ll never return", "insight": "The irreversible corruption that comes with entering certain spheres, a point of no return for one''s integrity."}, {"line": "To do the right thing but without recompense", "insight": "The harsh reality that good intentions often go unrewarded, making it harder to stay on the moral path."}, {"line": "And now you don''t know how you could ever complain", "insight": "The self-imposed silence that follows compromise, trapped by past actions and unable to voice dissatisfaction."}, {"line": "The information''s here / Here and everywhere", "insight": "Overload of knowledge making deep questioning feel unnecessary, yet not necessarily leading to understanding."}, {"line": "Stockholders / Same shit, a different life", "insight": "The unchanging nature of power dynamics and wealth disparity, regardless of who is in charge or how things appear to shift."}], "compound_mood": "Sardonic Restlessness", "sonic_texture": "A relentless, punchy drumbeat drives everything forward, layered with jangling, distorted guitars that weave between sharp, angular riffs and smoother, almost synth-like melodies. The bassline is prominent and propulsive, giving it a danceable edge, while the vocals cut through with a cool, slightly detached delivery. It''s a tight, energetic sound with a glossy, almost retro-futuristic sheen.", "audio_features": {"tempo": 164.959, "energy": 0.749, "valence": 0.649, "liveness": 0.314, "loudness": -5.67, "speechiness": 0.0475, "acousticness": 0.0113, "danceability": 0.593, "instrumentalness": 0.106}, "interpretation": "Navigating a world where \"the adults\" - the established, the powerful, the seemingly sophisticated - lay out a path that feels both unavoidable and deeply flawed. There''s a struggle to maintain integrity when every action is judged, every good intention is met with cynicism, and even trying to do the \"right thing\" feels like a compromise. It''s the frustrating realization that the system is rigged, and even those who recognize it often fall into its patterns.", "mood_description": "A driving rhythm pushes you forward, but the words pull you into a world of cynical observations and confused intentions. It feels like dancing while wrestling with uncomfortable truths."}', 'google:gemini-2.5-flash', '2', 6136, NULL, '2026-05-02 11:00:01.900666+00', '2026-05-02 11:00:01.900666+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('eca5bb55-06c7-4785-8ee3-b3b306b5c924', '68c501fb-fd58-44a9-ae44-c9d5acaf1bba', '{"themes": [{"name": "shared pleasure", "description": "Indulging in a moment where everyone''s desires align and multiply."}, {"name": "exploring boundaries", "description": "Stepping beyond traditional relationship structures into something fresh and exciting."}, {"name": "unfiltered desire", "description": "Openly expressing attraction and curiosity without hesitation or apology."}, {"name": "intimate adventure", "description": "The thrill of discovery in a deeply personal and unconventional experience."}], "journey": [{"mood": "sultry invitation", "section": "Verse 1", "description": "A smooth, direct invitation into a private world, hinting at shared anticipation and a knowing glance."}, {"mood": "shared confession", "section": "Chorus", "description": "The unspoken desire becomes clear, a mutual acknowledgment of attraction for all involved, establishing a thrilling new dynamic."}, {"mood": "unbothered indulgence", "section": "Post-Chorus", "description": "A push to simply surrender to the moment, letting go of any hesitation and just enjoying the experience as it unfolds."}, {"mood": "liberated connection", "section": "Verse 2", "description": "Confirming the unique bond, it dismisses any conventional jealousy, celebrating the freedom found in this shared, open moment."}, {"mood": "lingering satisfaction", "section": "Outro", "description": "The feeling slowly dissipates, leaving behind the warm glow of shared pleasure and the assurance that this experience was created just for them."}], "headline": "A smooth, confident invitation to explore shared desires, stepping into a new, exhilarating intimacy.", "key_lines": [{"line": "I know you like her too", "insight": "The quiet confirmation that a hidden desire is mutual, opening up new possibilities."}, {"line": "This point of view is something new", "insight": "Stepping into a fresh perspective on intimacy, where old rules don''t apply."}, {"line": "It''s okay to share", "insight": "A liberating dismissal of conventional expectations, finding comfort in open desire."}, {"line": "So don''t be jealous of your reflection", "insight": "Finding confidence and self-acceptance in a shared experience, seeing oneself through a new, affirmed lens."}, {"line": "Just know I do this for you", "insight": "The ultimate gesture of care, framing a daring act as an offering of devotion."}], "compound_mood": "Confident Exploration", "sonic_texture": "A warm, mid-tempo R&B groove, driven by a deep, pulsing bass and understated drums. Smooth, unhurried vocals float over a backdrop of hazy, almost liquid synths, creating an intimate, danceable space that feels both relaxed and subtly electrifying.", "audio_features": {"tempo": 124.034, "energy": 0.379, "valence": 0.629, "liveness": 0.109, "loudness": -7.739, "speechiness": 0.0395, "acousticness": 0.538, "danceability": 0.66, "instrumentalness": 0.00000212}, "interpretation": "Stepping boldly into a new space of shared intimacy, where desires are openly acknowledged and celebrated. It''s a confident, almost casual embrace of a multi-person dynamic, suggesting a thrill in discovering a ''new point of view'' on connection and pleasure, free from jealousy or judgment.", "mood_description": "A deep, unhurried groove wraps around you, pulling you into a space where boundaries blur and new desires spark. It feels like a knowing glance exchanged, a shared secret about to unfold."}', 'google:gemini-2.5-flash', '2', 4661, NULL, '2026-05-02 11:00:24.561789+00', '2026-05-02 11:00:24.561789+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('f937a6db-81b6-4a1f-9606-c111349ec7f3', 'a63cb7f9-f331-4bf5-8ffe-766daf5242cd', '{"themes": [{"name": "letting go", "description": "Giving in to forces beyond control and finding peace there."}, {"name": "overwhelm", "description": "The feeling of being drowned by daily noise, stress, and expectations."}, {"name": "personal evolution", "description": "Embracing transformative change and moving past old ways of being."}, {"name": "acceptance", "description": "Finding comfort and even joy in the inevitable unfolding of life, without resistance."}], "journey": [{"mood": "Initial friction", "section": "Verse 1", "description": "Caught in the everyday clutter, an inner voice pushes past the noise, hinting at a path of surrender."}, {"mood": "Mounting pressure", "section": "Chorus 1", "description": "The weight of pointless effort presses down, a deep internal shift makes everything else feel small, and the day''s grind begins anew."}, {"mood": "Impending shift", "section": "Verse 2", "description": "A powerful, uncontrollable force is approaching, promising to sweep away what isn''t essential, and the resolve to stop resisting takes hold."}, {"mood": "Critical juncture", "section": "Chorus 2", "description": "The fight against fate is over, something new is emerging, and a daring leap of faith is made, with full awareness of the risks."}, {"mood": "Full surrender", "section": "Outro", "description": "A peaceful readiness settles in, embracing the transition, realizing this acceptance was always a part of the journey."}], "headline": "A spiraling surrender to the inevitable, caught between the urgency of change and the comfort of letting go.", "key_lines": [{"line": "All this running around tryin'' to cover my shadow", "insight": "An impossible struggle to hide the self, revealing the futility of constant effort."}, {"line": "An ocean growing inside, now all the others seem shallow", "insight": "A deepening personal world, making external concerns feel trivial and distant."}, {"line": "Something''s trying to get out and it''s never been closer", "insight": "An internal force pushing for expression, on the verge of breaking through."}, {"line": "If my take-off fails, make up some other story", "insight": "A daring leap into the unknown, with a casual acknowledgment of potential failure."}, {"line": "Baby, now I''m ready, moving on", "insight": "A profound and calm acceptance of change, marking a definitive new beginning."}], "compound_mood": "Hypnotic Surrender", "sonic_texture": "A swirling vortex of layered synthesizers, a relentless, pulsing bassline, and driving, precise drums. Ethereal vocals drift through a highly polished, expansive soundscape, building a hypnotic groove that feels both vast and intimate.", "audio_features": {"tempo": 125.012, "energy": 0.881, "valence": 0.577, "liveness": 0.111, "loudness": -5.875, "speechiness": 0.0443, "acousticness": 0.00462, "danceability": 0.602, "instrumentalness": 0.0266}, "interpretation": "It’s a deeply personal reckoning with the incessant demands of life, the feeling of being worn down by constant motion and external pressures. Finding relief means giving in, letting the current take you, and discovering a powerful freedom in releasing control over things beyond your grasp.", "mood_description": "You''re caught in a powerful current, dancing on the edge of a breakthrough. There''s a joyful acceptance in the swirl, even as everything shifts around you."}', 'google:gemini-2.5-flash', '2', 4899, NULL, '2026-05-17 09:57:49.306999+00', '2026-05-17 09:57:49.306999+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('76ad137f-8c5f-47bc-a9c1-8425b7b6f409', 'a4278ea1-7f32-4a6c-b3bf-5fae3890d44b', '{"headline": "It’s the feeling of chasing after something just out of reach, propelled by a quiet, determined longing.", "compound_mood": "Driving Longing", "sonic_texture": "A propulsive kick drum anchors a shimmering landscape of hazy synth pads and clean, driving bass. Sharp, precise percussion cuts through the mix, while subtle, yearning synth melodies weave in and out, building a cool, polished sound.", "audio_features": {"tempo": 122.014, "energy": 0.945, "valence": 0.238, "liveness": 0.132, "loudness": -8.324, "speechiness": 0.0569, "acousticness": 0.186, "danceability": 0.719, "instrumentalness": 0.884}, "mood_description": "A persistent, driving beat takes hold, urging your body to move forward even as a deep, quiet yearning settles in your chest, a bittersweet ache beneath the rhythm."}', 'google:gemini-2.5-flash', '2', 2306, NULL, '2026-05-13 16:31:41.676313+00', '2026-05-13 16:31:41.676313+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('f6b88d16-8ad8-4a29-b326-66bb8eb0166b', 'c3255a99-e6fb-4a5d-b099-d69e3917fb51', '{"themes": [{"name": "past wounds", "description": "The partner''s previous hurts are acknowledged and addressed as a primary barrier to overcome."}, {"name": "patient devotion", "description": "Love is offered with a promise of time and a steady commitment to provide what''s needed."}, {"name": "protective love", "description": "A fierce intent to keep the partner safe and guard the relationship from external judgment or past pain."}, {"name": "changing for love", "description": "A willingness to adapt personal routines and behaviors to align with the needs of the beloved."}], "journey": [{"mood": "Gentle Invitation", "section": "Pre-Hook: Luciano", "description": "A night owl recognizing the daytime struggles of a hesitant love. A quiet vow to change, a gentle invitation to come closer."}, {"mood": "Insistent Tenderness", "section": "Hook: Luciano", "description": "An insistent, tender plea to open up and receive. The promise of everything needed, delivered with patient timing."}, {"mood": "Passionate Reassurance", "section": "Part 1: Mario", "description": "Cutting through the past with direct, passionate reassurance. An open invitation to dive into a real connection, regardless of public eyes."}, {"mood": "Fierce Commitment", "section": "Part 2: Luciano", "description": "Doubling down on commitment and protection, acknowledging personal pain. A fierce declaration of exclusive, healing love that erases old hurts."}, {"mood": "Warm Embrace", "section": "Outro Hooks", "description": "The repeated, hopeful promise of unconditional love, a warm embrace sealing the deal as the rhythm softly fades."}], "headline": "The tender struggle to shed past scars, reaching for a future built on patience and fierce protection.", "key_lines": [{"line": "Ich versteh'' deinen Pain, deshalb werd'' ich mich ändern", "insight": "Understanding the weight of someone''s past pain is the catalyst for personal transformation."}, {"line": "You and I fought these feelings, I know", "insight": "The silent battle against undeniable connection, eventually surrendered."}, {"line": "You''re safe in my world / So open, let me dive in", "insight": "The ultimate reassurance of security, inviting complete vulnerability and trust."}, {"line": "I''m a gangster in love, baby, fight for us, ja", "insight": "A fierce, unexpected blend of loyalty and tenderness, ready to defend the relationship against all odds."}, {"line": "Komm, vergess jetzt dein''n Ex-Boyfriend / Ich geb'' dir mehr Love, Baby, lass es zu", "insight": "Directly confronting past baggage with an overwhelming offer of a better future."}], "compound_mood": "Pleading Affirmation", "sonic_texture": "A warm, pulsing reggae rhythm builds a foundation for layered vocals, smooth and direct. The bassline moves with a confident, swaying groove, while sparse instrumental touches keep the focus on the heartfelt delivery, creating a feeling of intimate conversation on a gentle breeze.", "audio_features": {"tempo": 115.02, "energy": 0.541, "valence": 0.359, "liveness": 0.0909, "loudness": -7.397, "speechiness": 0.0914, "acousticness": 0.321, "danceability": 0.9, "instrumentalness": 0.000363}, "interpretation": "The deep commitment to heal someone else''s past wounds by offering unwavering, patient love. It''s an insistence on showing up, changing habits, and protecting a fragile connection, even when it means confronting personal demons and societal pressures.", "mood_description": "A steady, warm pulse invites closeness, even as a lingering shadow of past hurts hangs in the air. There''s an undeniable pull to connect, but it''s tinged with the understanding that healing takes time."}', 'google:gemini-2.5-flash', '2', 4958, NULL, '2026-05-13 16:32:13.102873+00', '2026-05-13 16:32:13.102873+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('c69373cc-d5a0-4964-9c4b-37e037f37e83', 'c6fd26df-f154-44ba-8bbc-393ec344e9ea', '{"themes": [{"name": "instant magnetism", "description": "The undeniable, immediate pull towards someone upon first sight."}, {"name": "playful pursuit", "description": "A lighthearted, confident approach to wanting to get to know someone better."}, {"name": "physical infatuation", "description": "The strong, almost involuntary bodily reaction to a captivating presence."}], "journey": [{"mood": "Confident anticipation", "section": "[Intro]", "description": "A smooth, inviting opening, setting the stage for a moment about to unfold."}, {"mood": "Smooth approach", "section": "[Verse 1]", "description": "A confident invitation, quickly turning into a confession of intense, unprecedented attraction."}, {"mood": "Playful clarity", "section": "[Pre-Chorus]", "description": "Drawing a clear line between strong attraction and falling in love, while still making the admiration plain."}, {"mood": "Overwhelmed infatuation", "section": "[Chorus]", "description": "The moment of pure, involuntary physical reaction, where every detail of a person makes the heart pound wildly."}, {"mood": "Deeper marvel", "section": "[Verse 2]", "description": "The initial amazement solidifies into a desire for a deeper connection, still captivated by an almost unbelievable presence."}, {"mood": "Lingering exhilaration", "section": "[Outro]", "description": "The electrifying feeling of infatuation echoes, looping back to the initial jolt of attraction."}], "headline": "An instant, exhilarating infatuation, where every glimpse of someone new makes the heart jump out of rhythm.", "key_lines": [{"line": "Oh, I''ve wanted girls before, but never like this", "insight": "A moment of genuine surprise, recognizing a unique and powerful connection."}, {"line": "Now I''m not falling in love with you But I think that you are hot, shawty", "insight": "A blunt, honest declaration of physical desire that explicitly avoids deeper emotional commitment."}, {"line": "Baby girl, you got my heart ski-ski-skippin''", "insight": "The immediate, physical manifestation of intense attraction, a visceral jolt."}, {"line": "Maybe you''re just born with it, maybe it''s Maybelline", "insight": "A playful compliment, acknowledging captivating beauty while hinting at its elusive source."}, {"line": "I wanna get you in closer, I love to hear when you whisper All the things that you wanna hear", "insight": "A confident invitation for intimacy, promising to fulfill unspoken desires."}], "compound_mood": "Flirtatious Euphoria", "sonic_texture": "A vibrant, mid-tempo groove driven by a funky bassline and crisp, propulsive drums. Smooth, confident vocals glide over a clean, rhythmic backdrop, creating a danceable, hip-hop infused R&B sound that feels both polished and immediate.", "audio_features": {"tempo": 123.898, "energy": 0.65, "valence": 0.617, "liveness": 0.123, "loudness": -6.882, "speechiness": 0.216, "acousticness": 0.198, "danceability": 0.795, "instrumentalness": 0}, "interpretation": "The raw, immediate jolt of attraction that strikes without warning. It''s a feeling so powerful it takes over the body, causing a physical reaction that''s impossible to ignore, even as one tries to keep emotions in check. It''s less about a soulmate connection and more about the thrilling, almost primal pull of magnetic charisma.", "mood_description": "A surge of confident desire, wrapped in a smooth, irresistible groove. The rhythm pulls you in, making you feel the electric buzz of new attraction."}', 'google:gemini-2.5-flash', '2', 6619, NULL, '2026-05-13 16:32:22.340955+00', '2026-05-13 16:32:22.340955+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('754a26f2-3add-4996-a3be-0233a97297fe', '9b060221-3dd7-42fd-aa2b-5b11e84b62df', '{"headline": "It feels like a headlong rush into the night, everything around you a blur as you surge forward with unstoppable energy.", "compound_mood": "Jagged Exhilaration", "sonic_texture": "Two bright, electric guitars play off each other, one laying down a sharp, catchy rhythm while the other darts with crisp, clean licks. A thick, steady bassline holds it all together, perfectly meshed with the tight, driving drum beat that keeps everything flying forward.", "audio_features": {"tempo": 158.009, "energy": 0.649, "valence": 0.77, "liveness": 0.101, "loudness": -5.11, "speechiness": 0.0336, "acousticness": 0.000603, "danceability": 0.489, "instrumentalness": 0.713}, "mood_description": "You''re caught in a current of pure, restless drive, a thrilling rush that makes your heart pound. There''s a clear sense of going somewhere fast, without looking back."}', 'google:gemini-2.5-flash', '2', 2656, NULL, '2026-05-13 16:32:22.651455+00', '2026-05-13 16:32:22.651455+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('d0e95f58-a8b8-4500-8955-f87c03400fc1', '95f6304c-2ac0-4705-b89e-2f505c24061f', '{"themes": [{"name": "digital intimacy", "description": "Connecting through modern tech and music metaphors, where buttons are pushed and frequencies flow."}, {"name": "sensual control", "description": "Taking the lead in a shared physical experience, acting as the DJ of a private party."}, {"name": "private pleasure", "description": "Creating an exclusive, uninhibited space where desires can be fully expressed away from prying eyes."}, {"name": "rhythm of desire", "description": "The cyclical, insistent nature of longing, wanting to replay the best moments again and again."}], "journey": [{"mood": "Direct Anticipation", "section": "Intro", "description": "An immediate, direct call. Getting right to the point, no time for hesitation."}, {"mood": "Bold Invitation", "section": "Chorus", "description": "A bold, expansive invitation to fully immerse in a shared sensual experience. Every beat is a promise."}, {"mood": "Playful Seduction", "section": "Verse 1", "description": "A playful, intimate moment unfolding in private. The metaphors of a music player become increasingly suggestive, building towards a peak and a desire for endless replay."}, {"mood": "Deepening Connection", "section": "Verse 2", "description": "Deepening the connection, taking on the role of a personal DJ. It’s about guiding and sharing, ensuring uninhibited enjoyment with mature understanding."}, {"mood": "Public Declaration", "section": "Bridge", "description": "Shifting from private whispers to a public declaration of desire. A request for constant rotation, wanting to be heard and felt everywhere."}, {"mood": "Lingering Desire", "section": "Outro", "description": "The lingering echo of a fervent request. Fading out, but the desire remains on repeat."}], "headline": "A confident invitation to private ecstasy, where every beat pulses with pure desire.", "key_lines": [{"line": "''Cause baby girl, this is the music for love", "insight": "The declaration of a deep, all-encompassing connection, where every sound translates to pure affection."}, {"line": "Baby, come push my buttons, I''ll show you all my functions", "insight": "The playful, digital invitation to explore every facet of desire and intimacy."}, {"line": "After we done, hit rewind, and we''ll go back to the top", "insight": "A yearning for an endless cycle of pleasure, wanting to relive the best moments again and again."}, {"line": "Just as long as you sing in my microphone", "insight": "The cheeky demand for reciprocal passion and vocal participation in the shared experience."}, {"line": "Girl, we in heavy rotation, I''ll be all on your station", "insight": "The confident certainty of being a constant, desired presence in someone''s world."}], "compound_mood": "Sultry Invitation", "sonic_texture": "A slick, mid-tempo R&B groove built on a prominent, undulating bassline and crisp drum programming. Smooth synths provide a warm, inviting backdrop, while vocal harmonies glide effortlessly, creating a confident yet tender soundscape.", "audio_features": {"tempo": 123.431, "energy": 0.423, "valence": 0.466, "liveness": 0.209, "loudness": -5.855, "speechiness": 0.0451, "acousticness": 0.106, "danceability": 0.705, "instrumentalness": 0}, "interpretation": "Desire takes center stage, framed through the language of music and digital romance. The invitation is direct and confident, blurring the lines between physical intimacy and the immersive experience of a perfect song. It’s about being both the composer and the instrument, guiding a partner into a shared rhythm of pleasure and connection, where every touch and sensation is a note in a passionate melody. The playful innuendo masks a genuine craving for deep, repeatable, and uninhibited connection.", "mood_description": "A smooth, irresistible groove that pulls you into a private world of longing. The air hums with playful promises, everything building towards a shared, electric moment."}', 'google:gemini-2.5-flash', '2', 6435, NULL, '2026-05-13 16:32:23.864456+00', '2026-05-13 16:32:23.864456+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('32c4dbd5-06e5-4372-b045-5581ea23e5bb', '2956bd67-93c6-4518-8490-266c238f9275', '{"themes": [{"name": "self-inflicted wounds", "description": "Pushing someone away, then confronting the brutal emptiness left behind."}, {"name": "suffocating regret", "description": "The feeling of being unable to function or even breathe without a former partner."}, {"name": "misplaced confidence", "description": "Believing a relationship was secure, only to have that assumption shattered."}, {"name": "the dance of sorrow", "description": "A smooth rhythm that belies the deep emotional pain expressed in the lyrics."}], "journey": [{"mood": "Breathless plea", "section": "Intro", "description": "A stark question hangs in the air, a gasp of disorientation before the story even begins."}, {"mood": "Sinking realization", "section": "Verse 1 & Pre-Chorus", "description": "The feeling of life shifting, becoming unrecognizable without a loved one, acknowledging the irreversible mistake of pushing them away."}, {"mood": "Urgent longing", "section": "Chorus", "description": "The central cry, repeated and desperate, for guidance and air in a world suddenly dark and unlivable."}, {"mood": "Panic and disbelief", "section": "Verse 2", "description": "Losing grip on reality, facing the horror of being replaced and the crushing weight of a mistake too big to comprehend."}, {"mood": "Raw confession", "section": "Bridge", "description": "A moment of honest self-blame, admitting personal flaws and pleading for a return, revealing the full extent of the impact on their ability to cope."}, {"mood": "Lingering despair", "section": "Outro Chorus", "description": "The desperate questions echo and fade, leaving behind a persistent, unanswered ache."}], "headline": "The crushing weight of a love lost, leaving a hollow ache where life once pulsed.", "key_lines": [{"line": "How do I breathe?", "insight": "The physical manifestation of emotional collapse, where life itself feels impossible."}, {"line": "I don''t know why I let it go too far", "insight": "A moment of bewildered self-condemnation, grappling with the irreversible nature of a terrible choice."}, {"line": "Another dude is replacing me God this can''t be happening", "insight": "The visceral shock of realizing your irreplaceable role has been filled, adding insult to injury."}, {"line": "Girl I should''ve been right there", "insight": "The quiet agony of knowing exactly where you went wrong, a path not taken that haunts every step."}], "compound_mood": "Groovy Desperation", "sonic_texture": "A smooth, almost understated R&B groove built on a steady, danceable beat and subtle bassline. Soft synth layers and vocal harmonies create a warm, inviting space, even as the lead vocal carries a heavy heart.", "audio_features": {"tempo": 97.956, "energy": 0.455, "valence": 0.487, "liveness": 0.263, "loudness": -8.216, "speechiness": 0.0307, "acousticness": 0.215, "danceability": 0.684, "instrumentalness": 0.00000108}, "interpretation": "It''s the agonizing realization that you destroyed your own happiness. The smooth, R&B production creates a danceable backdrop, but the words lay bare a raw, gut-wrenching plea for a love that''s already slipped away, acknowledging total fault in the process. It''s about facing the consequences of pushing someone away, only to find yourself completely lost without them, even as the beat tries to keep you moving.", "mood_description": "A smooth, undeniable beat carries the heavy weight of regret. It''s moving your body while your heart feels stuck, wishing you could go back."}', 'google:gemini-2.5-flash', '2', 4894, NULL, '2026-05-13 16:33:17.822826+00', '2026-05-13 16:33:17.822826+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('2ae2afe0-d8c5-4528-9e41-f2554e4b5ac6', 'd48a505a-18ca-4dc2-9e7f-85eea5699876', '{"themes": [{"name": "unacknowledged chemistry", "description": "The conviction that a deeper connection exists, despite being told otherwise."}, {"name": "confident self-advocacy", "description": "Boldly listing one''s own virtues and challenging someone''s resistance."}, {"name": "the friend zone''s frustration", "description": "The emotional confinement of being relegated to platonic status when romantic feelings are strong."}, {"name": "relentless pursuit", "description": "A continuous, almost insistent effort to win over someone who remains hesitant."}], "journey": [{"mood": "playful invitation", "section": "Intro", "description": "A quick, playful invitation to step closer, setting the stage for what''s to come."}, {"mood": "eager interrogation", "section": "Verse 1", "description": "A rapid-fire list of desires, eager to know everything about someone just out of reach."}, {"mood": "frustrated plea", "section": "Chorus", "description": "The core frustration hits, a melodic yet direct protest against being kept at arm''s length, even as the beat keeps moving with hopeful energy."}, {"mood": "bold declaration", "section": "Bridge", "description": "A moment of exasperated confidence, listing all the reasons why this connection should be undeniable, challenging the resistance head-on."}, {"mood": "softened appeal", "section": "Breakdown", "description": "The music pulls back slightly, a vulnerable plea to acknowledge unspoken feelings and break down barriers, appealing to an undeniable shared truth."}, {"mood": "lingering desire", "section": "Outro", "description": "The main refrain repeats, slowly fading, leaving behind the lingering question of whether the message ever got through, still hopeful."}], "headline": "A smooth, persistent plea to break free from the friend zone, driven by a hopeful confidence that borders on exasperation.", "key_lines": [{"line": "But you''re tellin'' me I''m just a friend", "insight": "The sting of being defined by less than what you feel, a core conflict that drives the entire song."}, {"line": "''Cause I can be your fantasy", "insight": "The conviction of offering something truly special and desired, a bold statement of potential."}, {"line": "Oh, can you give me one reason why You wouldn''t want this kinda guy?", "insight": "A frustrated, confident challenge to a denial that makes no sense, demanding an explanation for the resistance."}, {"line": "Don''t fight the feeling that you feel I can tell that its real", "insight": "Appealing to a shared, unacknowledged truth, a final push for honesty and mutual recognition."}], "compound_mood": "Persistent Desire", "sonic_texture": "Smooth, mid-tempo R&B production with a bouncing, insistent bassline and crisp, driving drums. Clear, confident vocals glide over shimmering synths and subtle melodic flourishes, creating a sound that feels both polished and direct.", "audio_features": {"tempo": 132.346, "energy": 0.677, "valence": 0.913, "liveness": 0.236, "loudness": -6.099, "speechiness": 0.187, "acousticness": 0.00541, "danceability": 0.538, "instrumentalness": 0}, "interpretation": "It''s the determined pursuit of more than friendship, rooted in the absolute conviction that you''re the right person for someone who keeps you at a distance. The bright, confident sound highlights the protagonist''s self-assuredness, even as the lyrics lay bare a deep frustration with the ''just a friend'' label, making a bold case for undeniable chemistry.", "mood_description": "An upbeat R&B rhythm carries a direct, almost relentless questioning about a potential lover. The groove is light, but the heart of the vocal is heavy with a clear, unfulfilled want."}', 'google:gemini-2.5-flash', '2', 5104, NULL, '2026-05-13 16:33:19.19784+00', '2026-05-13 16:33:19.19784+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('c1b76f7d-f1e3-43bc-9014-651f5c286652', '2b705e75-f880-4ed4-9543-96e062756e23', '{"themes": [{"name": "redemptive choice", "description": "How past mistakes or confusion are redeemed by a clear, present commitment."}, {"name": "fated connection", "description": "The sense that this relationship was always meant to be, a destination after a long search."}, {"name": "unwavering support", "description": "A promise of constant presence and care, no matter what."}, {"name": "clarity in love", "description": "The transformative power of a specific person to bring understanding and purpose."}], "journey": [{"mood": "Reflective Opening", "section": "Intro", "description": "A quiet, heartfelt confession acknowledging past missteps and the preciousness of a present love, setting a sincere, almost vulnerable tone."}, {"mood": "Unfolding Realization", "section": "Verse 1", "description": "A steady build as past confusion gives way to sudden, powerful clarity, seeing everything clearly only upon finding the right person."}, {"mood": "Visionary Affirmation", "section": "Pre-Chorus", "description": "The feeling expands into a hopeful vision of a shared future, enduring all of life''s ups and downs with an unchanging bond."}, {"mood": "Unshakeable Commitment", "section": "Chorus", "description": "A vibrant, rhythmic declaration, repeating the central truth with assured confidence, offering constant presence and support."}, {"mood": "Universal Destiny", "section": "Bridge", "description": "Stepping back to a broader, almost spiritual perspective, finding a deeply desired ''fire'' and realizing a destined path led directly to this chosen person."}, {"mood": "Enduring Assurance", "section": "Outro", "description": "The core message repeats and echoes, fading with ad-libs, leaving a lingering sense of absolute, joyful certainty."}], "headline": "A joyful declaration of unwavering commitment, looking back on a journey of self-discovery and forward to an endless shared future.", "key_lines": [{"line": "Until the day I saw your face When I saw everything", "insight": "The world snapping into perfect focus, realizing a missing piece was found."}, {"line": "And I still saw us together at the end of every day, girl", "insight": "A comforting, unchanging vision of a future that feels inevitable and right."}, {"line": "You don''t have to dance alone, no", "insight": "A promise of steadfast companionship, always being there through life''s movements."}, {"line": "Through my desire, thank God I found the fire", "insight": "The relief of having a deep, burning longing finally fulfilled and reciprocated."}, {"line": "I choose you", "insight": "The simple, powerful act of conscious, continuous selection and dedication."}], "compound_mood": "Affirmative Devotion", "sonic_texture": "Smooth, mid-tempo R&B groove with a prominent, confident vocal. The production is sleek and polished, featuring warm bass lines and crisp drums, creating an inviting, danceable backdrop for a heartfelt declaration.", "audio_features": {"tempo": 90.107, "energy": 0.628, "valence": 0.708, "liveness": 0.0812, "loudness": -5.192, "speechiness": 0.0683, "acousticness": 0.0819, "danceability": 0.673, "instrumentalness": 0}, "interpretation": "This isn''t just a love song; it''s the profound clarity that comes with recognizing your true partner. It''s about overcoming past confusion and self-doubt, realizing that all previous experiences, even mistakes, were part of a journey leading to this singular, undeniable choice. The commitment isn''t born of desperation but from a deep, almost fated understanding of who you''re meant to be with, offering a sanctuary of unwavering support.", "mood_description": "A warm, steady groove washes over, making you feel chosen and secure. There''s a clear, bright affirmation pulsing through every beat, settling any past doubts with pure, committed joy."}', 'google:gemini-2.5-flash', '2', 5327, NULL, '2026-05-13 16:33:20.783204+00', '2026-05-13 16:33:20.783204+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('2e7b4e5a-eca4-44c7-aab9-7be24f3531a5', '1432b479-a957-46e7-88be-741e59f7c441', '{"themes": [{"name": "unconditional offer", "description": "Offering everything someone could want and need: good love and protection, a complete sense of care."}, {"name": "rescue fantasy", "description": "The belief that one can save another from their difficult choices and unhealthy relationship patterns."}, {"name": "unseen worth", "description": "Highlighting the inherent beauty and value in someone who seems to be unaware of their own deservingness."}, {"name": "bold declaration", "description": "A direct and confident statement of intent to provide a better, more fulfilling relationship."}], "journey": [{"mood": "Warm invitation", "section": "Intro", "description": "A gentle, wordless call setting a smooth and inviting tone, drawing you into a space of potential comfort."}, {"mood": "Frustrated observation", "section": "Verse 1", "description": "Watching someone endure heartbreak, confused and pained by their willingness to stay in a damaging situation."}, {"mood": "Promising devotion", "section": "Pre-Chorus", "description": "A direct comparison to a better, more committed love, painting a picture of unwavering loyalty and care."}, {"mood": "Urgent plea", "section": "Chorus", "description": "The central, insistent request to be allowed to provide the protective, fulfilling love that''s been missing."}, {"mood": "Earnest conviction", "section": "Bridge", "description": "Reiterating a belief in the person''s worth, emphasizing that they deserve more and questioning why a shared future isn''t already happening."}, {"mood": "Lingering promise", "section": "Outro", "description": "The core message fades softly, leaving behind the comforting thought that true love is the only thing needed."}], "headline": "A confident, heartfelt plea to save a love interest from a cycle of heartbreak, promising a love that truly sees and values them.", "key_lines": [{"line": "Baby, I just don''t get it, do you enjoy bein'' hurt?", "insight": "The painful confusion of watching someone you value choose their own suffering."}, {"line": "You''re the type of woman who deserves good things", "insight": "Recognizing an inherent value that goes unnoticed by the one who should cherish it most."}, {"line": "You should let me love you, love you, love you", "insight": "The intense, singular desire to prove a better kind of affection is possible."}, {"line": "You deserve better, girl", "insight": "A firm statement of worth, challenging the acceptance of less than what''s deserved."}, {"line": "Show you the way love''s supposed to be", "insight": "A bold claim to possess the blueprint for genuine, fulfilling partnership."}], "compound_mood": "Resolute Devotion", "sonic_texture": "Smooth, mid-tempo R&B groove with a warm, inviting bassline and gentle, echoing synths. Confident, clear vocals float over a steady, head-nodding beat, creating a sense of hopeful assurance.", "audio_features": {"tempo": 94.364, "energy": 0.593, "valence": 0.607, "liveness": 0.0979, "loudness": -8.352, "speechiness": 0.0916, "acousticness": 0.163, "danceability": 0.622, "instrumentalness": 0}, "interpretation": "Seeing someone you care for trapped in a cycle of mistreatment, and being absolutely convinced you hold the key to their happiness. It''s a bold intervention, not just an offer of love, but a declaration of superior affection and protection, positioning oneself as the undeniable solution to their emotional pain.", "mood_description": "A smooth, confident groove carries a message of unwavering care. It feels like a warm hand reaching out, offering a safe harbor from past storms."}', 'google:gemini-2.5-flash', '2', 4776, NULL, '2026-05-13 16:33:29.658283+00', '2026-05-13 16:33:29.658283+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('ec86d960-d583-4828-935b-ee963c1bd03f', 'db91bd71-10de-460c-91e0-c912a46b5975', '{"themes": [{"name": "unspoken pain", "description": "The ability to perceive someone''s distress and longing even when they don''t articulate it aloud."}, {"name": "protective desire", "description": "The strong impulse to shield a loved one from further emotional harm and offer a safe haven."}, {"name": "conflicted loyalty", "description": "Navigating the painful space of loving someone who''s already committed, feeling torn between their current bond and a wish for them to choose you."}, {"name": "redemptive offer", "description": "Presenting oneself as the solution and the path to healing after someone has experienced repeated hurt."}], "journey": [{"mood": "Playful Setup", "section": "Intro", "description": "A lighthearted, confident opening, setting the stage for a remix that promises a fresh take on a familiar story."}, {"mood": "Smooth Persuasion", "section": "Verse 1", "description": "A confident approach, quickly getting to the point and offering a clear alternative to a past full of disappointment, hinting at deep understanding of their struggles."}, {"mood": "Heartfelt Resonance", "section": "Chorus", "description": "The central emotional core bursts forth, a soulful declaration of hearing a quiet suffering and offering a direct invitation to be saved."}, {"mood": "Vulnerable Acknowledgment", "section": "Verse 2 & Pre-Chorus", "description": "Admitting to developing feelings through shared intimate moments, and confronting the difficult reality of seeing someone you care about hurting for another, even as your own desire grows louder."}, {"mood": "Direct Confession", "section": "Bridge", "description": "A moment of honesty, laying bare feelings that can no longer be hidden and presenting a direct, earnest offer to be the answer to their pain."}, {"mood": "Lingering Echo", "section": "Outro", "description": "The plea gently fades, leaving behind the repeated refrain of a heart''s silent cry, a persistent hope for rescue that hangs in the air."}], "headline": "A smooth, heartfelt intervention, offering solace to a silent plea.", "key_lines": [{"line": "Shawty like a valet service, I swear she been through a lot", "insight": "Recognizing a history of short-lived, unsatisfactory connections, seeing how past experiences have worn her down."}, {"line": "I listen to her heart beat because it plays my favorite song", "insight": "Finding profound connection and joy in someone''s core essence, seeing their inner truth as the most beautiful melody."}, {"line": "But I’m stuck in the middle of seein'' you hurt / I know when you love him, and you wanna make it work", "insight": "The painful trap of empathizing with someone''s struggle while silently wishing they would turn to you for comfort instead."}, {"line": "I just can’t keep lyin'' to myself / When you’re holdin'' me, I can feel your pain", "insight": "The undeniable truth of shared emotional burdens, where physical closeness only amplifies the depth of their suffering, making pretense impossible."}], "compound_mood": "Urgent Empathy", "sonic_texture": "A warm, mid-tempo R&B groove built on smooth, syncopated bass lines and crisp, hip-hop-influenced drums. Layered, soulful vocals weave between confident verses and earnest, harmonized pleas, creating a texture that feels both driven and emotionally resonant, with subtle synth accents.", "audio_features": {"tempo": 130.063, "energy": 0.72, "valence": 0.505, "liveness": 0.284, "loudness": -6.935, "speechiness": 0.0682, "acousticness": 0.196, "danceability": 0.509, "instrumentalness": 0}, "interpretation": "It''s about the deep-seated desire to rescue someone from a toxic relationship, hearing their unspoken pain and believing you hold the key to their happiness. The initial suave confidence from a friend offers a way out, evolving into a more vulnerable confession of feelings. Beneath the smooth exterior, there’s a genuine ache to provide comfort and a better love, even while respecting the other person''s lingering attachment to their current situation.", "mood_description": "A driving R&B beat pulses with a deep concern for someone hurting. You''re swept into a heartfelt plea to heal a pain that can no longer be ignored."}', 'google:gemini-2.5-flash', '2', 6771, NULL, '2026-05-13 16:33:37.639491+00', '2026-05-13 16:33:37.639491+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('983b8cd5-c7e4-4839-84ad-1a952748b2cc', '30093248-ddac-4a26-bda4-c6acc72622ef', '{"themes": [{"name": "adolescent bravado", "description": "The sheer audacity of youth, pushing boundaries with explicit confidence and a desire to prove capability beyond one''s years."}, {"name": "club seduction", "description": "The ritualized dance of attraction and pursuit in a nightclub setting, focused on physical appearance and immediate gratification."}, {"name": "transactional desire", "description": "Relationships and interactions framed by what one can ''get'' or ''do'' for another, rather than deeper emotional connection."}, {"name": "social maneuvering", "description": "Navigating friendships and group dynamics to facilitate romantic or sexual encounters."}], "journey": [{"mood": "Confident arrival", "section": "Intro: Juelz Santana", "description": "A commanding voice steps into the space, announcing a dominant presence and setting the scene for a night of assertive desires and big-boy moves."}, {"mood": "Immediate focus", "section": "Verse 1: Chris Brown", "description": "Attention locks onto someone across the room, an irresistible pull to approach and lay out a direct, unblushing proposition."}, {"mood": "The shared opportunity", "section": "Pre-Chorus & Chorus: Chris Brown", "description": "The group dynamic takes over, dissolving individual boundaries into a collective hunt for fun, culminating in a bold challenge to potential rivals and an invitation to engage."}, {"mood": "Undeniable allure", "section": "Verse 2: Chris Brown", "description": "A youthful voice brags about capabilities that defy expectations, promising experiences that transcend age, asserting an undeniable magnetism."}, {"mood": "Escalating intensity", "section": "Bridge & Verse 3: Chris Brown & Juelz Santana", "description": "The physical connection deepens, fueled by observations of movement and direct commands, drawing listeners into a swirling fantasy of mutual gratification and suggestive play, as the lyrics grow more explicit."}, {"mood": "Lingering swagger", "section": "Outro: Chris Brown, Juelz Santana", "description": "The energy coasts out on ad-libs and confident exclamations, leaving behind the echo of a night that delivered on its promise of bold encounters and effortless cool."}], "headline": "A bold declaration of youthful desire, masked by an almost arrogant confidence that subtly hints at deeper, unacknowledged longings.", "key_lines": [{"line": "I know what girls want (Want) / I know what they like (Like)", "insight": "A self-assured declaration of understanding desire, even if it''s narrowly focused on immediate pleasure."}, {"line": "Don''t believe my age is gonna slow us down / I can definitely show you things / To have you sayin'' I can''t be sixteen", "insight": "Defiance of youthful limitations, asserting a maturity and capability far beyond expectations."}, {"line": "Is ya man (Man) on the floor? (Floor) / If he ain''t (Ain''t), lemme know (Know)", "insight": "A direct, almost confrontational challenge to availability, cutting straight to the chase with unwavering confidence."}, {"line": "Plus I heard if you can dance, you can bump", "insight": "A bold and common assumption, linking physical grace on the dance floor to intimate prowess."}, {"line": "Wait ''til you see my ayy! / Wait ''til you see my ayy!", "insight": "A suggestive tease, building anticipation for something unseen and potentially scandalous, playfully censored."}], "compound_mood": "Cocky Disconnect", "sonic_texture": "A confident hip-hop beat drives a smooth R&B groove, propelled by a walking bassline and crisp, snapping drums. Bright, clean synths provide a cool, almost understated backdrop, while vocal harmonies layer together with confident rap verses, creating a sleek, club-ready sound that prioritizes rhythm and understated swagger.", "audio_features": {"tempo": 100.969, "energy": 0.482, "valence": 0.212, "liveness": 0.393, "loudness": -6.721, "speechiness": 0.129, "acousticness": 0.0246, "danceability": 0.846, "instrumentalness": 0}, "interpretation": "This isn''t just a party anthem; it''s a bold declaration of youthful desire, wrapped in a confidence that borders on arrogance, where every interaction feels like a calculated move. The insistent pursuit of physical connection and social validation drives the narrative, yet an intriguing emotional distance in the music suggests this relentless chase for fleeting pleasure might leave one feeling unexpectedly empty or unfulfilled. It paints a picture of knowing what you want and aggressively going for it, but perhaps not fully understanding the cost or the deeper desires beneath the surface.", "mood_description": "The beat glides with a cool, head-nodding rhythm, building an atmosphere of smooth confidence. Yet, an undercurrent of something less bright pulses beneath, hinting at a hollowness in the relentless pursuit of surface-level thrills."}', 'google:gemini-2.5-flash', '2', 7971, NULL, '2026-05-13 16:33:59.797894+00', '2026-05-13 16:33:59.797894+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('d2403c67-c260-4988-b383-f0a52eb09f3e', '56deccb9-466d-4161-b74f-ecb19f648d97', '{"themes": [{"name": "absolute devotion", "description": "The complete surrender of oneself to another, finding everything needed in that person."}, {"name": "shared euphoria", "description": "The belief that this intense, joyful love is a universal experience, shared by others globally."}, {"name": "material irrelevance", "description": "The conviction that true love outweighs any material wealth or possessions."}], "journey": [{"mood": "Urgent Yearning", "section": "Intro", "description": "A repeated call for connection, a foundational need echoing globally before the story even begins."}, {"mood": "Awed Admiration", "section": "Verse 1", "description": "Spotlighting a perfect partner, every detail a reason for profound gladness and a world-stopping gaze."}, {"mood": "Unwavering Pledge", "section": "Pre-Chorus", "description": "Stripping away material desires, a promise of absolute devotion, where everything is found in the other."}, {"mood": "Soaring Affirmation", "section": "Chorus", "description": "The feeling explodes into a universal declaration of love, a joyful recognition that this intense connection can''t be unique."}, {"mood": "Undying Loyalty", "section": "Bridge", "description": "A dramatic escalation of commitment, declaring the partner as life itself, with a return to the intro''s global cry for connection."}, {"mood": "Deepening Embrace", "section": "Outro", "description": "The chorus repeats, stretching out the feeling, soaking in the complete, all-encompassing joy of being with that person."}], "headline": "The dizzying rush of new love, declaring absolute devotion and hoping everyone else feels this intensely too.", "key_lines": [{"line": "If I got you, I don''t need money, I don''t need cars Girl, you''re my all", "insight": "The ultimate reordering of priorities, where material wealth pales next to emotional fulfillment."}, {"line": "You''re like Jordan''s on Saturday", "insight": "The excitement of something eagerly awaited, a prized possession that you just have to have."}, {"line": "I will never try to deny that you are my whole life ''Cause if you ever let me go, I would die", "insight": "The intensity of absolute dependence, where love becomes the very breath of existence."}], "compound_mood": "Earnest Infatuation", "sonic_texture": "A smooth, mid-tempo R&B groove driven by a strong, understated bassline and gentle, flowing synths. Warm, layered vocal harmonies drift over a steady, unhurried drum beat, creating an an inviting and emotionally rich atmosphere.", "audio_features": {"tempo": 86.009, "energy": 0.693, "valence": 0.655, "liveness": 0.145, "loudness": -4.298, "speechiness": 0.0698, "acousticness": 0.134, "danceability": 0.662, "instrumentalness": 0}, "interpretation": "The overwhelming joy and certainty found in a new, profound romantic connection makes everything else irrelevant. There''s a hopeful desire for this feeling to be universal, a shared experience across the world.", "mood_description": "A smooth, pulsing beat underpins a heartfelt declaration, creating a sense of buoyant anticipation and deep connection. It feels like floating in a moment of pure adoration."}', 'google:gemini-2.5-flash', '2', 5084, NULL, '2026-05-13 16:34:45.749043+00', '2026-05-13 16:34:45.749043+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('4a395923-9c2f-4acc-94fb-03ea31b7230b', '9e44241a-1011-4618-891f-5d8c8f70311c', '{"themes": [{"name": "lingering possessiveness", "description": "The feeling that what was once yours should remain yours, even after a breakup."}, {"name": "unresolved grief", "description": "The inability to move past the pain of a lost relationship, constantly replaying what happened."}, {"name": "futile effort", "description": "The crushing realization that all the effort put into a relationship can simply vanish or be transferred."}, {"name": "haunted by the past", "description": "When memories and the person you once loved intrude on new experiences and relationships."}], "journey": [{"mood": "Conflicted haze", "section": "Verse 1", "description": "A restless mind struggles with the aftermath of a breakup, the lines between past and present blurring into a jaded confusion."}, {"mood": "Sinking realization", "section": "Pre-Chorus", "description": "The stark question of whether all the shared effort was just destined to fade, watching a prepared partner walk away."}, {"mood": "Obsessive reckoning", "section": "Chorus", "description": "A torrent of questions spills out, demanding to know who''s now receiving the love, time, and intimacy that once belonged to them, the pain of those ''residuals'' taking its toll."}, {"mood": "Bitter acceptance", "section": "Verse 2", "description": "A brief moment of clarity arrives, acknowledging mutual differences and the blindness of love, but the underlying pain still stings."}, {"mood": "Echoing ache", "section": "Chorus (reprise)", "description": "The same desperate questions resurface, amplifying the frustration and the heavy weight of what was lost, stuck in a loop of possessive grief."}, {"mood": "Fading fixation", "section": "Outro", "description": "The questions about ''residuals'' repeat, slowly dissolving into the music, leaving a lingering sense of loss and unanswered yearning."}], "headline": "A desperate tally of what was lost, watching fragments of a past love transfer to someone new.", "key_lines": [{"line": "Did we build it up, build it upJust to let it wash away?", "insight": "The crushing weight of effort poured into something inherently fragile."}, {"line": "Wasted on my mind, she''s still on my mind", "insight": "The maddening inability to reclaim mental space from an absent presence."}, {"line": "Better not give him my nickname", "insight": "A fierce, petty demand to protect the intimate, small details of a shared past."}, {"line": "All of that used to be mine, oh", "insight": "The raw, possessive ache of seeing shared history become someone else''s present."}, {"line": "Who''s gettin'' all of my residuals?", "insight": "The haunting question of who inherits the emotional aftershocks and leftover pieces of a shattered connection."}], "compound_mood": "Possessive Melancholy", "sonic_texture": "A velvety, melancholic R&B groove built on a smooth, persistent beat and deep bass. Warm, layered synth pads create a haze, while the vocals float with a bruised, yearning quality, often doubling for a fuller, more aching sound.", "audio_features": {"tempo": 114.905, "energy": 0.645, "valence": 0.171, "liveness": 0.108, "loudness": -7.793, "speechiness": 0.0821, "acousticness": 0.342, "danceability": 0.58, "instrumentalness": 0}, "interpretation": "The agonizing struggle to truly let go of a past love, especially when you feel a sense of ownership over the intimacy and effort poured into it. It''s the unique sting of imagining someone else benefiting from the lessons and love you once gave, creating a possessive grief that''s hard to shake.", "mood_description": "A heavy sadness hangs over a smooth, head-nodding beat. It feels like you''re caught in a loop of regret, trying to move on but still fixated on what you lost."}', 'google:gemini-2.5-flash', '2', 5255, NULL, '2026-05-13 16:34:49.062196+00', '2026-05-13 16:34:49.062196+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('b63daafb-f20b-47af-b877-b60e350c890f', '765811f0-f38a-46b1-8a4d-4d0128c01a44', '{"themes": [{"name": "transactional romance", "description": "Love is presented with a clear understanding of value, status, and the exchange of lavish gifts for loyalty."}, {"name": "possessive attraction", "description": "A powerful desire to claim and keep someone, seeing them as a prize to be won and protected from others."}, {"name": "self-assured seduction", "description": "Confidence in one''s ability to attract and secure a partner, presented with smooth words and an aura of effortless charm."}, {"name": "past baggage", "description": "The lingering presence of previous relationships and ''stupid exes'' shapes the new dynamic, requiring a clear declaration of dominance."}], "journey": [{"mood": "Raw anticipation", "section": "Intro", "description": "A sampled voice cuts through, a stark, almost desperate yearning for one last indulgence, shadowed by the consequences it might bring."}, {"mood": "Smooth appraisal", "section": "Drake''s observation", "description": "A cool, assessing eye takes in her independent spirit, her lavish lifestyle, and the attention she commands, a recognition of what makes her desirable."}, {"mood": "Confident offer", "section": "Chris Brown''s pledge", "description": "The smooth talk continues, moving towards a clear proposition: tired of games, offering stability and devotion, ready to claim her fully."}, {"mood": "Protective possessiveness", "section": "Asserting dominance", "description": "Any lingering doubts are dismissed, as past lovers are warned off, and a new, unwavering presence asserts its right to her undivided attention."}, {"mood": "Complex allure", "section": "Mutual understanding", "description": "The initial pursuit evolves into a recognition of her wilder side, an intriguing challenge, as he hints at his own past while expressing a desire to commit, but with a wary ''take it easy on me''."}, {"mood": "Soft fade", "section": "Lingering echo", "description": "The confident pronouncements gently dissolve, leaving a soft echo of the desires and hesitations that shape this complex connection."}], "headline": "A glossy seduction, where lavish promises barely conceal a deeper, almost transactional longing for control.", "key_lines": [{"line": "Before I die, I''m tryna fuck you, babyHopefully, we don''t have no babies", "insight": "A raw, immediate hunger for pleasure, tinged with a detached awareness of potential consequences."}, {"line": "Flew the coop at seventeen, no guidance", "insight": "A history of fierce independence, navigating the world on her own terms, making her intriguing and perhaps untamable."}, {"line": "Fuck around, give you my last name", "insight": "An offer of ultimate commitment, a clear signal to end the chase and settle into something serious."}, {"line": "All you need is me playin'' on your playlist", "insight": "A confident declaration of singular devotion, positioning himself as the only necessary companion and emotional anchor."}, {"line": "I can tell you crazy, but shit kind of intrigue me", "insight": "An acknowledgement of her challenging nature, which only deepens his fascination rather than deterring it."}], "compound_mood": "Slick Pursuit", "sonic_texture": "A smooth, laid-back R&B groove built on a deep, resonant bass and crisp, understated drums, with ethereal vocal samples weaving through minimal synth textures, creating a cool and confident flow.", "audio_features": {"tempo": 92.928, "energy": 0.454, "valence": 0.136, "liveness": 0.155, "loudness": -6.756, "speechiness": 0.153, "acousticness": 0.123, "danceability": 0.696, "instrumentalness": 0}, "interpretation": "Securing a prized partner becomes a subtle power play, where promises of loyalty are intertwined with an implicit challenge to past relationships and a desire to ''lock down'' someone who''s proven independently capable. There''s a confident offer of commitment, but it comes with a cool awareness of the game being played, not a vulnerable surrender.", "mood_description": "A smooth, confident groove carries you along, but beneath the surface, there''s a cool detachment, a sense of calculated moves rather than raw passion."}', 'google:gemini-2.5-flash', '2', 6979, NULL, '2026-05-13 16:34:52.658695+00', '2026-05-13 16:34:52.658695+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('439142aa-93aa-42eb-b820-a7af293218b4', 'cabeddd4-2218-47ca-89ea-5e5c679bbc61', '{"themes": [{"name": "eternal present", "description": "The desire to make a singular, perfect moment last forever, even if it''s confined to one night."}, {"name": "dancefloor romance", "description": "How physical connection and shared energy on a dancefloor can feel like the beginning of something profound."}, {"name": "intense infatuation", "description": "The overwhelming feeling of being captivated by someone, where everything else fades away."}, {"name": "shared ecstasy", "description": "The pursuit of a mutual, exhilarating experience that transcends the everyday."}], "journey": [{"mood": "Playful invitation", "section": "Intro", "description": "A light count-in opens the space, drawing you into a shimmering, hopeful anticipation."}, {"mood": "Building intensity", "section": "Verse 1", "description": "A direct address beckons you closer, promising a swift journey into shared rapture on the dancefloor."}, {"mood": "Limitless exhilaration", "section": "Chorus", "description": "The core desire explodes, echoing the wish for an endless dance that will span a lifetime, all packed into one night."}, {"mood": "Deepening connection", "section": "Verse 2", "description": "Confidence takes over, inviting trust and a feeling of becoming intertwined, pushing past boundaries together."}, {"mood": "Soaring devotion", "section": "Bridge", "description": "The connection lifts off the ground, becoming something almost sacred, a powerful promise not to let go."}, {"mood": "Lingering dream", "section": "Outro", "description": "The energy gently recedes, leaving behind the echo of forever as the night''s magic slowly fades."}], "headline": "A rush of infatuation on a pulsing dancefloor, clinging to an eternal moment that can only exist tonight. It''s a promise of forever, distilled into a single, exhilarating connection.", "key_lines": [{"line": "It''s like I''ve waited my whole life (Oh) for this one night (Oh)", "insight": "The singular focus on a moment so perfect it feels destined, even if it''s fleeting."}, {"line": "Double your pleasure, double your fun", "insight": "A catchy, almost commercialized declaration of amplified joy, hinting at a manufactured perfection."}, {"line": "We can be two rebels Breaking the rules, me and you, you and I", "insight": "The shared defiance and unique bond forged in the heat of the moment."}, {"line": "I''m releasing my heart and it''s feeling amazing", "insight": "The pure, unburdened joy of surrendering to new love."}, {"line": "I won''t let you fall, girl (Fall, girl), let you fall, girl, oh", "insight": "A protective instinct emerges, solidifying the emotional weight of the connection."}], "compound_mood": "Euphoric Urgency", "sonic_texture": "A bright, propulsive pulse drives everything forward, layered with shimmering synthesizers and a deep, infectious bassline. The vocals soar over the precise, electronic drums, creating a feeling of effortless, high-energy movement.", "audio_features": {"tempo": 120.005, "energy": 0.82, "valence": 0.438, "liveness": 0.184, "loudness": -4.456, "speechiness": 0.0459, "acousticness": 0.0368, "danceability": 0.672, "instrumentalness": 0.000188}, "interpretation": "It''s about the intense, all-consuming feeling of finding someone who makes a single night feel like an eternity. There''s a hopeful desperation to stretch a fleeting, perfect connection into something lasting, all played out against the backdrop of a vibrant, shared experience. The focus isn''t on a future together, but on solidifying an immediate, profound bond within a moment that feels too good to end.", "mood_description": "A wave of electric romance crashes over a relentless beat. Every pulse of the music pulls you deeper into an exhilarating, endless present."}', 'google:gemini-2.5-flash', '2', 5759, NULL, '2026-05-13 16:35:00.875983+00', '2026-05-13 16:35:00.875983+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('9f1cdff6-00a8-4aa2-a3c8-ffe919ab39c8', 'cb5073d0-a492-452d-be2c-aa6622e299dc', '{"themes": [{"name": "healing and spirituality", "description": "Seeking divine signs and spiritual energy for inner peace and recovery from past wounds."}, {"name": "street code and survival", "description": "The harsh realities of loyalty, enemies, and maintaining respect in a challenging environment."}, {"name": "anxiety and pressure", "description": "The constant internal struggle with fear, paranoia, and the external expectations of fame and lifestyle."}, {"name": "personal growth and fatherhood", "description": "Acknowledging past wrongs and looking toward a future of stability, marked by having children and learning life''s lessons."}], "journey": [{"mood": "Lost Longing", "section": "Angel Numbers (Verse & Chorus)", "description": "Feeling adrift in a vast, lonely space, haunted by past mistakes and tragedies, desperately wishing for a touch of grace and healing from above."}, {"mood": "Rising Tension", "section": "Transition (Intro to Ten Toes)", "description": "A sudden shift, an internal warning against letting pressure take over, preparing to face a confrontational world head-on."}, {"mood": "Hardened Resolve", "section": "Ten Toes (Verse 1)", "description": "Stepping out with heavy confidence, acknowledging the weight of success and the enemies it creates, holding onto faith while moving strategically."}, {"mood": "Anxious Defiance", "section": "Ten Toes (Chorus)", "description": "Welcoming challenges head-on, pleading for protection, but confessing a hidden paranoia and an internal battle with anxiety while maintaining a tough exterior."}, {"mood": "Reflective Growth", "section": "Ten Toes (Verse 2)", "description": "Recounting past relationships and sacrifices made for the game, now seeking stability and family, understanding life''s lessons amidst the grind."}, {"mood": "Lingering Echo", "section": "Outro", "description": "The assertive stance softens into a quiet, determined echo, a final urge to fight for what truly matters."}], "headline": "A fragmented plea for divine intervention, wrestling with inner demons and the relentless grind of street survival.", "key_lines": [{"line": "I lost my way, somewhere in another galaxy (''Xy)", "insight": "The profound isolation that comes from drifting far from a grounded self, feeling utterly disconnected."}, {"line": "When it''s 11:11, I need it", "insight": "A quiet, urgent plea for a cosmic intervention when all other avenues feel exhausted, hoping for a sign."}, {"line": "Mama, pray for me so I won''t fold (Fold)", "insight": "The vulnerable admission that beneath the tough exterior, there''s a deep fear of breaking under relentless pressure."}, {"line": "I be paranoid, but nobody knows (Woah)", "insight": "The heavy burden of an internal struggle, carefully hidden behind a facade of strength and composure."}, {"line": "Walkin'' in Giuseppe, I be ten on my toes", "insight": "A declaration of unwavering commitment and readiness, dressed in the symbols of hard-won success."}], "compound_mood": "Anxious Resilience", "sonic_texture": "A hazy, melancholic R&B soundscape in the first half, characterized by subtle synth washes and a searching vocal. This shifts into a heavier hip-hop beat with a persistent, driving rhythm, underpinned by dark, resonant bass and assertive vocal delivery, creating a feeling of simmering tension and street grit.", "audio_features": {"tempo": 157.984, "energy": 0.5, "valence": 0.0905, "liveness": 0.175, "loudness": -8.452, "speechiness": 0.0501, "acousticness": 0.192, "danceability": 0.406, "instrumentalness": 0}, "interpretation": "The track explores the heavy toll of past mistakes and public scrutiny, split between a yearning for spiritual healing and a gritty determination to survive street politics and personal anxieties. It''s a journey from vulnerability and a search for divine intervention to a hardened resolve to stand firm despite paranoia and relentless pressure.", "mood_description": "The sound pulls between desperate longing for healing and a hard-edged assertion of strength. It feels like navigating a chaotic world with a heavy heart, searching for a sign while battling internal and external pressures."}', 'google:gemini-2.5-flash', '2', 5641, NULL, '2026-05-13 16:35:03.142733+00', '2026-05-13 16:35:03.142733+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('33c71b83-8679-4d4c-985b-ec4aa754e471', '23aa3fc3-29c0-4443-acb2-2f540506a9bb', '{"themes": [{"name": "escapism", "description": "Finding refuge from reality through substances and intense physical encounters."}, {"name": "physical obsession", "description": "A singular, overwhelming focus on the partner''s body and the sensations it provides."}, {"name": "blurred lines", "description": "The influence of drugs making it hard to distinguish between genuine emotion and induced sensation."}, {"name": "control and abandon", "description": "A desire to dominate and possess, even while surrendering to the influence of others and substances."}], "journey": [{"mood": "Confident Swagger", "section": "Intro", "description": "A confident swagger emerges from the production tag, setting a sleek, almost nonchalant tone for what''s to come."}, {"mood": "Sedated Confession", "section": "Verse 1", "description": "A confession of being deep in a haze, battling lethargy from substances but still trying to chase a feeling."}, {"mood": "Hypnotic Pull", "section": "Pre-Chorus & Chorus", "description": "The partner''s undeniable pull takes over, a hypnotic focus on their body as the only clear thing in a blur."}, {"mood": "Escalating Desire", "section": "Verse 2", "description": "Desires escalate, pushing boundaries into explicit fantasies of control and capturing extreme intimacy."}, {"mood": "Lingering Haze", "section": "Outro", "description": "The haze returns, lingering and cyclical, with the same seductive invitation fading into the distance."}], "headline": "Dancing through a chemical fog, seeking an escape in every touch.", "key_lines": [{"line": "I don''t know why this shit got me lazy right now, yeah", "insight": "The contradiction of wanting to live it up, but being too sedated to fully engage."}, {"line": "Your body lightweight, speaks to me", "insight": "The profound, almost spiritual connection felt purely through physical presence."}, {"line": "Make you tattoo my name on it", "insight": "The ultimate declaration of ownership, even if it''s a fleeting desire born from influence."}, {"line": "Let''s GoPro and make a video, yeah", "insight": "Turning intimacy into a spectacle, capturing a moment of extreme passion as a lasting record."}], "compound_mood": "Seductive Detachment", "sonic_texture": "A slick, liquid R&B groove built on a deep, pulsing bassline and precise, snapping drums. Synths shimmer with a hazy, almost disorienting glow, while the vocals glide over the top, smooth and effortless.", "audio_features": {"tempo": 116.931, "energy": 0.562, "valence": 0.368, "liveness": 0.18, "loudness": -8.947, "speechiness": 0.0355, "acousticness": 0.0186, "danceability": 0.755, "instrumentalness": 0.000231}, "interpretation": "Pushing for ultimate physical connection and wild experiences, all while suspended in a drug-induced haze. It''s a chase for intensity, maybe to feel anything at all, or to distract from something unspoken beneath the surface.", "mood_description": "A slick, undeniable groove pulls you in, but underneath the surface, there''s a heavy sense of emotional distance and blurred reality."}', 'google:gemini-2.5-flash', '2', 4958, NULL, '2026-05-13 16:35:17.00601+00', '2026-05-13 16:35:17.00601+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('7c943d1d-d16b-446d-895c-bde5c886af0c', '08868bc3-2e95-42de-9fe7-175badd0835e', '{"themes": [{"name": "possessive longing", "description": "An inability to let go of a past relationship, marked by jealousy and a sense of ownership."}, {"name": "performative bravado", "description": "Hiding vulnerability and pain behind a facade of confidence, sexual conquest, and lavish partying."}, {"name": "emotional escapism", "description": "Using nightlife and new flings as a way to avoid confronting deeper feelings of loss and insecurity."}, {"name": "fragmented identity", "description": "The jarring shift between an aggrieved, heartbroken persona and a confident, almost aggressive, party-goer, suggesting a lack of integration."}], "journey": [{"mood": "Defeated and possessive", "section": "Opening Confession", "description": "A soul trapped in the past, endlessly scrolling, haunted by a lost connection while resentment simmers."}, {"mood": "Aggressive resentment", "section": "Jealous Threat", "description": "Turning from introspection to outward aggression. The fear of another''s intimacy morphs into a stark warning, a territorial claim on what was once theirs."}, {"mood": "Abrupt change", "section": "Sudden Shift", "description": "A beat drops, erasing the past. The scene instantly changes, leaving behind the bitterness for pure, unadulterated club energy and a hungry gaze across the room."}, {"mood": "Confident and unapologetic", "section": "Pure Seduction", "description": "Moving through the night with a predatory charm, focused solely on the intoxicating thrill of new pursuit."}, {"mood": "Uninhibited pleasure", "section": "Hedonistic Release", "description": "The ultimate surrender to the moment. All thoughts of the past are drowned out by loud music, lavish spending, and the aggressive pull of the dance floor."}], "headline": "A desperate plea for a lost connection swallowed whole by the neon-lit bravado of a wild night out.", "key_lines": [{"line": "Después que te fuiste de mi vida Me la paso jangueando con—, pero mirando mi cel", "insight": "Stuck in a loop of supposed moving on, unable to resist checking in on the one that got away."}, {"line": "Ya no me quedo tranquilo ni con la Percocet", "insight": "The desperation to find peace, resorting to extreme measures, and still failing."}, {"line": "Dile que se tiene que cuidar Porque la calle es mía y le vamo'' a bajar", "insight": "A dark warning, staking a claim on territory and threatening anyone who might cross it."}, {"line": "Bebé, ¿qué hacemos? Ese culo en la disco no cabe", "insight": "A sudden, complete pivot to confident, uninhibited desire, a world away from the previous anguish."}, {"line": "Vine solo y contigo me envolví \"Esa gata me la llevo\" dije cuando te vi", "insight": "The thrill of the hunt and the certainty of conquest, a fresh start under different pretenses."}], "compound_mood": "Obsessive Euphoria", "sonic_texture": "A thick, driving reggaeton pulse with a deep, rubbery bassline and crisp, snapping percussion that pushes the rhythm forward. There are hints of darker, almost metallic synth textures weaving through the bright, confident vocal delivery, creating a high-energy yet slightly aggressive club atmosphere.", "audio_features": {"tempo": 87.063, "energy": 0.557, "valence": 0.711, "liveness": 0.154, "loudness": -5.466, "speechiness": 0.204, "acousticness": 0.0358, "danceability": 0.651, "instrumentalness": 0}, "interpretation": "This is really about the fragmented self when dealing with heartbreak and an inflated ego. One moment, there''s a raw, possessive ache for a lost love, filled with jealousy and vulnerability, even threats. The next, it''s a defiant projection of carefree hedonism and sexual conquest, a desperate attempt to outrun the pain through performative confidence. The production, with its high energy and danceability, mostly embodies this escape, hinting at the intoxicating power of superficial distraction over unresolved feelings.", "mood_description": "Two distinct energies clash, one pulling you into a spiral of possessive longing, the other pushing you onto a dance floor pulsating with confident, unrestrained desire. It feels like a chaotic internal battle set to an irresistible beat."}', 'google:gemini-2.5-flash', '2', 5671, NULL, '2026-05-13 16:35:19.987139+00', '2026-05-13 16:35:19.987139+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('be557e24-11a5-47c7-a717-a224e94f4f74', 'f0a672ef-52e2-48c9-8f0a-c2a2d67b1bdb', '{"headline": "Stepping into a vibrant, sunlit space where everything feels possible.", "compound_mood": "Exuberant Pulse", "sonic_texture": "A steady, intricate beat drives the sound forward, layered with bright, echoing melodies that feel both warm and clear. Organic percussion elements weave in and out, creating a rich, flowing fabric. Subtle vocal textures appear occasionally, adding a human touch without any actual words, blending into the instrumental tapestry.", "audio_features": {"tempo": 69.039, "energy": 0.73, "valence": 0.869, "liveness": 0.131, "loudness": -7.442, "speechiness": 0.112, "acousticness": 0.536, "danceability": 0.508, "instrumentalness": 0.00112}, "mood_description": "A vibrant energy lifts your spirits, making your body want to sway. You feel light and full of a happy eagerness, like sunshine soaking into your skin."}', 'google:gemini-2.5-flash', '2', 2539, NULL, '2026-05-13 16:35:44.698822+00', '2026-05-13 16:35:44.698822+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('22d8d3ef-e917-4f6d-a97f-385a54dd8768', '4af11b64-c071-4feb-bcae-4554dccbdb7a', '{"themes": [{"name": "public shaming", "description": "A relentless, repetitive attack on an individual, turning personal scorn into a communal chant."}, {"name": "collective release", "description": "The energy of shared animosity transforms into an exhilarating, danceable freedom."}, {"name": "petty grievances", "description": "The triviality of the insults contrasted with the song''s intense energy."}, {"name": "performative anger", "description": "A show of outrage where the performance itself, rather than the reason for it, becomes the point."}], "journey": [{"mood": "Urgent anticipation", "section": "Intro", "description": "A stark countdown kicks off a tense, building energy, hinting at the storm about to break."}, {"mood": "Repetitive accusation", "section": "Verse 1", "description": "The target is named, repeatedly branded with simple, aggressive labels, a relentless mantra of rejection setting the tone."}, {"mood": "Collective declaration", "section": "Chorus", "description": "The core message explodes into a chant, a unified shout that solidifies the confrontational spirit, demanding participation."}, {"mood": "Escalating derision", "section": "Verse 2", "description": "The insults pile higher, becoming more specific and petty, adding layers to the communal scorn with each rhythmic jab."}, {"mood": "Bizarre escalation", "section": "Verse 3", "description": "The taunts take a strange, almost surreal turn, introducing a wild accusation and a command to freeze, pushing the frenetic energy into an even weirder space."}, {"mood": "Drowning chant", "section": "Outro", "description": "The chorus repeats, a final, unyielding wave of condemnation washing over everything, fading out with the last echoes of the collective cry."}], "headline": "A gleeful, relentless shaming, turning public scorn into a celebratory dance.", "key_lines": [{"line": "No sex, no sex for Ben Rymer now", "insight": "The ultimate social banishment, stripping away a fundamental aspect of human connection and status."}, {"line": "Lookin'' like a poor man''s Arthur Baker now", "insight": "A deep cut, implying not just a failure but a pathetic imitation, a lack of originality and substance."}, {"line": "Try to snatch the kitty off his girlfriend''s mother", "insight": "An absurd and shocking accusation designed to provoke maximum disgust and completely delegitimize the target."}], "compound_mood": "Frenzied Scorn", "sonic_texture": "A relentless, driving pulse of electronic drums and a throbbing bassline create an instant dancefloor urgency. Sharp, echoing guitars cut through the mix, while the vocals are delivered in a half-shouted, chant-like style, all wrapped in a loud, raw energy that feels both primal and tightly controlled.", "audio_features": {"tempo": 101.327, "energy": 0.948, "valence": 0.932, "liveness": 0.298, "loudness": -4.322, "speechiness": 0.117, "acousticness": 0.02, "danceability": 0.702, "instrumentalness": 0.00248}, "interpretation": "This isn''t just an insult; it''s a spectacle. The relentless, almost absurd shaming of \"Ben Rymer\" becomes a vehicle for pure, unadulterated release. It''s the primal satisfaction of a shared grievance exploding onto the dancefloor, where the target''s humiliation fuels an electrifying, collective joy. The sharp, cutting words are wrapped in a sound that makes you want to move, showing how easily anger can transform into a kind of twisted euphoria when it finds a rhythm.", "mood_description": "Relentless energy builds into a chant, pulling you into a swirling vortex of shared disdain. It''s the electric thrill of a public shaming you can dance to."}', 'google:gemini-2.5-flash', '2', 5316, NULL, '2026-05-17 09:57:20.547304+00', '2026-05-17 09:57:20.547304+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('3f1c5b9c-09f4-402a-b7fe-faa8ac2dcba2', '2ff01db8-fe2c-4b41-a96d-4004a280207d', '{"themes": [{"name": "ephemeral comfort", "description": "Finding fleeting relief and safety in the embrace of another person."}, {"name": "universal despair", "description": "A bleak outlook on humanity''s inherent violence and propensity for self-destruction."}, {"name": "cosmic indifference", "description": "The rejection of external salvation, suggesting meaning must be found within the present moment."}, {"name": "determined affirmation", "description": "A conscious choice to declare life''s worth and embrace the day, despite overarching cynicism."}], "journey": [{"mood": "Lost and seeking", "section": "Verse 1", "description": "A shared sense of disorientation hangs in the air, but an immediate physical connection brings a wave of quiet relief."}, {"mood": "Desperate yearning", "section": "Pre-Chorus", "description": "A fervent wish for a single night of closeness expands into an eternity, a moment out of time."}, {"mood": "Contradictory declaration", "section": "Chorus", "description": "The lyrics explode into a defiant affirmation that life is worth living, even while recognizing cosmic emptiness, propelled by a driving rhythm."}, {"mood": "Bleak realization", "section": "Verse 2", "description": "A harsh judgment on humanity''s nature resurfaces, only to be quickly overshadowed by the same simple, profound comfort of being held."}, {"mood": "Insistent struggle", "section": "Extended Chorus", "description": "The central message repeats and layers, a constant push and pull between resignation and the resolute belief that life holds value, building to an almost frantic insistence."}, {"mood": "Lingering echo", "section": "Outro", "description": "The voices and sentiments slowly fade, leaving behind a persistent echo of the quest for connection amidst an indifferent universe."}], "headline": "The quiet comfort found in another''s arms, a temporary shield against the bleakness of the world and the vastness of the cosmos.", "key_lines": [{"line": "She said, \"How did we Get ourselves so lost?\"", "insight": "The fundamental question of shared confusion, setting the stage for seeking an anchor."}, {"line": "When you hold me, I I feel better", "insight": "The immediate, visceral impact of human touch as a balm against uncertainty."}, {"line": "We are a violent race And we deserve what we get", "insight": "A stark, self-condemning indictment of humanity''s destructive tendencies."}, {"line": "Nothing is wasted and life is worth living", "insight": "A resolute declaration of value, a mantra against the void."}, {"line": "Heaven is nowhere, just look to the stars", "insight": "A rejection of external, spiritual salvation, focusing meaning on the observable and immediate."}], "compound_mood": "Urgent Longing", "sonic_texture": "Propulsive electronic drums drive a buoyant, yet slightly melancholic groove. Warm, shimmering synthesizers create a spacious backdrop, while vocals shift from intimate whispers to multi-layered, echoing declarations, all imbued with a late-night, dancefloor energy.", "audio_features": {"tempo": 125.086, "energy": 0.672, "valence": 0.338, "liveness": 0.106, "loudness": -5.291, "speechiness": 0.0438, "acousticness": 0.0134, "danceability": 0.598, "instrumentalness": 0}, "interpretation": "A poignant search for meaning and comfort in a chaotic world, finding temporary reprieve in the arms of another. It acknowledges humanity''s destructive nature and the ultimate insignificance of existence, yet chooses to affirm the value of life and connection, even if only for \"one night.\" The driving, danceable production creates a sense of determined optimism fighting against the lyrical gloom.", "mood_description": "A pulsing electronic beat carries a heavy heart through a long night. The dancefloor offers temporary escape, but the yearning for profound connection persists."}', 'google:gemini-2.5-flash', '2', 5357, NULL, '2026-05-17 09:57:51.883081+00', '2026-05-17 09:57:51.883081+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.song_analysis (id, song_id, analysis, model, prompt_version, tokens_used, cost_cents, created_at, updated_at, provider, input_tokens, output_tokens, cost_usd) VALUES ('1c186e22-7fef-40c0-9e1c-747469afbb2c', '4c09fd73-b649-414e-a24f-0b9534234dc1', '{"themes": [{"name": "enduring connection", "description": "The conscious effort and steadfast promise to remain in a relationship through time and change."}, {"name": "nostalgic gratitude", "description": "A heartfelt appreciation for how far a shared journey has come, recalling simpler beginnings."}, {"name": "quiet perseverance", "description": "The subtle but continuous work required to overcome personal doubts and keep a relationship strong."}, {"name": "reaffirmation of vows", "description": "The repeated declaration of love and commitment, acting as both a promise and a comfort."}], "journey": [{"mood": "Introspective search", "section": "Opening thoughts", "description": "A gentle synth hum opens into a reflective space, a search for clarity emerging from a quiet contemplation."}, {"mood": "Tender longing", "section": "Reaching out", "description": "A soft invitation extends, a fragile hope for closeness spoken aloud, wanting to bridge a small distance."}, {"mood": "Steadfast commitment", "section": "Shared history", "description": "The melody blooms into a warm, danceable promise, a celebratory look back at a shared past and a firm resolve to hold onto future love."}, {"mood": "Subtle uncertainty", "section": "Inner questioning", "description": "Beneath the steady rhythm, a hint of vulnerability appears, wondering if efforts are enough, yet still pushing forward."}, {"mood": "Determined affection", "section": "Renewed resolve", "description": "The core affirmation returns, stronger now, a defiant embrace of love despite any quiet anxieties, anchoring the feeling."}, {"mood": "Gentle fade", "section": "Lingering warmth", "description": "The final chants echo softly, a peaceful, comforting close that leaves behind a feeling of enduring tenderness."}], "headline": "A warm embrace of shared history, acknowledging the quiet struggle to keep love alive.", "key_lines": [{"line": "From the deep silence of my mind, There''s something I''m trying to find", "insight": "The quiet, internal quest for understanding what holds a relationship together."}, {"line": "But harder to mind, As I step, in vain", "insight": "The invisible struggles and effort that go into maintaining connection, often without immediate reward."}, {"line": "Look at where we are, Remember where we started out", "insight": "The act of grounding present love in shared memories and past foundations."}, {"line": "A memory tells us that we''re blessed, But opening up this chest, I discovered that a heart is lame", "insight": "The difficult truth that even deep love can face periods of weariness or doubt."}, {"line": "Never gonna be without each other''s love again", "insight": "A powerful, almost defiant promise to protect and cherish an enduring bond."}], "compound_mood": "Earnest Reflection", "sonic_texture": "A gentle pulse of synth bass underpins a tapestry of warm, chiming keyboards and subtle, shimmering electronic textures. The drums provide a steady, inviting groove, creating an open, airy feel that''s both danceable and reflective, with clear, intimate vocals.", "audio_features": {"tempo": 137.019, "energy": 0.384, "valence": 0.659, "liveness": 0.0714, "loudness": -8.274, "speechiness": 0.0451, "acousticness": 0.631, "danceability": 0.791, "instrumentalness": 0.0000761}, "interpretation": "The deliberate act of choosing love, day after day. It''s a testament to enduring commitment, the quiet strength found in remembering shared beginnings and reaffirming a bond, even when uncertainties linger beneath the surface. The upbeat rhythm wraps around these truths, making the resolve feel both effortless and deeply earned.", "mood_description": "A gentle synth-pop groove carries a hopeful echo, a steady beat for two hearts moving forward. It feels like a quiet conversation on a busy dance floor, full of unspoken history and soft affirmations."}', 'google:gemini-2.5-flash', '2', 5360, NULL, '2026-05-17 09:57:52.858164+00', '2026-05-17 09:57:52.858164+00', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
