4,-0.03261762,0.018752867,0.0029962412,-0.027829794,0.026576163,-0.008609788,0.049166873,-0.03350508,-0.014866334,0.029596109,0.027731549,-0.05079723,-0.05163938,0.030957723,0.0468023,-0.014432316,0.033324722,0.03276064,0.033134516,0.035918944,0.007787477,0.025323216,0.0030290217,-0.025379555,-0.008389555,0.008705768,0.042779513,0.032578994,0.03671922,0.04342829,0.034777436,-0.00880253,0.04672379,-0.016676227,0.022456292,-0.015401419,0.02065663,0.008126081,-0.03338527,-0.01807497,0.019499939,-0.015948812,-0.02564282,0.026527738,-0.015293684,0.050869923,-0.030876622,-0.01982366,0.0072611216,-0.046618767,0.051624026,-0.008346965,0.030236289,0.027272968,-0.002210808,0.028035033,0.0062925164,0.02496031,-0.016144998,0.026590735,-0.046309568,0.048466492,0.032256614,0.008208506,0.035222843,-0.051936995,0.010423456,-0.017253838,0.03978584,-0.030959569,0.0049747,-0.033078432,-0.030150015,0.0353142,0.036452834,0.0030287534,0.026819404,-0.0056399214,-0.039068043,0.029843641,-0.019587101,0.027664747,0.024006171,0.002972049,-0.038318,-0.06301038,0.027409405]', '2026-05-17 09:57:56.160859+00', '2026-05-17 09:57:56.160859+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('41f08966-d81f-4128-9548-fec0e0cd239e', 'cb5073d0-a492-452d-be2c-aa6622e299dc', 'genius', '{"source": "genius", "sections": [{"type": "Verse", "lines": [{"id": 1, "text": "I lost my way, somewhere in another galaxy (''Xy)", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Chris Brown found himself feeling lost and disconnected, as if he had strayed far from where he should be. Painful memories weighed heavily on him, leading to negative outcomes and consequences. Along his journey, he encountered various places and faces, but he didn’t want to let anyone down. Chris Brown acknowledged his own mistakes, understanding that they couldn’t be replaced or undone. Despite the challenges, he knew he had to find a way to move forward and continue his journey, seeking progress and growth.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 16}]}, {"id": 2, "text": "Too much to take, these memories end in tragedy (''Gy)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "And all of these places, all of these faces", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "I didn''t wanna let you down (Down)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "And all these mistakes of mine, I can''t replace it", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "I gotta move on somehow", "range": {"end": 6, "start": 6}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Healing energy on me", "range": {"end": 1, "start": 1}, "annotations": [{"text": "1111 is a four-digit (or highest order) angel number. Numerologically, it’s believed to show that angels are watching your back. It’s made up of ones, which are symbols of unity known as “God’s numbers.” 11:11 is often a time when people wish for guidance for their future lives, which perhaps involves a relationship or personal life.\n\nChris Brown is no stranger to being addicted to love, but he seems to be critically deep in his late-night thoughts, considering he needs “healing energy.” On his eleventh track “Messed Up,” Chris goes through a similar emotion:\n\nI was down, givin'' up (Up)\nGave me love I didn’t deserve\nI wasn’t worth it\nYou tried to show me what was right\nI didn’t wanna learn\nThis madness, tryna hide the savage\nI can’t lose another bad bitch, I’m not", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 26}]}, {"id": 2, "text": "Baby, all I really need''s one thing", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Healing energy on me", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Baby, can you make a wish for me?", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Healing energy on me", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Whеn it''s 11:11, I need it", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Healing energy on mе", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Baby, can you make a wish for me?", "range": {"end": 8, "start": 8}}]}, {"type": "Post-Chorus", "lines": [{"id": 1, "text": "11:11, oh", "range": {"end": 1, "start": 1}, "annotations": [{"text": "1111 is a four-digit (or highest order) angel number. Numerologically, it’s believed to show that angels are watching your back. It’s made up of ones, which are symbols of unity known as “God’s numbers.” 11:11 is often a time when people wish for guidance for their future lives, which perhaps involves a relationship or personal life.\n\nChris Brown is no stranger to being addicted to love, but he seems to be critically deep in his late-night thoughts, considering he needs “healing energy.” On his eleventh track “Messed Up,” Chris goes through a similar emotion:\n\nI was down, givin'' up (Up)\nGave me love I didn’t deserve\nI wasn’t worth it\nYou tried to show me what was right\nI didn’t wanna learn\nThis madness, tryna hide the savage\nI can’t lose another bad bitch, I’m not", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 26}]}, {"id": 2, "text": "11:11", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "When it''s 11:11, I need it", "range": {"end": 3, "start": 3}}]}, {"type": "Intro", "lines": [{"id": 1, "text": "Ooh, ooh", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Anxiety", "range": {"end": 2, "start": 2}, "annotations": []}, {"id": 3, "text": "Don''t let the pressure get to your head", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "You know we play for keeps", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Don''t let it go over your head", "range": {"end": 5, "start": 5}}]}, {"type": "Verse 1", "lines": [{"id": 1, "text": "Heavy stepper, I got too much weight on this", "range": {"end": 1, "start": 1}, "annotations": []}, {"id": 2, "text": "You can see the diamonds, don''t complain on this (Me)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "We was hustlin'', you niggas got no say on this (No)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "I''m just bein'' honest", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "I''m movin'' steady (Shoot)", "range": {"end": 5, "start": 5}, "annotations": []}, {"id": 6, "text": "You can''t buy success, ain''t got no sale on it", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "You know that God did, he never gon'' fail on us", "range": {"end": 7, "start": 7}, "annotations": []}, {"id": 8, "text": "Too much paper, got me thinkin'' I''ma save all this", "range": {"end": 8, "start": 8}, "annotations": []}, {"id": 9, "text": "I know the opps want it, they love this", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "Two-tone, got the bussdown like woah (Woah)", "range": {"end": 10, "start": 10}, "annotations": []}, {"id": 11, "text": "The streets crazy, they don''t love me no more (Ooh)", "range": {"end": 11, "start": 11}, "annotations": []}, {"id": 12, "text": "Not one for pressure, but I''ll bang for my bros (Bros)", "range": {"end": 12, "start": 12}}, {"id": 13, "text": "Walkin'' in Giuseppe, I be ten on my toes", "range": {"end": 13, "start": 13}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Welcome all the smoke (Smoke, smoke, smoke, ski)", "range": {"end": 1, "start": 1}, "annotations": []}, {"id": 2, "text": "Mama, pray for me so I won''t fold (Fold)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Walkin'' ten toes", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "I be paranoid, but nobody knows (Woah)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Anxiety", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Don''t let the pressure get to your head (Head)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "You know we play for keeps (For keeps)", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Don''t let it go over your head", "range": {"end": 8, "start": 8}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "Steady, movin'' onto greater (Ghetto, ghetto)", "range": {"end": 1, "start": 1}, "annotations": []}, {"id": 2, "text": "Never thought that I''d be ready (Ready)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "She let me, I let her keep her things (Keep)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "She told me, \"Why didn''t you just fight for it?\"", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "All these baddies, had too many (Many)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "I promised that I would have died for it", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "You just had to fuckin'' let me (Let me)", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Now I''m married to the game, I''m in that", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "No more chains, I''ma buy me some gold (Woah)", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "Three babies, tryna make room for some more (Ooh)", "range": {"end": 10, "start": 10}, "annotations": []}, {"id": 11, "text": "Life learnin'' lessons ''cause you reap what you sow (Grow)", "range": {"end": 11, "start": 11}}, {"id": 12, "text": "Walkin'' in Giuseppe, I be ten on my toes", "range": {"end": 12, "start": 12}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "You know I welcome all the smoke (Smoke, smoke, smoke, ski)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Mama, pray for me so I won''t fold (Fold)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Walkin'' ten toes (Ten toes)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "I be stressin'' out, but nobody knows (Yeah, yeah)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Anxiety (Anxiety)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Don''t let the pressure get to your head (Don''t let it get to your head)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "You know we play for keeps (We play, we play, we play)", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Don''t let it go over your head", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "Know we welcome all the", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "Welcome all the smoke (Welcome all the smoke, ooh)", "range": {"end": 10, "start": 10}}, {"id": 11, "text": "Mama, pray for me so I won''t fold (Fold)", "range": {"end": 11, "start": 11}}, {"id": 12, "text": "Walkin'' ten toes (Ten toes)", "range": {"end": 12, "start": 12}, "annotations": []}, {"id": 13, "text": "I be paranoid, but nobody knows (Yeah)", "range": {"end": 13, "start": 13}}, {"id": 14, "text": "Anxiety (Anxiety, yeah, oh)", "range": {"end": 14, "start": 14}}, {"id": 15, "text": "Don''t let the pressure get to your head (Don''t let it get to your head, don''t let it)", "range": {"end": 15, "start": 15}}, {"id": 16, "text": "You know we play for keeps (We play, we play, we play, play for keeps)", "range": {"end": 16, "start": 16}}, {"id": 17, "text": "Don''t let it go over your head", "range": {"end": 17, "start": 17}}]}, {"type": "Outro", "lines": [{"id": 1, "text": "Steady (Ooh)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Oh-woah", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Just fight for it", "range": {"end": 3, "start": 3}}]}], "schemaVersion": 1}', 'ly_v1_0cabd694438bf597', true, 1, '2026-05-29 11:13:19.906722+00', '2026-05-29 11:13:19.906722+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('18a4d778-f776-4c38-b6cc-0bdca2a7d322', '23089639-7c1d-4fad-9ebc-d102d2cee38a', 'genius', '{"source": "genius", "sections": [{"type": "Verse 1", "lines": [{"id": 1, "text": "For a while there, it was rough", "range": {"end": 1, "start": 1}, "annotations": []}, {"id": 2, "text": "But lately, I''ve been doin'' better", "range": {"end": 2, "start": 2}, "annotations": []}, {"id": 3, "text": "Than the last four cold Decembers I recall", "range": {"end": 3, "start": 3}, "annotations": []}, {"id": 4, "text": "And I see my family every month", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "I found a girl my parents love", "range": {"end": 5, "start": 5}, "annotations": [{"text": "In the Genius Verified video for “Beautiful Things”, Benson Boone revealed the inspiration behind this lyric:\n\nI’ve got pretty awesome parents, and I’m very blessed for that. When they met this person, they couldn’t stop talking about how much they loved the person I was when I was around them. When the people in your life that you love welcome, with open arms, a person that you’re in love with, it’s the best feeling.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 29}]}, {"id": 6, "text": "She''ll come and stay the night, and I think I might have it all", "range": {"end": 6, "start": 6}, "annotations": []}, {"id": 7, "text": "And I thank God every day", "range": {"end": 7, "start": 7}, "annotations": [{"text": "Religion is a recurring theme in Benson Boone’s songs. Here, the singer is thanking God for the “beautiful things” He has given him.\n\nAnd I thank God every day\nFor the girl He sent my way\n\nHowever, Benson knows that life is full of ups and downs: he’s full of doubts, and he fears that this happiness won’t last.\n\nBut I know the things He gives me, He can take away\n\nThe chorus of the song seems almost like a prayer: Benson is praying God not to take the “peace and love” he’s got now.\n\nI want you, I need you, oh God\nDon’t take\nThese beautiful things that I’ve got\n\nBenson’s relationship with God has been turbulent. For example, in the song In the stars, he said that his faith had been gone:\n\nIt’s like I’ve buried my faith with you\nI’m screaming at a God, I don’t know if I believe in\"", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 14}]}, {"id": 8, "text": "For the girl He sent my way", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "But I know the things He gives me, He can take away", "range": {"end": 9, "start": 9}, "annotations": [{"text": "This line is a  Biblical reference to Job 1:21, which reads:\n\nAnd said, Naked came I out of my mother’s womb, and naked shall I return thither: the Lord gave, and the Lord hath taken away; blessed be the name of the Lord”\n\n– Job 1:21, King James Version\n\nJob is the book in the Bible that addresses the age-old question: if a good God exists, why then do horrible things so often happen to good people? The book centers around God allowing the blessings in Job’s life, such as his health, wealth, and children, to be lost. The song is sung from a similar perspective where the singer fears that “these beautiful things that I’ve got,” including his lover, could be taken away.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 6}]}, {"id": 10, "text": "And I hold you every night", "range": {"end": 10, "start": 10}, "annotations": []}, {"id": 11, "text": "And that''s a feeling I wanna get used to", "range": {"end": 11, "start": 11}}, {"id": 12, "text": "But there''s no man as terrified as the man who stands to lose you", "range": {"end": 12, "start": 12}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "Oh, I hope I don''t losе you", "range": {"end": 1, "start": 1}, "annotations": [{"text": "The switch up from the verse, where Boone explores how he has found happiness in his relationship, to the pre-chorus and chorus reveals his fears of losing everything good that he has.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 13}]}, {"id": 2, "text": "Mm, please stay", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I want you, I need you, oh God", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Don''t take", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Thеse beautiful things that I''ve got", "range": {"end": 5, "start": 5}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Please stay", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "I want you, I need you, oh God", "range": {"end": 2, "start": 2}, "annotations": []}, {"id": 3, "text": "Don''t take", "range": {"end": 3, "start": 3}, "annotations": []}, {"id": 4, "text": "These beautiful things that I''ve got", "range": {"end": 4, "start": 4}}]}, {"type": "Post-Chorus", "lines": [{"id": 1, "text": "Oh, ooh", "range": {"end": 1, "start": 1}, "annotations": []}, {"id": 2, "text": "Please don''t take", "range": {"end": 2, "start": 2}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "I found my mind, I''m feelin'' sane", "range": {"end": 1, "start": 1}, "annotations": [{"text": "I found my mind, I’m feeling sane- Benson feels at peace with where his life is, and has relaxed at this small moment that he found.\n\nIt’s been a while, but I’m finding my faith- This goes back to his religious theme, and hints at the possibility that his belief in a higher power has been challenged. But because of this peaceful time that he is in, he is starting to grow his belief.\n\nIf everything’s good and it’s great why do I sit and wait til it’s gone?- Benson illustrates that it is easy to keep faith and to maintain happiness when everything around you is going well, but it’s harder to maintain that happiness and faith when something bad happens. He knows that the only thing constant in life is change, and the change is terrifying when you sit around and wait for the next tragedy to hit. He is worried that when this tragedy hits he will go back to where he was before his relationship.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 14}]}, {"id": 2, "text": "It''s been a while, but I''m finding my faith", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "If everything''s good and it''s great, why do I sit and wait ''til it''s gone?", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Oh, I''ll tell ya, I know I''ve got enough", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "I''ve got peace and I''ve got love", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "But I''m up at night thinkin'' I just might lose it all", "range": {"end": 6, "start": 6}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Please stay", "range": {"end": 1, "start": 1}, "annotations": []}, {"id": 2, "text": "I want you, I need you, oh God", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Don''t take", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "These beautiful things that I''ve got", "range": {"end": 4, "start": 4}}]}, {"type": "Post-Chorus", "lines": [{"id": 1, "text": "Oh, ooh", "range": {"end": 1, "start": 1}}]}, {"type": "Outro", "lines": [{"id": 1, "text": "Please stay", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "I want you, I need you, oh God", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I need", "range": {"end": 3, "start": 3}, "annotations": []}, {"id": 4, "text": "These beautiful things that I''ve got", "range": {"end": 4, "start": 4}}]}], "schemaVersion": 1}', 'ly_v1_b29798a30c67eb1e', true, 1, '2026-05-29 11:13:20.363331+00', '2026-05-29 11:13:20.363331+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('60da0326-55bb-4e6d-ae0d-8d5b0b53fe40', 'c6fd26df-f154-44ba-8bbc-393ec344e9ea', 'genius', '{"source": "genius", "sections": [{"type": "Intro", "lines": [{"id": 1, "text": "Right about now", "range": {"end": 1, "start": 1}, "annotations": []}]}, {"type": "Verse 1", "lines": [{"id": 1, "text": "As soon as you came in, I offered you a drink", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Better yet there''s a bar at my crib, shawty, what ya think?", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "You know I ain''t a stranger, so girl, let me take ya", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "To places that you don''t even know", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Oh, I''ve wanted girls before, but never like this", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "And I know I can''t have it all, but I''ll settle for a kiss", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "I''m playing less ya let me, ''cause damn, ya so sexy", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "And if feels like I''m losing control", "range": {"end": 8, "start": 8}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "Now I''m not falling in love with you", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "But I think that you are hot, shawty", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "See all I wanna do is let you know", "range": {"end": 3, "start": 3}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "From the moment I saw you", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "I knew that you were all that I wanted in a woman", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "From your stop to your walk to your fragrance", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Baby girl, you got my heart ski-ski-skippin''", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Just like boom, boom", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Ski-ski-skippin''", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Ba-ba boom, ba-ba boom, ba-ba boom, boom", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Ski-ski-skippin''", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "(Ski-ski-skippin'')", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "Ba-ba boom, boom, boom, boom, boom", "range": {"end": 10, "start": 10}}, {"id": 11, "text": "Ski-ski-skippin''", "range": {"end": 11, "start": 11}}, {"id": 12, "text": "Boom, boom", "range": {"end": 12, "start": 12}}, {"id": 13, "text": "Baby girl, you got my heart ski-ski-skippin'' just like", "range": {"end": 13, "start": 13}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "You got me in amazement, and I can''t believe", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "I''ve never seen nothing like you ever step on the scene", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Maybe you''re just born with it, maybe it''s Maybelline", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "But there''s no way for me to surely know", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Ain''t trying to be forward, girl, I wanna take you home", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "So from now moving forward, girl, you know what I want", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "I wanna get you in closer, I love to hear when you whisper", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "All the things that you wanna hear", "range": {"end": 8, "start": 8}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "Now I''m not falling in love with you", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "You see I think that you are bad, shawty", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "See all I wanna do is let you know", "range": {"end": 3, "start": 3}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "From the moment I saw you", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "I knew that you were all that I wanted in a woman", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "From your stop to your walk to your fragrance", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Baby girl, you got my heart ski-ski-skippin''", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "(Just like boom, boom)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Damn, baby", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "(Just like boom, boom)", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "You don''t know what you do to me", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "(Just like boom, boom)", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "I know it''s kinda crazy, but", "range": {"end": 10, "start": 10}}, {"id": 11, "text": "(Just like boom, boom)", "range": {"end": 11, "start": 11}}, {"id": 12, "text": "Girl, you got my heart", "range": {"end": 12, "start": 12}}, {"id": 13, "text": "(Ski-ski-skippin'')", "range": {"end": 13, "start": 13}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "From the moment I saw you", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "I knew that you were all that I wanted in a woman", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "From your stop to your walk to your fragrance", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Baby girl, you got my heart ski-ski-skippin''", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "From the moment I saw you", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "I knew that you were all that I wanted in a woman", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "From your stop to your walk to your fragrance", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Baby girl, you got my heart ski-ski-skippin''", "range": {"end": 8, "start": 8}}]}], "schemaVersion": 1}', 'ly_v1_3c661ccaca774725', false, 1, '2026-05-29 11:13:21.324414+00', '2026-05-29 11:13:21.324414+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('1262532c-09ea-466d-a894-4762e39321e2', '429d8a32-b808-47be-b3cb-7ada5081f334', 'genius', '{"source": "genius", "sections": [{"type": "Verse 1", "lines": [{"id": 1, "text": "Have you got colour in your cheeks?", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Blushing is one of the many involuntary body signals that is caused by blood rushing to the cheeks. This is usually caused by embarrassment (due to adrenaline) or sexual excitement (due to hormones) though it may also be a sign of intoxication (alcohol is a vasodilator).\n\nAlex is looking for a signal that she is either embarrassed, which would indicate her desire to be seen favorably, or sexual excitement, which would indicate a desire for him.\n\nThis line is the first in a series of questions asked in quick succession, showing Alex’s anxiety about his lover’s interest in him.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 317}]}, {"id": 2, "text": "Do you ever get that fear that you can''t shift the type", "range": {"end": 2, "start": 2}, "annotations": [{"text": "“Summat” is Yorkshire slang for “something.”\n\nBy asking if she worries about getting rid of something, Alex may be showing paranoia about him being the unwanted thing that’s sticking around like a little bit of food in her teeth.\n\nA common mondegreen here is “shift the tide,” though the official lyrics prove it’s actually “shift the type.”", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 259}]}, {"id": 3, "text": "That sticks around like summat in your teeth?", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Are there some aces up your sleeve?", "range": {"end": 4, "start": 4}, "annotations": [{"text": "The idiom “having an ace up your sleeve” means to have an advantage that other people don’t know about. In this case, Alex feels like she’s keeping something from him or has an advantage over him (being the one deciding whether or not she is interested in a relationship).\n\nContinuing the card game metaphor, “being in deep” describes someone deeply indebted to card sharks—the kind of person who would be lucky to have a few aces up their sleeves.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 150}]}, {"id": 5, "text": "Have you no idea that you''re in deep?", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "I''ve dreamt about you nearly every night this week", "range": {"end": 6, "start": 6}, "annotations": [{"text": "Freud theorized that the content of dreams were dictated by unconscious wish fulfillment. Alex is plagued by the desire to see his lover, and thus this is manifested in his dreams.\n\nFirst in this song and later in “I Wanna Be Yours”, the complex nature of secrets in human relationships is discussed. Here Alex is wishing his lover would reveal her secrets to him, but he’s also admitted to keeping secrets himself:\n\nSecrets I have held in my heart\nAre harder to hide than I thought", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 135}]}, {"id": 7, "text": "How many secrets can you keep?", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "''Cause there''s this tune I found", "range": {"end": 8, "start": 8}, "annotations": [{"text": "Memories are triggered by scents or sounds that were present during the event being remembered and/or the content of the song being played. Alex finds a song that reminds him of his lover, and in his infatuation, he continuously plays it.\n\nAn interesting lyric merely because this song is likely a tune that makes you think of someone.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 239}]}, {"id": 9, "text": "That makes me think of you somehow an'' I play it on repeat", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "Until I fall asleep, spillin'' drinks on my settee", "range": {"end": 10, "start": 10}, "annotations": [{"text": "A “settee” is an old English term for a sofa/couch, often seated for two.\n\nFurther proof that this girl is in deep in this relationship with him–he’s drinking alone and falls asleep while obsessively listening to a song that reminds him of her.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 232}]}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "(Do I wanna know) If this feelin'' flows both ways?", "range": {"end": 1, "start": 1}, "annotations": [{"text": "The several questions of the first verse, if answered, would tell him whether or not his lover is interested in him. He shows some anxiety about knowing the answers, indicating that he isn’t very optimistic about the answer he would get.\n\nThe modifier “sorta” softens the statement and thus understates his apprehension about revealing to his lover how much he truly desires that she would stay.\n\nHe lives with the hope that her answer might me positive and then be together, but in the same time, a negative response might destroy him. So it all comes to this rhetorical question, that he repeatedly asks throughout the song.\nIt’s like the Schrödinger’s cat: in the same time, he wants and he doesn’t want to know the answer.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 273}]}, {"id": 2, "text": "(Sad to see you go) Was sorta hopin'' that you''d stay", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "(Baby, we both know) That the nights were mainly made", "range": {"end": 3, "start": 3}, "annotations": [{"text": "Studies have shown what we’ve known for a while: alcohol makes you do stupid things. Alcohol is an inhibitor of the prefrontal cortex, which is in charge of processing information that “reflect both present and future circumstances.”\n\nUnder the influence due to his late-night drinking, Alex is going to admit his feelings to his lover, and later regret his decision.\n\nThis has a theme similar to their song “From The Ritz To The Rubble” from their first album, Whatever People Say I Am, That’s What I’m Not. In that song, the narrator deals with the difference between what is acceptable during daytime and what is acceptable during nighttime.\n\nThese lines may also be based on the idea that   during late nights people are more comfortable, more honest, more vulnerable and more real. We just say what we want or feel to say and then during the day we’re way more careful on what we say because we may not feel comfy enough.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 233}]}, {"id": 4, "text": "For sayin'' things that you can''t say tomorrow day", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Crawlin'' back to you", "range": {"end": 1, "start": 1}, "annotations": [{"text": "The word “crawling” highlights his desperate and vulnerable condition–he’s on his knees and can’t think of anyone else but his lover, despite the pain it’s been causing.\n\nAlex mentions his unfortunate habit of calling his lover later in the album in the song “Why’d You Only Call Me When You’re High?”—though in that case, he’s on something a little stronger than booze.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 248}]}, {"id": 2, "text": "Ever thought of callin'' when", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "You''ve had a few?", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "''Cause I always do", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Maybe I''m too", "range": {"end": 5, "start": 5}, "annotations": [{"text": "Rebounds are nothing new–getting over one person by having sex with someone else is an often promoted remedy to those lingering feelings of an ended relationship. Rebound relationships in this sense are seen merely as the ex-lover “getting over” the loss of their relationship without starting a new relationship since a new relationship would simply have the ex-lover harboring resentment toward their lover or not committing themselves fully to the new relationship.\n\nHowever, some research has shown that in committing to a new relationship, recovery and healing can take place. Such a relationship would be long-lasting and not merely a step in the recovery process. Alex realizes that he can recover by focusing on someone new, yet despite realizing this, he still decides not to. The deliberate nature of this choice is conveyed through his choice of language, as the reference to “thought” suggests that a lot of careful consideration had gone into it. This may be a convincing case of akrasia…", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 130}]}, {"id": 6, "text": "Busy bein'' yours", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "To fall for somebody new", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Now I''ve thought it through", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "Crawlin'' back to you", "range": {"end": 9, "start": 9}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "So have you got the guts?", "range": {"end": 1, "start": 1}, "annotations": [{"text": "After trying a few different tactics to get her to stay, like accusatory questions and subtle pleas, he now tries daring her to come back to him. This is a technique of reverse psychology, in which by challenging her- he makes her want to prove to him that she is in fact brave enough.\nThis also connects to the next line in the song because her heart was broken and she is fearful of liking someone again.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 94}]}, {"id": 2, "text": "Been wonderin'' if your heart''s still open", "range": {"end": 2, "start": 2}, "annotations": [{"text": "He plays on the idea of her heart as some sort of store or service that can be open or closed for him.\n\nNot only does he want to know if there’s a vacancy left for him, he wants to know how long it will be open – possibly to save himself from future heartbreak.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 128}]}, {"id": 3, "text": "And if so, I wanna know what time it shuts", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Simmer down an'' pucker up, I''m sorry to interrupt", "range": {"end": 4, "start": 4}, "annotations": [{"text": "Rather than hearing out what she’s trying to say, he interrupts her with an attempted kiss – seemingly as a last resort of resparking her interest in the relationship.\n\nAlso note the play on the directional words in this line: “simmer down and pucker up.\n\n\n\nAnd no, he’s not asking her to pucker up her lips for a duck face pose.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 122}]}, {"id": 5, "text": "It''s just I''m constantly on the cusp of tryin'' to kiss you", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "But I don''t know if you feel the same as I do", "range": {"end": 6, "start": 6}, "annotations": [{"text": "He’s not sure if the feelings between them are mutual, but his offer to be together is on the table if she does want it.\n\nThere’s also an inability to move on throughout this song, hence “crawling back to you”. Essentially, he’ll wait until she wants him. he puts the ball in her court.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 111}]}, {"id": 7, "text": "But we could be together if you wanted to", "range": {"end": 7, "start": 7}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "(Do I wanna know) If this feelin'' flows both ways?", "range": {"end": 1, "start": 1}, "annotations": [{"text": "The several questions of the first verse, if answered, would tell him whether or not his lover is interested in him. He shows some anxiety about knowing the answers, indicating that he isn’t very optimistic about the answer he would get.\n\nThe modifier “sorta” softens the statement and thus understates his apprehension about revealing to his lover how much he truly desires that she would stay.\n\nHe lives with the hope that her answer might me positive and then be together, but in the same time, a negative response might destroy him. So it all comes to this rhetorical question, that he repeatedly asks throughout the song.\nIt’s like the Schrödinger’s cat: in the same time, he wants and he doesn’t want to know the answer.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 273}]}, {"id": 2, "text": "(Sad to see you go) Was sorta hopin'' that you''d stay", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "(Baby, we both know) That the nights were mainly made", "range": {"end": 3, "start": 3}, "annotations": [{"text": "Studies have shown what we’ve known for a while: alcohol makes you do stupid things. Alcohol is an inhibitor of the prefrontal cortex, which is in charge of processing information that “reflect both present and future circumstances.”\n\nUnder the influence due to his late-night drinking, Alex is going to admit his feelings to his lover, and later regret his decision.\n\nThis has a theme similar to their song “From The Ritz To The Rubble” from their first album, Whatever People Say I Am, That’s What I’m Not. In that song, the narrator deals with the difference between what is acceptable during daytime and what is acceptable during nighttime.\n\nThese lines may also be based on the idea that   during late nights people are more comfortable, more honest, more vulnerable and more real. We just say what we want or feel to say and then during the day we’re way more careful on what we say because we may not feel comfy enough.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 233}]}, {"id": 4, "text": "For sayin'' things that you can''t say tomorrow day", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Crawlin'' back to you (Crawlin'' back to you)", "range": {"end": 1, "start": 1}, "annotations": [{"text": "The word “crawling” highlights his desperate and vulnerable condition–he’s on his knees and can’t think of anyone else but his lover, despite the pain it’s been causing.\n\nAlex mentions his unfortunate habit of calling his lover later in the album in the song “Why’d You Only Call Me When You’re High?”—though in that case, he’s on something a little stronger than booze.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 248}]}, {"id": 2, "text": "Ever thought of callin'' when", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "You''ve had a few? (You''ve had a few)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "''Cause I always do (''Cause I always do)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Maybe I''m too (Maybe I''m too busy)", "range": {"end": 5, "start": 5}, "annotations": [{"text": "Rebounds are nothing new–getting over one person by having sex with someone else is an often promoted remedy to those lingering feelings of an ended relationship. Rebound relationships in this sense are seen merely as the ex-lover “getting over” the loss of their relationship without starting a new relationship since a new relationship would simply have the ex-lover harboring resentment toward their lover or not committing themselves fully to the new relationship.\n\nHowever, some research has shown that in committing to a new relationship, recovery and healing can take place. Such a relationship would be long-lasting and not merely a step in the recovery process. Alex realizes that he can recover by focusing on someone new, yet despite realizing this, he still decides not to. The deliberate nature of this choice is conveyed through his choice of language, as the reference to “thought” suggests that a lot of careful consideration had gone into it. This may be a convincing case of akrasia…", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 130}]}, {"id": 6, "text": "Busy bein'' yours (Bein'' yours)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "To fall for somebody new", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Now I''ve thought it through", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "Crawlin'' back to you", "range": {"end": 9, "start": 9}}]}, {"type": "Outro", "lines": [{"id": 1, "text": "(Do I wanna know) If this feelin'' flows both ways?", "range": {"end": 1, "start": 1}, "annotations": [{"text": "The several questions of the first verse, if answered, would tell him whether or not his lover is interested in him. He shows some anxiety about knowing the answers, indicating that he isn’t very optimistic about the answer he would get.\n\nThe modifier “sorta” softens the statement and thus understates his apprehension about revealing to his lover how much he truly desires that she would stay.\n\nHe lives with the hope that her answer might me positive and then be together, but in the same time, a negative response might destroy him. So it all comes to this rhetorical question, that he repeatedly asks throughout the song.\nIt’s like the Schrödinger’s cat: in the same time, he wants and he doesn’t want to know the answer.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 273}]}, {"id": 2, "text": "(Sad to see you go) Was sorta hopin'' that you''d stay", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "(Baby, we both know) That the nights were mainly made", "range": {"end": 3, "start": 3}, "annotations": [{"text": "Studies have shown what we’ve known for a while: alcohol makes you do stupid things. Alcohol is an inhibitor of the prefrontal cortex, which is in charge of processing information that “reflect both present and future circumstances.”\n\nUnder the influence due to his late-night drinking, Alex is going to admit his feelings to his lover, and later regret his decision.\n\nThis has a theme similar to their song “From The Ritz To The Rubble” from their first album, Whatever People Say I Am, That’s What I’m Not. In that song, the narrator deals with the difference between what is acceptable during daytime and what is acceptable during nighttime.\n\nThese lines may also be based on the idea that   during late nights people are more comfortable, more honest, more vulnerable and more real. We just say what we want or feel to say and then during the day we’re way more careful on what we say because we may not feel comfy enough.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 233}]}, {"id": 4, "text": "For sayin'' things that you can''t say tomorrow day", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "(Do I wanna know?) Too busy bein'' yours to fall", "range": {"end": 5, "start": 5}, "annotations": [{"text": "Rebounds are nothing new–getting over one person by having sex with someone else is an often promoted remedy to those lingering feelings of an ended relationship. Rebound relationships in this sense are seen merely as the ex-lover “getting over” the loss of their relationship without starting a new relationship since a new relationship would simply have the ex-lover harboring resentment toward their lover or not committing themselves fully to the new relationship.\n\nHowever, some research has shown that in committing to a new relationship, recovery and healing can take place. Such a relationship would be long-lasting and not merely a step in the recovery process. Alex realizes that he can recover by focusing on someone new, yet despite realizing this, he still decides not to. The deliberate nature of this choice is conveyed through his choice of language, as the reference to “thought” suggests that a lot of careful consideration had gone into it. This may be a convincing case of akrasia…", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 130}]}, {"id": 6, "text": "(Sad to see you go) Ever thought of callin'', darlin''?", "range": {"end": 6, "start": 6}, "annotations": [{"text": "The word “crawling” highlights his desperate and vulnerable condition–he’s on his knees and can’t think of anyone else but his lover, despite the pain it’s been causing.\n\nAlex mentions his unfortunate habit of calling his lover later in the album in the song “Why’d You Only Call Me When You’re High?”—though in that case, he’s on something a little stronger than booze.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 248}]}, {"id": 7, "text": "(Do I wanna know?) Do you want me crawlin'' back to you?", "range": {"end": 7, "start": 7}, "annotations": [{"text": "The final line underlines his insecurity. He can’t move on, so he’s crawling back. However, he isn’t certain that she actually wants him back. This uncertainty itself is an unpleasant feeling, but putting himself out there means he risks humiliation if she actually doesn’t want him.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 160}]}]}], "schemaVersion": 1}', 'ly_v1_c97bad5adcebd18e', true, 1, '2026-05-29 11:13:21.912049+00', '2026-05-29 11:13:21.912049+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('daa1f33f-d7af-47b6-9b41-a09b62d683c9', 'e2ff9c6d-b39d-4cae-8b4b-5e934eaf132e', 'genius', '{"source": "genius", "sections": [{"type": "Intro", "lines": [{"id": 1, "text": "(Oh)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "(Oh)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "(Oh)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "(Oh)", "range": {"end": 4, "start": 4}}]}, {"type": "Verse: Elton John", "lines": [{"id": 1, "text": "It''s a human sign", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "When things go wrong", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "When the scent of her lingers", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "And temptation''s strong", "range": {"end": 4, "start": 4}}]}, {"type": "Pre-Chorus: Elton John", "lines": [{"id": 1, "text": "Cold, cold heart", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Hardened by you (Oh)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Some things lookin'' better, baby", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Just passin'' through (No, no, no, no, no)", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus: Dua Lipa, Dua Lipa & Elton John", "lines": [{"id": 1, "text": "And I think it''s gonna be a long, long time", "range": {"end": 1, "start": 1}, "annotations": [{"text": "These are the lyrics from Elton John’s song Rocketman.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 48}]}, {"id": 2, "text": "''Til touchdown brings me ''round again to find", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I''m not the man they think I am at home", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Oh no, no, no", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "And this is what I should have said", "range": {"end": 5, "start": 5}, "annotations": [{"text": "This line comes from Elton John’s 1983 single, “Kiss the Bride.\"", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 16}]}, {"id": 6, "text": "Well, I thought it, but I kept it hid", "range": {"end": 6, "start": 6}, "annotations": [{"text": "These are also the lyrics to Kiss The Bride by Elton John", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 10}]}]}, {"type": "Pre-Chorus: Elton John", "lines": [{"id": 1, "text": "Cold, cold heart", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Written by Elton John, the first verse and the pre-chorus of Cold Hearted are taken out of Elton’s 1989 song Sacrifice. PNAU has incorporated the same synth throughout Cold Hearted as heard in Sacrifice.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 41}]}, {"id": 2, "text": "Hardened by you (Oh)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Some things lookin'' better, baby", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Just passin'' through (No, no, no, no, no)", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus: Dua Lipa, Dua Lipa & Elton John", "lines": [{"id": 1, "text": "And I think it''s gonna be a long, long time", "range": {"end": 1, "start": 1}, "annotations": [{"text": "These are the lyrics from Elton John’s song Rocketman.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 48}]}, {"id": 2, "text": "''Til touchdown brings me ''round again to find", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I''m not the man they think I am at home", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Oh no, no, no (No, no, no, no, no)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "And this is what I should have said", "range": {"end": 5, "start": 5}, "annotations": [{"text": "This line comes from Elton John’s 1983 single, “Kiss the Bride.\"", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 16}]}, {"id": 6, "text": "Well, I thought it, but I kept it hid", "range": {"end": 6, "start": 6}, "annotations": [{"text": "These are also the lyrics to Kiss The Bride by Elton John", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 10}]}]}, {"type": "Pre-Chorus: Elton John", "lines": [{"id": 1, "text": "Cold, cold heart (Oh)", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Written by Elton John, the first verse and the pre-chorus of Cold Hearted are taken out of Elton’s 1989 song Sacrifice. PNAU has incorporated the same synth throughout Cold Hearted as heard in Sacrifice.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 41}]}, {"id": 2, "text": "Hardened by you", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Some things lookin'' better, baby (Oh)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Just passin'' through (No, no, no, no, no)", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus: Dua Lipa", "lines": [{"id": 1, "text": "And I think it''s gonna be a long, long time\n(And I think it''s gonna be a long, long time)\n(I''m not the man they think I am at home)", "range": {"end": 9, "start": 1}, "annotations": [{"text": "These are the lyrics from Elton John’s song Rocketman.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 48}]}, {"id": 2, "text": "''Til touchdown brings me ''round again to find", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I''m not the man they think I am at home", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Oh no, no, no (No, no, no, no, no)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "And this is what I should have said", "range": {"end": 5, "start": 5}, "annotations": [{"text": "This line comes from Elton John’s 1983 single, “Kiss the Bride.\"", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 16}]}, {"id": 6, "text": "(''Til touchdown brings me ''round again to find)", "range": {"end": 7, "start": 7}}, {"id": 7, "text": "Well, I thought it, but I kept it hid", "range": {"end": 8, "start": 8}, "annotations": [{"text": "These are also the lyrics to Kiss The Bride by Elton John", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 10}]}, {"id": 8, "text": "(Oh, no, no, no; no, no, no, no, no)", "range": {"end": 10, "start": 10}}]}, {"type": "Outro", "lines": [{"id": 1, "text": "Shoorah (Oh)", "range": {"end": 1, "start": 1}, "annotations": [{"text": "These are the lyrics from Elton John’s song ‘Where’s the Shoorah?’", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 18}]}, {"id": 2, "text": "Shoorah", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Shoorah (Oh)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Shoorah", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "(No, no, no, no, no)", "range": {"end": 5, "start": 5}, "annotations": []}]}], "schemaVersion": 1}', 'ly_v1_8432a2c94974ab16', true, 1, '2026-05-29 11:13:23.645562+00', '2026-05-29 11:13:23.645562+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('b470edbd-3df9-4f5e-af6d-debaa173448a', 'acb2449c-e1eb-49da-8fc3-e62b01657013', 'genius', '{"source": "genius", "sections": [{"type": "Intro", "lines": [{"id": 1, "text": "(But I wanna stay)", "range": {"end": 1, "start": 1}}]}, {"type": "Verse 1", "lines": [{"id": 1, "text": "I want you to stay", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "''Til I''m in the grave", "range": {"end": 2, "start": 2}, "annotations": [{"text": "Billie speaks of her strong love for her partner. She expresses this intense inkling by saying that this love would last until death.\n\nThis is alike the common saying:\n\nTill death do us part.\n\nThis phrase is used as a vow in wedding ceremonies to mean that the marriage vow is binding until one spouse dies.\n\nBillie saying that the only way, if possible, that her and her partner would ever stop being together would be death. If not, their love is a lifelong commitment.\n\nThese lyrics were teased in the Season 3 teaser for the Netflix series Heartstopper.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 89}]}, {"id": 3, "text": "''Til I rot away, dead and buried", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "''Til I''m in the casket you carry", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "If you go, I''m goin'' too, uh", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "''Cause it was always you (Alright)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "And if I''m turnin'' blue, please don''t save me", "range": {"end": 7, "start": 7}, "annotations": [{"text": "The expression “turning blue” means someone turning sad, as the color blue is referred to as a sad color most of the time. This also can be taken literally, as someone’s skin turns blueish when they die, regarding the earlier lyrics where she says,“‘til death do us part” in different wording. In this line, she is implying that if she turns sad, or if she dies, don’t try to help her because nothing will help if she has to live without her lover.\n\n\n\nThis is also a reference to “BLUE”, the closer of HIT ME HARD AND SOFT.\n\nThis may also be an easter egg alluding to her song “listen before i go” from Eilish’s 2019 debut studio album WHEN WE ALL FALL ASLEEP, WHERE DO WE GO?:\n\nTake me to the rooftop\nI wanna see the world when I stop breathing\nTurnin'' blue", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 72}]}, {"id": 8, "text": "Nothin'' left to lose without my baby", "range": {"end": 8, "start": 8}, "annotations": [{"text": "Billie feels without her lover she’s feeling reckless and a sense of apathy, hence she has “nothin'' left to lose.” It can also mean the only good thing she has is her partner and if she loses them she has nothing else.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 24}]}]}, {"type": "Refrain", "lines": [{"id": 1, "text": "Birds of a feather, we should stick together, I know", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This is a play on the classic English saying “Birds of a feather flock together.” It is usually used to express how people with similar traits and interests gravitate towards each other. Here Eilish may be expressing that herself and her lover share both a romantic connection and a lot more. Therefore, according to the proverb, they must stay together.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 122}]}, {"id": 2, "text": "I said I''d never think I wasn''t better alone", "range": {"end": 2, "start": 2}, "annotations": []}, {"id": 3, "text": "Can''t change the weather, might not be forever", "range": {"end": 3, "start": 3}, "annotations": [{"text": "The common saying, “can’t change the weather” means to accept that some things are beyond one’s control.\n\nBillie uses this phrase to refer to the fact that, like her love for her partner, the weather patterns are vast and complex. Sometimes even unpredictable, showing that her love for her partner isn’t by choice, but that it hit her unexpectedly, with it’s intensity and emotions.\n\nAdding on the line “might not be forever” further tells us that just like the weather, Billie’s love might not last forever. Just like when a rainstorm passes after a while.\n\nBefore clarifying in the next line that if it were to be forever, it’d be even better.\n\nThe phrase “can’t change the weather” is also a lyric from “Don’t Smile At Me” in the song “Party Favor”.\n\nBut we can’t change the weather, when the weather’s come and gone.\n\nIn this song, it is also used to express that some things are out of our control and once it’s gone, it’s gone, unchangable, unreversable.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 52}]}, {"id": 4, "text": "But if it''s forever, it''s even better", "range": {"end": 4, "start": 4}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "And I don''t know what I''m cryin'' for", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Eillish expresses that she has such strong feelings for her partner that she is no longer in control of her emotions and they are instead in control of her. She finds herself crying out of love for her partner and does not even recognise why.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 51}]}, {"id": 2, "text": "I don''t think I could love you more", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "It might not be long, but baby, I", "range": {"end": 3, "start": 3}, "annotations": [{"text": "Billie implies that even if there’s a possibility her life might be short and end in the near future, she still loves her partner until her death, until her last breath.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 13}]}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "I''ll love you ''til the day that I die", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Billie speaks of her strong love for her partner. She expresses this intense inkling by saying that this love would last until death.\n\nThis is alike the common saying:\n\nTill death do us part.\n\nThis phrase is used as a vow in wedding ceremonies to mean that the marriage vow is binding until one spouse dies.\n\nBillie saying that the only way, if possible, that her and her partner would ever stop being together would be death. If not, their love is a lifelong commitment.\n\nThese lyrics were teased in the Season 3 teaser for the Netflix series Heartstopper.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 89}]}, {"id": 2, "text": "''Til the day that I die", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "''Til the light leaves my eyes", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "''Til the day that I die", "range": {"end": 4, "start": 4}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "I want you to see, hm", "range": {"end": 1, "start": 1}, "annotations": []}, {"id": 2, "text": "How you look to me, hm", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "You wouldn''t believe if I told ya", "range": {"end": 3, "start": 3}, "annotations": []}, {"id": 4, "text": "You would keep the compliments I throw ya", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "But you''re so full of shit, uh", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Tell me it''s a bit, oh", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Say you don''t see it, your mind''s polluted", "range": {"end": 7, "start": 7}, "annotations": [{"text": "The person she loves can’t seem to understand why she would love them. Their mind is preoccupied with all the reasons why they aren’t worth being loved. They seem to have an avoidant attachment style and would prefer being alone and quitting the relationship altogether", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 72}]}, {"id": 8, "text": "Say you wanna quit, don''t be stupid", "range": {"end": 8, "start": 8}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "And I don''t know what I''m cryin'' for", "range": {"end": 1, "start": 1}, "annotations": [{"text": "It can be agonizing for some people to contemplate the finiteness of everything, specially when we’ve found true love.\n\nThe thought that one day the light will fade and we’ll have to bid farewell to that love is difficult to bear.\n\nDespite knowing we’ve found someone special, the idea of a future without them is a pain we’d rather not entertain. The uncertainty of what comes next, when the intensity of that love may no longer be as palpable, is something that consumes us and makes us want to hold onto that happiness forever.\n\n\n\nThis could also be Billie expressing her confusion over feeling sad when she has so much love for Finneas, her brother. She acknowledges the depth of her love for him and the possibility that their time working together may not last forever. Despite this uncertainty, she conveys her strong desire to continue making music with him, emphasizing her reluctance to end their collaboration. This line highlights the emotional complexity of their relationship and the profound connection they share as both siblings and creative partners.\n\nSpecifically during this song at the album release party, instead of Finneas filming Billie (like throughout the entire event), she was the one filming her brother. So, we can also consider this song a tribute to their strong relationship as siblings.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 37}]}, {"id": 2, "text": "I don''t think I could love you more", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "It might not be long, but baby, I", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Don''t wanna say goodbye", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Birds of a feather, we should stick together, I know (''Til the day that I die)\nI said I''d never think I wasn''t better alone (''Til the light leaves my eyes)\nCan''t change the weather, might not be forever (''Til the day that I die)", "range": {"end": 3, "start": 1}, "annotations": [{"text": "Billie speaks of her strong love for her partner. She expresses this intense inkling by saying that this love would last until death.\n\nThis is alike the common saying:\n\nTill death do us part.\n\nThis phrase is used as a vow in wedding ceremonies to mean that the marriage vow is binding until one spouse dies.\n\nBillie saying that the only way, if possible, that her and her partner would ever stop being together would be death. If not, their love is a lifelong commitment.\n\nThese lyrics were teased in the Season 3 teaser for the Netflix series Heartstopper.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 89}]}, {"id": 2, "text": "But if it''s forever, it''s even better", "range": {"end": 4, "start": 4}, "annotations": [{"text": "The common saying, “can’t change the weather” means to accept that some things are beyond one’s control.\n\nBillie uses this phrase to refer to the fact that, like her love for her partner, the weather patterns are vast and complex. Sometimes even unpredictable, showing that her love for her partner isn’t by choice, but that it hit her unexpectedly, with it’s intensity and emotions.\n\nAdding on the line “might not be forever” further tells us that just like the weather, Billie’s love might not last forever. Just like when a rainstorm passes after a while.\n\nBefore clarifying in the next line that if it were to be forever, it’d be even better.\n\nThe phrase “can’t change the weather” is also a lyric from “Don’t Smile At Me” in the song “Party Favor”.\n\nBut we can’t change the weather, when the weather’s come and gone.\n\nIn this song, it is also used to express that some things are out of our control and once it’s gone, it’s gone, unchangable, unreversable.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 52}]}]}, {"type": "Post-Chorus", "lines": [{"id": 1, "text": "I knew you in another life", "range": {"end": 1, "start": 1}, "annotations": [{"text": "These lines could be inspired by one of Billie’s favorite movies, I Origins. They may also reference Spirited Away, highlighting how Chihiro and Haku manage to remember each other despite losing their memories as they navigate between realms.\n\nhttps://filepicker-images.genius.com/c5705a12c60384c4046c1a2272ba56dd0e79ec6189a4909aeba5a1f9da7aa920%2F3h8ylpkxtq9", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 55}]}, {"id": 2, "text": "You had that same look in your eyes", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I love you, don''t act so surprised", "range": {"end": 3, "start": 3}, "annotations": [{"text": "The song ends on a confirmation, if not already clear enough. that Billie loves her partner that she writes about.\n\nThis is interesting when you look at its contrary song “Halley’s Comet” from her “Happier Than Ever” album which is the similar love-sick song. It’s last verse writes:\n\nI think I might have fallen in love, what am I to do?\n\nThis is a contrary as instead of the confirmation and certainty shown in “Birds of a Feather”, the verse in “Halley’s Comet” shows uncertainty and questioning, like she doesn’t want to be/fall in love.\n\nThe progression of this similar idea is an interesting concept as Billie evolves through her albums.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 64}]}]}], "schemaVersion": 1}', 'ly_v1_7227ce4343b40532', true, 1, '2026-05-29 11:13:24.494026+00', '2026-05-29 11:13:24.494026+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('5c36dc4f-1227-43df-ac98-d945496feaf4', '140ebf68-f075-45f4-83c1-893170346487', 'genius', '{"source": "genius", "sections": [{"type": "Intro", "lines": [{"id": 1, "text": "Yeah", "range": {"end": 1, "start": 1}}]}, {"type": "Verse 1", "lines": [{"id": 1, "text": "I''ve been tryna call", "range": {"end": 1, "start": 1}, "annotations": [{"text": "The first line of this song represents Abel’s vulnerability. A theme explored throughout the rest of this song. On the song “Coming Down,” Abel expresses very similar feelings:\n\nPick up your phone\nThe party’s finished and I want you to know\nI’m all alone\n\nWithout drugs, Abel feels a sense of loneliness. This is perhaps Abel’s truest and most authentic self.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 187}]}, {"id": 2, "text": "I''ve been on my own for long enough", "range": {"end": 2, "start": 2}, "annotations": [{"text": "Abel’s been on his own since around the age of 17 when he dropped out of high school and left home to never come back. This is referenced on many of his songs, like “Rolling Stone,” from his mixtape Thursday, where he said:\n\n‘Cause I’ve been on these streets way too long, too long, too long\nBaby, I’ve been on this too long\n\nHe’s also implying that he has been single for quite some time now and has forgotten how to love. From 2015 to 2019 Abel and model Bella Hadid had an on and off relationship, and after spending a few months apart, Abel seems to have lost his ability to love.\n\nTo add on, throughout After Hours, Abel plays with the idea of being “alone together” or simply “alone” on songs like “Save Your Tears”, “Faith,” and the opening track “Alone Again:”\n\n‘Cause I don’t know if I can be alone again\nI don’t know if I can be alone again", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 168}]}, {"id": 3, "text": "Maybe you can show me how to love, maybe", "range": {"end": 3, "start": 3}, "annotations": []}, {"id": 4, "text": "I''m goin'' through withdrawals", "range": {"end": 4, "start": 4}, "annotations": [{"text": "A “withdrawal” can both mean the behavior in which one prefers to be alone or also the physical and mental effects experienced when a person stops using a drug. Considering Abel’s historic of drug abuse, which is largely mentioned in his songs, the second one is more likely.\n\nMoreover, in a 2016 interview with The Guardian he referred to the subject:\n\nWhen I had nothing to do but make music, it was very heavy. Drugs were a crutch for me.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 146}]}, {"id": 5, "text": "You don''t even have to do too much", "range": {"end": 5, "start": 5}, "annotations": [{"text": "Abel may be talking about opiate withdrawal. During opiate withdrawal, your body is extremely sensitive. Because of this, even the slightest touch could turn him on.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 8}]}, {"id": 6, "text": "You can turn me on with just a touch, baby", "range": {"end": 6, "start": 6}, "annotations": [{"text": "Abel expresses his great sensitivity towards the girl he’s with to show he’s really in love with her, or that he clings to every sign of affection, following what he says in the verse.\n\nAlso, even if that mustn’t be the same person he’s talking about in this track, Abel is not unfamiliar with this kind of touch. That could imply a reminiscence of feelings he had in his (fictional) past life, and the fact that he’s very sensitive towards women, and has always been.\n\nThis idea is somewhat confirmed in the chorus.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 49}]}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "I look around and", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Las Vegas is nicknamed “Sin City” due to the city’s overwhelming presence of crime, drugs, and sexual promiscuity—all important themes throughout The Weeknd’s career. He also explores hedonism on his August 2011 song “Heaven or Las Vegas.”\n\nAbel experienced emptiness and heartbreak when he was briefly separated from Bella Hadid in 2019. The two have since reunited and emotionally completed The Weeknd.\n\nAbel previously touched upon his need for Bella on his November 2019 single, “Heartless”:\n\nYou just came back in my life\nYou never gave up on me (Why don’t you?)\nI’ll never know what you see (Why won’t you?)\nI don’t do well when alone (Oh yeah)", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 278}]}, {"id": 2, "text": "Sin City''s cold and empty (Oh)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "No one''s around to judge me (Oh)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "I can''t see clearly when you''re gone", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "I said, ooh, I''m blinded by the lights", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This song directly follows the outro of “Faith,” where The Weeknd speaks about being in the back of a police car presumably after an overdose:\n\nI ended up in the back of a flashing car\nWith the city shining on my face\nThe lights are blinding me again\n\nThe “lights” here not only represent the lights from the police car or the city but also the fame Abel’s enjoyed for his recording career. From stage lights to paparazzi camera flashes, he’s been “blinded” by many examples of a wealthy and successful life, and he doesn’t plan on stopping anytime soon. However, his celebrity life often overshadows his deep personal life. On his 2018 song “Privilege,” Abel discusses how many fans and media sources didn’t believe that he could have a real and genuine relationship with a partner because of his status in fame:\n\nThey said our love is just a game, I don’t care what they say\n\nNevertheless, his relationship seems to be real and sound, as he claims that it is the only thing that can keep him peacefully inserted in this lifestyle.\n\nAbel also uses a similar line on “Snowchild,” the fifth track from After Hours:\n\nLeaving, leaving into the night\nNow a nigga leaving, leaving\nLeaving into the night, oh", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 269}]}, {"id": 2, "text": "No, I can''t sleep until I feel your touch (Touch)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I said, ooh, I''m drowning in the night", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Oh, when I''m like this, you''re the one I trust", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Hey, hey, hey", "range": {"end": 5, "start": 5}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "I''m running out of time", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This line has several meanings:\n\nFirst, he alludes to Las Vegas again. As mentioned in the pre-chorus of the song, Abel has a special emotional connection to the city. He recalls it here and automatically combines it with the chorus:\n\nNo, I can’t sleep until I feel your touch\n\nFurthermore, Vegas is a city, known for being “alive” at night. Another reason this song’s story, or the whole album takes place in Vegas are Abel’s\nrepeated references of it, adding to the fact, that he feels at home there.\n\nAbel fears, that he won’t be able to sleep, because he lost his loved one and needs to get her back to finally get sleep. At the end of his journey, he recalls this line. On “Final Lullaby”, the last track off the deluxe version of his album After Hours, Abel tries to accept the fact that he won’t find his love back in that night.\n\nI’m running out of time\nAnd you’ll always be on my mind\n\nAnother explanation could be his habit to be awake late at night, as already mentioned in “Alone Again”:\n\nI’m falling only for the night\n\nA possible reason for him being stressed during the day is his fame and popularity. During the day, Abel is blinded by the lights of police cars, but also by flashing camera lights, representing fame. Therefore, he likes to escape into the night, just like in his record “Snowchild”:\n\nLeaving, leaving into the night\nNow a nigga leaving, leaving\nLeaving into the night, oh", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 40}]}, {"id": 2, "text": "''Cause I can see the sun light up the sky", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "So I hit the road in overdrive, baby, oh", "range": {"end": 3, "start": 3}, "annotations": [{"text": "Here, Abel alludes to his habit of driving over the speed limit, which he has mentioned in several songs in the past, such as on “Heartless,”“ featured on his fourth studio album, After Hours:\n\nI’ve been dodgin'' death in the six-speed\n\nAbel also admits his love for dangerous speeding on his September 2016 single “Starboy”\n\n100 on the dash get me close to God\n\n“Blinding Lights” was also originally teased in a German Mercedes-Benz commercial, where The Weeknd is shown driving an electric car while the song plays in the background.\n\nhttps://www.youtube.com/watch?v=97eZHGbaGZQ", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 87}]}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "The city''s cold and empty (Oh)", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Las Vegas is nicknamed “Sin City” due to the city’s overwhelming presence of crime, drugs, and sexual promiscuity—all important themes throughout The Weeknd’s career. He also explores hedonism on his August 2011 song “Heaven or Las Vegas.”\n\nAbel experienced emptiness and heartbreak when he was briefly separated from Bella Hadid in 2019. The two have since reunited and emotionally completed The Weeknd.\n\nAbel previously touched upon his need for Bella on his November 2019 single, “Heartless”:\n\nYou just came back in my life\nYou never gave up on me (Why don’t you?)\nI’ll never know what you see (Why won’t you?)\nI don’t do well when alone (Oh yeah)", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 278}]}, {"id": 2, "text": "No one''s around to judge me (Oh)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I can''t see clearly when you''re gone", "range": {"end": 3, "start": 3}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "And I said, ooh, I''m blinded by the lights", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This song directly follows the outro of “Faith,” where The Weeknd speaks about being in the back of a police car presumably after an overdose:\n\nI ended up in the back of a flashing car\nWith the city shining on my face\nThe lights are blinding me again\n\nThe “lights” here not only represent the lights from the police car or the city but also the fame Abel’s enjoyed for his recording career. From stage lights to paparazzi camera flashes, he’s been “blinded” by many examples of a wealthy and successful life, and he doesn’t plan on stopping anytime soon. However, his celebrity life often overshadows his deep personal life. On his 2018 song “Privilege,” Abel discusses how many fans and media sources didn’t believe that he could have a real and genuine relationship with a partner because of his status in fame:\n\nThey said our love is just a game, I don’t care what they say\n\nNevertheless, his relationship seems to be real and sound, as he claims that it is the only thing that can keep him peacefully inserted in this lifestyle.\n\nAbel also uses a similar line on “Snowchild,” the fifth track from After Hours:\n\nLeaving, leaving into the night\nNow a nigga leaving, leaving\nLeaving into the night, oh", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 269}]}, {"id": 2, "text": "No, I can''t sleep until I feel your touch (Touch)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I said, ooh, I''m drowning in the night", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Oh, when I''m like this, you''re the one I trust", "range": {"end": 4, "start": 4}}]}, {"type": "Bridge", "lines": [{"id": 1, "text": "I''m just coming back to let you know (Back to let you know)", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This line is very similar to the song “Heartless,” released just days before this song. Here, Abel describes how his love for whom is presumed to be Bella Hadid is much stronger than he can say on the phone to her. This is different than the feelings Abel has shown in previous albums, with his typical themes usually revolving around never showing love towards anyone he is with and only using them for sex.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 149}]}, {"id": 2, "text": "I could never say it on the phone (Say it on the phone)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Will never let you go this time (Ooh)", "range": {"end": 3, "start": 3}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "I said, ooh, I''m blinded by the lights", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This song directly follows the outro of “Faith,” where The Weeknd speaks about being in the back of a police car presumably after an overdose:\n\nI ended up in the back of a flashing car\nWith the city shining on my face\nThe lights are blinding me again\n\nThe “lights” here not only represent the lights from the police car or the city but also the fame Abel’s enjoyed for his recording career. From stage lights to paparazzi camera flashes, he’s been “blinded” by many examples of a wealthy and successful life, and he doesn’t plan on stopping anytime soon. However, his celebrity life often overshadows his deep personal life. On his 2018 song “Privilege,” Abel discusses how many fans and media sources didn’t believe that he could have a real and genuine relationship with a partner because of his status in fame:\n\nThey said our love is just a game, I don’t care what they say\n\nNevertheless, his relationship seems to be real and sound, as he claims that it is the only thing that can keep him peacefully inserted in this lifestyle.\n\nAbel also uses a similar line on “Snowchild,” the fifth track from After Hours:\n\nLeaving, leaving into the night\nNow a nigga leaving, leaving\nLeaving into the night, oh", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 269}]}, {"id": 2, "text": "No, I can''t sleep until I feel your touch (Touch)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Hey, hey, hey", "range": {"end": 3, "start": 3}}]}, {"type": "Post-Chorus", "lines": [{"id": 1, "text": "Hey, hey, hey", "range": {"end": 1, "start": 1}}]}, {"type": "Outro", "lines": [{"id": 1, "text": "I said, ooh, I''m blinded by the lights", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This song directly follows the outro of “Faith,” where The Weeknd speaks about being in the back of a police car presumably after an overdose:\n\nI ended up in the back of a flashing car\nWith the city shining on my face\nThe lights are blinding me again\n\nThe “lights” here not only represent the lights from the police car or the city but also the fame Abel’s enjoyed for his recording career. From stage lights to paparazzi camera flashes, he’s been “blinded” by many examples of a wealthy and successful life, and he doesn’t plan on stopping anytime soon. However, his celebrity life often overshadows his deep personal life. On his 2018 song “Privilege,” Abel discusses how many fans and media sources didn’t believe that he could have a real and genuine relationship with a partner because of his status in fame:\n\nThey said our love is just a game, I don’t care what they say\n\nNevertheless, his relationship seems to be real and sound, as he claims that it is the only thing that can keep him peacefully inserted in this lifestyle.\n\nAbel also uses a similar line on “Snowchild,” the fifth track from After Hours:\n\nLeaving, leaving into the night\nNow a nigga leaving, leaving\nLeaving into the night, oh", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 269}]}, {"id": 2, "text": "No, I can''t sleep until I feel your touch", "range": {"end": 2, "start": 2}}]}], "schemaVersion": 1}', 'ly_v1_76be5700fd6dd9f1', true, 1, '2026-05-29 11:13:25.715987+00', '2026-05-29 11:13:25.715987+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('37508114-f365-4416-ad85-612fdc45afd4', '7c3cba29-b42c-4a5c-975f-80b9673caae8', 'genius', '{"source": "genius", "sections": [{"type": "Intro", "lines": [{"id": 1, "text": "Okay", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Mm, ah", "range": {"end": 2, "start": 2}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "I come and I go", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This song and its particular lyrics refer to the art of “ghosting”. Which is an act of leaving your partner without saying or doing anything.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 29}]}, {"id": 2, "text": "Tell me all the ways you need me", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I''m not here for long", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Catch me or I go Houdini\nCatch me or I go Houdini", "range": {"end": 8, "start": 4}, "annotations": [{"text": "Harry Houdini, born Erik Weisz (March 24, 1874 – October 31, 1926), was a Hungarian-American illusionist and stunt performer notorious for getting out of time-sensitive situations in handcuffs or straight jackets. He became famous for extricating himself from seemingly impossible situations, earning him the nickname “The Handcuff King” and “The Great Houdini.”\n\nDua Lipa references Houdini to describe the way that she’ll escape if he doesn’t make his mind up – like how Houdini only had a small amount of time to wriggle his way out of harm’s way – she won’t stay if she doesn’t have a reason to.\n\n\nPictured: Houdini Trying To Escape", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 80}]}, {"id": 5, "text": "I come and I go", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Prove you got the right to please me", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Everybody knows", "range": {"end": 7, "start": 7}}]}, {"type": "Verse 1", "lines": [{"id": 1, "text": "Time is passin'' like a solar eclipse", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Dua Lipa uses this as a simile to suggest that time is fleeting or passing quickly, much like the relatively short-lived event of a solar eclipse, implying that it seems to move swiftly and that moments can feel transient or fleeting.\n\nA solar eclipse occurs when the moon passes between the Earth and the sun, temporarily blocking out the sun’s light. It’s a relatively brief and rare event, lasting only a few minutes in any given location (generally 10 seconds to 7.5 minutes).\n\nhttps://filepicker-images.genius.com/SMzaAkfTdqcVR2f8PPf2_ap23287640299161_custom-263d9e88a3996e07224fd878e5831a0169d07c42-s1300-c85.webp\nPictured: People watch a rare “ring of fire” solar eclipse along the Las Vegas Strip, on October 14, 2023", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 31}]}, {"id": 2, "text": "See you watchin'' and you blow me a kiss", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "It''s your moment, baby, don''t let it slip", "range": {"end": 3, "start": 3}, "annotations": []}, {"id": 4, "text": "Come in closer, are you readin'' my lips?", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "They say I come and I go", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This song and its particular lyrics refer to the art of “ghosting”. Which is an act of leaving your partner without saying or doing anything.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 29}]}, {"id": 2, "text": "Tell me all the ways you need me", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I''m not here for long", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Catch me or I go Houdini\nCatch me or I go Houdini", "range": {"end": 8, "start": 4}, "annotations": [{"text": "Harry Houdini, born Erik Weisz (March 24, 1874 – October 31, 1926), was a Hungarian-American illusionist and stunt performer notorious for getting out of time-sensitive situations in handcuffs or straight jackets. He became famous for extricating himself from seemingly impossible situations, earning him the nickname “The Handcuff King” and “The Great Houdini.”\n\nDua Lipa references Houdini to describe the way that she’ll escape if he doesn’t make his mind up – like how Houdini only had a small amount of time to wriggle his way out of harm’s way – she won’t stay if she doesn’t have a reason to.\n\n\nPictured: Houdini Trying To Escape", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 80}]}, {"id": 5, "text": "I come and I go", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Prove you got the right to please me", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Everybody knows", "range": {"end": 7, "start": 7}}]}, {"type": "Post-Chorus", "lines": [{"id": 1, "text": "If you''re good enough, you''ll find the way", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Although Dua warns her potential suitor that she could leave him for the next one in a heartbeat, the singer confesses in the post-chorus that she’s willing to change her roving ways and stick around, but only if her partner proves himself worthy of her attention.\n\nDuring her November 2023 interview with Rolling Stone, Dua revealed that she likes to leave room for positive outcomes like this in all her songs:\n\n“Maybe you could be the one to make me stay,” feels like an unexpected line but also it’s the idea that you never really know what’s gonna happen, and I love to have a little twist of something positive in all the songs. I feel like songs, no matter what, I end up manifesting them, in one way or another they become a part of my life, regardless of how I feel in the moment, later down the line. There’s always some kind of payoff, in a way, ‘cause it never feels right for it to be a song that’s gonna be out there that maybe lots of people are gonna sing or that I’m gonna sing on stage every night and for it to not have some kind of payoff, or some kind of happy ending, or some kind of feeling that you can get through whatever is happening in your life.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 27}]}, {"id": 2, "text": "Maybe you could cause a girl to change (Her ways)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Do you think about it night and day?", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Maybe you could be the one to make me stay", "range": {"end": 4, "start": 4}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "Everything you say is soundin'' so sweet (Ah-ah)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "But do you practise everything that you preach? (Ah-ah)", "range": {"end": 2, "start": 2}, "annotations": [{"text": "This line is an obvious reference to the line “Some people do, but some, they just like to talk” in Want To and to “You don’t have to be so cautious if you practice what you preach” in High.\nIn all three songs (the above mentioned and Houdini) she is comes across as a strong character, especially in Houdini and Want To, she really tells us that she is the one in charge.\nDua Lipa never precisely said what she means with the quoted lines, but considering the meaning of the saying she might refer to some disappointing interactions she had with poeple in the past. This would be in line with her use of a simular line in “Good in Bed”:\n“You love to disappoint me, don’t ya?\nYou tell me what I want, but ain’t no follow through”\nBut in the context of the songs she uses them in, she might be using it to distance herself from people who don’t practise what they preach, claiming strength and determination by implying that she does do that.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 13}]}, {"id": 3, "text": "I need something that''ll make me believe (Ah-ah)", "range": {"end": 3, "start": 3}, "annotations": []}, {"id": 4, "text": "If you got it, baby, give it to me", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "They say I come and I go", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This song and its particular lyrics refer to the art of “ghosting”. Which is an act of leaving your partner without saying or doing anything.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 29}]}, {"id": 2, "text": "Tell me all the ways you need me", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I''m not here for long", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Catch me or I go Houdini\nCatch me or I go Houdini", "range": {"end": 8, "start": 4}, "annotations": [{"text": "Harry Houdini, born Erik Weisz (March 24, 1874 – October 31, 1926), was a Hungarian-American illusionist and stunt performer notorious for getting out of time-sensitive situations in handcuffs or straight jackets. He became famous for extricating himself from seemingly impossible situations, earning him the nickname “The Handcuff King” and “The Great Houdini.”\n\nDua Lipa references Houdini to describe the way that she’ll escape if he doesn’t make his mind up – like how Houdini only had a small amount of time to wriggle his way out of harm’s way – she won’t stay if she doesn’t have a reason to.\n\n\nPictured: Houdini Trying To Escape", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 80}]}, {"id": 5, "text": "I come and I go (I come and I go)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Prove you got the right to please me", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Everybody knows (I''m not here for long)", "range": {"end": 7, "start": 7}}]}, {"type": "Post-Chorus", "lines": [{"id": 1, "text": "If you''re good enough, you''ll find the way", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Although Dua warns her potential suitor that she could leave him for the next one in a heartbeat, the singer confesses in the post-chorus that she’s willing to change her roving ways and stick around, but only if her partner proves himself worthy of her attention.\n\nDuring her November 2023 interview with Rolling Stone, Dua revealed that she likes to leave room for positive outcomes like this in all her songs:\n\n“Maybe you could be the one to make me stay,” feels like an unexpected line but also it’s the idea that you never really know what’s gonna happen, and I love to have a little twist of something positive in all the songs. I feel like songs, no matter what, I end up manifesting them, in one way or another they become a part of my life, regardless of how I feel in the moment, later down the line. There’s always some kind of payoff, in a way, ‘cause it never feels right for it to be a song that’s gonna be out there that maybe lots of people are gonna sing or that I’m gonna sing on stage every night and for it to not have some kind of payoff, or some kind of happy ending, or some kind of feeling that you can get through whatever is happening in your life.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 27}]}, {"id": 2, "text": "Maybe you could cause a girl to change (Her ways)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Do you think about it night and day?", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Maybe you could be the one to make me stay", "range": {"end": 4, "start": 4}}]}, {"type": "Bridge", "lines": [{"id": 1, "text": "Oh-oh", "range": {"end": 1, "start": 1}, "annotations": []}, {"id": 2, "text": "Ooh", "range": {"end": 2, "start": 2}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "I come and I go", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This song and its particular lyrics refer to the art of “ghosting”. Which is an act of leaving your partner without saying or doing anything.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 29}]}, {"id": 2, "text": "Tell me all the ways you need me (Ooh)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I''m not here for long", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Catch me or I go Houdini\nCatch me or I go Houdini", "range": {"end": 8, "start": 4}, "annotations": [{"text": "Harry Houdini, born Erik Weisz (March 24, 1874 – October 31, 1926), was a Hungarian-American illusionist and stunt performer notorious for getting out of time-sensitive situations in handcuffs or straight jackets. He became famous for extricating himself from seemingly impossible situations, earning him the nickname “The Handcuff King” and “The Great Houdini.”\n\nDua Lipa references Houdini to describe the way that she’ll escape if he doesn’t make his mind up – like how Houdini only had a small amount of time to wriggle his way out of harm’s way – she won’t stay if she doesn’t have a reason to.\n\n\nPictured: Houdini Trying To Escape", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 80}]}, {"id": 5, "text": "I come and I go (I come and I go)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Prove you got the right to please me", "range": {"end": 6, "start": 6}, "annotations": []}, {"id": 7, "text": "Everybody knows (I''m not here for long)", "range": {"end": 7, "start": 7}}]}, {"type": "Outro", "lines": [{"id": 1, "text": "Houdini (Ah)", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Harry Houdini, born Erik Weisz (March 24, 1874 – October 31, 1926), was a Hungarian-American illusionist and stunt performer notorious for getting out of time-sensitive situations in handcuffs or straight jackets. He became famous for extricating himself from seemingly impossible situations, earning him the nickname “The Handcuff King” and “The Great Houdini.”\n\nDua Lipa references Houdini to describe the way that she’ll escape if he doesn’t make his mind up – like how Houdini only had a small amount of time to wriggle his way out of harm’s way – she won’t stay if she doesn’t have a reason to.\n\n\nPictured: Houdini Trying To Escape", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 80}]}, {"id": 2, "text": "Catch me or I go Houdini", "range": {"end": 2, "start": 2}}]}], "schemaVersion": 1}', 'ly_v1_79de1642c08582df', true, 1, '2026-05-29 11:13:26.980665+00', '2026-05-29 11:13:26.980665+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('df1c0e2f-402f-42c5-8cb9-b6fbe7eb0569', 'a803252e-b76d-4839-8332-a47c83b63ed2', 'genius', '{"source": "genius", "sections": [{"type": "Verse 1", "lines": [{"id": 1, "text": "I got my driver''s license last week", "range": {"end": 1, "start": 1}, "annotations": [{"text": "As Rodrigo told the New York Times, this lyric was originally an excerpt from a diary entry. She elaborated on this during a Vogue interview:\n\nI was aimlessly driving around my neighborhood, listening to sad music, and bringing up these emotions I hadn’t felt in a while. I’d just got my license, so I was relishing my freedom. When I got home, I sat down at the piano — and I love songs that feel like a diary entry and are confessional — so I took some lyrics from my diary and went from there.\n\n\n\nA parody of Rodrigo’s driver’s license, as printed on her offical merch.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 61}]}, {"id": 2, "text": "Just like we always talked about", "range": {"end": 2, "start": 2}, "annotations": [{"text": "Joshua Bassett, who the song is rumored to be about, helped teach Olivia how to drive. In an Instagram Story from January 2020, Olivia talked about getting her first driving experience with Joshua, after they learned that the song they wrote together, “Just for a Moment.” would be used in High School Musical: The Musical: The Series:\n\nWe celebrated and we went to In-N-Out, and I couldn’t drive actually. I was sixteen, but I didn’t have my permit, and so he took me in his car, and we drove around the In-N-Out parking lot. That was my first time driving, so I’ll always remember that.\n\nOlivia has also referenced driving on her unreleased track “Gross”:\n\nAnd driving in your car, I feel all grown up", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 88}]}, {"id": 3, "text": "''Cause you were so excited for me", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "To finally drive up to your house", "range": {"end": 4, "start": 4}, "annotations": [{"text": "Olivia Rodrigo was born in Temecula, California, a city of about 114,000 people though currently, she resides in Los Angeles. Joshua Bassett, who the song is rumored to be based off of, is from Oceanside, California which a population of about 167,000. Both stars currently reside in LA, where the song can be assumed to take place. The suburbs of a city are smaller communities adjacent to a city. Los Angeles has the most suburban cities in the United States with 15.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 51}]}, {"id": 5, "text": "But today, I drove through the suburbs", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Crying ''cause you weren''t around", "range": {"end": 6, "start": 6}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "And you''re probably with that blonde girl", "range": {"end": 1, "start": 1}, "annotations": [{"text": "It’s rumored that Olivia and Joshua Bassett began dating in 2019 while filming High School Musical: The Musical: The Series, and called it quits in early 2020.\n\nIn June 2020, Joshua and Sabrina Carpenter were spotted together at a protest, sparking dating rumors. Olivia posted the demo version of the song on Instagram the following month.\n\nSabrina has blonde hair and is four years older than Olivia. However, in the original lyrics, Olivia instead referred to the girl as a brunette. While Olivia has stated that some lyrics were changed at the recommendation of the song’s producer, Dan Nigro, the reason for this specific change has not been confirmed. There are multiple theories as to why, including “blonde” having less syllables than “brunette,” thus improving the lyrical flow; to emphasize how different the girl is from Olivia, who is a brunette herself; or that Olivia was being intentionally cryptic with the original lyrics.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 374}]}, {"id": 2, "text": "Who always made me doubt", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "She''s so much older than me", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "She''s everything I''m insecure about", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Yeah, today, I drove through the suburbs", "range": {"end": 5, "start": 5}, "annotations": []}, {"id": 6, "text": "''Cause how could I ever love someone else?", "range": {"end": 6, "start": 6}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "And I know we weren''t perfect, but I''ve never felt this way for no one", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "And I just can''t imagine how you could be so okay now that I''m gone", "range": {"end": 2, "start": 2}, "annotations": [{"text": "This line is yet another confirmation of the theory that Joshua Bassett is the subject of Rodrigo’s multi-platinum debut single.\n\nAround the release of the track, rumors were swirling that Bassett and other Disney star Sabrina Carpenter were dating. Though not confirmed by either party, it would explain why Rodrigo would be upset that Bassett moved on so quickly without her.\n\nSabrina Carpenter’s song “Skin” was released in apparent response to “drivers license.” Some of the lines in the scathing track appear to be directly pointing to Bassett:\n\nYou can try\nTo get under my, under my, under my skin\nWhile he’s on mine\n\nWhile nothing is confirmed regarding who the songs are directed to, it appears to be a painful shot at Bassett for starting up a new relationship with Carpenter while Rodrigo was still getting over their relationship.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 56}]}, {"id": 3, "text": "Guess you didn''t mean what you wrote in that song about me", "range": {"end": 3, "start": 3}, "annotations": [{"text": "This could be a reference to Joshua Bassett’s July 2020 song “Anyone Else.” He stated that he wrote this song in the Salt Lake City apartment he lived in while filming season one of High School Musical: The Musical: The Series, after realizing that he was “hopelessly falling in love with a close friend… who was in a relationship.”\n\nSince the production of the show began back in early 2019, Bassett could’ve been referencing Rodrigo’s then-relationship with Ethan Wacker, her former Bizaardvark co-star.\n\nThis line differs from the original version of the song teased on Instagram on July 23, 2020, in which Rodrigo sings:\n\nAnd I don’t believe you when you say I did nothing wrong", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 241}]}, {"id": 4, "text": "''Cause you said forever, now I drive alone past your street", "range": {"end": 4, "start": 4}, "annotations": [{"text": "This line alludes to breakups, the theme of the song as Rodrigo has stated, and reminiscing on memories. As the song is presumably about Joshua Bassett and Olivia promising to obtain a driver’s license, — as stated in the song bio — the line also supports her fulfilling the promise.\n\nIn addition, this specific line was heavily popularized on the social media platform, TikTok, where most most of the short videos using this audio involved relationships and melancholic settings.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 71}]}]}, {"type": "Verse 3", "lines": [{"id": 1, "text": "And all my friends are tired", "range": {"end": 1, "start": 1}, "annotations": [{"text": "These lyrics are reminiscent of another SOUR track, called “favourite crime”:\n\nI crossed my heart as you crossed the line\nAnd I defended you to all my friends\n\nOlivia also sang a similar lyric on one of her unreleased songs, “Gross”:\n\nI bring you up in every conversation\n\nOlivia said on an Instagram Live (at about 29:45) the night the song came out that this line was especially about her former Bizaardvark co-star Madison Hu. She said she talked to Madison about all of her problems and Madison was more of the neutral one in the situation.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 203}]}, {"id": 2, "text": "Of hearing how much I miss you, but", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I kinda feel sorry for them", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "''Cause they''ll never know you the way that I do", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Yeah, today, I drove through the suburbs", "range": {"end": 5, "start": 5}, "annotations": [{"text": "On Olivia’s 2022 project for Disney+, Olivia Rodrigo: driving home 2 u (a SOUR film), she explained:\n\nThat line can very literally be, like, I was driving home to your house or whatever, but I remember, at that time, I was really reconciling with the fact that sometimes, when you love a person so much and you spend so much time with them, that’s who you feel the most at home with. And I remember listening to that song, even when I hadn’t put it out, when I just had a demo on my phone and I’d drive around and listen to it. Every time that came on, my stomach would drop, just because I felt like it was so acutely how I was feeling.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 18}]}, {"id": 6, "text": "And pictured I was driving home to you", "range": {"end": 6, "start": 6}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "And I know we weren''t perfect, but I''ve never felt this way for no one, oh", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "And I just can''t imagine how you could be so okay now that I''m gone", "range": {"end": 2, "start": 2}, "annotations": [{"text": "This line is yet another confirmation of the theory that Joshua Bassett is the subject of Rodrigo’s multi-platinum debut single.\n\nAround the release of the track, rumors were swirling that Bassett and other Disney star Sabrina Carpenter were dating. Though not confirmed by either party, it would explain why Rodrigo would be upset that Bassett moved on so quickly without her.\n\nSabrina Carpenter’s song “Skin” was released in apparent response to “drivers license.” Some of the lines in the scathing track appear to be directly pointing to Bassett:\n\nYou can try\nTo get under my, under my, under my skin\nWhile he’s on mine\n\nWhile nothing is confirmed regarding who the songs are directed to, it appears to be a painful shot at Bassett for starting up a new relationship with Carpenter while Rodrigo was still getting over their relationship.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 56}]}, {"id": 3, "text": "I guess you didn''t mean what you wrote in that song about me", "range": {"end": 3, "start": 3}, "annotations": [{"text": "This could be a reference to Joshua Bassett’s July 2020 song “Anyone Else.” He stated that he wrote this song in the Salt Lake City apartment he lived in while filming season one of High School Musical: The Musical: The Series, after realizing that he was “hopelessly falling in love with a close friend… who was in a relationship.”\n\nSince the production of the show began back in early 2019, Bassett could’ve been referencing Rodrigo’s then-relationship with Ethan Wacker, her former Bizaardvark co-star.\n\nThis line differs from the original version of the song teased on Instagram on July 23, 2020, in which Rodrigo sings:\n\nAnd I don’t believe you when you say I did nothing wrong", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 241}]}, {"id": 4, "text": "''Cause you said forever, now I drive alone past your street", "range": {"end": 4, "start": 4}, "annotations": [{"text": "This line alludes to breakups, the theme of the song as Rodrigo has stated, and reminiscing on memories. As the song is presumably about Joshua Bassett and Olivia promising to obtain a driver’s license, — as stated in the song bio — the line also supports her fulfilling the promise.\n\nIn addition, this specific line was heavily popularized on the social media platform, TikTok, where most most of the short videos using this audio involved relationships and melancholic settings.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 71}]}]}, {"type": "Bridge", "lines": [{"id": 1, "text": "Red lights, stop signs", "range": {"end": 1, "start": 1}, "annotations": [{"text": "In keeping with the ideology of driving through the song, Rodrigo points to two symbols of stopping: traffic lights and stop signs, symbolizing the ending of her relationship.\n\nOlivia posted these lines to her Instagram accompanied by a red picture of her, in line with the songs.\n\n\n\nThis line is the first of three colored lyrics in the bridge, the other two colors being white and blue.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 95}]}, {"id": 2, "text": "I still see your face in the white cars, front yards", "range": {"end": 2, "start": 2}, "annotations": [{"text": "This line further points towards the song being about Joshua Bassett. As we know from Joshua’s YouTube channel, he does in fact drive a white Honda.\n\nhttps://www.youtube.com/watch?v=-c2o6wSLblk\n\nFurthermore, on January 4th, 2020, Bassett teased his then-upcoming song “Lie Lie Lie” on Instagram, and posted a picture of him and a blonde-haired girl in a dimly lit car, linking back to the second verse where Rodrigo sings “and you’re probably with that blonde girl.” Similarly, in Rodrigo’s “drivers license” video, she can also be seen in a dimly lit car.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 131}]}, {"id": 3, "text": "Can''t drive past the places we used to go to", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "''Cause I still fuckin'' love you, babe (Ooh, ooh-ooh, ooh, ooh-ooh)\nBut I still fuckin'' love you, babe (Ooh, ooh-ooh, ooh, ooh-ooh)", "range": {"end": 9, "start": 4}, "annotations": [{"text": "Olivia talked about writing this line with producer Dan Nigro and the decision to swear, in The New York Times series “Diary of a Song”:\n\nhttps://youtu.be/hWq_ma9ZDxk?t=425\n\nDan was like, “What if we say, ‘I still fuckin’ love you,‘” and I’m like, “That’s brilliant. Let’s do it.” […] And I think it’s actually really cool that I did swear in my first song. I guess it’s a nice, like, \"Ah, look, I’m an adult. I can say—” I’m not an adult, I’m like, seventeen, haha.\n\nIn the clean version and in certain live performances, these lines are changed to:\n\n[‘Cause/But] you know I still love you, babe", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 99}]}, {"id": 5, "text": "Sidewalks we crossed", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "I still hear your voice in the traffic, we''re laughing", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Over all the noise", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "God, I''m so blue, know we''re through", "range": {"end": 8, "start": 8}, "annotations": [{"text": "“Feeling blue” is a phrase meaning to feel depressed or disappointed. The color blue is often associated with being sad, with a genre of music even being named after these emotions.\n\nThe music video for “drivers license” contains darker colors, tinting Olivia’s skin tone. In scenes within the video, she is cast in a blue shade. This is a clever nod to this line, as well as a unique rendering of her emotions throughout the song.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 180}]}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "I know we weren''t perfect, but I''ve never felt this way for no one", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "And I just can''t imagine how you could be so okay now that I''m gone", "range": {"end": 2, "start": 2}, "annotations": [{"text": "This line is yet another confirmation of the theory that Joshua Bassett is the subject of Rodrigo’s multi-platinum debut single.\n\nAround the release of the track, rumors were swirling that Bassett and other Disney star Sabrina Carpenter were dating. Though not confirmed by either party, it would explain why Rodrigo would be upset that Bassett moved on so quickly without her.\n\nSabrina Carpenter’s song “Skin” was released in apparent response to “drivers license.” Some of the lines in the scathing track appear to be directly pointing to Bassett:\n\nYou can try\nTo get under my, under my, under my skin\nWhile he’s on mine\n\nWhile nothing is confirmed regarding who the songs are directed to, it appears to be a painful shot at Bassett for starting up a new relationship with Carpenter while Rodrigo was still getting over their relationship.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 56}]}, {"id": 3, "text": "Guess you didn''t mean what you wrote in that song about me", "range": {"end": 3, "start": 3}, "annotations": [{"text": "This could be a reference to Joshua Bassett’s July 2020 song “Anyone Else.” He stated that he wrote this song in the Salt Lake City apartment he lived in while filming season one of High School Musical: The Musical: The Series, after realizing that he was “hopelessly falling in love with a close friend… who was in a relationship.”\n\nSince the production of the show began back in early 2019, Bassett could’ve been referencing Rodrigo’s then-relationship with Ethan Wacker, her former Bizaardvark co-star.\n\nThis line differs from the original version of the song teased on Instagram on July 23, 2020, in which Rodrigo sings:\n\nAnd I don’t believe you when you say I did nothing wrong", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 241}]}, {"id": 4, "text": "''Cause you said forever, now I drive alone past your street", "range": {"end": 4, "start": 4}, "annotations": [{"text": "This line alludes to breakups, the theme of the song as Rodrigo has stated, and reminiscing on memories. As the song is presumably about Joshua Bassett and Olivia promising to obtain a driver’s license, — as stated in the song bio — the line also supports her fulfilling the promise.\n\nIn addition, this specific line was heavily popularized on the social media platform, TikTok, where most most of the short videos using this audio involved relationships and melancholic settings.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 71}]}]}, {"type": "Outro", "lines": [{"id": 1, "text": "Yeah, you said forever, now I drive alone past your street", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This line alludes to breakups, the theme of the song as Rodrigo has stated, and reminiscing on memories. As the song is presumably about Joshua Bassett and Olivia promising to obtain a driver’s license, — as stated in the song bio — the line also supports her fulfilling the promise.\n\nIn addition, this specific line was heavily popularized on the social media platform, TikTok, where most most of the short videos using this audio involved relationships and melancholic settings.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 71}]}]}], "schemaVersion": 1}', 'ly_v1_f61ad3d67528d2ab', true, 1, '2026-05-29 11:13:27.587459+00', '2026-05-29 11:13:27.587459+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('3a4e22fa-f27c-4b17-8ee2-c7c0e5d7de80', '93d580b3-10ae-4123-871c-b3f2508256b6', 'genius', '{"source": "genius", "sections": [{"type": "Verse 1", "lines": [{"id": 1, "text": "I got my driver''s license last week", "range": {"end": 1, "start": 1}, "annotations": [{"text": "As Rodrigo told the New York Times, this lyric was originally an excerpt from a diary entry. She elaborated on this during a Vogue interview:\n\nI was aimlessly driving around my neighborhood, listening to sad music, and bringing up these emotions I hadn’t felt in a while. I’d just got my license, so I was relishing my freedom. When I got home, I sat down at the piano — and I love songs that feel like a diary entry and are confessional — so I took some lyrics from my diary and went from there.\n\n\n\nA parody of Rodrigo’s driver’s license, as printed on her offical merch.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 61}]}, {"id": 2, "text": "Just like we always talked about", "range": {"end": 2, "start": 2}, "annotations": [{"text": "Joshua Bassett, who the song is rumored to be about, helped teach Olivia how to drive. In an Instagram Story from January 2020, Olivia talked about getting her first driving experience with Joshua, after they learned that the song they wrote together, “Just for a Moment.” would be used in High School Musical: The Musical: The Series:\n\nWe celebrated and we went to In-N-Out, and I couldn’t drive actually. I was sixteen, but I didn’t have my permit, and so he took me in his car, and we drove around the In-N-Out parking lot. That was my first time driving, so I’ll always remember that.\n\nOlivia has also referenced driving on her unreleased track “Gross”:\n\nAnd driving in your car, I feel all grown up", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 88}]}, {"id": 3, "text": "''Cause you were so excited for me", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "To finally drive up to your house", "range": {"end": 4, "start": 4}, "annotations": [{"text": "Olivia Rodrigo was born in Temecula, California, a city of about 114,000 people though currently, she resides in Los Angeles. Joshua Bassett, who the song is rumored to be based off of, is from Oceanside, California which a population of about 167,000. Both stars currently reside in LA, where the song can be assumed to take place. The suburbs of a city are smaller communities adjacent to a city. Los Angeles has the most suburban cities in the United States with 15.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 51}]}, {"id": 5, "text": "But today, I drove through the suburbs", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Crying ''cause you weren''t around", "range": {"end": 6, "start": 6}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "And you''re probably with that blonde girl", "range": {"end": 1, "start": 1}, "annotations": [{"text": "It’s rumored that Olivia and Joshua Bassett began dating in 2019 while filming High School Musical: The Musical: The Series, and called it quits in early 2020.\n\nIn June 2020, Joshua and Sabrina Carpenter were spotted together at a protest, sparking dating rumors. Olivia posted the demo version of the song on Instagram the following month.\n\nSabrina has blonde hair and is four years older than Olivia. However, in the original lyrics, Olivia instead referred to the girl as a brunette. While Olivia has stated that some lyrics were changed at the recommendation of the song’s producer, Dan Nigro, the reason for this specific change has not been confirmed. There are multiple theories as to why, including “blonde” having less syllables than “brunette,” thus improving the lyrical flow; to emphasize how different the girl is from Olivia, who is a brunette herself; or that Olivia was being intentionally cryptic with the original lyrics.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 374}]}, {"id": 2, "text": "Who always made me doubt", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "She''s so much older than me", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "She''s everything I''m insecure about", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Yeah, today, I drove through the suburbs", "range": {"end": 5, "start": 5}, "annotations": []}, {"id": 6, "text": "''Cause how could I ever love someone else?", "range": {"end": 6, "start": 6}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "And I know we weren''t perfect, but I''ve never felt this way for no one", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "And I just can''t imagine how you could be so okay now that I''m gone", "range": {"end": 2, "start": 2}, "annotations": [{"text": "This line is yet another confirmation of the theory that Joshua Bassett is the subject of Rodrigo’s multi-platinum debut single.\n\nAround the release of the track, rumors were swirling that Bassett and other Disney star Sabrina Carpenter were dating. Though not confirmed by either party, it would explain why Rodrigo would be upset that Bassett moved on so quickly without her.\n\nSabrina Carpenter’s song “Skin” was released in apparent response to “drivers license.” Some of the lines in the scathing track appear to be directly pointing to Bassett:\n\nYou can try\nTo get under my, under my, under my skin\nWhile he’s on mine\n\nWhile nothing is confirmed regarding who the songs are directed to, it appears to be a painful shot at Bassett for starting up a new relationship with Carpenter while Rodrigo was still getting over their relationship.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 56}]}, {"id": 3, "text": "Guess you didn''t mean what you wrote in that song about me", "range": {"end": 3, "start": 3}, "annotations": [{"text": "This could be a reference to Joshua Bassett’s July 2020 song “Anyone Else.” He stated that he wrote this song in the Salt Lake City apartment he lived in while filming season one of High School Musical: The Musical: The Series, after realizing that he was “hopelessly falling in love with a close friend… who was in a relationship.”\n\nSince the production of the show began back in early 2019, Bassett could’ve been referencing Rodrigo’s then-relationship with Ethan Wacker, her former Bizaardvark co-star.\n\nThis line differs from the original version of the song teased on Instagram on July 23, 2020, in which Rodrigo sings:\n\nAnd I don’t believe you when you say I did nothing wrong", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 241}]}, {"id": 4, "text": "''Cause you said forever, now I drive alone past your street", "range": {"end": 4, "start": 4}, "annotations": [{"text": "This line alludes to breakups, the theme of the song as Rodrigo has stated, and reminiscing on memories. As the song is presumably about Joshua Bassett and Olivia promising to obtain a driver’s license, — as stated in the song bio — the line also supports her fulfilling the promise.\n\nIn addition, this specific line was heavily popularized on the social media platform, TikTok, where most most of the short videos using this audio involved relationships and melancholic settings.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 71}]}]}, {"type": "Verse 3", "lines": [{"id": 1, "text": "And all my friends are tired", "range": {"end": 1, "start": 1}, "annotations": [{"text": "These lyrics are reminiscent of another SOUR track, called “favourite crime”:\n\nI crossed my heart as you crossed the line\nAnd I defended you to all my friends\n\nOlivia also sang a similar lyric on one of her unreleased songs, “Gross”:\n\nI bring you up in every conversation\n\nOlivia said on an Instagram Live (at about 29:45) the night the song came out that this line was especially about her former Bizaardvark co-star Madison Hu. She said she talked to Madison about all of her problems and Madison was more of the neutral one in the situation.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 203}]}, {"id": 2, "text": "Of hearing how much I miss you, but", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I kinda feel sorry for them", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "''Cause they''ll never know you the way that I do", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Yeah, today, I drove through the suburbs", "range": {"end": 5, "start": 5}, "annotations": [{"text": "On Olivia’s 2022 project for Disney+, Olivia Rodrigo: driving home 2 u (a SOUR film), she explained:\n\nThat line can very literally be, like, I was driving home to your house or whatever, but I remember, at that time, I was really reconciling with the fact that sometimes, when you love a person so much and you spend so much time with them, that’s who you feel the most at home with. And I remember listening to that song, even when I hadn’t put it out, when I just had a demo on my phone and I’d drive around and listen to it. Every time that came on, my stomach would drop, just because I felt like it was so acutely how I was feeling.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 18}]}, {"id": 6, "text": "And pictured I was driving home to you", "range": {"end": 6, "start": 6}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "And I know we weren''t perfect, but I''ve never felt this way for no one, oh", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "And I just can''t imagine how you could be so okay now that I''m gone", "range": {"end": 2, "start": 2}, "annotations": [{"text": "This line is yet another confirmation of the theory that Joshua Bassett is the subject of Rodrigo’s multi-platinum debut single.\n\nAround the release of the track, rumors were swirling that Bassett and other Disney star Sabrina Carpenter were dating. Though not confirmed by either party, it would explain why Rodrigo would be upset that Bassett moved on so quickly without her.\n\nSabrina Carpenter’s song “Skin” was released in apparent response to “drivers license.” Some of the lines in the scathing track appear to be directly pointing to Bassett:\n\nYou can try\nTo get under my, under my, under my skin\nWhile he’s on mine\n\nWhile nothing is confirmed regarding who the songs are directed to, it appears to be a painful shot at Bassett for starting up a new relationship with Carpenter while Rodrigo was still getting over their relationship.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 56}]}, {"id": 3, "text": "I guess you didn''t mean what you wrote in that song about me", "range": {"end": 3, "start": 3}, "annotations": [{"text": "This could be a reference to Joshua Bassett’s July 2020 song “Anyone Else.” He stated that he wrote this song in the Salt Lake City apartment he lived in while filming season one of High School Musical: The Musical: The Series, after realizing that he was “hopelessly falling in love with a close friend… who was in a relationship.”\n\nSince the production of the show began back in early 2019, Bassett could’ve been referencing Rodrigo’s then-relationship with Ethan Wacker, her former Bizaardvark co-star.\n\nThis line differs from the original version of the song teased on Instagram on July 23, 2020, in which Rodrigo sings:\n\nAnd I don’t believe you when you say I did nothing wrong", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 241}]}, {"id": 4, "text": "''Cause you said forever, now I drive alone past your street", "range": {"end": 4, "start": 4}, "annotations": [{"text": "This line alludes to breakups, the theme of the song as Rodrigo has stated, and reminiscing on memories. As the song is presumably about Joshua Bassett and Olivia promising to obtain a driver’s license, — as stated in the song bio — the line also supports her fulfilling the promise.\n\nIn addition, this specific line was heavily popularized on the social media platform, TikTok, where most most of the short videos using this audio involved relationships and melancholic settings.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 71}]}]}, {"type": "Bridge", "lines": [{"id": 1, "text": "Red lights, stop signs", "range": {"end": 1, "start": 1}, "annotations": [{"text": "In keeping with the ideology of driving through the song, Rodrigo points to two symbols of stopping: traffic lights and stop signs, symbolizing the ending of her relationship.\n\nOlivia posted these lines to her Instagram accompanied by a red picture of her, in line with the songs.\n\n\n\nThis line is the first of three colored lyrics in the bridge, the other two colors being white and blue.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 95}]}, {"id": 2, "text": "I still see your face in the white cars, front yards", "range": {"end": 2, "start": 2}, "annotations": [{"text": "This line further points towards the song being about Joshua Bassett. As we know from Joshua’s YouTube channel, he does in fact drive a white Honda.\n\nhttps://www.youtube.com/watch?v=-c2o6wSLblk\n\nFurthermore, on January 4th, 2020, Bassett teased his then-upcoming song “Lie Lie Lie” on Instagram, and posted a picture of him and a blonde-haired girl in a dimly lit car, linking back to the second verse where Rodrigo sings “and you’re probably with that blonde girl.” Similarly, in Rodrigo’s “drivers license” video, she can also be seen in a dimly lit car.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 131}]}, {"id": 3, "text": "Can''t drive past the places we used to go to", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "''Cause I still fuckin'' love you, babe (Ooh, ooh-ooh, ooh, ooh-ooh)\nBut I still fuckin'' love you, babe (Ooh, ooh-ooh, ooh, ooh-ooh)", "range": {"end": 9, "start": 4}, "annotations": [{"text": "Olivia talked about writing this line with producer Dan Nigro and the decision to swear, in The New York Times series “Diary of a Song”:\n\nhttps://youtu.be/hWq_ma9ZDxk?t=425\n\nDan was like, “What if we say, ‘I still fuckin’ love you,‘” and I’m like, “That’s brilliant. Let’s do it.” […] And I think it’s actually really cool that I did swear in my first song. I guess it’s a nice, like, \"Ah, look, I’m an adult. I can say—” I’m not an adult, I’m like, seventeen, haha.\n\nIn the clean version and in certain live performances, these lines are changed to:\n\n[‘Cause/But] you know I still love you, babe", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 99}]}, {"id": 5, "text": "Sidewalks we crossed", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "I still hear your voice in the traffic, we''re laughing", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Over all the noise", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "God, I''m so blue, know we''re through", "range": {"end": 8, "start": 8}, "annotations": [{"text": "“Feeling blue” is a phrase meaning to feel depressed or disappointed. The color blue is often associated with being sad, with a genre of music even being named after these emotions.\n\nThe music video for “drivers license” contains darker colors, tinting Olivia’s skin tone. In scenes within the video, she is cast in a blue shade. This is a clever nod to this line, as well as a unique rendering of her emotions throughout the song.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 180}]}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "I know we weren''t perfect, but I''ve never felt this way for no one", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "And I just can''t imagine how you could be so okay now that I''m gone", "range": {"end": 2, "start": 2}, "annotations": [{"text": "This line is yet another confirmation of the theory that Joshua Bassett is the subject of Rodrigo’s multi-platinum debut single.\n\nAround the release of the track, rumors were swirling that Bassett and other Disney star Sabrina Carpenter were dating. Though not confirmed by either party, it would explain why Rodrigo would be upset that Bassett moved on so quickly without her.\n\nSabrina Carpenter’s song “Skin” was released in apparent response to “drivers license.” Some of the lines in the scathing track appear to be directly pointing to Bassett:\n\nYou can try\nTo get under my, under my, under my skin\nWhile he’s on mine\n\nWhile nothing is confirmed regarding who the songs are directed to, it appears to be a painful shot at Bassett for starting up a new relationship with Carpenter while Rodrigo was still getting over their relationship.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 56}]}, {"id": 3, "text": "Guess you didn''t mean what you wrote in that song about me", "range": {"end": 3, "start": 3}, "annotations": [{"text": "This could be a reference to Joshua Bassett’s July 2020 song “Anyone Else.” He stated that he wrote this song in the Salt Lake City apartment he lived in while filming season one of High School Musical: The Musical: The Series, after realizing that he was “hopelessly falling in love with a close friend… who was in a relationship.”\n\nSince the production of the show began back in early 2019, Bassett could’ve been referencing Rodrigo’s then-relationship with Ethan Wacker, her former Bizaardvark co-star.\n\nThis line differs from the original version of the song teased on Instagram on July 23, 2020, in which Rodrigo sings:\n\nAnd I don’t believe you when you say I did nothing wrong", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 241}]}, {"id": 4, "text": "''Cause you said forever, now I drive alone past your street", "range": {"end": 4, "start": 4}, "annotations": [{"text": "This line alludes to breakups, the theme of the song as Rodrigo has stated, and reminiscing on memories. As the song is presumably about Joshua Bassett and Olivia promising to obtain a driver’s license, — as stated in the song bio — the line also supports her fulfilling the promise.\n\nIn addition, this specific line was heavily popularized on the social media platform, TikTok, where most most of the short videos using this audio involved relationships and melancholic settings.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 71}]}]}, {"type": "Outro", "lines": [{"id": 1, "text": "Yeah, you said forever, now I drive alone past your street", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This line alludes to breakups, the theme of the song as Rodrigo has stated, and reminiscing on memories. As the song is presumably about Joshua Bassett and Olivia promising to obtain a driver’s license, — as stated in the song bio — the line also supports her fulfilling the promise.\n\nIn addition, this specific line was heavily popularized on the social media platform, TikTok, where most most of the short videos using this audio involved relationships and melancholic settings.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 71}]}]}], "schemaVersion": 1}', 'ly_v1_f61ad3d67528d2ab', true, 1, '2026-05-29 11:13:27.837245+00', '2026-05-29 11:13:27.837245+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('0e46f283-5a4e-4a9e-92d4-2c681095cbb9', '9e44241a-1011-4618-891f-5d8c8f70311c', 'genius', '{"source": "genius", "sections": [{"type": "Verse 1", "lines": [{"id": 1, "text": "Don''t know when my nights became so complicated", "range": {"end": 1, "start": 1}, "annotations": []}, {"id": 2, "text": "Can’t recall my mornings ever bein'' this faded", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Maybe this is karma, definition of jaded, oh", "range": {"end": 3, "start": 3}, "annotations": []}, {"id": 4, "text": "This stays on my mind, this stays on my mind", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Tryna put a muzzle on my crazy feelings", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "One minute I''m cool and then the next, I’m trippin'', no", "range": {"end": 6, "start": 6}, "annotations": []}, {"id": 7, "text": "With somebody new, I swear she don''t deserve this", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Wasted on my mind, she''s still on my mind", "range": {"end": 8, "start": 8}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "Did we build it up, build it up", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This is an allusion to sandcastles. People spend a lot of time and effort into building them, but in the end, even if you don’t destroy them, they’ll always wash away.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 11}]}, {"id": 2, "text": "Just to let it wash away?", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Tell me, did I lace you up, lace you up", "range": {"end": 3, "start": 3}, "annotations": []}, {"id": 4, "text": "Just to watch you run away?", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Please tell me who", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Who''s gettin'' all my love? (Love)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Who''s gettin'' all my love?", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Tell me who", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Who’s gettin’ all my time?", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "All of that used to be mine, oh", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Who did you teach what I taught ya? (Oh)", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Better not give him my nickname", "range": {"end": 8, "start": 8}, "annotations": []}, {"id": 9, "text": "I don''t like thinkin’ about it", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "I swear that it''s wearin'' me down, no", "range": {"end": 10, "start": 10}}, {"id": 11, "text": "But tell me who", "range": {"end": 11, "start": 11}}, {"id": 12, "text": "Who''s gettin’ all of my?", "range": {"end": 12, "start": 12}}, {"id": 13, "text": "Who''s gettin'' all of my residuals?", "range": {"end": 13, "start": 13}}]}, {"type": "Post-Chorus", "lines": [{"id": 1, "text": "(Who)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Who''s gettin'' all of my?", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Who''s gettin'' all of my residuals?", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "(Who)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Who''s gettin'' all of my?", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Who''s gettin'' all of my residuals?", "range": {"end": 6, "start": 6}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "Made it clear you didn''t wanna see the sequel", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "I was lyin'' when I said the feeling''s mutual, oh", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "It took some time to realize that we''re different people", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "And love is blind, I see love is blind", "range": {"end": 4, "start": 4}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "Did we build it up, build it up", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Just to let it wash away?", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "And tell me, did I lace you up, lace you up", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Just to watch you run away?", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Please tell me who", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Who''s gettin'' all my love? (Who''s gettin''? Love)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Who''s gettin'' all my love? (My love)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "And tell me who", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Who''s gettin'' all my time? (My time, no)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "All of that used to be mine, oh (Believe it)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Who did you teach what I taught ya? (Oh)", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Better not give him my nickname", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "I don''t like thinkin'' about it", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "I swear that it''s wearin'' me down, no", "range": {"end": 10, "start": 10}}, {"id": 11, "text": "But tell me who (So tell me who, yeah)", "range": {"end": 11, "start": 11}}, {"id": 12, "text": "Who''s gettin'' all of my? (My)", "range": {"end": 12, "start": 12}}, {"id": 13, "text": "Who''s gettin'' all of my (Oh) residuals?", "range": {"end": 13, "start": 13}, "annotations": []}]}, {"type": "Post-Chorus", "lines": [{"id": 1, "text": "(Who)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "(Who)", "range": {"end": 2, "start": 2}}]}], "schemaVersion": 1}', 'ly_v1_09f740852b3ab9d5', true, 1, '2026-05-29 11:13:29.778355+00', '2026-05-29 11:13:29.778355+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('431a3b37-6fb3-426d-b00b-a34a144ecdc7', '7dfe0dce-e229-48e5-bef8-024cff55be56', 'genius', '{"source": "genius", "sections": [{"type": "Intro", "lines": [{"id": 1, "text": "If you don''t wanna see me", "range": {"end": 1, "start": 1}}]}, {"type": "Verse 1", "lines": [{"id": 1, "text": "Did a full one-eighty, crazy", "range": {"end": 1, "start": 1}, "annotations": []}, {"id": 2, "text": "Thinking ''bout the way I was", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Did the heartbreak change me? Maybe", "range": {"end": 3, "start": 3}, "annotations": [{"text": "In a September 2019 Vogue interview, Dua Lipa revealed that songs from her upcoming second studio album will be more “mature.” This song is speculated to be about her ex-boyfriends Isaac Carew and Paul Klein.\n\nDua and Isaac began dating in 2015 and ended their relationship after 18 months. Dua moved on to date Paul Klein, who is a member of the indie-pop band LANY, before getting back together with Isaac in June 2018. After nearly a year, the pair decided to split again, ending their relationship in June 2019.\n\nIt is also worth noting that later on in the second verse of the song, Dua mentions “goodbye[s]” and “walk[ing] away,” which were recurring themes on LANY’s October 2018 album Malibu Nights, rumoured to be about their break-up.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 106}]}, {"id": 4, "text": "But look at where I ended up", "range": {"end": 4, "start": 4}}]}, {"type": "Refrain", "lines": [{"id": 1, "text": "I''m all good already", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "So moved on, it''s scary", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I''m not where you left me at all, so", "range": {"end": 3, "start": 3}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "If you don''t wanna see me dancing with somebody", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This line could possibly be a dig at  Dua Lipa’s on and off ex, Isaac Carew. Shortly after their breakup, she was seen dancing with Anwar Hadid at the British Summertime Hyde Park Concert.\n\n\n\nAnwar and Dua are now still dating and could mean that Isaac wanted her back but she was happy and moved onthe line", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 34}]}, {"id": 2, "text": "If you wanna believe that anything could stop me", "range": {"end": 2, "start": 2}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Don''t show up, don''t come out", "range": {"end": 1, "start": 1}, "annotations": []}, {"id": 2, "text": "Don''t start caring about me now", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Walk away, you know how", "range": {"end": 3, "start": 3}, "annotations": [{"text": "“Don’t Start Now” is speculated to be addressing Dua Lipa’s exes, Isaac Carew or Paul Klein, the latter being the indie-pop band frontman for LANY. In fact, this line echoes an idea from LANY’s December 2015 song, “Walk Away”:\n\nI’m too good at leaving love\nI don’t wanna be (walk away, walk away)\n\nDua Lipa and Klein dated back in 2017.\n\nOn the other hand, Dua Lipa and Carew first dated from 2013 until 2017. They got back together in early 2018 but broke up for the second time in 2019.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 95}]}, {"id": 4, "text": "Don''t start caring about me now", "range": {"end": 4, "start": 4}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "Aren''t you the guy who tried to", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This is a nod to Gloria Gaynor’s October 1978 hit song “I Will Survive”:\n\nWeren’t you the one who tried to hurt me with goodbye?\n\nDua Lipa dated LANY’s frontman Paul Klein for five months in 2017 and 2018. Following the break-up, the band released their October 2018 album Malibu Nights, that was rumored to be heavily inspired by the split. On the album, Klein noticeably uses the word “goodbye” multiple times to characterize the ended relationship.\n\nOn “Thru These Tears,” he explains in the bridge that he is finally letting go:\n\nYou said it was over\nBut when we got closer\nYou cried on my shoulder\nGoodbye\n\nOn “If You See Her,” he uses the word “goodbye” as a metonymy for the break-up:\n\nThe night before goodbye, she said forever (Ahh)\n\n\n\nDua Lipa wears a cropped LANY merchandise t-shirt as she is pictured alongside Paul Klein", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 100}]}, {"id": 2, "text": "Hurt me with the word \"goodbye\"?", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Though it took some time to survive you", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "I''m better on the other side", "range": {"end": 4, "start": 4}}]}, {"type": "Refrain", "lines": [{"id": 1, "text": "I''m all good already", "range": {"end": 1, "start": 1}, "annotations": [{"text": "In a September 2019 Vogue interview, Dua Lipa revealed that songs from her upcoming second studio album will be more “mature.” This song is speculated to be about her ex-boyfriends Isaac Carew and Paul Klein.\n\nDua and Isaac began dating in 2015 and ended their relationship after 18 months. Dua moved on to date Paul Klein, who is a member of the indie-pop band LANY, before getting back together with Isaac in June 2018. After nearly a year, the pair decided to split again, ending their relationship in June 2019.\n\nIt is also worth noting that later on in the second verse of the song, Dua mentions “goodbye[s]” and “walk[ing] away,” which were recurring themes on LANY’s October 2018 album Malibu Nights, rumoured to be about their break-up.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 106}]}, {"id": 2, "text": "So moved on, it''s scary", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I''m not where you left me at all, so", "range": {"end": 3, "start": 3}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "If you don''t wanna see me dancing with somebody", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "If you wanna believe that anything could stop me", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "(Don''t, don''t, don''t)", "range": {"end": 3, "start": 3}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Don''t show up, don''t come out", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Don''t start caring about me now", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Walk away, you know how", "range": {"end": 3, "start": 3}, "annotations": [{"text": "“Don’t Start Now” is speculated to be addressing Dua Lipa’s exes, Isaac Carew or Paul Klein, the latter being the indie-pop band frontman for LANY. In fact, this line echoes an idea from LANY’s December 2015 song, “Walk Away”:\n\nI’m too good at leaving love\nI don’t wanna be (walk away, walk away)\n\nDua Lipa and Klein dated back in 2017.\n\nOn the other hand, Dua Lipa and Carew first dated from 2013 until 2017. They got back together in early 2018 but broke up for the second time in 2019.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 95}]}, {"id": 4, "text": "Don''t start caring about me now (''Bout me now, ''bout me)", "range": {"end": 4, "start": 4}}]}, {"type": "Post Chorus", "lines": [{"id": 1, "text": "Up, up", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Don''t come out, out, out", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Don''t show up, up, up", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Don''t start now (Oh)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Up, up", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Don''t come out, out", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "I''m not where you left me at all, so", "range": {"end": 7, "start": 7}}]}, {"type": "Bridge", "lines": [{"id": 1, "text": "If you don''t wanna see me dancing with somebody", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "If you wanna believe that anything could stop me", "range": {"end": 2, "start": 2}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Don''t show up (Don''t show up), don''t come out (Don''t come out)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Don''t start caring about me now (''Bout me now)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Walk away (Walk away), you know how (You know how)", "range": {"end": 3, "start": 3}, "annotations": [{"text": "“Don’t Start Now” is speculated to be addressing Dua Lipa’s exes, Isaac Carew or Paul Klein, the latter being the indie-pop band frontman for LANY. In fact, this line echoes an idea from LANY’s December 2015 song, “Walk Away”:\n\nI’m too good at leaving love\nI don’t wanna be (walk away, walk away)\n\nDua Lipa and Klein dated back in 2017.\n\nOn the other hand, Dua Lipa and Carew first dated from 2013 until 2017. They got back together in early 2018 but broke up for the second time in 2019.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 95}]}, {"id": 4, "text": "Don''t start caring about me now (So)", "range": {"end": 4, "start": 4}}]}, {"type": "Outro", "lines": [{"id": 1, "text": "Up, up", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Don''t come out, out, out", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Don''t show up, up, up", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Walk away, walk away (So)\nWalk away, walk away, oh", "range": {"end": 8, "start": 4}, "annotations": [{"text": "“Don’t Start Now” is speculated to be addressing Dua Lipa’s exes, Isaac Carew or Paul Klein, the latter being the indie-pop band frontman for LANY. In fact, this line echoes an idea from LANY’s December 2015 song, “Walk Away”:\n\nI’m too good at leaving love\nI don’t wanna be (walk away, walk away)\n\nDua Lipa and Klein dated back in 2017.\n\nOn the other hand, Dua Lipa and Carew first dated from 2013 until 2017. They got back together in early 2018 but broke up for the second time in 2019.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 95}]}, {"id": 5, "text": "Up, up", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Don''t come out, out, out", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Don''t show up, up, up", "range": {"end": 7, "start": 7}}]}], "schemaVersion": 1}', 'ly_v1_dc72fd62611275e3', true, 1, '2026-05-29 11:13:30.362533+00', '2026-05-29 11:13:30.362533+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('4d1f6490-ec49-4a47-bb6f-0cc1cbb73401', '462d171c-27ff-4bec-a2d0-303c2b97f739', 'genius', '{"source": "genius", "sections": [{"type": "Verse 1", "lines": [{"id": 1, "text": "I should burn in hell", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Winter (or at least the character on this album) has made many bad decisions in his life. He’s abandoned his family, done cocaine, bowed down to authority, and contributed to corrupt society.\nWhatever Winter is facing in this song, whether a prison sentence or actual judgement day (as alluded to by all of the angel imagery, including Gabriel’s trumpet), he believes that not even him, an avid sinner, deserves it.\n\nHe deserves the worst future , yet he doesn’t deserve his current hardships.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 34}]}, {"id": 2, "text": "I should burn in hell", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "But I don''t deserve this", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Nobody deserves this", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Ooh-ooh, ooh-ooh", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Ooh-ooh, ooh-ooh", "range": {"end": 6, "start": 6}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "If you want me to pay my taxes", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Taxes are compulsory by nature. They are not freely offered but demanded. The “nail me down” line indicates the narrator would sooner sacrifice their life than pay up.\n\nThe song’s closing reference to a broken heart suggests an emotional debt or burden.\n\nCameron Winter previously explored the language of currency in relationships in “$0,” where the narrator was made to feel like a “dollar in your hand” and a “zero dollar man.”", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 21}]}, {"id": 2, "text": "If you want me to pay my taxes", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "You''d better come over with a crucifix", "range": {"end": 3, "start": 3}, "annotations": [{"text": "The lyric “You’d better come over with a crucifix / You’re gonna have to nail me down” is a reference to crucifixion.\n\nGiven the following verse’s “Doctor, heal yourself,” the passage below, spoken to Jesus as he was crucified, is relevant:\n\nLuke 23:35\n\nThe people stood watching, and the rulers even sneered at him. They said, “He saved others; let him save himself if he is God’s Messiah, the Chosen One.”\n\nJesus foreshadows this moment in Luke 4:23\n\nJesus said to them, “Surely you will quote this proverb to me: ‘Physician, heal yourself!’", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 20}]}, {"id": 4, "text": "You''re gonna have to nail me down", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Ooh-ooh, ooh-ooh", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Ooh-ooh", "range": {"end": 6, "start": 6}}]}, {"type": "Verse 3", "lines": [{"id": 1, "text": "Doctor, doctor, heal yourself", "range": {"end": 1, "start": 1}, "annotations": [{"text": "From the ancient proverb dating back to the 6th Century BCE (“physician, heal thyself”), it refers to a healer’s inability to cure themselves, with the moral being that one should fix one’s problems before trying to fix others''. It is even quoted to a similar effect in the Bible, continuing the religious theme of the song.\n\nHere, Winter makes the comparison between medical and emotional healing. Perhaps the doctor, in their attempts to cure patients, does more damage than good; similarly, the protagonist may be prone to breaking people’s hearts rather than making them feel whole in their relationship. “From now on” implies that the protagonist has likely broken more than one heart in the past.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 54}]}, {"id": 2, "text": "Doctor, doctor, heal yourself", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "And I will break my own heart", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "I will break my own heart from now on", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Ooh-ooh, ooh-ooh", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Ooh-ooh, ooh-ooh", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Ooh", "range": {"end": 7, "start": 7}}]}], "schemaVersion": 1}', 'ly_v1_41eb32beb245df75', true, 1, '2026-05-29 11:13:31.082259+00', '2026-05-29 11:13:31.082259+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('46bacccc-7c8b-4b33-98d3-62a825d10cdc', 'df14a8d9-303c-4fe9-a862-b31dfcc0b510', 'genius', '{"source": "genius", "sections": [{"type": "Intro", "lines": [{"id": 1, "text": "Come on, Harry, we wanna say goodnight to you", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Styles introduces us to his lead single with a voicemail from his goddaughter Ruby, whose father is British television producer Ben Winston, a close friend of the artist who also directed quite a few One Direction music videos. Styles confirmed this during an interview promoting the release of the single:\n\nIt’s my goddaughter at the start of the song. [She] got a streak of calling me every night before bed, and I missed it once, and she wanted to let me know that she was quite angry with me.\n\nA potential interpretation of this interjection, following the album’s promotional motif of doors, is that Ruby is speaking to Harry from the other side of a closed door as he refuses to let anyone into his house. This metaphor relates to the theme of struggling with honesty and vulnerability that is prevalent through Styles’s discography. The image of Styles behind a door mirrors the beginning of the music video.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 372}]}]}, {"type": "Verse 1", "lines": [{"id": 1, "text": "Holdin'' me back", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Gravity''s holdin'' me back", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I want you to hold out the palm of your hand", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Why don''t we leave it at that?", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Nothin'' to say", "range": {"end": 5, "start": 5}, "annotations": [{"text": "This specific lyric reminisces of another line from “Two Ghosts,” a 2017 track that belongs to Harry’s debut album\n\nTelling those stories we already told\n\nStyles'' 2019 single “Falling,” also shows similarities, when he sings:\n\nAnd the coffee’s out at the Beachwood Cafe\nAnd it kills me, ‘cause I know we’ve run out of things we can say\n\nAt this point in “As It Was,” we can interpret this line as Harry only being able to think about or focus on the past. Stuck within a loop of struggle, he can’t move on from whatever it is that has happened to him, but also doesn’t want to open up about it — which is something he probably should do, since talking with someone tends to be a healthy way of processing feelings or emotions.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 113}]}, {"id": 6, "text": "When everything gets in the way", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Seems you cannot be replaced", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "And I''m the one who will stay, oh-oh-oh", "range": {"end": 8, "start": 8}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "In this world, it''s just us", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "You know it''s not the same as it was\nYou know it''s not the same as it was", "range": {"end": 4, "start": 2}, "annotations": [{"text": "In a May 2022 interview for Apple Music, Styles explained his perspective on this line:\n\nFor me, everything that happened in the pandemic, like, it’s never gonna be the same as before. All of the things happening in the world, it was so obvious that you just can’t go backwards, whether that’s us as people, or me in my personal life, or any of those things, you learn so much in those moments. A force to, like, face things head-on, whether that is your least favourite things about the world, or your least favourite things about yourself, all of those things, you just can’t then pretend that stuff doesn’t exist.\n\nThis line reflects on how the passage of time affects on many things and changes its essence. On one side, maybe because of a breakup, a hypothetical couple has been affected by some circumstances that changed them and their ways of acting with each other.\n\nOn the other hand, Styles could be talking to himself, contemplating how time and the experiences he faced have modified him.\n\nIn both cases, Harry seems to have gone through situations like this one, as he wrote in a similar way in the 2017 track, “Two Ghosts.” His debut album song reflects on the major character developments of two people after some time:\n\nWe’re not who we used to be", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 198}]}, {"id": 3, "text": "In this world, it''s just us", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "As it was, as it was", "range": {"end": 5, "start": 5}}, {"id": 5, "text": "You know it''s not the same", "range": {"end": 6, "start": 6}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "Answer the phone", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "\"Harry, you''re no good alone", "range": {"end": 2, "start": 2}, "annotations": [{"text": "This manner of bearing with the distance of an ex partner resembles of the attitude Styles took previously on his 2017 track, “Meet Me in the Hallway:”\n\nJust let me know, I’ll be at the door, at the door\nHoping you’ll come around\nJust let me know, I’ll be on the floor, on the floor\nMaybe we’ll work it out\nI gotta get better, gotta get better\n\nThese lyrics show devastation, caused by the break-up. Styles finds himself alone and outside his lover’s bedroom, crawling for their comeback “on the floor,” “at the door.”\n\nThere’s also an interpretation that suggests those lyrics are taken from a possible conversation between Styles and his sister, Gemma, after their parents'' divorce.\n\nThe pills mentioned in this verse are also reminiscent of the opening lines from “Meet Me In The Hallway:”\n\nMeet me in the hallway, meet me in the hallway\nI just left your bedroom, give me some morphine\nIs there any more to do?\n\nStyles also writes about his self-destructive behaviours on tracks such as April 2017’s “Ever Since New York,” as well as December 2019’s “To Be So Lonely.”", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 173}]}, {"id": 3, "text": "Why are you sitting at home on the floor?", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "What kind of pills are you on?\"", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Ringin'' the bell", "range": {"end": 5, "start": 5}, "annotations": [{"text": "In most inpatient care facilities worldwide, patients have some form of ‘bell’ or ‘button’ they can ‘ring’ or activate to notify medical providers that they need assistance of some kind. Harry seems to be referencing this here – he keeps ringing the bell, and yet no one seems to notice or want to help him. Or maybe it just feels like that. Either way, the emotions are there.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 19}]}, {"id": 6, "text": "And nobody''s coming to help", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Your daddy lives by himself", "range": {"end": 7, "start": 7}, "annotations": [{"text": "This lyric is probably the literal truth. When Styles was seven years old, his parents divorced. While his mother got remarried twice after the divorce, Styles'' father has stayed single since, making it likely that he lives alone.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 108}]}, {"id": 8, "text": "He just wants to know that you''re well, oh-oh-oh", "range": {"end": 8, "start": 8}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "In this world, it''s just us", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "You know it''s not the same as it was\nYou know it''s not the same as it was", "range": {"end": 4, "start": 2}, "annotations": [{"text": "In a May 2022 interview for Apple Music, Styles explained his perspective on this line:\n\nFor me, everything that happened in the pandemic, like, it’s never gonna be the same as before. All of the things happening in the world, it was so obvious that you just can’t go backwards, whether that’s us as people, or me in my personal life, or any of those things, you learn so much in those moments. A force to, like, face things head-on, whether that is your least favourite things about the world, or your least favourite things about yourself, all of those things, you just can’t then pretend that stuff doesn’t exist.\n\nThis line reflects on how the passage of time affects on many things and changes its essence. On one side, maybe because of a breakup, a hypothetical couple has been affected by some circumstances that changed them and their ways of acting with each other.\n\nOn the other hand, Styles could be talking to himself, contemplating how time and the experiences he faced have modified him.\n\nIn both cases, Harry seems to have gone through situations like this one, as he wrote in a similar way in the 2017 track, “Two Ghosts.” His debut album song reflects on the major character developments of two people after some time:\n\nWe’re not who we used to be", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 198}]}, {"id": 3, "text": "In this world, it''s just us", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "As it was, as it was", "range": {"end": 5, "start": 5}}, {"id": 5, "text": "You know it''s not the same", "range": {"end": 6, "start": 6}}]}, {"type": "Bridge", "lines": [{"id": 1, "text": "Go home, get ahead, light-speed internet", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "I don''t wanna talk about the way that it was", "range": {"end": 2, "start": 2}, "annotations": [{"text": "The motif of not wanting to talk about certain topics has already been expressed throughout Styles'' discography. It made its first appearance on his breakout debut single, “Sign of the Times:”\n\nWe don’t talk enough, we should open up\nBefore it’s all too much\nWill we ever learn? We’ve been here before\nIt’s just what we know\n\nHarry’s debut album’s opening track, “Meet Me in the Hallway,” also expresses similar feelings:\n\nWe don’t talk about it, it’s something we don’t do\n‘Cause once you go without it, nothing else will do\n\nCarrying emotions and oppressing them because of the pain they could cause when opening up about them, seems to be a habit. This attitude towards emotions can lead to the recurrence of these harmful feelings. Consequently, it can also cause a sudden explosion of emotion within the person, which may destroy valuable things in their life.\n\nThis cycle was also represented on the song’s music video, where Styles and his partner can be seen running in a circle:", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 131}]}, {"id": 3, "text": "Leave America, two kids follow her", "range": {"end": 3, "start": 3}, "annotations": []}, {"id": 4, "text": "I don''t wanna talk about who''s doin'' it first", "range": {"end": 4, "start": 4}}]}, {"type": "Outro", "lines": [{"id": 1, "text": "(Hey)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "As it was", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "You know it''s not the same as it was", "range": {"end": 3, "start": 3}, "annotations": [{"text": "In a May 2022 interview for Apple Music, Styles explained his perspective on this line:\n\nFor me, everything that happened in the pandemic, like, it’s never gonna be the same as before. All of the things happening in the world, it was so obvious that you just can’t go backwards, whether that’s us as people, or me in my personal life, or any of those things, you learn so much in those moments. A force to, like, face things head-on, whether that is your least favourite things about the world, or your least favourite things about yourself, all of those things, you just can’t then pretend that stuff doesn’t exist.\n\nThis line reflects on how the passage of time affects on many things and changes its essence. On one side, maybe because of a breakup, a hypothetical couple has been affected by some circumstances that changed them and their ways of acting with each other.\n\nOn the other hand, Styles could be talking to himself, contemplating how time and the experiences he faced have modified him.\n\nIn both cases, Harry seems to have gone through situations like this one, as he wrote in a similar way in the 2017 track, “Two Ghosts.” His debut album song reflects on the major character developments of two people after some time:\n\nWe’re not who we used to be", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 198}]}, {"id": 4, "text": "As it was, as it was", "range": {"end": 4, "start": 4}}]}], "schemaVersion": 1}', 'ly_v1_282cac5858b41bd2', true, 1, '2026-05-29 11:13:31.248397+00', '2026-05-29 11:13:31.248397+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('32052fcf-af10-488f-a9ba-c7309308a77e', '21b8e7a6-a1d4-481f-b1ff-827a2d70de90', 'genius', '{"source": "genius", "sections": [{"type": "Intro", "lines": [{"id": 1, "text": "Oh boy", "range": {"end": 1, "start": 1}, "annotations": [{"text": "According to Sabrina for the July edition of Rolling Stone, this phrase serves as a re-introduction into the narrative attempted to be presented by Carpenter after her short but sweet musical hiatus:\n\nIt’s literally like, ‘Previously on’. It’s been a second since we’ve said hi, so there is a sense of ‘We’re back in it.’ It’s a deep breath and an eye roll, and back into the story.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 30}]}]}, {"type": "Verse 1", "lines": [{"id": 1, "text": "You said your phone was broken, just forgot to charge it", "range": {"end": 1, "start": 1}, "annotations": [{"text": "This could be a reference to Sabrina’s track “Coincidence”, where she sings:\n\nWhat a surprise, your phone just died\n\nIn “Manchild”, the phone shows how dumb he is, whereas in “Coincidence”, he’s making excuses like his phone dying at just the wrong time. This provides duality of men, innocent ignorance versus intentional deception.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 62}]}, {"id": 2, "text": "Whole outfit you''re wearing, God, I hope it''s ironic", "range": {"end": 2, "start": 2}, "annotations": [{"text": "Sabrina uses biting sarcasm here to call out the subject’s fashion choices, implying that the outfit is so questionable or mismatched that she hopes it’s being worn ironically, as a joke or statement, rather than sincerely.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 32}]}, {"id": 3, "text": "Did you just say you''re finished? Didn''t know we started", "range": {"end": 3, "start": 3}, "annotations": [{"text": "This line is reminiscent of the first track on the deluxe edition of Short n’ Sweet, “15 Minutes,” on which Carpenter sings:\n\nI can do a lot with fifteen minutes\nOnly gonna take two to make you finish\n\nMoreover, Carpenter is a big fan of double entendres. She’s addressing her partner leaving her and the relationship in which she was unaware they were in one, and at the same time referring to her partner reaching climax too quickly.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 74}]}, {"id": 4, "text": "It''s all just so familiar, baby, what do you call it?", "range": {"end": 4, "start": 4}, "annotations": [{"text": "She takes a fairly braggadocious angle on this first verse, talking to a boy, likely suspicious he was cheating on her. She is saying how she has been in countless relationships, and even if this guy doesn’t like her, or is cheating on her, there are more fish in the sea.\nThe general public agrees that she is very attractive, though allegations recently came out of her boyfriend cheating on her, so this lyric may be referencing that.\nAt this point, relationships are becoming so familiar to her, which was a similar approach to her last album, Short And Sweet, though she took a much different angle on the album before that, Emails I Can’t Send, where she seemed much less into dating as a whole.\nShe talks about her transition from these two albums on her Spotify profile.\nThis may also not be referencing cheating and talking about guys that she has dated who have treated her badly. She is saying that she does not want to go on that route again and is unimpressed with how this boy is treating her.\nTheir behavior has also often been the same to her, with them being immature, dumb, slow, and useless, further shown during the chorus. She’s seen how she often doesn’t choose great men, and thinks that it will happen again, though at this point, it’s happened to her so many times that she doesn’t even care anymore.\nIt could be referencing Deja Vu, when you feel as though something has already happened, which is also the name of an Olivia Rodrigo song, so she could be throwing a shot at her and referencing Joshua Bassett, whom Olivia Rodrigo wrote the song about. She may have avoided the actual words “Deja Vu” to potentially not try and re-ignite their feud.\nAnother way to look at this is that she is continuing the trend of contradictions throughout this verse, continuing from: is the phone broken or just out of charge? and are we finishing or just beginning? by wondering: if this experience is so familiar, why can’t she name it?\nShe may not actually be that braggadocious, and may simply be exasperated and put on a “smiling-through-your-teeth” look, leading to the slightly spiteful lyrical content of this song. She is simply like this because every time she gets to know a man, he turns out to be immature and incompetent, always shown in the same ways (such as being incompetent)", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 17}]}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "Stupid", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Or is it slow?", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Maybe it''s useless?", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "But there''s a cuter word for it, I know", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Man-child", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Sabrina calls this man a “manchild,” a phrase that is used to refer to an immature man who refuses to grow up or take responsibility. Here, she asks him why he constantly asks for emotional support or love her, even though it is evident that he cannot have a proper relationship with him. Sabrina implies she hasn’t wronged the man and doesn’t deserve his behavior. She asks to be left alone, free from his drama or dependency. She’s distancing herself from responsibility for these recurring dynamics—implying that these men gravitate toward her, not the other way around.\n\nThis may be a subtle shot at Sabrina’s ex-boyfriend, Barry Keoghan, who reportedly broke up with Sabrina in December 2024. Furthermore, on Instagram, Sabrina posted this caption while promoting the song:\n\nthis one’s about you!!\n\nFans have also drawn comparisons to Sabrina saying similar things (such as “This one’s for you!”) before performing her 2024 song, “Bed Chem,” while on the Short n’ Sweet Tour in Dublin. This is significant as “Bed Chem” is about Sabrina falling in love with Barry Keoghan, who is from Dublin.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 52}]}, {"id": 2, "text": "Why you always come a-running to me?", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Fuck my life", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Won''t you let an innocent woman be?", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Never heard of self-care", "range": {"end": 5, "start": 5}, "annotations": [{"text": "It is common that in children’s minds there is not much self-care because they have not matured that part of their awareness, this man projects that energy.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 21}]}, {"id": 6, "text": "Half your brain just ain''t there", "range": {"end": 6, "start": 6}, "annotations": [{"text": "The lyric “Half your brain just ain’t there” is a comedic takedown of men who look grown but act like they skipped a few stages of emotional development.\n\nIn an Instagram caption about the project, she said:\n“this song became to me something I can look back on that will score the mental montage to the very confusing and fun young adult years of life.”\n\nThe idea of turning those chaotic years into a record is perfectly embodied not only in this lyric, but the whole track. Manchild reflects the confusion of caring about someone who clearly doesn’t have their act together, and the fun of writing them off with a chuckle.\n\nPlus, the left hemisphere of the brain is generally associated with logical, analytical, and verbal tasks, including language processing, math, and scientific reasoning, so Sabrina might be joking about him missing this side of the brain.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 33}]}, {"id": 7, "text": "Man-child", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Why you always come a-running, taking all my loving from me?", "range": {"end": 8, "start": 8}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "Why so sexy if so dumb?", "range": {"end": 1, "start": 1}, "annotations": [{"text": "With this line, Sabrina possibly alludes to an unreleased track titled “Why So Sexy?”\n\nIt also alludes to her track, “Dumb & Poetic”, in which she sung,\n\nYou’re so dumb and poetic, It’s just what I fall for, I like the aesthetic\n\nThe lyric shows Sabrina’s love for self-referential writing and giving longtime listeners easter eggs that trace her emotional growth across albums.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 40}]}, {"id": 2, "text": "And how survive the Earth so long?", "range": {"end": 2, "start": 2}, "annotations": [{"text": "Likely referencing the concept of natural selection, Sabrina is questioning how men as a group have survived over the course of human evolution, since they frequently can’t seem to do anything for themselves (cook, clean, make smart choices, etc.)\n\nShe expands on this concept in the next line, indicating that she has to do all of these things for the men she dates.\n\nThe grammar used in the phrase “how survive” implies that Sabrina is talking down to these underdeveloped men, using less advanced sentence structure so they can understand her.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 31}]}, {"id": 3, "text": "If I''m not there, it won''t get done", "range": {"end": 3, "start": 3}, "annotations": [{"text": "At this point in the song, Sabrina has conveyed her annoyance at always having to pick up after this man’s mistakes. Sabrina has expectations that he can handle doing what has to get done, but her supervision is necessary, therefore making him help is pointless.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 12}]}, {"id": 4, "text": "I choose to blame your mom", "range": {"end": 4, "start": 4}, "annotations": [{"text": "Sabrina blames her partner’s upbringing from his mother for his inability to handle his responsibilities on his own, inferring that he was coddled by his mother and she did not give him independence. She continues this theme on the album’s sixth track “Nobody’s Son”, in which she directly addresses her partner’s parents:\n\nThat boy is corrupt\nCould you raise him to love me, maybe?\nHe sure fucked me up\nAnd yes, I’m talking ‘bout your baby\n\nThis lyric was first teased on April 1, 2025 during the second Copenhagen date of the Short n'' Sweet Tour, where Sabrina wore a pair of tights that read “I choose to blame your mom”. She regularly wore different tights throughout the tour that contained lyrics for songs from Short n'' Sweet, but this line remained a mystery at the time as “Manchild” had not been released yet.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 48}]}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Man-child", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Sabrina calls this man a “manchild,” a phrase that is used to refer to an immature man who refuses to grow up or take responsibility. Here, she asks him why he constantly asks for emotional support or love her, even though it is evident that he cannot have a proper relationship with him. Sabrina implies she hasn’t wronged the man and doesn’t deserve his behavior. She asks to be left alone, free from his drama or dependency. She’s distancing herself from responsibility for these recurring dynamics—implying that these men gravitate toward her, not the other way around.\n\nThis may be a subtle shot at Sabrina’s ex-boyfriend, Barry Keoghan, who reportedly broke up with Sabrina in December 2024. Furthermore, on Instagram, Sabrina posted this caption while promoting the song:\n\nthis one’s about you!!\n\nFans have also drawn comparisons to Sabrina saying similar things (such as “This one’s for you!”) before performing her 2024 song, “Bed Chem,” while on the Short n’ Sweet Tour in Dublin. This is significant as “Bed Chem” is about Sabrina falling in love with Barry Keoghan, who is from Dublin.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 52}]}, {"id": 2, "text": "Why you always come a-running to me?", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Fuck my life", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Won''t you let an innocent woman be?", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Never heard of self-care", "range": {"end": 5, "start": 5}, "annotations": [{"text": "It is common that in children’s minds there is not much self-care because they have not matured that part of their awareness, this man projects that energy.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 21}]}, {"id": 6, "text": "Half your brain just ain''t there", "range": {"end": 6, "start": 6}, "annotations": [{"text": "The lyric “Half your brain just ain’t there” is a comedic takedown of men who look grown but act like they skipped a few stages of emotional development.\n\nIn an Instagram caption about the project, she said:\n“this song became to me something I can look back on that will score the mental montage to the very confusing and fun young adult years of life.”\n\nThe idea of turning those chaotic years into a record is perfectly embodied not only in this lyric, but the whole track. Manchild reflects the confusion of caring about someone who clearly doesn’t have their act together, and the fun of writing them off with a chuckle.\n\nPlus, the left hemisphere of the brain is generally associated with logical, analytical, and verbal tasks, including language processing, math, and scientific reasoning, so Sabrina might be joking about him missing this side of the brain.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 33}]}, {"id": 7, "text": "Man-child", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Why you always come a-running, taking all my loving from me?", "range": {"end": 8, "start": 8}}]}, {"type": "Bridge", "lines": [{"id": 1, "text": "Oh, I like my boys playing hard to get\nOh, I like my boys playing hard to get (Play hard to get)", "range": {"end": 5, "start": 1}, "annotations": [{"text": "Carpenter is sarcastically commenting on her pattern of choosing emotionally unavailable or immature partners, similar to the line in the track “Good Graces”:\n\nDon’t mistake my nice for naive\n\nThese lines emphasize her self awareness and the confidence she exudes through her tracks.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 37}]}, {"id": 2, "text": "And I like my men all incompetent", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "And I swear they choose me, I''m not choosing them\nAnd I swear they choose me, I''m not choosing them (Not choosing them)", "range": {"end": 7, "start": 3}, "annotations": [{"text": "This lyric was spotted on a billboard before the release of the song.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 29}]}, {"id": 4, "text": "Amen, hey, men\nAmen (Amen), hey, men (Hey, men)", "range": {"end": 8, "start": 4}, "annotations": [{"text": "This lyric was first teased at a billboard on interstate-69.\n\nIn and of itself, this lyric can be interpreted as a message to men in general to stop being so childish. Having said that, “Hey, men” is said in a very flirty tone, poking fun of and calling into question her claim that she isn’t the one choosing the men who frustrate her.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 33}]}, {"id": 5, "text": "And I like my men all incompetent (Incompetent)", "range": {"end": 6, "start": 6}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Man-child", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Sabrina calls this man a “manchild,” a phrase that is used to refer to an immature man who refuses to grow up or take responsibility. Here, she asks him why he constantly asks for emotional support or love her, even though it is evident that he cannot have a proper relationship with him. Sabrina implies she hasn’t wronged the man and doesn’t deserve his behavior. She asks to be left alone, free from his drama or dependency. She’s distancing herself from responsibility for these recurring dynamics—implying that these men gravitate toward her, not the other way around.\n\nThis may be a subtle shot at Sabrina’s ex-boyfriend, Barry Keoghan, who reportedly broke up with Sabrina in December 2024. Furthermore, on Instagram, Sabrina posted this caption while promoting the song:\n\nthis one’s about you!!\n\nFans have also drawn comparisons to Sabrina saying similar things (such as “This one’s for you!”) before performing her 2024 song, “Bed Chem,” while on the Short n’ Sweet Tour in Dublin. This is significant as “Bed Chem” is about Sabrina falling in love with Barry Keoghan, who is from Dublin.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 52}]}, {"id": 2, "text": "Why you always come a-running to me? (Always come a-running to me)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Fuck my life", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Won''t you let an innocent woman be? (Amen)", "range": {"end": 4, "start": 4}}]}, {"type": "Outro", "lines": [{"id": 1, "text": "Oh, I like my boys playing hard to get (Play hard to get)", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Carpenter is sarcastically commenting on her pattern of choosing emotionally unavailable or immature partners, similar to the line in the track “Good Graces”:\n\nDon’t mistake my nice for naive\n\nThese lines emphasize her self awareness and the confidence she exudes through her tracks.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 37}]}, {"id": 2, "text": "And I like my men all incompetent (Incompetent)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "And I swear they choose me, I''m not choosing them (Not choosing them)", "range": {"end": 3, "start": 3}, "annotations": [{"text": "This lyric was spotted on a billboard before the release of the song.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 29}]}, {"id": 4, "text": "Amen (Amen), hey, men (Hey, men, yee-haw)", "range": {"end": 4, "start": 4}, "annotations": [{"text": "This lyric was first teased at a billboard on interstate-69.\n\nIn and of itself, this lyric can be interpreted as a message to men in general to stop being so childish. Having said that, “Hey, men” is said in a very flirty tone, poking fun of and calling into question her claim that she isn’t the one choosing the men who frustrate her.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 33}]}]}], "schemaVersion": 1}', 'ly_v1_0793d1bc194b2931', true, 1, '2026-05-29 11:13:31.375073+00', '2026-05-29 11:13:31.375073+00') ON CONFLICT DO NOTHING;
