art": 7}}, {"id": 8, "text": "Lookin'' like a poor man''s Arthur Baker now", "range": {"end": 8, "start": 8}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "No-oh, no-oh", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "No sex for Ben", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "No-oh, no-oh", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "No sex for Ben", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "No-ho", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "No sex for Ben", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "No-ho", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "No sex for Ben", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "No-ho", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "No-ho-ho-ho", "range": {"end": 10, "start": 10}}]}, {"type": "Verse 3", "lines": [{"id": 1, "text": "Cheap faker, cheap, cheap faker", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Lookin'' like a poor man''s Arthur Baker now", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Ben Rymer, big-time lover", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Try to snatch the kitty off his girlfriend''s mother", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "We gotta freeze them up now", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "We gotta freeze them up, oh, come on, let''s go", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "We gotta freeze them up", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "I said a one, two, three, freeze", "range": {"end": 8, "start": 8}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "No-oh, no-oh", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "No sex for Ben", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "No-oh, no-oh", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "No sex for Ben", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "No-ho", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "No sex for Ben", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "No-ho", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "No sex for Ben", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "No-ho", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "No-ho-ho-ho", "range": {"end": 10, "start": 10}}]}], "schemaVersion": 1}', 'ly_v1_6d6475650a9c1f25', false, 1, '2026-05-29 11:13:42.570298+00', '2026-05-29 11:13:42.570298+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('eae2f34a-9630-4fae-8767-b985d9c4f6bf', 'cabeddd4-2218-47ca-89ea-5e5c679bbc61', 'genius', '{"source": "genius", "sections": [{"type": "Intro", "lines": [{"id": 1, "text": "One, two, three, four", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Hey, hey (Forever)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Hey, hey (Forever)", "range": {"end": 3, "start": 3}}]}, {"type": "Verse 1", "lines": [{"id": 1, "text": "It''s you and me, moving at the speed of light into eternity, yeah", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Tonight is the night to join me in the middle of ecstasy", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Feel the melody and the rhythm of the music", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Around you, around you (Oh-oh)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "I''ma take you there, I''ma take you there (Oh)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "So don''t be scared, I''m right here, baby", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "We can go anywhere, go anywhere (Yeah)", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "But first, it''s your chance, take my hand, come with me", "range": {"end": 8, "start": 8}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "It''s like I''ve waited my whole life (Oh) for this one night (Oh)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "It''s gon'' be me, you and the dance floor", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "''Cause we only got one night (Oh, oh)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Double your pleasure, double your fun", "range": {"end": 4, "start": 4}, "annotations": [{"text": "These lyrics might sound familiar if you’re an avid Doublemint gum fan.\n\nThis line is proof that “Forever” is actually just an extended version of a Doublemint jingle.\n\nhttps://www.youtube.com/watch?v=enJbXlb4zqo\n\nFun Fact: The commercial was part of a trio of commercials for three of Wrigley’s best known brands.\n\nNe-Yo sang a newer version of “kiss a little longer” for Big Red… while Julianne Hough sang a version of, “The taste is gonna move ya.”", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 24}]}, {"id": 5, "text": "And dance fore-e-ever, fore-e-ever", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Fore-e-ever, forever", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Fore-e-ever, fore-e-ever, fore-e-ever", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Forever on the dance floor", "range": {"end": 8, "start": 8}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "Feels like we''re on another level, oh", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Feels like our love''s intertwined", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "We can be two rebels", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Breaking the rules, me and you, you and I", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "All you gotta do is watch me (Watch me)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Look what I can do with my feet (My feet)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Baby, feel the beat inside", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "I''m driving, you can take the front seat (Front seat)", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "I just need you to trust me (Trust me)", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "Oh (Girl), oh (Girl), oh (Girl)", "range": {"end": 10, "start": 10}}, {"id": 11, "text": "It''s like I''ve—", "range": {"end": 11, "start": 11}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "It''s like I''ve waited my whole life (Oh) for this one night (One night, oh)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "It''s gon'' be me, you and the dance floor (Dance floor)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "''Cause we only got one night (Oh, oh, one night)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Double your pleasure, double your fun (Yeah)", "range": {"end": 4, "start": 4}, "annotations": [{"text": "These lyrics might sound familiar if you’re an avid Doublemint gum fan.\n\nThis line is proof that “Forever” is actually just an extended version of a Doublemint jingle.\n\nhttps://www.youtube.com/watch?v=enJbXlb4zqo\n\nFun Fact: The commercial was part of a trio of commercials for three of Wrigley’s best known brands.\n\nNe-Yo sang a newer version of “kiss a little longer” for Big Red… while Julianne Hough sang a version of, “The taste is gonna move ya.”", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 24}]}, {"id": 5, "text": "And dance fore-e-ever, fore-e-ever", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Fore-e-ever, forever", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Fore-e-ever, fore-e-ever, fore-e-ever", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Forever on the dance floor", "range": {"end": 8, "start": 8}}]}, {"type": "Bridge", "lines": [{"id": 1, "text": "It''s a long way down, we so high off the ground", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Sending for an angel to bring me your heart", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Girl, where did you come from? Got me so undone", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Gaze in your eyes, got me saying, \"What a beautiful lady\"", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "No ifs, ands or maybes", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "I''m releasing my heart and it''s feeling amazing", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "There''s no one else that matters, you love me", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "And I won''t let you fall, girl (Fall, girl), let you fall, girl, oh", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "Oh, oh, yeah, yeah", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "I won''t let you fall, let you fall, let you fall, oh, oh-oh", "range": {"end": 10, "start": 10}}, {"id": 11, "text": "Yeah, yeah", "range": {"end": 11, "start": 11}}, {"id": 12, "text": "Yeah, yeah", "range": {"end": 12, "start": 12}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "It''s like—", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "It''s like I''ve waited my whole life (Oh, whole life) for this one night (One night, oh)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "It''s gon'' be me, you and the dance floor (Me, you and the dance floor)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "''Cause we only got one night (Oh, oh)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Double your pleasure, double your fun", "range": {"end": 5, "start": 5}, "annotations": [{"text": "These lyrics might sound familiar if you’re an avid Doublemint gum fan.\n\nThis line is proof that “Forever” is actually just an extended version of a Doublemint jingle.\n\nhttps://www.youtube.com/watch?v=enJbXlb4zqo\n\nFun Fact: The commercial was part of a trio of commercials for three of Wrigley’s best known brands.\n\nNe-Yo sang a newer version of “kiss a little longer” for Big Red… while Julianne Hough sang a version of, “The taste is gonna move ya.”", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 24}]}, {"id": 6, "text": "And dance fore-e-ever, fore-e-ever", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Fore-e-ever, forever", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Fore-e-ever, fore-e-ever, fore-e-ever", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "Forever on the dance floor", "range": {"end": 9, "start": 9}}]}, {"type": "Outro", "lines": [{"id": 1, "text": "Oh, oh, oh-oh-oh-oh-oh", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Oh-oh-oh, yeah", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Forever, ever, ever, ever", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Forever, ever, ever", "range": {"end": 4, "start": 4}}]}], "schemaVersion": 1}', 'ly_v1_8157d3e44f227d6f', true, 1, '2026-05-29 11:13:48.803409+00', '2026-05-29 11:13:48.803409+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('22fd43c8-ab0c-4025-a84f-2a4ed482f076', '2ff01db8-fe2c-4b41-a96d-4004a280207d', 'genius', '{"source": "genius", "sections": [{"type": "Verse 1: Joe Goddard", "lines": [{"id": 1, "text": "She said, \"How did we", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Our life is confusing, and has many twists and turns. “She” is in a relationship with the narrator of this song, and she asks him how they got “so lost” into this relationship. They may have gone through many roads to get here, but they aren’t leaving their relationship tonight.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 0}]}, {"id": 2, "text": "Get ourselves so lost?\"", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "And I said, \"I don''t know", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "But we will not be leaving tonight, tonight\"", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "When you hold me, I", "range": {"end": 5, "start": 5}, "annotations": [{"text": "Though life is scary and confusing, intimately touching a person and being physically close can give a sense of security. While they feel lost, they can feel at home in each others'' arms.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 2}]}, {"id": 6, "text": "I feel better", "range": {"end": 6, "start": 6}}]}, {"type": "Pre-Chorus: Alexis Taylor", "lines": [{"id": 1, "text": "I only want one night", "range": {"end": 1, "start": 1}, "annotations": [{"text": "He knows this moment won’t last forever, and eventually he will find himself lost and alone again. But he is going to enjoy the night as it passes.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 0}]}, {"id": 2, "text": "Together in our arms", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "This is the longest night", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "We''re meeting arms to arms", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus: Alexis Taylor", "lines": [{"id": 1, "text": "Nothing is wasted and life is worth living\nNothing is wasted and life is worth living", "range": {"end": 5, "start": 1}, "annotations": []}, {"id": 2, "text": "Heaven is nowhere, just look to the stars", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "There is a day that is yours for embracing\nThere is a day that is yours for embracing", "range": {"end": 8, "start": 3}, "annotations": [{"text": "But this turns around once again. Even though heaven doesn’t exist, and there isn’t a meaning or an endpoint to life, the day is still there for the taking. We can make meaning out of life if we choose to.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 1}]}, {"id": 4, "text": "Everything''s nothing, and nothing is ours\nEverything''s nothing, and nothing is ours", "range": {"end": 10, "start": 4}, "annotations": [{"text": "This is probably the most important line of the song. The narrator admits that there isn’t meaning to life, that nothing really matters, and yet that nothing is still there for the taking. Life is meaningless, unless we give it meaning. The narrator is giving meaning to life by embracing the night with his lover.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 2}]}, {"id": 5, "text": "(I only want one night)\n(This is the longest night)", "range": {"end": 9, "start": 6}, "annotations": [{"text": "He knows this moment won’t last forever, and eventually he will find himself lost and alone again. But he is going to enjoy the night as it passes.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 0}]}, {"id": 6, "text": "Heaven is nowhere, just look to the stars", "range": {"end": 7, "start": 7}}, {"id": 7, "text": "Our–, our–", "range": {"end": 11, "start": 11}}]}, {"type": "Verse 2: Joe Goddard", "lines": [{"id": 1, "text": "And maybe if we''d never come this way", "range": {"end": 1, "start": 1}, "annotations": [{"text": "The narrator reflects once again on the circumstances that brought him here. Maybe if he hadn’t “gotten lost” with this girl, with this relationship, he could have been better off, and maybe her too. But it also could have gone in a worse direction. This feeds into the theme that he should just enjoy the moment rather than over-analyzing it.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 0}]}, {"id": 2, "text": "Then we would live and prosper", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "But I doubt it", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "We are a violent race", "range": {"end": 4, "start": 4}, "annotations": [{"text": "Humans are far from perfect, we have caused many wars, slavery, violence etc. We don’t deserve a perfect life, which we will never get anyway. So we need to seize on to these small moments that the narrator describes.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 1}]}, {"id": 5, "text": "And we deserve what we get", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "When you hold me, when you hold me", "range": {"end": 6, "start": 6}, "annotations": []}, {"id": 7, "text": "I feel better", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "I feel better", "range": {"end": 8, "start": 8}}]}, {"type": "Pre-Chorus: Alexis Taylor & Joe Goddard", "lines": [{"id": 1, "text": "I only want one night", "range": {"end": 1, "start": 1}, "annotations": []}, {"id": 2, "text": "Together in our arms (I feel better)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "This is the longest night", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "We''re meeting arms to arms (I feel better)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "I only want one night", "range": {"end": 5, "start": 5}, "annotations": [{"text": "He knows this moment won’t last forever, and eventually he will find himself lost and alone again. But he is going to enjoy the night as it passes.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 0}]}, {"id": 6, "text": "Together in our arms (I feel better)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "This is the longest night", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "We''re meeting arms to arms", "range": {"end": 8, "start": 8}}]}, {"type": "Chorus: Alexis Taylor", "lines": [{"id": 1, "text": "Nothing is wasted, a life is worth living\nNothing is wasted, a life is worth living\nNothing is wasted, a life is worth living\nNothing is wasted, a life is worth living", "range": {"end": 17, "start": 1}, "annotations": []}, {"id": 2, "text": "Heaven is nowhere, just look to the stars", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "There is a day that is yours for embracing\nThere is a day that is yours for embracing\nThere is a day that is yours for embracing\nThere is a day that is yours for embracing", "range": {"end": 21, "start": 3}, "annotations": [{"text": "But this turns around once again. Even though heaven doesn’t exist, and there isn’t a meaning or an endpoint to life, the day is still there for the taking. We can make meaning out of life if we choose to.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 1}]}, {"id": 4, "text": "Everything''s nothing, and nothing is ours\nEverything''s nothing, and nothing is ours\nEverything''s nothing, and nothing is ours\nEverything''s nothing, and nothing is ours", "range": {"end": 23, "start": 4}, "annotations": [{"text": "This is probably the most important line of the song. The narrator admits that there isn’t meaning to life, that nothing really matters, and yet that nothing is still there for the taking. Life is meaningless, unless we give it meaning. The narrator is giving meaning to life by embracing the night with his lover.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 2}]}, {"id": 5, "text": "Heaven is nowhere, just look to the stars", "range": {"end": 6, "start": 6}}, {"id": 6, "text": "(I only want one night)\n(Together in our arms)\n(This is the longest night)\n(We''re meeting arms to arms)\n(I only want one night)\n(Together in our arms)\n(This is the longest night)\n(We''re meeting arms to arms)", "range": {"end": 24, "start": 10}, "annotations": [{"text": "He knows this moment won’t last forever, and eventually he will find himself lost and alone again. But he is going to enjoy the night as it passes.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 0}]}, {"id": 7, "text": "Heaven is nowhere, just look to the stars", "range": {"end": 11, "start": 11}}, {"id": 8, "text": "Heaven is nowhere, just look to the stars", "range": {"end": 19, "start": 19}}]}], "schemaVersion": 1}', 'ly_v1_edd2f01c9c750452', true, 1, '2026-05-29 11:13:58.601057+00', '2026-05-29 11:13:58.601057+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('0a02859e-a984-46cc-bed5-d707a344fe33', '30093248-ddac-4a26-bda4-c6acc72622ef', 'genius', '{"source": "genius", "sections": [{"type": "Intro: Juelz Santana", "lines": [{"id": 1, "text": "Okay, check it, check it, check it out", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "It''s Santana again steppin'', steppin'', steppin'' out (Uh)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "One of the brand-new big-boy toys", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "I do big-boy things, I make big-boy noise, ''cause", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "I know what girls want (Want)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "I know what they like (Like)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "They wanna stay up (Ayy!) and party all night", "range": {"end": 7, "start": 7}, "annotations": [{"text": "A reference to a Jay Z song, “I Know What Girls Like”. The song itself samples The Waitresses‘ 1980 single “I Know What Boys Like”.\n\nApparently Juelz is forgetting a lot of other stuff that girls want guys to do… She might want to bring a friend cause you know, it ain’t fun unless the homies get some.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 5}]}, {"id": 8, "text": "So bring a friend", "range": {"end": 8, "start": 8}}]}, {"type": "Verse 1: Chris Brown", "lines": [{"id": 1, "text": "Let me talk to you, tell you how it is", "range": {"end": 1, "start": 1}, "annotations": [{"text": "When Chris saw this pretty young thing, he couldn’t even help himself.\n\nChris has never been a stranger to going up to a beautiful girl, he’s gotta tell her what’s gonna go down tonight.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 11}]}, {"id": 2, "text": "I was thinkin'' when I saw that body", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Gotta get shawty, tell her what the young boy gon'' do", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Damn, them chicks with you gotta be okay", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Babe, pretty thick with the kick that''s sick", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "That need to be hit, so tell me what y''all gon'' do", "range": {"end": 6, "start": 6}}]}, {"type": "Pre-Chorus: Chris Brown, Juelz Santana", "lines": [{"id": 1, "text": "I got friends and you got friends (Word, oh)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "They hop out, and you hop in (Word, oh-oh)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I look fly and they jockin'' (Word)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "The way you drop, drop makes me wanna pop", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "I got friends and you got friends (Word, hey)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "They hop out, and you hop in (Word)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "I look fly and they jockin'' (Word)", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "The way you drop, drop makes me wanna pop", "range": {"end": 8, "start": 8}}]}, {"type": "Chorus: Chris Brown", "lines": [{"id": 1, "text": "Is ya man (Man) on the floor? (Floor)", "range": {"end": 1, "start": 1}, "annotations": [{"text": "As Chris has already established, her body caught his attention on the dance floor. However, the fact that he’s 16 isn’t gonna stop him from showing her a few moves of his own.\n\nIt can be assumed this girl is taken (“Is ya man on the floor?”) but Chris is adamant that he can move better than her man can and he’s more than willing to prove this to her.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 30}]}, {"id": 2, "text": "If he ain''t (Ain''t), lemme know (Know)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Let me see if you can run it, run it", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Girl, indeed I can run it, run it", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Is ya man (Man) on the floor? (Floor)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "If he ain''t (Ain''t), lemme know (Lemme know)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Let me see if you can run it, run it", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Girl, indeed I can run it, run it (Come here!)", "range": {"end": 8, "start": 8}}]}, {"type": "Verse 2: Chris Brown", "lines": [{"id": 1, "text": "You''ll see, girl, I can set you off", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Don''t believe my age is gonna slow us down", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I can definitely show you things", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "To have you sayin'' I can''t be sixteen", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Once I get in you won''t let go", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "(And I) I''ll have the girls wishin'' they were you", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "(And I) I know you heard about me", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "But guess what''s goin'' down if we leave", "range": {"end": 8, "start": 8}}]}, {"type": "Pre-Chorus: Chris Brown, Juelz Santana", "lines": [{"id": 1, "text": "I got friends and you got friends (Word, oh)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "They hop out, and you hop in (Word, oh)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I look fly and they jockin'' (Word)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "The way you drop, drop makes me wanna pop", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "I got friends and you got friends (Word)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "They hop out, and you hop in (Word, hey)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "I look fly and they jockin'' (Word, ooh)", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "The way you drop, drop makes me wanna pop (Ooh, ooh)", "range": {"end": 8, "start": 8}}]}, {"type": "Chorus: Chris Brown, Juelz Santana", "lines": [{"id": 1, "text": "Is ya man (Man) on the floor? (Floor, uh-huh)", "range": {"end": 1, "start": 1}, "annotations": [{"text": "As Chris has already established, her body caught his attention on the dance floor. However, the fact that he’s 16 isn’t gonna stop him from showing her a few moves of his own.\n\nIt can be assumed this girl is taken (“Is ya man on the floor?”) but Chris is adamant that he can move better than her man can and he’s more than willing to prove this to her.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 30}]}, {"id": 2, "text": "If he ain''t (Ain''t), lemme know (Know, uh-huh)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Let me see if you can run it, run it (Yeah)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Girl, indeed I can run it, run it (Ayy)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Is ya man (Man) on the floor? (Floor, uh-huh)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "If he ain''t (Ain''t), lemme know (Lemme know, uh-huh)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Let me see if you can run it, run it (Ayy)", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Girl, indeed I can run it, run it (Let''s go)", "range": {"end": 8, "start": 8}}]}, {"type": "Bridge: Chris Brown, Juelz Santana", "lines": [{"id": 1, "text": "Girl, you feel right (Feel right)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Make me feel like (Feel like)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I wanna do a little somethin'' (Do a little somethin'')", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Ain''t no thing ''less you do it for sure", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Girl, the way that you''re wearin'' them jeans", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Is turnin'' me on", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "I''m the hottest thing that''s in these streets (DipSet, Santana)", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "So, baby, won''t you rock me? (Ayy)", "range": {"end": 8, "start": 8}}]}, {"type": "Verse 3: Juelz Santana", "lines": [{"id": 1, "text": "Make it drop, honey (Honey), make it pop, honey (Honey)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Whip whop, tick-tock to the clock for me", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Don''t stop doin'' that (Don''t)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "And shorty know I mean what I say so she won''t stop doin'' that", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Plus I heard if you can dance, you can bump", "range": {"end": 5, "start": 5}, "annotations": [{"text": "It’s a common assumption that if somebody can dance, they are good in bed. The reason for this is that they can clearly move their body to the beat and know how to work their body.\n\nJulez can see what this girl is doing on the dance floor so he can’t wait to bring her home and see how she works her body for him.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 18}]}, {"id": 6, "text": "Well dance time is up, let''s go, let''s go (Yup)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "We can get it in (Yup), we can get some friends", "range": {"end": 7, "start": 7}, "annotations": [{"text": "Shouting (or whispering) out Ying Yang Twins‘ track “Wait (The Whisper Song)”.\n\nJust wait ‘til you see my dick\n\nHowever, for parental reasons (as Chris was only 16 when this song was released), the word “dick” is muted. Although, if this song was to be released today, it’s safe to say that “dick” and more would be included on the track.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 27}]}, {"id": 8, "text": "Do it like the Ying Yang Twins, start whisperin''", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "Wait ''til you see my ayy!", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "Wait ''til you see my ayy!", "range": {"end": 10, "start": 10}}, {"id": 11, "text": "Let me fall back, you ain''t ready for all that", "range": {"end": 11, "start": 11}}, {"id": 12, "text": "Have you sleep late, real late, yeah, takin'' a long nap (Ayy)", "range": {"end": 12, "start": 12}}, {"id": 13, "text": "You tell your friends to get with my friends", "range": {"end": 13, "start": 13}, "annotations": [{"text": "Interpreting Puff Daddy’s lyrics on Biggie’s hit single, “Big Poppa”.\n\nHoney, check it\nTell your friends to get with my friends\nAnd we can be friends\nShit, we can do this every weekend, aight?\nIs that aight with you?\nYeah, keep bangin''", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 23}]}, {"id": 14, "text": "We could be friends, switch and meet friends", "range": {"end": 14, "start": 14}}, {"id": 15, "text": "(Switch!) We can do it all night long and", "range": {"end": 15, "start": 15}, "annotations": [{"text": "Juelz is referencing the Will Smith song “Switch”, which Smith says in the same commanding voice on his record.\n\n“Switch” came out in February in 2005, a few months before “Run It!” came out.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 16}]}, {"id": 16, "text": "''Til the clock hit mornin'', ya dig? (Ayy)", "range": {"end": 16, "start": 16}}]}, {"type": "Chorus: Chris Brown", "lines": [{"id": 1, "text": "Is ya man (Man, oh) on the floor? (Floor)", "range": {"end": 1, "start": 1}, "annotations": [{"text": "As Chris has already established, her body caught his attention on the dance floor. However, the fact that he’s 16 isn’t gonna stop him from showing her a few moves of his own.\n\nIt can be assumed this girl is taken (“Is ya man on the floor?”) but Chris is adamant that he can move better than her man can and he’s more than willing to prove this to her.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 30}]}, {"id": 2, "text": "If he ain''t (Ain''t), lemme know (Know, ooh, ooh, yeah)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Let me see if you can run it, run it", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Girl, indeed I can run it, run it (Oh, woah-oh)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Is ya man (Man, oh, woah-oh) on the floor? (Floor)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "If he ain''t (Ain''t), lemme know (Lemme know, mmm)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Let me see if you can run it, run it (Run it)", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Girl, indeed I can run it, run it (Yeah)", "range": {"end": 8, "start": 8}}]}, {"type": "Outro: Chris Brown, Juelz Santana", "lines": [{"id": 1, "text": "Oh-oh (Uh)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Oh, oh (Woo! Uh-huh)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Oh, woah (Woo!)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Oh-oh (Woo! Chris Brown)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "(Ayy! Woo!)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "(Woo! Ayy!)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "(Woo!)", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "(Ayy, ayy)", "range": {"end": 8, "start": 8}}]}], "schemaVersion": 1}', 'ly_v1_752b244c3ef93ea4', true, 1, '2026-05-29 11:14:03.894534+00', '2026-05-29 11:14:03.894534+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('1102e144-ec95-4355-9166-8fd6d4e1dc58', '03b0c165-6c9b-47d9-8e1e-131bddcaf106', 'genius', '{"source": "genius", "sections": [{"type": "Verse 1", "lines": [{"id": 1, "text": "I could go and read your mind", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Gracie Abrams explained the meaning behind these lines in the story of my song:\n\nFeeling like you know someone so well, that no words are required to understand exactly what it is the’re thinking", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 2}]}, {"id": 2, "text": "Think about your dumb face all the time", "range": {"end": 2, "start": 2}, "annotations": [{"text": "Gracie Abrams explained the meaning behind these lines in the story of my song:\n\nI think you’re dumb, but you’re in my head constantly. Sort off like this push and pull between like, I’m so over it, it’s so embarrassing, you’re so embarrassing, but clearly they’re occupying a lot of space in your head.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 3}]}, {"id": 3, "text": "Living in your glass house, I''m outside, uh", "range": {"end": 3, "start": 3}, "annotations": [{"text": "Abrams'' assertion that the subject of this song lives in a “glass house” can be interpreted in a few ways. The well-known metaphor “those who live in glass houses shouldn’t throw stones,” can be applied, painting the subject as the proverbial hypocrite. Another reason could be that Abrams is actually outside the subject’s home, a place that may have been home to both, but no longer is.\n\nThe final and clearest explanation of the glass house’s symbolic significance is to emphasize Abram’s current views on the subject and their relationship. With Abrams already asserting in the opening line her ability to read the subject’s mind with ease, the glass house essentially represents the subject’s mind. Transparent to Abrams, this suggests that the subject is easy to understand now that she is out of the relationship. It can be further speculated that the subject has a history of manipulating Abrams through their actions during the relationship, with their true intentions now “clear as glass” to Abrams now.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 29}]}, {"id": 4, "text": "Looking in her big blue eyes", "range": {"end": 4, "start": 4}, "annotations": [{"text": "In Story of My Song, Gracie discussed this line:\n\n\nThis piece felt important to Audrey and I. And I remember us, between sips of wine, kind of listing all of the potential qualities that we could dissect about her\n\nI think as a brown-eyed person, sometimes people with blue eyes are like, “Why’d you get that? It’s a good thing to have?”", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 5}]}, {"id": 5, "text": "Did it just to hurt me, make me cry", "range": {"end": 5, "start": 5}, "annotations": [{"text": "Gracie Abrams explained the meaning behind these lines in the story of my song:\n\nI also feel like this song is a good example of being like broken up with can sort of trigger some pretty navel gazing, a bit self-centered or like mildly narcissistic thoughts to come up. I think I’m a bigger person than these lyrics would suggest. But we ultimately ended writing the lyrics really, really quick. Every song I’ve ever really cared about making, you’re kind of just pulling it out of thin air a little bit and then there’s like a mini blackout period where you then like hear it in full at the end, and it just [snaps] it just appeared.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 3}]}, {"id": 6, "text": "Smiling through it all, yeah, that''s my life", "range": {"end": 6, "start": 6}, "annotations": [{"text": "A riff on the “Can’t Believe This My Life” / LeBron James Smiling meme:\n\n\n\nAs explained during her Interscope Records artist showcase, the meme holds significance for Gracie and her best friend turned co-writer Audrey:\n\nAudrey and I would send that [meme] back and forth when we were really sad to each other, and then, during Covid, I think it was my birthday? She made me a huge blanket with that picture on it. Like the entirety of the blanket was just that photo, […] and his big smile.\n\nGracie later shared an Instagram story depicting a custom-made lighter featuring the meme.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 33}]}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "You''re an idiot, now I''m sure", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Now I''m positive, I should go and warn her", "range": {"end": 2, "start": 2}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Ooh, bet you''re thinking, \"She''s so cool\"", "range": {"end": 1, "start": 1}, "annotations": [{"text": "On The Secret of Us (Deluxe), “That’s So True” is preceded by “Cool”, which this line is likely a reference to. “Cool” also has a line in the first verse about kicking back on a couch:\n\nYou kick back on your couch with a glass of wine", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 48}]}, {"id": 2, "text": "Kicking back on your couch, making eyes from across the room", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Wait, I think I''ve been there too, ooh", "range": {"end": 3, "start": 3}, "annotations": []}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "What''d she do to get you off? (Uh-huh)", "range": {"end": 1, "start": 1}, "annotations": []}, {"id": 2, "text": "Taking down her hair like, oh, my God", "range": {"end": 2, "start": 2}, "annotations": [{"text": "In Story of My Song, Gracie shared her love of this verse and this line in particular:\n\nSimilarly to the blue eyes piece, I had recently cut my hair off, so I felt like that’s another thing that we could point to that I, I was like, “Well, maybe it’s because she’s got gorgeous long hair”?", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 2}]}, {"id": 3, "text": "Taking off your shirt, I did that once", "range": {"end": 3, "start": 3}, "annotations": []}, {"id": 4, "text": "Or twice, uh", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "No, I know, I know I''ll fuck off (Uh-huh)", "range": {"end": 5, "start": 5}, "annotations": []}, {"id": 6, "text": "But I think I like her, she''s so fun", "range": {"end": 6, "start": 6}, "annotations": [{"text": "In Gracie’s 2021 song “Rockland”, the first verse ends with:\n\nI’m sure that I would like her\nIf I were slightly nicer\n\nWhich these lines are likely a reference to.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 49}]}, {"id": 7, "text": "Wait, I think I hate her, I''m not that evolved, I''m sorry", "range": {"end": 7, "start": 7}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "She''s missing it, sad, sad boy", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Not my business, but I had to warn ya", "range": {"end": 2, "start": 2}, "annotations": []}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Ooh, bet you''re thinking, \"She''s so cool\"", "range": {"end": 1, "start": 1}, "annotations": [{"text": "On The Secret of Us (Deluxe), “That’s So True” is preceded by “Cool”, which this line is likely a reference to. “Cool” also has a line in the first verse about kicking back on a couch:\n\nYou kick back on your couch with a glass of wine", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 48}]}, {"id": 2, "text": "Kicking back on your couch, making eyes from across the room", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Wait, I think I''ve been there too, ooh", "range": {"end": 3, "start": 3}, "annotations": []}, {"id": 4, "text": "Ooh, you''ve got me thinking, \"She''s so cool\"", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "But I know what I know and you''re just another dude", "range": {"end": 5, "start": 5}, "annotations": []}, {"id": 6, "text": "Ooh, that''s so true, ooh", "range": {"end": 6, "start": 6}}]}, {"type": "Bridge", "lines": [{"id": 1, "text": "Made it out alive, but I think I lost it", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Said that I was fine, said it from my coffin", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Remember how I died when you started walking?", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "That''s my life, that''s my life", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "I''ll put up a fight, taking out my earrings", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Don''t you know the vibe? Don''t you know the feeling?", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "And she''ll spend the night, catch me on your ceiling", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "That''s your price, that''s your price", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "Well", "range": {"end": 9, "start": 9}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Mm, bet you''re thinking, \"She''s so cool\"", "range": {"end": 1, "start": 1}, "annotations": [{"text": "On The Secret of Us (Deluxe), “That’s So True” is preceded by “Cool”, which this line is likely a reference to. “Cool” also has a line in the first verse about kicking back on a couch:\n\nYou kick back on your couch with a glass of wine", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 48}]}, {"id": 2, "text": "Kicking back on your couch, making eyes from across the room", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Wait, I think I''ve been there too, ooh", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Ooh, you''ve got me thinking, \"She''s so cool\"", "range": {"end": 4, "start": 4}, "annotations": []}, {"id": 5, "text": "But I know what I know, and you''re just another dude", "range": {"end": 5, "start": 5}, "annotations": []}, {"id": 6, "text": "Ooh, that''s so true, ooh-ooh, oh", "range": {"end": 6, "start": 6}}]}], "schemaVersion": 1}', 'ly_v1_44bac268adda5b0f', true, 1, '2026-05-29 11:13:49.784391+00', '2026-05-29 11:13:49.784391+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('afc21e46-63a8-47a4-8c86-c58c004cb65b', '4b92eb17-60f6-41ce-849a-a9bd905a9282', 'genius', '{"source": "genius", "sections": [{"type": "Verse 1", "lines": [{"id": 1, "text": "I know you wanted me to stay", "range": {"end": 1, "start": 1}, "annotations": [{"text": "In the opening lyric of “Pink Pony Club,” Chappell Roan addresses her mother’s expectations for her. She struggles with her family’s desires to stay in her Midwest hometown — a concept that is referenced in the album’s title (The Rise and Fall of a Midwest Princess).\n\nThis isn’t the first time Roan’s addressed her mother’s conservative desires. In “Die Young,” Roan conveys a similar sentiment:\n\n”Look at your mama, now she’s crying”\n\nRoan has expressed in an interview with Headliner Magazine that she believes her lyrics have matured significantly since that song. “Pink Pony Club” shows less angst and more of a mature struggle between familial expectations and one’s own dreams.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 19}]}, {"id": 2, "text": "But I can''t ignore the crazy visions of me in L.A.", "range": {"end": 2, "start": 2}, "annotations": [{"text": "Chappell had gone to LA for a little while back before she had blown up as an artist. She said that the space felt so comforting and welcoming, particularly to the queer community. In her words, she could “be who I wanted to be.” and that “changed everything.” Chappell grew up in the Midwest with a very conservative Christian family. She reported memories of going to church camp every summer, and always being considered a “god’s girl”. LA had changed her life and helped her discover who she wanted to be. She still resides there to this day.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 36}]}, {"id": 3, "text": "And I heard that there''s a special place", "range": {"end": 3, "start": 3}, "annotations": [{"text": "According to Roan, this special place is West Hollywood’s iconic gay bar The Abbey, which features male and female go-go dancers and regular drag shows. In 2023, she talked with Teen Vogue about her first time going to The Abbey at 21, just after moving to Los Angeles:\n\nThey have fog shooting out whenever the beat drops, and there’s dancers swinging from the ceiling.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 74}]}, {"id": 4, "text": "Where boys and girls can all be queens every single day", "range": {"end": 4, "start": 4}}]}, {"type": "Refrain", "lines": [{"id": 1, "text": "I''m having wicked dreams of leaving Tennessee", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Despite naming Tennessee in the refrain, Roan actually grew up in Willard, Missouri. She talked a bit about her experience growing up there in a 2022 profile with Rolling Stone:\n\nI felt so out of place in my hometown. I wish it was better. I wish I had better things to say. But mentally, I had a really tough time.\n\nIn recent years, Tennessee has become increasingly hostile towards its LGBTQ+ population, banning drag shows and attacking trans rights. Roan feels called to Santa Monica Boulevard in West Hollywood, CA, which is famous for its gay bars, drag shows, and queer culture and businesses, making it the perfect location for the Pink Pony Club.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 73}]}, {"id": 2, "text": "Hear Santa Monica, I swear it''s calling me", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Won''t make my mama proud, it''s gonna cause a scene", "range": {"end": 3, "start": 3}, "annotations": [{"text": "Here Roan touches on a painful experience familiar to many LGBTQ+ people raised in conservative families: To be true to herself as a queer person, she risks disappointment and rejection from her family and community, whom she still loves nonetheless.\n\nRoan’s narrator can embrace the “wicked dreams” she longs for as a performer dancing onstage at gay clubs, OR she can make her mother proud of her—but she can’t have both.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 36}]}, {"id": 4, "text": "She sees her baby girl, I know she''s gonna scream", "range": {"end": 4, "start": 4}, "annotations": [{"text": "“Baby girl” shows her mother still viewing her as a baby and not the women she grew to be.\nThe first line is basically saying when her southern conservative mother sees her as this person she’s never actually viewed her as. Her mother has never seen her as a drag and LGBTQ icon. Shes only ever seen her as a religious young girl.\n\nThe second line shows the hate her mother would have towards the person she is since it contradicts all her mothers southern conservative views.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 25}]}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "\"God, what have you done?", "range": {"end": 1, "start": 1}, "annotations": [{"text": "While being a “pink pony girl” here means that she dances at the Pink Pony Club, a pink pony is a stereotypical interest for a little girl in a place like Tennessee with strong horse riding and owning culture. Her mother, who would have seen her grow up, could also be decrying that she used to be such a feminine child and conformed to what was expected of her, and now she’s thrown that all away by leaving to live a Queer lifestyle and dance at a club.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 73}]}, {"id": 2, "text": "You''re a pink pony girl, and you dance at the club,\" oh mama", "range": {"end": 2, "start": 2}, "annotations": [{"text": "She is trying to explain to her mother who hates her lifestyle that she’s living this way because she enjoys it and is having fun by living this way. Her mother would view her lifestyle as a dancer at the pink pony club almost blasphemous so the way Chappell is responding is almost brushing it off by saying “I’m just having fun” cause it’s telling her mother she actually enjoys this lifestyle.\n\n“On the stage in my heels” could be hinting towards her being a drag queen at the pink pony club. It could also be showing her mother that she still has the same femininity about her that her mother believed she had no matter her lifestyle.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 35}]}, {"id": 3, "text": "I''m just having fun", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "On the stage in my heels, it''s where I belong, down at the", "range": {"end": 4, "start": 4}, "annotations": [{"text": "Moving to Los Angeles in 2018 allowed Roan to live freely as a queer woman for the first time in her life. Roan found a sense of belonging outside her biological family within queer spaces, a common experience among LGBTQ+ people whose families may not offer support or acceptance. In response, many seek out chosen family and communities where they can express themselves freely and feel genuinely welcome.\n\nThe “Pink Pony Club” represents that space for Roan, a place where she discovered her queer community, sense of family, and safe space. This is reaffirmed in an interview with Rolling Stone, where Roan shared:\n\nI feel allowed to be who I want to be here. That changed everything.\n\nRoan is celebrating this idea of found family, the joy and healing that come from being fully accepted for who you are. When writing “Pink Pony Club,” Roan planned to have drag performers open for her if she ever took it on tour, in homage to her time at The Abbey, a gay bar located in West Hollywood, CA, known for their Drag Brunch performances.\n\nIn 2023, Roan performed alongside local drag queens in Nashville the same day that the Tennessee General Assembly passed an anti-drag bill prohibiting drag shows in non age-restricted venues. Roan would go on to share her sentiment of the show, revealing:\n\nIt was a very emotional show, it was heartbreaking. To know that I was one of the last shows that would happen with all ages with drag performers [for now] is just… I am not scared, because the queer community is strong, we have each other’s backs, and we will overcome hate. We always do. I will continue doing drag. We will continue this, this is not stopping.\n\n—via Teen Vogue\n\n\n\nA drag queen performs at Drag Brunch at the Abbey", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 63}]}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Pink Pony Club, I''m gonna keep on dancing at the\nWest Hollywood, I''m gonna keep on dancing at the", "range": {"end": 3, "start": 1}, "annotations": [{"text": "In a 2023 interview with Teen Vogue, Roan stated that the eponymous Pink Pony Club has become a real space through the crowd of her live shows, where drag queens are the openers and which are unapologetically queer, despite “whatever the fuck the lawmakers are doing.”:\n\nThe pink pony club not just as an idea, but as a real, tangible place she can create for people, if only for a night.  “You have to protect it,” she says. Queer joy, queer safety, queer love. “I have to protect it.”", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 74}]}, {"id": 2, "text": "Pink Pony Club, I''m gonna keep on dancing down in", "range": {"end": 2, "start": 2}, "annotations": [{"text": "West Hollywood is a city located between Los Angeles and Beverly Hills in Los Angeles County, known for a large LGBTQ+ population and a historic association with the community, including numerous queer venues and businesses. One of these venues, The Abbey, is a bar that Chappell has said inspired this song after an “unforgettable” night out.\n\nThis song is a celebration of the freedom experienced by queer people in the environment of a gay bar.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 43}]}, {"id": 3, "text": "Pink Pony Club, Pink Pony Club", "range": {"end": 4, "start": 4}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "I''m up and jaws are on the floor", "range": {"end": 1, "start": 1}, "annotations": [{"text": "The metaphor: she’s higher than the floor, dancing “on the stage in [her] heels,” giving a jaw dropping performance.  She is up; jaws are down.  It’s a firm, concrete image, one that measures both the audience’s awe and her double elevation—stage and heels.\n\nAnother playful example of this juxtaposition: she’s “down at the Pink Pony Club” where she is also “up.” And so, while “jaws are on the floor” that’s also where she is too, in awe, floored, amazed and amazing, “down.”", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 12}]}, {"id": 2, "text": "Lovers in the bathroom and a line outside the door", "range": {"end": 2, "start": 2}, "annotations": [{"text": "‘Lovers in the Bathroom’ seems like an obvious allusion to people making out (or having sex) in a bathroom stall. This liberal attitude towards sexuality is often associated with queer venues like the ‘Pink Pony Club’ that the song is being written about –  Chappell sings about this in a seemingly celebratory manner.\n\nThis line also refers to the lovers being in their own world, not noticing their surroundings or the ‘line outside the door.’ This could show that in this fantasy place, it’s easy to get caught up in yourselves and not have to think about everyone else’s needs, which contrasts the commonly mentioned southern values that prevent the speaker’s mother from being able to support her dreams.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 38}]}, {"id": 3, "text": "Black lights and a mirrored disco ball", "range": {"end": 3, "start": 3}, "annotations": []}, {"id": 4, "text": "Every night''s another reason why I left it all", "range": {"end": 4, "start": 4}, "annotations": [{"text": "Everything she’s experiencing since leave is just proving that leaving was the right thing to do. Shows she has no regrets of leaving everything behind.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 11}]}]}, {"type": "Refrain", "lines": [{"id": 1, "text": "I thank my wicked dreams, a year from Tennessee", "range": {"end": 1, "start": 1}, "annotations": [{"text": "The prior Refrain begins “I’m having wicked dreams”; this one, “I thank my wicked dreams.”  The song articulates and then realizes the narrator’s fantasy: what was first (only) a “wicked dream” and a “crazy vision” is now, “a year” later, a reality, a deliciously unreal reality “where boys and girls can all be queens every single day.”  But strangely and importantly, this Refrain repeats the narrator’s fantasy about her mother’s reaction: “She sees her baby girl, I know she’s gonna scream…”  Not, “She sees her baby girl and now she screams…“ Whereas her wicked dreams come true, she can only imagine—and continues to imagine—her mother’s reaction; the wickedness of the dream remains wicked even as it’s enjoyed.  The song then raises a question: why does the narrator sustain her mother’s scream?   As the narrator’s dream comes true, as she is finally “up and jaws on the floor / Lovers in the bathroom and a line outside the door,” the voice from Tennessee remains an imagined one, one she carries with her.  That is, the fantasy does not include her mother’s approval.  The fantasy, on the contrary, seems to require the forceful “scream,” the “drawl [heard] a thousand miles away.”  The Pink Pony Club then isn’t a delight in spite of her mother’s “what have you done?” but is a delight because it sustains the question as it answers it, if defiantly.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 21}]}, {"id": 2, "text": "Oh, Santa Monica, you''ve been too good to me", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Won''t make my mama proud, it''s gonna cause a scene", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "She sees her baby girl, I know she''s gonna scream", "range": {"end": 4, "start": 4}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "\"God, what have you done?", "range": {"end": 1, "start": 1}, "annotations": [{"text": "While being a “pink pony girl” here means that she dances at the Pink Pony Club, a pink pony is a stereotypical interest for a little girl in a place like Tennessee with strong horse riding and owning culture. Her mother, who would have seen her grow up, could also be decrying that she used to be such a feminine child and conformed to what was expected of her, and now she’s thrown that all away by leaving to live a Queer lifestyle and dance at a club.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 73}]}, {"id": 2, "text": "You''re a pink pony girl, and you dance at the club,\" oh mama", "range": {"end": 2, "start": 2}, "annotations": [{"text": "She is trying to explain to her mother who hates her lifestyle that she’s living this way because she enjoys it and is having fun by living this way. Her mother would view her lifestyle as a dancer at the pink pony club almost blasphemous so the way Chappell is responding is almost brushing it off by saying “I’m just having fun” cause it’s telling her mother she actually enjoys this lifestyle.\n\n“On the stage in my heels” could be hinting towards her being a drag queen at the pink pony club. It could also be showing her mother that she still has the same femininity about her that her mother believed she had no matter her lifestyle.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 35}]}, {"id": 3, "text": "I''m just having fun", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "On the stage in my heels, it''s where I belong, down at the", "range": {"end": 4, "start": 4}, "annotations": [{"text": "Moving to Los Angeles in 2018 allowed Roan to live freely as a queer woman for the first time in her life. Roan found a sense of belonging outside her biological family within queer spaces, a common experience among LGBTQ+ people whose families may not offer support or acceptance. In response, many seek out chosen family and communities where they can express themselves freely and feel genuinely welcome.\n\nThe “Pink Pony Club” represents that space for Roan, a place where she discovered her queer community, sense of family, and safe space. This is reaffirmed in an interview with Rolling Stone, where Roan shared:\n\nI feel allowed to be who I want to be here. That changed everything.\n\nRoan is celebrating this idea of found family, the joy and healing that come from being fully accepted for who you are. When writing “Pink Pony Club,” Roan planned to have drag performers open for her if she ever took it on tour, in homage to her time at The Abbey, a gay bar located in West Hollywood, CA, known for their Drag Brunch performances.\n\nIn 2023, Roan performed alongside local drag queens in Nashville the same day that the Tennessee General Assembly passed an anti-drag bill prohibiting drag shows in non age-restricted venues. Roan would go on to share her sentiment of the show, revealing:\n\nIt was a very emotional show, it was heartbreaking. To know that I was one of the last shows that would happen with all ages with drag performers [for now] is just… I am not scared, because the queer community is strong, we have each other’s backs, and we will overcome hate. We always do. I will continue doing drag. We will continue this, this is not stopping.\n\n—via Teen Vogue\n\n\n\nA drag queen performs at Drag Brunch at the Abbey", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 63}]}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Pink Pony Club, I''m gonna keep on dancing at the\nWest Hollywood, I''m gonna keep on dancing at the", "range": {"end": 3, "start": 1}, "annotations": [{"text": "In a 2023 interview with Teen Vogue, Roan stated that the eponymous Pink Pony Club has become a real space through the crowd of her live shows, where drag queens are the openers and which are unapologetically queer, despite “whatever the fuck the lawmakers are doing.”:\n\nThe pink pony club not just as an idea, but as a real, tangible place she can create for people, if only for a night.  “You have to protect it,” she says. Queer joy, queer safety, queer love. “I have to protect it.”", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 74}]}, {"id": 2, "text": "Pink Pony Club, I''m gonna keep on dancing down in", "range": {"end": 2, "start": 2}, "annotations": [{"text": "West Hollywood is a city located between Los Angeles and Beverly Hills in Los Angeles County, known for a large LGBTQ+ population and a historic association with the community, including numerous queer venues and businesses. One of these venues, The Abbey, is a bar that Chappell has said inspired this song after an “unforgettable” night out.\n\nThis song is a celebration of the freedom experienced by queer people in the environment of a gay bar.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 43}]}, {"id": 3, "text": "Pink Pony Club, Pink Pony Club", "range": {"end": 4, "start": 4}}]}, {"type": "Bridge", "lines": [{"id": 1, "text": "Don''t think I''ve left you all behind", "range": {"end": 1, "start": 1}, "annotations": [{"text": "Despite leaving Tennessee, Chappell is still in touch with where she once was and the experiences she had while growing up. She hasn’t forgotten about anybody there and especially not her mother who wouldn’t approve of her new hyper femme/queer lifestyle in LA", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 22}]}, {"id": 2, "text": "Still love you and Tennessee, you''re always on my mind", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "And mama, every Saturday", "range": {"end": 3, "start": 3}, "annotations": []}, {"id": 4, "text": "I can hear your Southern drawl a thousand miles away, saying", "range": {"end": 4, "start": 4}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "\"God, what have you done?", "range": {"end": 1, "start": 1}, "annotations": [{"text": "While being a “pink pony girl” here means that she dances at the Pink Pony Club, a pink pony is a stereotypical interest for a little girl in a place like Tennessee with strong horse riding and owning culture. Her mother, who would have seen her grow up, could also be decrying that she used to be such a feminine child and conformed to what was expected of her, and now she’s thrown that all away by leaving to live a Queer lifestyle and dance at a club.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 73}]}, {"id": 2, "text": "You''re a pink pony girl, and you dance at the club,\" oh mama", "range": {"end": 2, "start": 2}, "annotations": [{"text": "She is trying to explain to her mother who hates her lifestyle that she’s living this way because she enjoys it and is having fun by living this way. Her mother would view her lifestyle as a dancer at the pink pony club almost blasphemous so the way Chappell is responding is almost brushing it off by saying “I’m just having fun” cause it’s telling her mother she actually enjoys this lifestyle.\n\n“On the stage in my heels” could be hinting towards her being a drag queen at the pink pony club. It could also be showing her mother that she still has the same femininity about her that her mother believed she had no matter her lifestyle.", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 35}]}, {"id": 3, "text": "I''m just having fun", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "On the stage in my heels, it''s where I belong, down at the", "range": {"end": 4, "start": 4}, "annotations": [{"text": "Moving to Los Angeles in 2018 allowed Roan to live freely as a queer woman for the first time in her life. Roan found a sense of belonging outside her biological family within queer spaces, a common experience among LGBTQ+ people whose families may not offer support or acceptance. In response, many seek out chosen family and communities where they can express themselves freely and feel genuinely welcome.\n\nThe “Pink Pony Club” represents that space for Roan, a place where she discovered her queer community, sense of family, and safe space. This is reaffirmed in an interview with Rolling Stone, where Roan shared:\n\nI feel allowed to be who I want to be here. That changed everything.\n\nRoan is celebrating this idea of found family, the joy and healing that come from being fully accepted for who you are. When writing “Pink Pony Club,” Roan planned to have drag performers open for her if she ever took it on tour, in homage to her time at The Abbey, a gay bar located in West Hollywood, CA, known for their Drag Brunch performances.\n\nIn 2023, Roan performed alongside local drag queens in Nashville the same day that the Tennessee General Assembly passed an anti-drag bill prohibiting drag shows in non age-restricted venues. Roan would go on to share her sentiment of the show, revealing:\n\nIt was a very emotional show, it was heartbreaking. To know that I was one of the last shows that would happen with all ages with drag performers [for now] is just… I am not scared, because the queer community is strong, we have each other’s backs, and we will overcome hate. We always do. I will continue doing drag. We will continue this, this is not stopping.\n\n—via Teen Vogue\n\n\n\nA drag queen performs at Drag Brunch at the Abbey", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 63}]}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Pink Pony Club, I''m gonna keep on dancing at the\nWest Hollywood, I''m gonna keep on dancing at the", "range": {"end": 3, "start": 1}, "annotations": [{"text": "In a 2023 interview with Teen Vogue, Roan stated that the eponymous Pink Pony Club has become a real space through the crowd of her live shows, where drag queens are the openers and which are unapologetically queer, despite “whatever the fuck the lawmakers are doing.”:\n\nThe pink pony club not just as an idea, but as a real, tangible place she can create for people, if only for a night.  “You have to protect it,” she says. Queer joy, queer safety, queer love. “I have to protect it.”", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 74}]}, {"id": 2, "text": "Pink Pony Club, I''m gonna keep on dancing down in", "range": {"end": 2, "start": 2}, "annotations": [{"text": "West Hollywood is a city located between Los Angeles and Beverly Hills in Los Angeles County, known for a large LGBTQ+ population and a historic association with the community, including numerous queer venues and businesses. One of these venues, The Abbey, is a bar that Chappell has said inspired this song after an “unforgettable” night out.\n\nThis song is a celebration of the freedom experienced by queer people in the environment of a gay bar.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 43}]}, {"id": 3, "text": "Pink Pony Club, Pink Pony Club", "range": {"end": 4, "start": 4}}]}, {"type": "Outro", "lines": [{"id": 1, "text": "I''m gonna keep on dancing", "range": {"end": 1, "start": 1}, "annotations": [{"text": "The repetition throughout of “I’m gonna keep on dancing” cements the song as a defiant celebration of survival, persistence and resilience. Despite rejection and oppression from hostile families, communities, and legislation, LGBTQ+ people will continue to find joy in their queer experiences and communities like the Pink Pony Club!", "state": "pending", "verified": false, "pinnedRole": null, "votes_total": 33}]}, {"id": 2, "text": "I''m gonna keep on dancing", "range": {"end": 2, "start": 2}}]}], "schemaVersion": 1}', 'ly_v1_439052b11ac392b1', true, 1, '2026-05-29 11:13:59.333675+00', '2026-05-29 11:13:59.333675+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('b25c7977-6127-47c1-a69d-4b08cb6d579f', '56deccb9-466d-4161-b74f-ecb19f648d97', 'genius', '{"source": "genius", "sections": [{"type": "Intro", "lines": [{"id": 1, "text": "I need you, boo", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "I gotta see you, boo", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "And the hearts all over the world tonight", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Said the hearts all over the world tonight", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "And I need you, boo (Oh)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "I gotta see you, boo (Hey)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "And the hearts all over the world tonight", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "Said the hearts all over the world tonight (Uh, uh)", "range": {"end": 8, "start": 8}}]}, {"type": "Verse 1", "lines": [{"id": 1, "text": "Hey, little mama, ooh, you''re a stunner", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Hot little figure, yes, you''re a winner", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "And I''m so glad to be yours", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "You''re a class all your own", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "And ooh, little cutie, when you talk to me", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "I swear the whole world stops, you''re my sweetheart", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "And I''m so glad that you''re mine", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "You are one of a kind and", "range": {"end": 8, "start": 8}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "You mean to me what I mean to you", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "And together, baby, there is nothin'' we won''t do", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "''Cause if I got you, I don''t need money, I don''t need cars", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Girl, you''re my all", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "And oh, I''m into you", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "And girl, no one else would do", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "''Cause with every kiss and every hug", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "You make me fall in love", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "And now I know I can''t be the only one", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "I bet there''s hearts all over the world tonight", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "With the love of their life who feels", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "What I feel when I''m", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "With you, with you, with you, with you, with you, girl", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "With you, with you, with you, with you, with you", "range": {"end": 10, "start": 10}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "Oh, girl, I don''t want nobody else", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Without you, there''s no one left then", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "You''re like Jordan''s on Saturday", "range": {"end": 3, "start": 3}, "annotations": [{"text": "Jordan sneakers are typically released on Saturdays. Just like Chris would line up to buy a fresh pair every Saturday and he can’t wait to get his hands on them, he doesn’t want to wait any longer for his girl—he needs her now.\n\nChris has a huge sneaker collection and devoted a new room in his house to them as he ran out of space in his closets. In an interview with Complex, he said he rocks the Jordan 3’s.", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 42}]}, {"id": 4, "text": "I gotta have you and I cannot wait now", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Hey, little shawty, say you care for me", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "You know I care for you, you know that I''ll be true", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "You know that I won''t lie, you know that I would try", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "To be your everything, yeah", "range": {"end": 8, "start": 8}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "''Cause if I got you, I don''t need money, I don''t need cars", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Girl, you''re my all", "range": {"end": 2, "start": 2}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "And oh, I''m into you (Into you)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "And girl, no one else would do (Won''t)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "''Cause with every kiss and every hug (Hug)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "You make me fall in love", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "And now I know I can''t be the only one (I know I can''t be the only)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "I bet there''s hearts all over the world tonight", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "With the love of their life who feels", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "What I feel when I''m", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "With you, with you, with you, with you, with you, oh", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "With you, with you, with you, with you, with you, hey, hey", "range": {"end": 10, "start": 10}}]}, {"type": "Bridge", "lines": [{"id": 1, "text": "And I will never try to deny that you are my whole life", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "''Cause if you ever let me go, I would die so I won''t front", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I don''t need another woman, I just need your all-or-nothin''", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "''Cause if I got that then I''ll be straight", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Baby, you''re the best part of my day", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "I need you, boo", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "I gotta see you, boo", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "And the hearts all over the world tonight (Hey, hey)", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "Said the hearts all over the world tonight (Ooh, ooh, ooh, yeah)", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "They need it, boo (They need it)", "range": {"end": 10, "start": 10}}, {"id": 11, "text": "They gotta see their boo", "range": {"end": 11, "start": 11}}, {"id": 12, "text": "Said there''s hearts all over the world tonight", "range": {"end": 12, "start": 12}}, {"id": 13, "text": "Hearts all over the world tonight", "range": {"end": 13, "start": 13}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Oh, oh, I''m into you (I''m into you, baby)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "And girl, no one else would do", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "''Cause with every kiss (Every kiss) and every hug (Every hug)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "You make me fall in love (You make me)", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "And now I know I can''t be the only one (Can''t be the only one)", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "I bet there''s hearts all over the world tonight", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "With the love of their life who feels", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "What I feel when I''m", "range": {"end": 8, "start": 8}}, {"id": 9, "text": "With you, with you, with you, with you, with you, girl", "range": {"end": 9, "start": 9}}, {"id": 10, "text": "With you, with you, with you, with you, with you, oh", "range": {"end": 10, "start": 10}}, {"id": 11, "text": "With you, with you, with you, with you, with you, with you", "range": {"end": 11, "start": 11}}, {"id": 12, "text": "Only with you, with you, with you, with you, with you, babe, yeah", "range": {"end": 12, "start": 12}}]}], "schemaVersion": 1}', 'ly_v1_3c1c6c0bab4178ae', true, 1, '2026-05-29 11:13:51.8038+00', '2026-05-29 11:13:51.8038+00') ON CONFLICT DO NOTHING;
INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('bc05d4fb-b145-49de-9f87-9a45868241eb', '4c09fd73-b649-414e-a24f-0b9534234dc1', 'genius', '{"source": "genius", "sections": [{"type": "Verse 1", "lines": [{"id": 1, "text": "From the deep silence of my mind", "range": {"end": 1, "start": 1}, "annotations": [{"text": "he’s saying that he’s looking for something, maybe his identity as a person, that’s deep within himself. coming from a place he doesn’t even seem to know. and even though he doesn’t know or communicate with this unknown subconscious, it recognizes who he is. and without effort or thought it stays true to his identity", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 4}]}, {"id": 2, "text": "There''s something I''m trying to find", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "When it speaks, you know you will hear my name", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Not so complex in design", "range": {"end": 4, "start": 4}, "annotations": [{"text": "this foreign and incomprehensible subconscious isn’t as amazing as some people make it out to be. it doesn’t have a creator or designer. however, it is all too elusive and confusing to us mortals.\nhere he makes somewhat of a contradiction. he almost denies the possibility of something beyond humans and beyond this life by saying the pinnacle of human accomplishment, our subconscious and minds (“the deep silence of my mind”), are not complex. yet, he admits he “steps in vain” implying there is right and wrong in the world. if that were true, something would have to have ordained what in fact is right and wrong. and this singer would also have to believe in that.\nwhat he might mean by stepping in vain is that his efforts to follow and listen to his mind are leading him down the wrong path", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 1}]}, {"id": 5, "text": "But harder to mind", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "As I step, in vain", "range": {"end": 6, "start": 6}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "Won''t you come down to my arms?", "range": {"end": 1, "start": 1}, "annotations": [{"text": "totally changing the subject from the complex philosophy in the previous lines, he turns his attention to someone he cares about or loves. maybe his pensive thoughts have resulted in neglect towards this person but know he’s ready to tell them how he really feels. he would rather hear this person say his name and recognize his identity than his inner self", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 1}]}, {"id": 2, "text": "There''s something I''m ready to say", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Would you call my name?", "range": {"end": 3, "start": 3}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Look at where we are\nLook at where we are", "range": {"end": 6, "start": 1}, "annotations": [{"text": "he feels like he has gone through a lot with this other person and that, along with their love, is enough to keep them together. he needs this person to be his more than he needs to know his true identity or who he should be in life", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 4}]}, {"id": 2, "text": "Remember where we started out", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Never gonna be without each other''s love again", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Look at where we are, are, are", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "I need your name", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Remember where we started out", "range": {"end": 7, "start": 7}}, {"id": 7, "text": "Never gonna be without each other''s love again", "range": {"end": 8, "start": 8}}, {"id": 8, "text": "Look at where we are, are, are", "range": {"end": 9, "start": 9}}, {"id": 9, "text": "I need your name", "range": {"end": 10, "start": 10}}]}, {"type": "Refrain", "lines": [{"id": 1, "text": "Oh, oh, oh, oh, oh, oh, oh, oh", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Oh, oh, oh, oh, oh, oh, oh, oh", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Oh, oh, oh, oh, oh, oh, oh, oh", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Oh, oh, oh, oh, oh", "range": {"end": 4, "start": 4}}]}, {"type": "Verse 2", "lines": [{"id": 1, "text": "A memory tells us that we''re blessed", "range": {"end": 1, "start": 1}, "annotations": [{"text": "he’s trying to convince himself that everything is ok now because everything used to be ok. but when he looks underneath the surface of his emotions, he realizes that everything is far from ok. you can’t live without a working heart. he’s trying to keep on living and accepting the guess that he’ll be ok but he’s falling behind. he’s asking maybe himself, his significant other, or the listener if he should just give up and stop trying right here and now", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 2}]}, {"id": 2, "text": "But opening up this chest", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I discovered that a heart is lame", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Falling behind what we guess", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "But trying to do our best", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Do we stop, do we stop in frame?", "range": {"end": 6, "start": 6}}]}, {"type": "Pre-Chorus", "lines": [{"id": 1, "text": "Won''t you come back to my heart?", "range": {"end": 1, "start": 1}, "annotations": [{"text": "all he wants is for this person to come back into his life. he’s ready to stop being distant or cold and ready to tell them the truth. the truth about his emotions and that person are more important than the truth about himself", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 2}]}, {"id": 2, "text": "There''s something I''m trying to say", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Would you call my name?", "range": {"end": 3, "start": 3}}]}, {"type": "Chorus", "lines": [{"id": 1, "text": "Look at where we are\nLook at where we are", "range": {"end": 6, "start": 1}, "annotations": [{"text": "he feels like he has gone through a lot with this other person and that, along with their love, is enough to keep them together. he needs this person to be his more than he needs to know his true identity or who he should be in life", "state": "accepted", "verified": false, "pinnedRole": null, "votes_total": 4}]}, {"id": 2, "text": "Remember where we started out", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Never gonna be without each other''s love again", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Look at where we are, are, are", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "I need your name", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Remember where we started out", "range": {"end": 7, "start": 7}}, {"id": 7, "text": "Never gonna be without each other''s love again", "range": {"end": 8, "start": 8}}, {"id": 8, "text": "Look at where we are, are, are", "range": {"end": 9, "start": 9}}, {"id": 9, "text": "I need your name", "range": {"end": 10, "start": 10}}]}, {"type": "Refrain", "lines": [{"id": 1, "text": "Oh, oh, oh, oh, oh, oh, oh, oh", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Oh, oh, oh, oh, oh, oh", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "Oh, oh, oh, oh, oh, oh, oh, oh", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Oh, oh, oh, oh, oh, oh", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Oh, oh, oh, oh, oh, oh, oh, oh", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Oh, oh, oh, oh, oh", "range": {"end": 6, "start": 6}}]}], "schemaVersion": 1}', 'ly_v1_e332a63339d90027', true, 1, '2026-05-29 11:13:59.75321+00', '2026-05-29 11:13:59.75321+00') ON CONFLICT DO 