INSERT INTO public.song_lyrics (id, song_id, source, document, content_hash, has_annotations, schema_version, created_at, updated_at) VALUES ('9b649765-550f-45ca-984b-d8f8e65f2109', '4c803f80-1dd3-45f0-922b-e67997165cd0', 'genius', '{"source": "genius", "sections": [{"type": "Chorus: JENNIE", "lines": [{"id": 1, "text": "I trip and fall in love", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Just like a Tuesday drunk", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I always go all in, all in, all in", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Over the handlebars", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Hitting the ground so hard", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "If I''m alone, fallin'', fallin'', fallin''", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "We ain''t gotta talk about it", "range": {"end": 7, "start": 7}}]}, {"type": "Verse 1: JENNIE, Dua Lipa", "lines": [{"id": 1, "text": "Mercy", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Why is it love is never kind to me? (Me)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I heard that fools rush in and, yeah, that''s me (Me)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "It burns me time and time again", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "So why am I still fixing for this frying pan (Thinkin'')", "range": {"end": 5, "start": 5}}]}, {"type": "Pre-Chorus: Dua Lipa, JENNIE & Both", "lines": [{"id": 1, "text": "I wonder what you''re doing for tonight and forever (Oh-oh)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "I could be the rest of your life or whatever", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "My lips and your lips, we could press them together (Together, ''gether)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "I don''t ever think twice, and, baby, that''s why", "range": {"end": 4, "start": 4}}]}, {"type": "Chorus: JENNIE & Dua Lipa", "lines": [{"id": 1, "text": "I trip and fall in love", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Just like a Tuesday drunk", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I always go all in, all in, all in", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Over the handlebars", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Hitting the ground so hard", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "If I''m alone, fallin'', fallin'', fallin''", "range": {"end": 6, "start": 6}}]}, {"type": "Verse 2: Dua Lipa", "lines": [{"id": 1, "text": "Another round, another drink", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "I try to stop, but I can''t think", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "About anything else but you (But you)", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "And I''m a little too buzzed on your love to play it cute", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "A single kiss, I lost my mind for seven days and seven nights", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "Can''t eat, sleep, baby, it''s true (It''s true)", "range": {"end": 6, "start": 6}}, {"id": 7, "text": "Tryna bite my lip, I''m probably gonna slip", "range": {"end": 7, "start": 7}}, {"id": 8, "text": "And say some crazy things to you", "range": {"end": 8, "start": 8}}]}, {"type": "Pre-Chorus: JENNIE & Dua Lipa", "lines": [{"id": 1, "text": "I wonder what you''re doing for tonight and forever (Oh-oh)", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "I don''t ever think twice, and, baby, that''s why", "range": {"end": 2, "start": 2}}]}, {"type": "Chorus: JENNIE & Dua Lipa, Dua Lipa", "lines": [{"id": 1, "text": "I trip and fall in love", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Just like a Tuesday drunk", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "I always go all in, all in, all in", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Over the handlebars", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "Hitting the ground so hard", "range": {"end": 5, "start": 5}}, {"id": 6, "text": "If I''m alone, fallin'', fallin'', fallin'' (Fallin'', yeah)", "range": {"end": 6, "start": 6}}]}, {"type": "Outro: Dua Lipa & JENNIE", "lines": [{"id": 1, "text": "We ain''t gotta talk about", "range": {"end": 1, "start": 1}}, {"id": 2, "text": "Na-na-na-na-na-na-na (Yeah)", "range": {"end": 2, "start": 2}}, {"id": 3, "text": "We ain''t gotta talk about", "range": {"end": 3, "start": 3}}, {"id": 4, "text": "Na-na-na-na-na-na-na", "range": {"end": 4, "start": 4}}, {"id": 5, "text": "We ain''t gotta talk about it", "range": {"end": 5, "start": 5}}]}], "schemaVersion": 1}', 'ly_v1_5ce740aa2520ca87', false, 1, '2026-05-29 11:13:52.837486+00', '2026-05-29 11:13:52.837486+00') ON CONFLICT DO NOTHING;
